window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q04"]=window.__LIBQ["pham-nhan-tu-tien"]["q04"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q04"]["artifacts"]={"updatedAt":"2026-07-13","count":330,"artifacts":[{"id":"ngan-sac-cu-kiem-cua-khuc-hon","name":"Ngân sắc cự kiếm của Khúc Hồn","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Khúc Hồn"],"trangThai":"đang dùng","blurb":"Thanh cự kiếm màu bạc do Khúc Hồn sử dụng trong lúc bảo hộ Hàn Lập trên cô đảo.","detail":"Khúc Hồn dùng ngân sắc cự kiếm phá hỏng Truyền Tống trận cổ xưa theo lệnh Hàn Lập. Thanh kiếm còn được dùng để chém khối đá núi chắn lối ra như chém đậu hũ.","hinhDang":"Cự kiếm màu bạc","uyLuc":"Có thể phá hỏng Truyền Tống trận cổ xưa và chém mở đá núi chắn đường.","congNang":["Phá hủy Truyền Tống trận cổ xưa @c0364","Chém nát khối đá chắn lối ra khỏi thạch động @c0364"],"chuSoHuu":[{"ten":"Khúc Hồn","tuChuong":"@c0364","denChuong":"","cachCoDuoc":"Đã mang theo khi truyền tống cùng Hàn Lập","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0364","loai":"dùng","importance":"normal","giaiDoan":"Phá trận mở đường","text":"Khúc Hồn dùng ngân sắc cự kiếm phá Truyền Tống trận cổ xưa và chém mở khối đá chắn lối ra.","anchor":"Mà Khúc Hồn lại nhanh chóng tiến lên, giương ngân kiếm trong tay lên cao, chém khối đá này tựa như là đậu hủ vậy"}]},"capNhatToi":"@c0364","nguon":["@c0364"]},{"id":"ngan-giac-thu","name":"Ngân Giác Thụ","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh thực","phamCap":"bảo vật hiếm cho người đi biển","soHuu":["Cố đông chủ"],"trangThai":"đặt trong phòng hảo hạng trên hải thuyền","blurb":"Ngân Giác Thụ là cây lạ màu bạc được đặt trong phòng hảo hạng trên hải thuyền của Cố đông chủ. Theo Vương Trường Thanh, cây có thể làm không khí u ám trở nên thuần tịnh, rất quý đối với người đi biển.","detail":"Ngân Giác Thụ có thân thẳng không nhánh, lá hình tam giác lớn và toàn cây ánh bạc. Nó được dùng trong phòng trên thuyền để tịnh hóa không khí u ám, nên được xem là bảo vật khó có đối với người thường xuyên đi biển.","phanLoaiPhu":"linh thực","hinhDang":"thân thẳng không nhánh, lá tam giác lớn, toàn cây ánh bạc","congNang":["Làm không khí u ám trở nên thuần tịnh @c0365"],"chuHienThoi":"Cố đông chủ","chuSoHuu":[{"ten":"Cố đông chủ","tuChuong":"@c0365","denChuong":"","cachCoDuoc":"đặt trong phòng hảo hạng trên hải thuyền","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0365","loai":"xuất hiện","importance":"normal","giaiDoan":"Trong phòng hảo hạng","text":"Ngân Giác Thụ xuất hiện trong phòng trên hải thuyền và được Vương Trường Thanh giới thiệu là vật có thể tịnh hóa không khí u ám.","anchor":"khi đặt ở nơi có không khí u ám sẽ làm cho không khí trở nên thuần tịnh lại"}]},"capNhatToi":"@c0365","nguon":["@c0365"]},{"id":"hoan-long-dan","name":"Hoàn Long Đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"chưa rõ","soHuu":["Hàn Lập"],"trangThai":"đã dùng một viên","blurb":"Đan dược Hàn Lập dùng khi luyện khí để sớm khôi phục tu vi.","detail":"Hàn Lập lấy ra một bình Hoàn Long Đan, uống một viên rồi bắt đầu luyện khí, nhằm mau chóng khôi phục tu vi trong hoàn cảnh lạ ở Loạn Tinh Hải.","congNang":["Phụ trợ Hàn Lập luyện khí và khôi phục tu vi @c0367"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0367","denChuong":"","cachCoDuoc":"đã mang theo trên người","trangThai":"đã dùng một viên"}],"tabs":{"tienTrinh":[{"chuong":"@c0367","loai":"dùng","importance":"normal","giaiDoan":"Khôi phục tu vi","text":"Hàn Lập uống một viên Hoàn Long Đan rồi luyện khí để sớm khôi phục tu vi.","anchor":"từ trên người lấy ra một bình “Hoàn Long Đan”, đem một viên cho vào miệng, bắt đầu luyện khí"}]},"capNhatToi":"@c0367","nguon":["@c0367"]},{"id":"ngoc-bai-mau-xanh-cua-khoi-tinh-dao","name":"Ngọc bài màu xanh của Khôi Tinh Đảo","cn":"","aliases":["Lục sắc ngọc bài"],"category":"khac","categoryLabel":"Thẻ bài/lệnh bài thân phận","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đang giữ","blurb":"Thẻ bài thân phận do Dương tiên sư cấp cho Hàn Lập tại cảng khẩu Khôi Tinh Đảo. Nó chứng minh thân phận hợp lệ trên đảo và mất thẻ sẽ bị xử theo luật như kẻ xâm nhập nếu không kịp cấp lại.","detail":"Dương tiên sư dùng pháp lực khắc dấu hiệu lên ngọc bài màu xanh rồi giao cho Hàn Lập. Thẻ bài phải được bảo quản cẩn thận; nếu mất phải đến chỗ Dương tiên sư lĩnh cái khác, nếu không sẽ bị trị tội theo luật Khôi Tinh Đảo như người xâm nhập.","phanLoaiPhu":"lệnh bài thân phận","hinhDang":"ngọc bài màu xanh","chuHienThoi":"Hàn Lập","congNang":["Chứng minh thân phận hợp lệ trên Khôi Tinh Đảo @c0368"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0368","denChuong":"","cachCoDuoc":"Được Dương tiên sư cấp sau khi làm thủ tục tại thạch ốc bên cảng khẩu.","trangThai":"đang giữ"}],"dinhDanh":"goc","capNhatToi":"@c0368","tabs":{"tienTrinh":[{"chuong":"@c0368","loai":"xuất hiện","importance":"normal","giaiDoan":"Được cấp tại cảng khẩu","text":"Dương tiên sư khắc dấu hiệu lên ngọc bài màu xanh và giao cho Hàn Lập làm thẻ bài thân phận trên Khôi Tinh Đảo.","anchor":"Thẻ bài này phải bảo quản cho thật tốt. Nếu bị mất phải đến ngay chỗ ta lĩnh cái khác"}]},"nguon":["@c0368"]},{"id":"vong-tron-bang-dong-cua-ve-binh","name":"Vòng tròn bằng đồng của vệ binh","cn":"","aliases":[],"category":"khac","categoryLabel":"Pháp khí/công cụ kiểm tra","phamCap":"Không rõ","soHuu":["Vệ binh phàm nhân thành đá trắng"],"trangThai":"đang dùng","blurb":"Công cụ kiểm tra ở cửa thành đá trắng trên Khôi Tinh Đảo. Khi vệ binh khua vòng trên người Hàn Lập, vòng phát lục quang khiến họ nhận ra thân phận tu tiên giả và hành lễ.","detail":"Vòng tròn bằng đồng được vệ binh dùng khi kiểm tra người vào thành. Trong lần Hàn Lập vào thành đá trắng, vòng được khua trên người hắn vài cái rồi phát lục quang, sau đó vệ binh lập tức cung kính hành lễ.","phanLoaiPhu":"công cụ kiểm tra thân phận","hinhDang":"vòng tròn bằng đồng","chuHienThoi":"Vệ binh phàm nhân thành đá trắng","congNang":["Kiểm tra và nhận biết tu tiên giả hoặc thân phận hợp lệ khi vào thành @c0368"],"chuSoHuu":[{"ten":"Vệ binh phàm nhân thành đá trắng","tuChuong":"@c0368","denChuong":"","cachCoDuoc":"Dùng tại cửa thành đá trắng để kiểm tra người vào thành.","trangThai":"đang dùng"}],"dinhDanh":"goc","capNhatToi":"@c0368","tabs":{"tienTrinh":[{"chuong":"@c0368","loai":"dùng","importance":"normal","giaiDoan":"Kiểm tra Hàn Lập ở cửa thành","text":"Vệ binh dùng vòng đồng khua trên người Hàn Lập, vòng phát lục quang nên họ hành lễ với hắn.","anchor":"vệ binh lấy ra một cái vòng tròn bằng đồng, khua khua trên người Hàn Lập vài cái"}]},"nguon":["@c0368"]},{"id":"linh-ban","name":"Linh bàn","cn":"","category":"khac","categoryLabel":"Vật phẩm nhận biết tu sĩ","phamCap":"Không rõ","soHuu":["Vệ binh phàm nhân thành đá trắng"],"trangThai":"đang dùng","blurb":"Linh bàn là vòng đồng có ngọc bàn khảm, được phàm nhân ở Đông Thạch thành dùng để nhận biết tiên sư. Hàn Lập chú ý đến vật này vì vệ binh không có linh lực vẫn có thể phân biệt người tu tiên.","detail":"Vật phẩm này gắn với nhóm vệ binh phàm nhân canh giữ thành và cung điện. Nhờ Linh bàn, phàm nhân có thể xác nhận thân phận người tu tiên, cho thấy Khôi Tinh Đảo có phương thức kiểm tra tu sĩ riêng trong sinh hoạt địa phương.","phanLoaiPhu":"Vật phẩm nhận biết","hinhDang":"Vòng đồng có ngọc bàn khảm","congNang":["Giúp phàm nhân nhận biết thân phận người tu tiên dù bản thân không có linh lực @c0369"],"chuSoHuu":[{"ten":"Vệ binh phàm nhân thành đá trắng","tuChuong":"@c0369","denChuong":"","cachCoDuoc":"Được trang bị để kiểm tra tiên sư","trangThai":"đang dùng"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c0369","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập vào Đông Thạch thành","text":"Linh bàn được Vương Trường Thanh giải thích là vật giúp phàm nhân nhận biết thân phận tiên sư.","anchor":"có thể giúp cho phàm nhân chúng ta nhận biết được thân phận của các tiên sư"}]},"nguon":["@c0369"]},{"id":"ong-ngoc-mau-xanh","name":"Ống ngọc màu xanh","cn":"","category":"khac","categoryLabel":"Vật phẩm rút thẻ","phamCap":"Không rõ","soHuu":["Lão giả chủ trì khiêu chiến"],"trangThai":"đang dùng","blurb":"Ống ngọc màu xanh là vật lão giả chủ trì dùng để chứa thẻ trúc trong vòng đấu loại. Nó phát thanh quang che chắn thẻ và bài xích thần thức dò xét của các tu sĩ.","detail":"Trong lúc rút thẻ, ống ngọc chứa hơn hai mươi thẻ trúc và dùng để ghép cặp các tu sĩ khiêu chiến. Thanh quang trên ống có thể đẩy thần thức ra ngoài, khiến vài người dò xét bị phản chấn nhẹ, còn Hàn Lập dù có thể phá vẫn không làm để tránh gây chú ý.","phanLoaiPhu":"Vật phẩm rút thẻ","congNang":["Che chắn thẻ trúc bằng thanh quang và bài xích thần thức dò xét @c0369"],"chuSoHuu":[{"ten":"Lão giả chủ trì khiêu chiến","tuChuong":"@c0369","denChuong":"","cachCoDuoc":"Dùng để chủ trì vòng rút thẻ","trangThai":"đang dùng"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c0369","loai":"dùng","importance":"normal","giaiDoan":"Rút thẻ vòng khiêu chiến","text":"Ống ngọc màu xanh phát thanh quang khi các tu sĩ muốn dò xét thẻ trúc bên trong.","anchor":"Mà ống ngọc bỗng nhiên toát ra một tầng thanh quang"}]},"nguon":["@c0369"]},{"id":"the-truc-thi-dau","name":"Thẻ trúc thi đấu","cn":"","category":"khac","categoryLabel":"Vật phẩm tỷ thí","phamCap":"Không rõ","soHuu":["Lão giả chủ trì khiêu chiến","Các tu sĩ khiêu chiến và bị khiêu chiến","Hàn Lập"],"trangThai":"đang dùng","blurb":"Thẻ trúc thi đấu là vật dùng để xác định cặp đấu trong vòng khiêu chiến. Tu sĩ rút được ký hiệu hoặc số tương ứng sẽ vào sân, người thắng lấy thẻ đối phương giao lại để được công nhận.","detail":"Lão giả chủ trì đặt các thẻ trúc trong ống ngọc màu xanh để những người khiêu chiến rút thăm. Hàn Lập rút được thẻ có ký hiệu bạc nhưng vì không biết văn tự địa phương nên suýt không nhận ra lượt số bảy của mình.","phanLoaiPhu":"Vật phẩm tỷ thí","congNang":["Xác định cặp đấu và dùng làm bằng chứng thắng bại trong vòng khiêu chiến @c0369"],"chuSoHuu":[{"ten":"Lão giả chủ trì khiêu chiến","tuChuong":"@c0369","denChuong":"","cachCoDuoc":"Quản lý thẻ cho vòng đấu","trangThai":"đang dùng"},{"ten":"Hàn Lập","tuChuong":"@c0369","denChuong":"","cachCoDuoc":"Rút thẻ trong vòng đấu loại","trangThai":"đang giữ khi vào trận số bảy"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c0369","loai":"dùng","importance":"normal","giaiDoan":"Rút thẻ xác định cặp đấu","text":"Thẻ trúc được dùng để phân cặp và người thắng chỉ cần lấy thẻ của đối phương giao cho lão giả.","anchor":"Chỉ cần có thể lấy thẻ trúc của đối phương giao cho ta là thắng"}]},"nguon":["@c0369"]},{"id":"ngoc-gian-mau-lam","name":"Ngọc giản màu lam","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản chứng bằng","phamCap":"Chưa rõ","soHuu":["Hàn Lập","Cố đông chủ"],"trangThai":"Đã giao cho Cố gia","blurb":"Ngọc giản màu lam do lão giả chủ trì giao cho Hàn Lập sau vòng tỷ thí. Nó chứng nhận Cố gia giành được tư cách buôn bán giữa các đảo lớn.","detail":"Sau khi Hàn Lập là người duy nhất thay Cố gia đoạt tư cách buôn bán giữa các đảo lớn, lão giả chủ trì giao ngọc giản màu lam cho hắn để chuyển lại cho người Cố gia.","congNang":["Chứng nhận tư cách buôn bán giữa các đảo lớn cho Cố gia @c0370"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0370","denChuong":"@c0370","cachCoDuoc":"Nhận từ lão giả chủ trì để chuyển cho Cố gia","trangThai":"đã chuyển giao"},{"ten":"Cố đông chủ","tuChuong":"@c0370","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập thay mặt Cố gia","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0370","loai":"xuất hiện","importance":"normal","giaiDoan":"Chứng bằng tư cách buôn bán","text":"Lão giả giao ngọc giản màu lam cho Hàn Lập sau khi tuyên bố Cố gia đoạt tư cách buôn bán giữa các đảo lớn.","anchor":"lão giả đem một khối ngọc giản màu lam giao cho Hàn Lập"}]},"capNhatToi":"@c0370","nguon":["@c0370"]},{"id":"dam-bao-thu-co-gia-dong-dau","name":"Đảm bảo thư Cố gia đóng dấu","cn":"","aliases":[],"category":"khac","categoryLabel":"Văn thư bảo đảm","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"Đang dùng cho thủ tục định cư","blurb":"Văn thư bảo đảm có dấu của Cố gia. Hàn Lập kiểm tra nó trước khi tới trung bộ Khôi Tinh Đảo làm thủ tục ở lại.","detail":"Đảm bảo thư được Cố gia đóng dấu là giấy tờ Hàn Lập mang theo khi lên Đăng Tiên Các, phục vụ thủ tục xin tư cách ở lại Khôi Tinh Đảo lâu dài.","congNang":["Làm văn thư bảo đảm cho thủ tục định cư tại Khôi Tinh Đảo @c0370"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0370","denChuong":"","cachCoDuoc":"Cố gia chuẩn bị để Hàn Lập làm thủ tục định cư","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0370","loai":"nhắc tới","importance":"normal","giaiDoan":"Chuẩn bị thủ tục định cư","text":"Hàn Lập xem lại đảm bảo thư Cố gia đóng dấu trước khi bay tới trung bộ Khôi Tinh Đảo.","anchor":"Hàn Lập xem lại đảm bảo thư được Cố gia đóng dấu"}]},"capNhatToi":"@c0370","nguon":["@c0370"]},{"id":"phap-khi-phi-hanh-hinh-banh-xe-cua-van-tuong","name":"Pháp khí phi hành hình bánh xe của Văn Tường","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí phi hành","phamCap":"Chưa rõ","soHuu":["Văn Tường"],"trangThai":"Đang sử dụng","blurb":"Pháp khí phi hành dạng bánh xe của Văn Tường. Hắn cưỡi nó khi xuất hiện gần tiên sơn trung bộ Khôi Tinh Đảo để gặp Hàn Lập.","detail":"Pháp khí có hình giống bánh xe, được Văn Tường đạp dưới chân để phi hành khi tiếp cận Hàn Lập gần tiên sơn.","hinhDang":"Giống một cái bánh xe","congNang":["Dùng để phi hành @c0370"],"chuSoHuu":[{"ten":"Văn Tường","tuChuong":"@c0370","denChuong":"","cachCoDuoc":"Đang sở hữu khi xuất hiện gần tiên sơn","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0370","loai":"xuất hiện","importance":"normal","giaiDoan":"Văn Tường cưỡi pháp khí","text":"Văn Tường xuất hiện trước Hàn Lập khi đang đạp lên pháp khí phi hành hình bánh xe.","anchor":"dưới chân đang dậm lên một cái luân tử (bánh xe) giống như pháp khí phi hành"}]},"capNhatToi":"@c0370","nguon":["@c0370"]},{"id":"lam-sac-ngoc-boi","name":"Lam sắc ngọc bội","cn":"","category":"phap-bao","categoryLabel":"Pháp khí cấp thấp / tín vật định cư","phamCap":"pháp khí cấp thấp","soHuu":["Hàn Lập"],"trangThai":"đang do Hàn Lập giữ","blurb":"Lam sắc ngọc bội là tín vật định cư mà Hàn Lập nhận tại Đăng Tiên Các sau khi nộp lại ngọc bài màu xanh cũ. Vật này có lam quang và công hiệu tị thủy, được nói là khá hữu dụng trên đảo.","detail":"Trung niên nhân phụ trách Đăng Tiên Các thu lại ngọc bài màu xanh của Hàn Lập rồi đổi cho hắn lam sắc ngọc bội. Ngoài vai trò tín vật định cư, ngọc bội còn có hiệu quả tị thủy.","phanLoaiPhu":"tín vật định cư","hinhDang":"ngọc bội màu lam","chuHienThoi":"Hàn Lập","congNang":["Tị thủy, hỗ trợ khi ở trên đảo @c0371"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0371","denChuong":"","cachCoDuoc":"Được trung niên nhân phụ trách Đăng Tiên Các cấp sau khi thu lục sắc ngọc bài cũ.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0371","loai":"xuất hiện","importance":"normal","giaiDoan":"Cấp tín vật định cư","text":"Trung niên nhân phụ trách Đăng Tiên Các đổi lam sắc ngọc bội cho Hàn Lập, nói vật này có công hiệu tị thủy và hữu dụng trên đảo.","anchor":"mà đổi thành một cái lam sắc ngọc bội"}]},"capNhatToi":"@c0371","nguon":["@c0371"]},{"id":"kim-sac-thu-sach","name":"Kim sắc thư sách","cn":"","category":"khac","categoryLabel":"Sổ đăng ký định cư","phamCap":"không rõ","soHuu":["Trung niên nhân phụ trách Đăng Tiên Các"],"trangThai":"đang dùng","blurb":"Kim sắc thư sách là sổ đăng ký mà người phụ trách Đăng Tiên Các dùng để ghi tên Hàn Lập. Nó gắn với thủ tục định cư của tu sĩ trên Khôi Tinh Đảo.","detail":"Trong lúc làm thủ tục, trung niên nhân phụ trách Đăng Tiên Các lấy kim sắc thư sách ra và điền tên Hàn Lập vào đó. Vật này có công dụng ghi danh định cư trên đảo.","phanLoaiPhu":"sổ đăng ký","hinhDang":"thư sách màu vàng kim","chuHienThoi":"Trung niên nhân phụ trách Đăng Tiên Các","congNang":["Ghi danh định cư cho tu sĩ trên Khôi Tinh Đảo @c0371"],"chuSoHuu":[{"ten":"Trung niên nhân phụ trách Đăng Tiên Các","tuChuong":"@c0371","denChuong":"","cachCoDuoc":"Được ông lấy ra khi làm thủ tục cho Hàn Lập.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0371","loai":"dùng","importance":"normal","giaiDoan":"Ghi danh Hàn Lập","text":"Trung niên nhân phụ trách Đăng Tiên Các lấy kim sắc thư sách ra để ghi tên Hàn Lập vào sổ định cư.","anchor":"trung niên nhân xuất ra một khối kim sắc thư sách"}]},"capNhatToi":"@c0371","nguon":["@c0371"]},{"id":"ngan-sac-hoa-sach","name":"Ngân sắc họa sách","cn":"","aliases":["Họa sách bản đồ chọn nơi tu luyện"],"category":"khac","categoryLabel":"Bản đồ chọn nơi tu luyện","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang do Hàn Lập giữ","blurb":"Ngân sắc họa sách là bản đồ mà người phụ trách Đăng Tiên Các đưa cho Hàn Lập để chọn nơi tu luyện. Nó hiển thị những địa điểm đã có người ở và những nơi còn có thể lựa chọn.","detail":"Sau khi ghi danh cho Hàn Lập, trung niên nhân phụ trách Đăng Tiên Các đưa ngân sắc họa sách để hắn tự chọn nơi tu luyện. Trên họa sách, vị trí có kim quang là nơi đã có người ở, còn lại là nơi có thể tu luyện.","phanLoaiPhu":"bản đồ chọn nơi tu luyện","hinhDang":"họa sách màu bạc","chuHienThoi":"Hàn Lập","congNang":["Hiển thị nơi đã có người ở và nơi còn có thể tu luyện @c0371"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0371","denChuong":"","cachCoDuoc":"Được trung niên nhân phụ trách Đăng Tiên Các giao để tự chọn chỗ tu luyện.","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0371","loai":"xuất hiện","importance":"normal","giaiDoan":"Chọn nơi tu luyện","text":"Trung niên nhân phụ trách Đăng Tiên Các giao ngân sắc họa sách cho Hàn Lập để xem địa điểm đã có người ở và tự chọn nơi tu luyện còn trống.","anchor":"trung niên nhân lại lấy ra từ trên người một kiện ngân sắc họa sách"}]},"capNhatToi":"@c0371","nguon":["@c0371"]},{"id":"kim-sac-mao-but","name":"Kim sắc mao bút","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm ghi nhận","phamCap":"không rõ","soHuu":["Trung niên tu sĩ ở Đăng Tiên Các"],"trangThai":"đang dùng","blurb":"Cây bút vàng được trung niên tu sĩ ở Đăng Tiên Các dùng để xác nhận lựa chọn nơi tu luyện. Nó có thể điểm lên họa sách bản đồ để đổi dấu khu vực đã chọn.","detail":"Khi Hàn Lập chọn Tiểu Hoàn Đảo, trung niên tu sĩ lấy kim sắc mao bút điểm lên hòn đảo trên họa sách, khiến bạch quang biến thành kim quang, rồi tiếp tục viết lên ngọc giản chứng minh.","hinhDang":"mao bút màu vàng","chuHienThoi":"Trung niên tu sĩ ở Đăng Tiên Các","congNang":["Ghi nhận lựa chọn nơi tu luyện trên họa sách bản đồ @c0372"],"chuSoHuu":[{"ten":"Trung niên tu sĩ ở Đăng Tiên Các","tuChuong":"@c0372","denChuong":"","cachCoDuoc":"đã mang theo khi xử lý thủ tục","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0372","loai":"dùng","importance":"normal","giaiDoan":"xác nhận Tiểu Hoàn Đảo","text":"Kim sắc mao bút được dùng để điểm lên Tiểu Hoàn Đảo trên họa sách, xác nhận lựa chọn của Hàn Lập.","anchor":"Hắn lần trong áo xuất ra một cái kim sắc mao bút, nhẹ nhàng điểm lên hòn đảo trên bản đồ"}]},"capNhatToi":"@c0372","nguon":["@c0372"]},{"id":"ngoc-gian-chung-minh-tieu-hoan-dao","name":"Ngọc giản chứng minh Tiểu Hoàn Đảo","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản chứng từ","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Ngọc giản chứng minh Hàn Lập là người tu luyện trên Tiểu Hoàn Đảo. Bên trong còn có danh sách cư dân trên đảo.","detail":"Sau khi ghi nhận lựa chọn Tiểu Hoàn Đảo, trung niên tu sĩ viết lên một ngọc giản và giao cho Hàn Lập. Ngọc giản này là bằng chứng quyền tu luyện của hắn tại Tiểu Hoàn Đảo.","hinhDang":"ngọc giản có phù hiệu kim sắc","chuHienThoi":"Hàn Lập","congNang":["Chứng minh quyền tu luyện của Hàn Lập trên Tiểu Hoàn Đảo @c0372","Lưu danh sách cư dân trên Tiểu Hoàn Đảo @c0372"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0372","denChuong":"","cachCoDuoc":"được trung niên tu sĩ ở Đăng Tiên Các giao sau khi chọn đảo","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0372","loai":"xuất hiện","importance":"normal","giaiDoan":"chứng minh quyền tu luyện","text":"Ngọc giản được giao cho Hàn Lập làm chứng minh hắn là người tu luyện trên Tiểu Hoàn Đảo.","anchor":"Ngọc giản này, chính là chứng minh ngươi là người tu luyện trên Tiểu Hoàn Đảo"}]},"capNhatToi":"@c0372","nguon":["@c0372"]},{"id":"kim-sac-ngoc-gian-tin-vat-quan-dao","name":"Kim sắc ngọc giản","cn":"","aliases":[],"category":"khac","categoryLabel":"Tín vật","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Kim sắc ngọc giản được Hàn Lập dùng làm tín vật xác nhận thân phận quản đảo. Trưởng trấn kiểm tra vật này rồi thừa nhận quyền điều khiển của tiên sư.","detail":"Khi đến trấn nhỏ trên đảo, Hàn Lập giao kim sắc ngọc giản cho trưởng trấn kiểm tra. Sau đó trưởng trấn thay mặt toàn trấn nghe theo điều khiển và tiếp nhận việc Hàn Lập cấp linh thạch duy trì phòng hộ trận.","congNang":["Xác nhận thân phận quản đảo của Hàn Lập trước trưởng trấn @c0373"],"nguon":["@c0373"],"tabs":{"tienTrinh":[{"chuong":"@c0373","loai":"dùng","importance":"normal","giaiDoan":"xác lập quyền quản đảo","text":"Hàn Lập giao kim sắc ngọc giản cho trưởng trấn kiểm tra để xác nhận thân phận quản đảo.","anchor":"Hàn Lập đem kim sắc ngọc giản giao cho lão giả kia"}]}},{"id":"tieu-binh","name":"Tiểu bình","cn":"","aliases":["Bình thần bí"],"category":"phap-bao","categoryLabel":"Pháp bảo tàn phiến","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Tiểu bình là pháp bảo tàn phiến của Hàn Lập, có thể ngưng tụ lục dịch. Tại động phủ mới, hắn đặt bình trong góc dược viên để tiếp tục bồi dưỡng linh thảo.","detail":"Trong dược viên ẩn bí của động phủ thật, Hàn Lập đặt tiểu bình ở một góc. Chương xác nhận pháp bảo tàn phiến này vẫn có thể thông qua vách động ngưng tụ lục dịch, phục vụ việc bồi dưỡng linh thảo lâu dài.","congNang":["Ngưng tụ lục dịch qua vách động để phục vụ bồi dưỡng linh thảo @c0373"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0373","denChuong":"","cachCoDuoc":"đang sở hữu từ trước","trangThai":"đang giữ"}],"nguon":["@c0373"],"tabs":{"tienTrinh":[{"chuong":"@c0373","loai":"dùng","importance":"normal","giaiDoan":"thiết lập dược viên","text":"Hàn Lập đặt tiểu bình tại góc dược viên để tiếp tục ngưng tụ lục dịch trong động phủ thật.","anchor":"pháp bảo tàn phiến này vẫn thông qua động bích ngưng tụ xuất lục dịch"}]}},{"id":"hoi-bach-sac-ngoc-gian-cua-viet-hoang","name":"Hôi bạch sắc ngọc giản của Việt hoàng","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản bí thuật","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Ngọc giản màu hôi bạch tìm được bên người Việt hoàng, chứa nhiều bí thuật quỷ dị. Hàn Lập nghiên cứu vật này và phát hiện Thân ngoại hóa thân nằm trong đó.","detail":"Hàn Lập lấy hôi bạch sắc ngọc giản từ túi trữ vật ra nghiên cứu kỹ nhiều lần. Nội dung bên trong gồm nhiều bí thuật quỷ dị, trong đó Thân ngoại hóa thân khiến hắn đặc biệt chấn động vì vừa hữu dụng vừa có rủi ro lớn.","congNang":["Lưu giữ nhiều bí thuật quỷ dị, bao gồm Thân ngoại hóa thân @c0373"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0373","denChuong":"","cachCoDuoc":"tìm được bên người Việt hoàng","trangThai":"đang giữ"}],"nguon":["@c0373"],"tabs":{"tienTrinh":[{"chuong":"@c0373","loai":"xuất hiện","importance":"normal","giaiDoan":"nghiên cứu bí thuật","text":"Hàn Lập lấy hôi bạch sắc ngọc giản của Việt hoàng ra nghiên cứu và phát hiện trong đó ghi nhiều bí thuật quỷ dị.","anchor":"bên trong ghi lại rất nhiều bí thuật cực kỳ quỷ dị"}]}},{"id":"bach-tri-thu-linh-trung","name":"Bạch tri thù","cn":"","aliases":[],"category":"khac","categoryLabel":"Kỳ trùng","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"được nuôi trong mật thất","blurb":"Đôi Bạch tri thù được Hàn Lập đưa vào mật thất nuôi trùng trong động phủ mới. Chúng được đặt trong môi trường cải tạo theo Dục Trùng tâm đắc và có cấm chế phòng chạy trốn.","detail":"Sau khi mở hơn mười mật thất nuôi trùng, Hàn Lập đưa đôi Bạch tri thù cùng các kỳ trùng còn sống vào bên trong. Hắn đặt cấm chế và chuẩn bị trùng thực để nuôi dưỡng chúng lâu dài.","congNang":["Linh trùng được Hàn Lập nuôi dưỡng trong mật thất chuyên biệt @c0373"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0373","denChuong":"","cachCoDuoc":"đang sở hữu và đưa vào mật thất nuôi trùng","trangThai":"đang nuôi"}],"nguon":["@c0373"],"tabs":{"tienTrinh":[{"chuong":"@c0373","loai":"dùng","importance":"normal","giaiDoan":"xây trùng thất","text":"Hàn Lập đưa đôi Bạch tri thù cùng các kỳ trùng còn sống vào mật thất đã cải tạo và đặt cấm chế phòng trốn chạy.","anchor":"đem đôi Bạch tri thù cùng đám kỳ trùng còn sống"}]}},{"id":"kim-tuy-dan","name":"Kim Tủy Đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đã dùng","blurb":"Kim Tủy Đan là đan dược Hàn Lập điều chế trong thời gian tu vi sa sút. Nó được dùng cùng Hoàng Long Đan để hỗ trợ luyện khí.","detail":"Trong giai đoạn khổ tu ban đầu ở Tiểu Hoàn Đảo, Hàn Lập điều chế Kim Tủy Đan cùng Hoàng Long Đan làm đan dược cần thiết cho việc luyện khí và khôi phục cảnh giới.","congNang":["Hỗ trợ Hàn Lập luyện khí trong thời gian khổ tu @c0374"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0374","denChuong":"","cachCoDuoc":"tự điều chế","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0374","loai":"xuất hiện","importance":"normal","giaiDoan":"Điều chế luyện khí","text":"Kim Tủy Đan được Hàn Lập điều chế cùng Hoàng Long Đan để hỗ trợ luyện khí.","anchor":"điều chế mấy thứ cần thiết “Hoàng Long Đan” cùng “Kim Tủy Đan”"}]},"nguon":["@c0374"]},{"id":"dan-duoc-truc-co-ky-tu-ba-dan-phuong-con-lai","name":"Đan dược Trúc Cơ kỳ từ ba đan phương còn lại","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược tu luyện","phamCap":"Trúc Cơ kỳ","soHuu":["Hàn Lập"],"trangThai":"được luyện chế và tích trữ","blurb":"Nhóm đan dược Trúc Cơ kỳ này được Hàn Lập tính toán có thể giúp hắn tinh tiến đến Trúc Cơ hậu kỳ. Chúng trở thành phần chuẩn bị cho giai đoạn tu Đại Diễn Quyết và Tam chuyển trọng nguyên công.","detail":"Sau khi khôi phục Trúc Cơ kỳ và có thể dùng Tiên thiên chân hỏa, Hàn Lập bắt đầu luyện các đan dược thích hợp cho Trúc Cơ kỳ theo các đan phương còn lại, dự tính đủ để đưa tu vi tiến tới Trúc Cơ hậu kỳ.","congNang":["Giúp Hàn Lập tinh tiến tu vi tới Trúc Cơ hậu kỳ @c0374"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0374","denChuong":"","cachCoDuoc":"tự luyện theo đan phương","trangThai":"được tích trữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0374","loai":"xuất hiện","importance":"normal","giaiDoan":"Luyện đan Trúc Cơ kỳ","text":"Hàn Lập luyện các đan dược Trúc Cơ kỳ từ những đan phương còn lại để chuẩn bị tinh tiến tu vi.","anchor":"có thể đưa hắn tinh tiến tu vi tới Trúc cơ hậu kỳ"}]},"nguon":["@c0374"]},{"id":"vat-pham-phu-tro-ngung-ket-sat-dan","name":"Vật phẩm phụ trợ ngưng kết Sát đan","cn":null,"category":"khac","categoryLabel":"Vật phẩm tu luyện","phamCap":null,"soHuu":["Khúc Hồn"],"trangThai":"dang-tim","blurb":"Các vật phụ trợ đặc thù cần cho Khúc Hồn ngưng kết Sát đan. Đây là một nguyên nhân trực tiếp khiến Hàn Lập phải rời động phủ ở Tiểu Hoàn Sơn.","detail":"Chương này chỉ nêu chúng là vài loại vật phẩm phụ trợ đặc thù cần cho việc ngưng kết Sát đan của Khúc Hồn, chưa nói rõ tên cụ thể hay số lượng.","chuSoHuu":[{"ten":"Khúc Hồn","tuChuong":"@c0375","denChuong":"","cachCoDuoc":"Đang cần tìm để phục vụ ngưng kết Sát đan","trangThai":"chưa có"}],"congNang":["Phụ trợ Khúc Hồn ngưng kết Sát đan @c0375"],"capNhatToi":"@c0375","nguon":["@c0375"]},{"id":"tuyet-linh-thuy","name":"Tuyết Linh Thủy","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh vật phụ trợ Kết Đan","phamCap":"không rõ","soHuu":["Âu Dương đạo hữu"],"trangThai":"đang được đưa ra giao dịch","blurb":"Tuyết Linh Thủy là linh vật phụ trợ giúp tăng hiệu suất Kết Đan. Trong chương này, Âu Dương đạo hữu mang nó tới Bạch Thủy Lâu trong một hộp ngọc, còn Hàn Lập xem đây là vật bắt buộc phải lấy.","detail":"Tuyết Linh Thủy được Khúc Hồn hỏi mua khi lấy lý do chuẩn bị tiến lên Kết Đan. Vật này được chứa trong hộp ngọc, hiện ra dưới dạng chất lỏng trong suốt tỏa hàn khí, không hiếm bằng linh thảo ngàn năm nhưng vẫn khó cầu và rất cần cho việc phụ trợ kết đan.","congNang":["Phụ trợ gia tăng hiệu suất Kết Đan @c0376"],"chuSoHuu":[{"ten":"Âu Dương đạo hữu","tuChuong":"@c0376","denChuong":"","cachCoDuoc":"Mang tới từ Ngọc Hoàn Cư theo liên hệ của Tào Lộc","trangThai":"đem ra giao dịch"}],"tabs":{"tienTrinh":[{"chuong":"@c0376","loai":"xuất hiện","importance":"normal","giaiDoan":"Được mang tới Bạch Thủy Lâu","text":"Tuyết Linh Thủy được Âu Dương đạo hữu mang tới trong hộp ngọc để giao dịch với Khúc Hồn và Hàn Lập.","anchor":"Tuyết Linh Thủy cùng với Thiên Hỏa Dịch không có hiếm hoi như là linh thảo ngàn năm"}]},"capNhatToi":"@c0376","nguon":["@c0376"]},{"id":"thien-hoa-dich","name":"Thiên Hỏa Dịch","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh vật phụ trợ Kết Đan","phamCap":"không rõ","soHuu":["Âu Dương đạo hữu"],"trangThai":"đang được đưa ra giao dịch","blurb":"Thiên Hỏa Dịch là linh vật phụ trợ Kết Đan được đem tới cùng Tuyết Linh Thủy. Hàn Lập xác định nó rất cần cho việc tăng hiệu suất kết đan nên quyết tâm phải lấy.","detail":"Thiên Hỏa Dịch được Âu Dương đạo hữu mang tới trong một hộp ngọc, bên trong là chất lỏng màu hỏa hồng nóng rực. Nó được nhắc cùng Tuyết Linh Thủy như vật khó cầu, có tác dụng phụ trợ gia tăng hiệu suất Kết Đan.","congNang":["Phụ trợ gia tăng hiệu suất Kết Đan @c0376"],"chuSoHuu":[{"ten":"Âu Dương đạo hữu","tuChuong":"@c0376","denChuong":"","cachCoDuoc":"Mang tới từ Ngọc Hoàn Cư theo liên hệ của Tào Lộc","trangThai":"đem ra giao dịch"}],"tabs":{"tienTrinh":[{"chuong":"@c0376","loai":"xuất hiện","importance":"normal","giaiDoan":"Được mang tới Bạch Thủy Lâu","text":"Thiên Hỏa Dịch được Âu Dương đạo hữu mang tới cùng Tuyết Linh Thủy để Khúc Hồn kiểm tra và hỏi giá.","anchor":"lại là vật rất cần để phụ trợ gia tăng hiệu suất kết đan"}]},"capNhatToi":"@c0376","nguon":["@c0376"]},{"id":"hop-ngoc-hao-quang-mau-vang","name":"Hộp ngọc hào quang màu vàng","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Hộp đựng linh vật","phamCap":"dị bảo","soHuu":["Âu Dương đạo hữu"],"trangThai":"đang dùng để chứa linh vật","blurb":"Hộp ngọc hào quang màu vàng là hộp chứa Tuyết Linh Thủy và Thiên Hỏa Dịch do Âu Dương đạo hữu mang tới. Hộp được làm từ cực ngọc thổ thuộc tính dưới biển sâu, bản thân cũng được gọi là dị bảo.","detail":"Âu Dương đạo hữu lấy ra hai hộp ngọc hào quang màu vàng để chứa hai linh vật phụ trợ Kết Đan. Ông nói hộp được điêu khắc từ cực ngọc mang thổ thuộc tính ở dưới biển sâu, tuy là dị bảo nhưng giá trị vẫn kém xa linh vật bên trong.","hinhDang":"Hộp ngọc tỏa hào quang màu vàng","vatLieu":"Cực ngọc mang thổ thuộc tính ở dưới biển sâu","congNang":["Dùng để chứa và bảo quản Tuyết Linh Thủy cùng Thiên Hỏa Dịch @c0376"],"chuSoHuu":[{"ten":"Âu Dương đạo hữu","tuChuong":"@c0376","denChuong":"","cachCoDuoc":"Mang theo khi tới Bạch Thủy Lâu giao dịch","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0376","loai":"xuất hiện","importance":"normal","giaiDoan":"Chứa hai linh vật","text":"Âu Dương đạo hữu dùng hai hộp ngọc màu vàng để chứa Tuyết Linh Thủy và Thiên Hỏa Dịch khi mang tới Bạch Thủy Lâu.","anchor":"chỉ dùng cực ngọc mang thổ thuộc tính ở dưới biển sâu điêu khắc mà thành"}]},"capNhatToi":"@c0376","nguon":["@c0376"]},{"id":"truyen-am-phu-cua-tao-loc","name":"Truyền âm phù của Tào Lộc","cn":"","aliases":[],"category":"khac","categoryLabel":"Phù truyền tin","phamCap":"không rõ","soHuu":["Tào Lộc"],"trangThai":"đã sử dụng","blurb":"Truyền âm phù của Tào Lộc là phù truyền tin được dùng tại Bạch Thủy Lâu. Tào Lộc dùng nó để liên hệ Âu Dương đạo hữu của Ngọc Hoàn Cư, gọi người mang linh vật tới.","detail":"Sau khi Khúc Hồn hỏi mua Tuyết Linh Thủy và Thiên Hỏa Dịch, Tào Lộc lấy truyền âm phù, nói nhỏ vài câu rồi khiến phù biến thành một đạo bạch quang bay ra khỏi phòng để truyền tin cho Âu Dương đạo hữu.","congNang":["Truyền tin liên hệ tu sĩ khác @c0376"],"chuSoHuu":[{"ten":"Tào Lộc","tuChuong":"@c0376","denChuong":"@c0376","cachCoDuoc":"Vật dùng trong giao dịch tại Bạch Thủy Lâu","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0376","loai":"dùng","importance":"normal","giaiDoan":"Gọi Âu Dương đạo hữu","text":"Tào Lộc dùng truyền âm phù để gọi Âu Dương đạo hữu của Ngọc Hoàn Cư tới Bạch Thủy Lâu.","anchor":"nhỏ giọng nói mấy câu liền đem nó biến thành một đạo bạch quang"}]},"capNhatToi":"@c0376","nguon":["@c0376"]},{"id":"hang-tran-dan","name":"Hàng Trần Đan","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Lục Liên Điện"],"trangThai":"được hứa làm thù lao","blurb":"Đan dược Lục Liên Điện dùng làm thù lao để mời tu sĩ Giả Đan tham gia hành động lấy Yêu Đan yêu thú cấp sáu. Theo lời Tào Lộc và đại hán, đan này có trợ ích cho việc kết đan.","detail":"Mỗi tu sĩ Giả Đan tham gia hành động của Lục Liên Điện sẽ được hứa một viên Hàng Trần Đan. Đan dược này được nêu là có thể trợ giúp kết đan, nên trở thành điều kiện hấp dẫn đối với Khúc Hồn trong mắt Lục Liên Điện.","dinhDanh":"goc","congNang":["Có trợ ích cho việc kết đan và được dùng để tăng sức hấp dẫn của lời mời tham gia săn yêu thú cấp sáu @c0377"],"chuSoHuu":[{"ten":"Lục Liên Điện","tuChuong":"@c0377","denChuong":"","cachCoDuoc":"Được Lục Liên Điện nêu làm thù lao cho người tham gia hành động","trangThai":"đang nắm giữ"}],"capNhatToi":"@c0377","tabs":{"tienTrinh":[{"chuong":"@c0377","loai":"xuất hiện","importance":"normal","giaiDoan":"Thù lao săn yêu thú","text":"Lục Liên Điện hứa tặng Hàng Trần Đan cho mỗi tu sĩ Giả Đan tham gia hành động lấy Yêu Đan của yêu thú cấp sáu.","anchor":"loại đan dược này đối với với việc kết đan rất có trợ ích"}]},"nguon":["@c0377"]},{"id":"yeu-dan-cua-yeu-thu-cap-sau","name":"Yêu Đan của yêu thú cấp sáu","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Yêu đan","phamCap":"yêu thú cấp sáu","soHuu":[],"trangThai":"mục tiêu bị Lục Liên Điện nhắm tới","blurb":"Nội đan của con yêu thú cấp sáu mà Lục Liên Điện phát hiện. Đây là mục tiêu chính của hành động cần sáu tu sĩ Giả Đan và hai trưởng lão Kết Đan kỳ phối hợp.","detail":"Lục Liên Điện muốn lấy Yêu Đan của một con yêu thú cấp sáu đã phát hiện, nên mời thêm tu sĩ Giả Đan chủ trì Lục độn thủy ba đại trận. Giá trị và độ nguy hiểm của mục tiêu khiến Khúc Hồn không lập tức nhận lời.","dinhDanh":"goc","congNang":["Là nội đan mục tiêu trong hành động săn yêu thú cấp sáu của Lục Liên Điện @c0377"],"capNhatToi":"@c0377","tabs":{"tienTrinh":[{"chuong":"@c0377","loai":"nhắc tới","importance":"normal","giaiDoan":"Mục tiêu hành động","text":"Lục Liên Điện tiết lộ mục tiêu của hành động là lấy Yêu Đan từ một con yêu thú cấp sáu.","anchor":"bổn điếm muốn lấy Yêu Đan của yêu thú này"}]},"nguon":["@c0377"]},{"id":"dan-phuong-truc-co-dan-ban-loan-tinh-hai","name":"Đan phương Trúc Cơ Đan bản Loạn Tinh Hải","cn":"","aliases":[],"category":"khac","categoryLabel":"Đan phương","phamCap":"Trúc Cơ kỳ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đang giữ","blurb":"Đan phương Trúc Cơ Đan mà Hàn Lập mua tại Loạn Tinh Hải. Nội dung phần lớn giống đan phương trong trí nhớ hắn, nhưng một số linh dược Thiên Nam được thay bằng nội đan yêu thú cấp năm.","detail":"Sau khi khảo sát các đan phương Trúc Cơ kỳ, Hàn Lập mua một tấm đan phương giá thấp để đối chiếu. Hắn nhận ra bản Loạn Tinh Hải vẫn là Trúc Cơ Đan nhưng dùng vài loại nội đan yêu thú cấp năm thay cho một số linh dược từng có trong Huyết Sắc Cấm Địa ở Thiên Nam.","dinhDanh":"goc","congNang":["Cung cấp dị bản Trúc Cơ Đan tại Loạn Tinh Hải, trong đó vài linh dược Thiên Nam được thay bằng nội đan yêu thú cấp năm @c0377"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0377","denChuong":"","cachCoDuoc":"Mua tại cửa hàng đan dược ở Loạn Tinh Hải","trangThai":"đang giữ"}],"capNhatToi":"@c0377","tabs":{"tienTrinh":[{"chuong":"@c0377","loai":"xuất hiện","importance":"normal","giaiDoan":"Đối chiếu đan phương","text":"Hàn Lập mua đan phương Trúc Cơ Đan bản Loạn Tinh Hải và phát hiện vài linh dược từ Huyết Sắc Cấm Địa được thay bằng nội đan yêu thú cấp năm.","anchor":"có vài loại đan dược trong Huyết Sắc Cấm Địa ở Thiên Nam được thay bằng vài loại nội đan của yêu thú cấp năm"}]},"nguon":["@c0377"]},{"id":"dan-dao-binh-giam","name":"Đan đạo bình giám","cn":"","aliases":[],"category":"khac","categoryLabel":"Điển tịch luyện đan","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập đã mua","blurb":"Điển tịch luyện đan Hàn Lập mua ở cửa hàng điển tịch vì có lời bình về Hàng Trần Đan. Sách giúp hắn hiểu thêm đan dược Loạn Tinh Hải và cân nhắc nhiệm vụ của Lục Liên Điện.","detail":"Đan đạo bình giám ghi nhận lời bình về Hàng Trần Đan, khiến Hàn Lập mua về nghiên cứu. Sau một đêm đọc sách, hắn biết rõ hơn về nguyên liệu, công dụng của loại đan dược này và từ đó quyết định mạo hiểm tham gia chuyến xuất hải.","phanLoaiPhu":"điển tịch luyện đan","congNang":["Cung cấp tri thức và lời bình về Hàng Trần Đan, giúp Hàn Lập có căn cứ cân nhắc việc nhận lời Lục Liên Điện @c0378"],"chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0378","denChuong":"","cachCoDuoc":"Mua tại cửa hàng điển tịch","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0378","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập mua sách","text":"Hàn Lập mua Đan đạo bình giám vì trong sách có lời bình về Hàng Trần Đan, rồi dùng nó để nghiên cứu đan dược Loạn Tinh Hải trước khi quyết định nhận việc của Lục Liên Điện.","anchor":"Sở dĩ hắn mua quyển này là bởi vì bên trong có một vị cao nhanh nào đó nói về “Hàng Trần Đan”"}]},"capNhatToi":"@c0378","nguon":["@c0378"]},{"id":"hai-thuyen-lon-xuat-hai","name":"Hải thuyền lớn","cn":"","aliases":[],"category":"khac","categoryLabel":"Phương tiện đường biển","phamCap":"phàm thuyền","soHuu":["Khôi Tinh Đảo"],"trangThai":"rời cảng Khôi Tinh Đảo","blurb":"Hải thuyền lớn rời cảng Khôi Tinh Đảo trong chuyến đưa các tiên sư đến nơi yêu thú xuất hiện. Trong khoang thuyền có đại sảnh rộng và sang trọng, nơi nhóm tu sĩ gặp nhau trước chuyến đi.","detail":"Nửa tháng sau quyết định của Hàn Lập, hải thuyền lớn rời cảng Khôi Tinh Đảo. Lạc Chánh làm thuyền trưởng, còn Hàn Lập, Khúc Hồn và các tiên sư khác tụ họp trong khoang thuyền để đi tới địa điểm yêu thú xuất hiện.","phanLoaiPhu":"hải thuyền","congNang":["Đưa nhóm tiên sư rời cảng Khôi Tinh Đảo tới địa điểm yêu thú xuất hiện @c0378"],"chuHienThoi":"Khôi Tinh Đảo","tabs":{"tienTrinh":[{"chuong":"@c0378","loai":"xuất hiện","importance":"normal","giaiDoan":"Rời cảng Khôi Tinh Đảo","text":"Hải thuyền lớn rời cảng Khôi Tinh Đảo, chở Lạc Chánh cùng nhóm tiên sư đến địa điểm yêu thú xuất hiện.","anchor":"Nữa tháng sau, một chiếc hải thuyền lớn vô cùng đi ra khỏi cảng khẩu của Khôi Tinh Đảo."}]},"capNhatToi":"@c0378","nguon":["@c0378"]},{"id":"linh-thach-boi-thuong-giu-bi-mat","name":"Linh thạch bồi thường giữ bí mật","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Lục Liên Điện"],"trangThai":"được hứa thưởng","blurb":"Khoản linh thạch Lục Liên Điện hứa tặng thêm để bù việc giữ bí mật về Anh Lý Thú.","detail":"Ngoài Hàng Trần Đan, Phùng Tam Nương hứa mỗi người được thêm một ngàn linh thạch nhằm xoa dịu nhóm tu sĩ sau khi họ biết mục tiêu thật nguy hiểm hơn dự liệu.","dinhDanh":"goc","congNang":["Bồi thường và ổn định đội ngũ tu sĩ được thuê săn Anh Lý Thú @c0380"],"chuSoHuu":[{"ten":"Lục Liên Điện","tuChuong":"@c0380","denChuong":"","cachCoDuoc":"dùng làm khoản thưởng bổ sung","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c0380","loai":"nhắc tới","importance":"normal","giaiDoan":"Ổn định đội ngũ","text":"Lục Liên Điện hứa tặng thêm mỗi người một ngàn linh thạch để bồi thường việc che giấu thông tin nhiệm vụ.","anchor":"bổn điện còn tặng mỗi người một ngàn linh thạch để bồi thường"}]},"capNhatToi":"@c0380","nguon":["@c0380"]},{"id":"dai-ky-mau-lam-cua-dai-tran","name":"Đại kỳ màu lam của đại trận","cn":"","category":"phap-bao","categoryLabel":"Trận khí","phamCap":"không rõ","soHuu":["Khúc Hồn","Sáu tu sĩ Trúc Cơ hậu kỳ"],"trangThai":"đang dùng","blurb":"Đại kỳ màu lam là trận khí được sáu tu sĩ Trúc Cơ hậu kỳ cầm khi vận hành đại trận trên mặt biển.","detail":"Mỗi cây dài khoảng hai trượng, phát hào quang chói mắt. Các tu sĩ cầm đại kỳ đứng thành nửa vòng tròn, chờ Phùng Tam Nương ra lệnh phong tỏa trận môn khi Anh Lý Thú tiến vào.","dinhDanh":"goc","hinhDang":"Đại kỳ màu lam dài khoảng hai trượng","congNang":["Hỗ trợ vận hành trận địa phong tỏa Anh Lý Thú trên mặt biển @c0380"],"chuSoHuu":[{"ten":"Khúc Hồn","tuChuong":"@c0380","denChuong":"","cachCoDuoc":"cầm trong đội hình đại trận","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0380","loai":"dùng","importance":"normal","giaiDoan":"Đứng trận trên biển","text":"Sáu tu sĩ Trúc Cơ hậu kỳ cầm đại kỳ màu lam, đứng thành nửa vòng tròn trên mặt biển để chờ phong tỏa trận môn.","anchor":"trong tay còn có thêm một cây đại kỳ màu lam"}]},"capNhatToi":"@c0380","nguon":["@c0380"]},{"id":"phi-kiem-truyen-thu","name":"Phi kiếm truyền thư","aliases":["Kim quang truyền tin"],"cn":"","category":"khac","categoryLabel":"Vật phẩm truyền tin","phamCap":"không rõ","soHuu":["Miêu trưởng lão","Phùng Tam Nương"],"trangThai":"đã dùng","blurb":"Phi kiếm truyền thư là phương tiện truyền tin khẩn giữa nhóm dẫn dụ Anh Lý Thú và đội hình trận pháp phía trước.","detail":"Miêu trưởng lão dùng nó để hỏi đội hình đã chuẩn bị xong chưa. Kim quang bay tới rơi vào tay Phùng Tam Nương, ngay sau đó nàng ra lệnh phong tỏa trận môn.","dinhDanh":"goc","congNang":["Truyền tin khẩn từ nhóm dẫn dụ yêu thú đến đội hình chờ trận @c0380"],"chuSoHuu":[{"ten":"Miêu trưởng lão","tuChuong":"@c0380","denChuong":"","cachCoDuoc":"dùng để truyền tin cho đội hình phía trước","trangThai":"da-dung"},{"ten":"Phùng Tam Nương","tuChuong":"@c0380","denChuong":"","cachCoDuoc":"nhận kim quang truyền tin trước khi ra lệnh","trangThai":"da-nhan"}],"tabs":{"tienTrinh":[{"chuong":"@c0380","loai":"dùng","importance":"normal","giaiDoan":"Truyền lệnh phong tỏa","text":"Miêu trưởng lão dùng phi kiếm truyền thư báo cho nhóm Phùng Tam Nương, khiến nàng kịp ra lệnh phong tỏa trận môn.","anchor":"Miêu trưởng lão, dùng phi kiếm truyền thư xem bọn họ đã chuẩn bị tốt chưa"}]},"capNhatToi":"@c0380","nguon":["@c0380"]},{"id":"hon-nguyen-bat","name":"Hỗn Nguyên Bát","aliases":["Hổn Nguyên Bát","Pháp bảo bát hình màu vàng"],"cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phi hành","phamCap":"không rõ","soHuu":["Cổ trưởng lão"],"trangThai":"đang dùng","blurb":"Hỗn Nguyên Bát là pháp bảo của Cổ trưởng lão, được dùng để tăng tốc khi bị Anh Lý Thú truy đuổi.","detail":"Trong lúc khối sương trắng chứa Anh Lý Thú áp sát, Cổ trưởng lão dùng Hỗn Nguyên Bát để tăng tốc hoàng quang, tạm nới rộng khoảng cách và tránh nguy cơ Thủy Cương Thần Lôi.","dinhDanh":"goc","congNang":["Tăng tốc độ phi hành của Cổ trưởng lão khi bị Anh Lý Thú truy đuổi @c0380"],"uyLuc":"Có thể giúp hoàng quang nhanh chóng kéo giãn khoảng cách với khối sương trắng truy đuổi.","chuSoHuu":[{"ten":"Cổ trưởng lão","tuChuong":"@c0380","denChuong":"","cachCoDuoc":"pháp bảo đang sở hữu","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0380","loai":"dùng","importance":"normal","giaiDoan":"Thoát khỏi sương trắng","text":"Cổ trưởng lão dựa vào tốc độ của Hỗn Nguyên Bát để tăng tốc và nới rộng khoảng cách với Anh Lý Thú.","anchor":"Yên tâm, tốc độ Hỗn Nguyên Bát của ta cũng không chậm"}]},"capNhatToi":"@c0380","nguon":["@c0380"]},{"id":"kien-thien-qua","name":"Kiền Thiên Qua","aliases":["Đôi đồng qua","Hai thanh trường thương màu vàng","Đôi giáo đồng xanh cũ kỹ"],"cn":"","category":"phap-bao","categoryLabel":"Dị bảo","phamCap":"dị bảo","soHuu":["Miêu trưởng lão","Cổ trưởng lão"],"trangThai":"đang được sử dụng","blurb":"Kiền Thiên Qua là dị bảo do Miêu trưởng lão và Cổ trưởng lão hợp lực tế ra trong cuộc chiến với Anh Lý Thú. Nguyên hình là đôi giáo đồng xanh cũ kỹ, sau khi niệm chú hóa thành hai thanh trường thương vàng lớn có khả năng chế trụ chân thân yêu thú, được xem là khắc tinh trời sinh của Anh Lý Thú.","detail":"Kiền Thiên Qua vốn mang hình dạng đôi giáo đồng xanh cũ kỹ, do hai vị trưởng lão Kết Đan kỳ — Miêu trưởng lão và Cổ trưởng lão — cùng nắm giữ và kích phát. Khi hai người niệm chú tế bảo, đôi giáo đồng hóa thành hai thanh trường thương vàng khổng lồ, từ trên cao đánh xuống cuồng phong, ghim chế Anh Lý Thú trên mặt biển ngay cả sau khi yêu thú đã phá vỡ đại trận. Tuy nhiên, việc thích phóng Kiền Thiên Qua khiến cả hai trưởng lão nguyên khí đại thương, cho thấy bảo vật đòi hỏi cái giá rất lớn khi sử dụng.","phanLoaiPhu":"dị bảo khắc yêu","hinhDang":"Đôi giáo đồng xanh cũ kỹ, khi phát uy hóa thành hai trường thương vàng lớn.","uyLuc":"Chế trụ được Anh Lý Thú sau khi nó phá đại trận.","dacDiem":"Tựa như khắc tinh trời sinh của Anh Lý Thú.","chuHienThoi":"Miêu trưởng lão và Cổ trưởng lão","congNang":["Đôi giáo đồng xanh hóa thành hai thanh trường thương vàng lớn, từ trên cao đánh xuống cuồng phong để chế trụ Anh Lý Thú @c0381"],"chuSoHuu":[{"ten":"Miêu trưởng lão","tuChuong":"@c0381","denChuong":"","cachCoDuoc":"Mang theo và tế ra trong cuộc săn Anh Lý Thú","trangThai":"đang giữ"},{"ten":"Cổ trưởng lão","tuChuong":"@c0381","denChuong":"","cachCoDuoc":"Mang theo và tế ra trong cuộc săn Anh Lý Thú","trangThai":"đang giữ"}],"capNhatToi":"@c0381","nguon":["@c0381"],"tabs":{"tienTrinh":[{"chuong":"@c0381","loai":"dùng","importance":"major","giaiDoan":"Chế trụ Anh Lý Thú","phamCap":"dị bảo","text":"Miêu trưởng lão và Cổ trưởng lão tế Kiền Thiên Qua, khiến đôi giáo đồng hóa thành trường thương vàng đánh xuống và chế trụ Anh Lý Thú trên mặt biển.","anchor":"hai thanh trường thương này tựa hồ trời sinh chính là khắc tinh của nó"}]}},{"id":"con-cua-mau-do-cua-anh-ly-thu","name":"Con cua màu đỏ của Anh Lý Thú","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"không rõ","soHuu":["Anh Lý Thú"],"trangThai":"trong tay Anh Lý Thú","blurb":"Một trong bốn bảo vật sáng rực nằm trong tay Anh Lý Thú khi chân thân hiện ra. Vật này có hình con cua lớn màu đỏ.","detail":"Khi Anh Lý Thú bị chế trụ và lộ chân thân, một cánh tay của nó nắm con cua lớn màu đỏ. Vật này cùng ba món còn lại đều phát sáng, được nhìn nhận là bảo vật trân quý khiến các tu sĩ nổi lòng tham.","hinhDang":"Con cua lớn màu đỏ.","dacDiem":"Phát sáng cùng các bảo vật khác trong tay Anh Lý Thú.","chuHienThoi":"Anh Lý Thú","chuSoHuu":[{"ten":"Anh Lý Thú","tuChuong":"@c0381","denChuong":"","cachCoDuoc":"Nắm giữ khi chân thân hiện ra","trangThai":"đang giữ"}],"capNhatToi":"@c0381","nguon":["@c0381"],"tabs":{"tienTrinh":[{"chuong":"@c0381","loai":"xuất hiện","importance":"normal","giaiDoan":"Hiện cùng chân thân Anh Lý Thú","text":"Con cua màu đỏ xuất hiện trong tay Anh Lý Thú cùng ba bảo vật sáng rực khác.","anchor":"một con cua thật lớn màu đỏ"}]}},{"id":"thuoc-san-ho-mau-lam-cua-anh-ly-thu","name":"Thước san hô màu lam của Anh Lý Thú","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"không rõ","soHuu":["Anh Lý Thú"],"trangThai":"trong tay Anh Lý Thú","blurb":"Một trong bốn bảo vật do Anh Lý Thú nắm giữ khi chân thân hiện ra. Vật này được miêu tả là cây thước san hô màu lam.","detail":"Thước san hô màu lam nằm trong một cánh tay của Anh Lý Thú khi yêu thú bị chế trụ trên mặt biển. Nó cùng các vật còn lại sáng rực, khiến nhóm tu sĩ nhận ra giá trị bất thường.","hinhDang":"Cây thước san hô màu lam.","dacDiem":"Phát sáng cùng các bảo vật khác trong tay Anh Lý Thú.","chuHienThoi":"Anh Lý Thú","chuSoHuu":[{"ten":"Anh Lý Thú","tuChuong":"@c0381","denChuong":"","cachCoDuoc":"Nắm giữ khi chân thân hiện ra","trangThai":"đang giữ"}],"capNhatToi":"@c0381","nguon":["@c0381"],"tabs":{"tienTrinh":[{"chuong":"@c0381","loai":"xuất hiện","importance":"normal","giaiDoan":"Hiện cùng chân thân Anh Lý Thú","text":"Thước san hô màu lam xuất hiện trong tay Anh Lý Thú cùng ba bảo vật sáng rực khác.","anchor":"một cây thước san hô màu lam"}]}},{"id":"chau-tu-mau-trang-cua-anh-ly-thu","name":"Châu tử màu trắng của Anh Lý Thú","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"không rõ","soHuu":["Anh Lý Thú"],"trangThai":"trong tay Anh Lý Thú","blurb":"Viên châu trắng cỡ trứng gà nằm trong tay Anh Lý Thú. Nó thuộc nhóm bốn bảo vật sáng rực lộ ra sau khi yêu thú bị chế trụ.","detail":"Châu tử màu trắng bằng quả trứng gà được một cánh tay của Anh Lý Thú nắm giữ. Khi chân thân yêu thú hiện ra, viên châu cùng các vật khác sáng lấp lánh và làm các tu sĩ nổi tham niệm.","hinhDang":"Viên châu trắng bằng quả trứng gà.","dacDiem":"Phát sáng cùng các bảo vật khác trong tay Anh Lý Thú.","chuHienThoi":"Anh Lý Thú","chuSoHuu":[{"ten":"Anh Lý Thú","tuChuong":"@c0381","denChuong":"","cachCoDuoc":"Nắm giữ khi chân thân hiện ra","trangThai":"đang giữ"}],"capNhatToi":"@c0381","nguon":["@c0381"],"tabs":{"tienTrinh":[{"chuong":"@c0381","loai":"xuất hiện","importance":"normal","giaiDoan":"Hiện cùng chân thân Anh Lý Thú","text":"Châu tử màu trắng cỡ trứng gà xuất hiện trong tay Anh Lý Thú cùng ba bảo vật sáng rực khác.","anchor":"một viên châu tử màu trắng bằng quả trứng gà"}]}},{"id":"vo-con-trai-mau-bac-cua-anh-ly-thu","name":"Vỏ con trai màu bạc của Anh Lý Thú","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"không rõ","soHuu":["Anh Lý Thú"],"trangThai":"trong tay Anh Lý Thú","blurb":"Bảo vật giống tấm chắn màu bạc nằm trong tay Anh Lý Thú. Nó xuất hiện cùng ba món bảo vật khác khi chân thân yêu thú bị ghim trên mặt biển.","detail":"Vỏ con trai màu bạc có hình dạng giống tấm chắn, được một cánh tay của Anh Lý Thú nắm giữ. Vật này cùng con cua đỏ, thước san hô lam và châu trắng đều sáng rực, khiến các tu sĩ thèm muốn.","hinhDang":"Vỏ con trai giống tấm chắn màu bạc.","dacDiem":"Phát sáng cùng các bảo vật khác trong tay Anh Lý Thú.","chuHienThoi":"Anh Lý Thú","chuSoHuu":[{"ten":"Anh Lý Thú","tuChuong":"@c0381","denChuong":"","cachCoDuoc":"Nắm giữ khi chân thân hiện ra","trangThai":"đang giữ"}],"capNhatToi":"@c0381","nguon":["@c0381"],"tabs":{"tienTrinh":[{"chuong":"@c0381","loai":"xuất hiện","importance":"normal","giaiDoan":"Hiện cùng chân thân Anh Lý Thú","text":"Vỏ con trai màu bạc xuất hiện trong tay Anh Lý Thú cùng ba bảo vật sáng rực khác.","anchor":"một cái vỏ con trai giống như tấm chắn màu bạc"}]}},{"id":"ma-dao-den-nhanh-cua-o-suu","name":"Ma đao đen nhánh của Ô Sửu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Ma đao / pháp khí","phamCap":"không rõ","soHuu":["Ô Sửu"],"trangThai":"đang thuộc Ô Sửu @c0382","blurb":"Ma đao đen nhánh của Ô Sửu là pháp khí được hắn triệu ra bằng hắc mang. Hắn dùng nó để mổ đầu và cắt lấy các bộ phận quý của Anh Lý Thú.","detail":"Ô Sửu triệu ma đao đen nhánh khi cưỡng đoạt chiến lợi phẩm từ Anh Lý Thú. Thanh đao được dùng để lấy viên châu màu lam trong đầu yêu thú rồi tiếp tục xử lý các bộ phận khác.","phanLoaiPhu":"ma đao","hinhDang":"một thanh ma đao đen nhánh","uyLuc":"Có thể mổ xác Anh Lý Thú để lấy kỳ vật và bộ phận quý.","congNang":["Mổ đầu Anh Lý Thú để lấy viên châu màu lam @c0382","Cắt lấy các bộ phận quý của Anh Lý Thú @c0382"],"chuSoHuu":[{"ten":"Ô Sửu","tuChuong":"@c0382","denChuong":"","cachCoDuoc":"đang sở hữu khi xuất hiện","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0382","loai":"dùng","importance":"normal","giaiDoan":"Mổ Anh Lý Thú","text":"Ô Sửu triệu ma đao đen nhánh và dùng nó để mổ Anh Lý Thú lấy chiến lợi phẩm.","anchor":"trong tay hắc mang chợt lóe, một thanh ma đao đen nhánh xuất hiện"}]},"capNhatToi":"@c0382","nguon":["@c0382"]},{"id":"vien-chau-mau-lam-trong-dau-anh-ly-thu","name":"Viên châu màu lam trong đầu Anh Lý Thú","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Yêu đan / kỳ vật","phamCap":"không rõ","soHuu":["Ô Sửu"],"trangThai":"bị Ô Sửu lấy @c0382","blurb":"Viên châu màu lam trong đầu Anh Lý Thú là kỳ vật do Ô Sửu mổ từ đầu yêu thú. Khi cầm vật này, Ô Sửu lộ vẻ mừng rỡ và tham lam.","detail":"Sau khi ép Lục Liên Điện, Ô Sửu dùng ma đao đen nhánh lấy ra viên châu màu lam từ đầu Anh Lý Thú. Đây là chiến lợi phẩm cốt lõi khiến Lục Liên Điện muốn giữ lại nhưng bị Ô Sửu cưỡng đoạt.","phanLoaiPhu":"yêu đan hoặc kỳ vật yêu thú","hinhDang":"viên châu màu lam","nguonGoc":"lấy từ đầu Anh Lý Thú","congNang":["Là chiến lợi phẩm quý trong đầu Anh Lý Thú, được Ô Sửu muốn dùng làm lễ vật @c0382"],"chuSoHuu":[{"ten":"Ô Sửu","tuChuong":"@c0382","denChuong":"","cachCoDuoc":"mổ đầu Anh Lý Thú lấy ra","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0382","loai":"đổi chủ","importance":"normal","giaiDoan":"Bị Ô Sửu lấy","text":"Ô Sửu lấy viên châu màu lam từ đầu Anh Lý Thú bất chấp yêu cầu của Lục Liên Điện.","anchor":"trong đầu của con Anh Lý Thú lấy ra một viên châu màu lam"}]},"capNhatToi":"@c0382","nguon":["@c0382"]},{"id":"lenh-bai-dau-quy","name":"Lệnh bài đầu quỷ","cn":"","aliases":[],"category":"khac","categoryLabel":"Lệnh bài","phamCap":"không rõ","soHuu":["Cổ trưởng lão","Ô Sửu"],"trangThai":"được đưa ra chứng minh thân phận @c0382","blurb":"Lệnh bài đầu quỷ là lệnh bài khắc đầu quỷ dữ tợn, tỏa hắc khí nhàn nhạt. Cổ trưởng lão đưa vật này cho Ô Sửu để chứng minh thân phận của hai người được nhắc tới.","detail":"Sau khi Cổ trưởng lão truyền âm cho Ô Sửu, lệnh bài đầu quỷ được đưa ra và khiến tình thế chuyển hướng nguy hiểm. Hàn Lập dùng thần thức nhìn thấy vật này rồi sinh dự cảm xấu, còn Thanh Toán Tử cũng lập tức bỏ chạy.","phanLoaiPhu":"lệnh bài","hinhDang":"trên khắc một cái đầu quỷ dữ tợn","dacDiem":"Tỏa hắc khí nhàn nhạt và liên quan đến thân phận của hai người chưa lộ rõ.","congNang":["Dùng để chứng minh thân phận của hai người được Cổ trưởng lão nhắc tới @c0382"],"chuSoHuu":[{"ten":"Cổ trưởng lão","tuChuong":"@c0382","denChuong":"@c0382","cachCoDuoc":"đang giữ trước khi đưa ra","trangThai":"đã đưa ra"},{"ten":"Ô Sửu","tuChuong":"@c0382","denChuong":"","cachCoDuoc":"nhận từ Cổ trưởng lão sau truyền âm","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0382","loai":"xuất hiện","importance":"normal","giaiDoan":"Chứng minh thân phận","text":"Cổ trưởng lão đưa lệnh bài đầu quỷ cho Ô Sửu, khiến Hàn Lập và Thanh Toán Tử nhận ra nguy cơ.","anchor":"một lệnh bài trên khắc một cái đầu quỷ dữ tợn"}]},"capNhatToi":"@c0382","nguon":["@c0382"]},{"id":"phap-bao-hinh-tron-mau-vang-dat-cua-co-truong-lao","name":"Pháp bảo hình tròn màu vàng đất của Cổ trưởng lão","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phi hành/phòng hộ","phamCap":"Pháp bảo của tu sĩ Kết Đan","soHuu":["Cổ trưởng lão"],"trangThai":"đang dùng","blurb":"Pháp bảo hình tròn màu vàng đất là vật Cổ trưởng lão đạp lên khi truy sát Hàn Lập. Nó phát hoàng quang bao phủ quanh hắn và hỗ trợ truy kích trong trận chiến.","detail":"Cổ trưởng lão đứng trên pháp bảo hình tròn màu vàng đất khi hiện thân trước Hàn Lập. Hoàng quang từ pháp bảo bao phủ quanh hắn như lớp bảo hộ, đồng thời cho thấy tốc độ truy kích đủ áp sát Thần Phong Chu trước đảo vô danh.","phanLoaiPhu":"Phi hành, phòng hộ","hinhDang":"Hình tròn màu vàng đất","uyLuc":"Tạo hoàng quang bao quanh Cổ trưởng lão khi truy kích và giao chiến.","dacDiem":"Tốc độ không bằng mốc Hàn Lập so với Lôi Vân Hạc nhưng vẫn đủ đuổi sát Thần Phong Chu trong hoàn cảnh này.","chuHienThoi":"Cổ trưởng lão","congNang":["Phi hành truy kích Hàn Lập @c0383","Phát hoàng quang bao quanh Cổ trưởng lão @c0383"],"chuSoHuu":[{"ten":"Cổ trưởng lão","tuChuong":"@c0383","denChuong":"","cachCoDuoc":"Đã sở hữu khi truy sát Hàn Lập","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0383","loai":"xuất hiện","importance":"normal","giaiDoan":"Truy sát Hàn Lập","text":"Cổ trưởng lão đạp pháp bảo hình tròn màu vàng đất, dùng hoàng quang truy kích và áp sát Hàn Lập trước đảo vô danh.","anchor":"Bây giờ chân hắn đạp một pháp bảo hình tròn mày vàng đất"}]},"capNhatToi":"@c0383","nguon":["@c0383"]},{"id":"o-long-cap","name":"Ô Long Cập","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Đỉnh giai pháp khí","soHuu":["Hàn Lập"],"trangThai":"bị hủy","blurb":"Ô Long Cập là pháp khí Hàn Lập phóng ra nhằm bảo vệ Khúc Hồn trước Nguyệt Nha quang nhận của Cổ trưởng lão. Pháp khí chỉ cản được trong khoảnh khắc rồi bị quang nhận nghiền thành bột, không đủ sức chống chịu công kích cấp Kết Đan.","detail":"Trong trận chiến tại Hoàng Phong Cốc, khi Quy Xác pháp khí sắp không chịu nổi sức ép, Hàn Lập phóng hai đạo Ô Long Cập cùng năm đạo phi nhận trắng đen ra phía trước Khúc Hồn, tạo thêm một lớp phòng ngự mới. Tuy nhiên, các pháp khí này chỉ chắn được Nguyệt Nha quang nhận trong khoảnh khắc. Ô Long Cập cùng nhóm phi nhận trắng đen đều bị quang nhận phá nát thành bột, cho thấy chúng hoàn toàn không đủ sức đối kháng công kích từ tu sĩ Kết Đan kỳ.","phanLoaiPhu":"Pháp khí phòng ngự/công kích","uyLuc":"Tạm thời chắn trước Khúc Hồn nhưng không chịu nổi công kích Kết Đan, bị Nguyệt Nha quang nhận nghiền thành bột.","dacDiem":"Bị phá hủy cùng nhóm phi nhận trắng đen.","chuHienThoi":"Hàn Lập","congNang":["Tạo lớp phòng ngự chặn trước Nguyệt Nha quang nhận @c0383"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0383","denChuong":"@c0383","cachCoDuoc":"Đã mang theo khi đối chiến Cổ trưởng lão","trangThai":"bị hủy"}],"tabs":{"tienTrinh":[{"chuong":"@c0383","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị quang nhận nghiền nát","text":"Ô Long Cập được Hàn Lập dùng để chắn trước Khúc Hồn nhưng bị Nguyệt Nha quang nhận phá thành bột.","anchor":"‘Ô long cập’ cùng với năm đạo phi nhân trắng đen kia lập tức biến thành bột","phamCap":"Đỉnh giai pháp khí"}]},"capNhatToi":"@c0383","nguon":["@c0383"]},{"id":"nam-dao-phi-nhan-trang-den","name":"Năm đạo phi nhận trắng đen","cn":"","category":"phap-bao","categoryLabel":"Phi nhận pháp khí","phamCap":"Đỉnh giai pháp khí","soHuu":["Hàn Lập"],"trangThai":"bị hủy","blurb":"Năm đạo phi nhận trắng đen là nhóm pháp bảo phòng ngự được Hàn Lập sử dụng trong trận giao phong với Cổ trưởng lão, phối hợp cùng Ô Long Cập để chặn đỡ Nguyệt Nha quang nhận. Chúng bị nghiền nát trước uy lực của tu sĩ Kết Đan.","detail":"Trong trận chiến tại @c0383, Hàn Lập tung năm đạo phi nhận màu trắng và đen, phối hợp cùng Ô Long Cập để hình thành phòng tuyến bảo vệ Khúc Hồn trước đòn tấn công của Cổ trưởng lão. Tuy nhiên, trước uy lực Nguyệt Nha quang nhận của đối phương, nhóm phi nhận này bị nghiền thành bột, cho thấy giới hạn rõ rệt khi đối đầu tu sĩ Kết Đan.","phanLoaiPhu":"Phi nhận pháp khí","uyLuc":"Có thể tạo lớp ngăn cản tức thời nhưng không đủ chống tu sĩ Kết Đan.","dacDiem":"Tồn tại dưới dạng năm đạo phi nhận trắng đen.","chuHienThoi":"Hàn Lập","congNang":["Phối hợp cùng Ô Long Cập hình thành phòng tuyến ngăn cản quang nhận của đối phương @c0383"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0383","denChuong":"@c0383","cachCoDuoc":"Đã mang theo khi đối chiến Cổ trưởng lão","trangThai":"bị hủy"}],"tabs":{"tienTrinh":[{"chuong":"@c0383","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Bị phá trong giao chiến","text":"Năm đạo phi nhận trắng đen được tung ra để bảo vệ Khúc Hồn rồi bị quang nhận của Cổ trưởng lão nghiền nát.","anchor":"lần lượt bày ra các đạo quang nhận màu trắng và đen","phamCap":"Đỉnh giai pháp khí"}]},"capNhatToi":"@c0383","nguon":["@c0383"]},{"id":"chu-tran-ky-mau-xanh","name":"Chủ trận kỳ màu xanh","cn":"","category":"phap-bao","categoryLabel":"Trận kỳ","phamCap":"Trận kỳ điều khiển đại trận","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Chủ trận kỳ màu xanh là vật Hàn Lập dùng để khống chế Bích Thủy Thanh Giáp Đại Trận. Khi được ném vào trận, nó làm cảnh nước biển mãnh liệt hơn và tăng áp lực vây khốn.","detail":"Sau khi thấy Cổ trưởng lão phá trận quá nhanh, Hàn Lập lấy một cây tiểu kỳ màu xanh, niệm chú rồi ném vào trận. Chủ trận kỳ giúp hắn tăng uy lực Bích Thủy Thanh Giáp Đại Trận, khiến áp lực trong ảo cảnh đại hải mạnh thêm.","phanLoaiPhu":"Trận kỳ chủ trận","hinhDang":"Tiểu kỳ màu xanh","uyLuc":"Tăng áp lực của Bích Thủy Thanh Giáp Đại Trận lên Cổ trưởng lão.","dacDiem":"Dùng để khống chế trận pháp do Hàn Lập bày ra.","chuHienThoi":"Hàn Lập","congNang":["Khống chế Bích Thủy Thanh Giáp Đại Trận @c0383","Tăng uy lực áp lực và biến động nước biển trong trận @c0383"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0383","denChuong":"","cachCoDuoc":"Đã mang theo để điều khiển trận pháp","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0383","loai":"dùng","importance":"normal","giaiDoan":"Tăng uy lực trận pháp","text":"Hàn Lập dùng chủ trận kỳ màu xanh để làm Bích Thủy Thanh Giáp Đại Trận gia tăng áp lực lên Cổ trưởng lão.","anchor":"một cây tiểu kỳ màu xanh xuất hiên trong tay, đúng là chủ trận kỳ khống chế trận pháp này"}]},"capNhatToi":"@c0383","nguon":["@c0383"]},{"id":"tui-tru-vat-cua-co-truong-lao","name":"Túi trữ vật của Cổ trưởng lão","cn":"","aliases":[],"category":"khac","categoryLabel":"Túi trữ vật","phamCap":"không rõ","soHuu":["Cổ trưởng lão","Hàn Lập"],"trangThai":"Hàn Lập giữ @c0384","blurb":"Túi trữ vật của Cổ trưởng lão là chiến lợi phẩm mà Hàn Lập thu được sau khi hạ sát Cổ trưởng lão, lấy từ thi thể không đầu của đối thủ. Bên trong chứa nhiều vật phẩm giá trị bao gồm linh thạch, phù lục, công pháp, yêu đan và đan dược.","detail":"Túi trữ vật này vốn thuộc về Cổ trưởng lão. Sau khi Hàn Lập chém đầu Cổ trưởng lão, hắn thu lấy túi từ thi thể không đầu của đối phương và tiến hành kiểm kê. Bên trong túi chứa bảy tám mươi khối linh thạch trung phẩm, bình ngọc, hai cuốn phù lục, đạo thư Thổ Ly Quyết, nội đan yêu thú cấp năm, Hàn Trần Đan cùng một số vật phẩm không đáng giá khác. Đây là một trong những chiến lợi phẩm Hàn Lập thu hoạch được trong giao chiến.","phanLoaiPhu":"túi trữ vật chiến lợi phẩm","chuHienThoi":"Hàn Lập","congNang":["Chứa đựng nhiều vật phẩm giá trị: linh thạch trung phẩm, phù lục, công pháp, yêu đan và đan dược @c0384"],"chuSoHuu":[{"ten":"Cổ trưởng lão","tuChuong":"@c0384","denChuong":"@c0384","cachCoDuoc":"vật tùy thân trước khi chết","trangThai":"đã mất"},{"ten":"Hàn Lập","tuChuong":"@c0384","denChuong":"","cachCoDuoc":"lấy từ thi thể Cổ trưởng lão sau trận chiến","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0384","loai":"đổi chủ","importance":"major","giaiDoan":"Sau khi Cổ trưởng lão chết","text":"Hàn Lập lấy túi trữ vật từ thi thể không đầu của Cổ trưởng lão và sau đó kiểm kê được nhiều vật phẩm giá trị.","anchor":"đến gần tử thi không đầu quơ tay lấy túi trử vật bên hông"}]},"capNhatToi":"@c0384","nguon":["@c0384"]},{"id":"tam-lua-mong-doan-tuyet-khi-tuc","name":"Tấm lụa mỏng đoạn tuyệt khí tức","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm ẩn nấp","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng @c0384","blurb":"Tấm lụa mỏng có khả năng đoạn tuyệt khí tức, được Hàn Lập dùng khi ẩn dưới đáy biển.","detail":"Hàn Lập lấy tấm lụa mỏng bao phủ bản thân và Khúc Hồn, phối hợp vô danh khẩu quyết để tránh luồng thần thức cường đại phát hiện tung tích.","phanLoaiPhu":"vật phẩm che giấu khí tức","chuHienThoi":"Hàn Lập","congNang":["Đoạn tuyệt khí tức, che giấu Hàn Lập và Khúc Hồn trước thần thức truy tìm @c0384"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0384","denChuong":"","cachCoDuoc":"đã mang theo trước khi ẩn dưới biển","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0384","loai":"dùng","importance":"normal","giaiDoan":"Ẩn dưới đáy biển","text":"Hàn Lập dùng tấm lụa mỏng để bao phủ mình và Khúc Hồn, hỗ trợ che giấu khí tức trước thần thức cường đại.","anchor":"lấy ra tấm lụa mỏng có khả năng đoạn tuyệt khí tức kia"}]},"capNhatToi":"@c0384","nguon":["@c0384"]},{"id":"phu-bao-tieu-kiem-mau-vang","name":"Phù bảo tiểu kiếm màu vàng","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"không rõ","soHuu":["Cổ trưởng lão","Hàn Lập"],"trangThai":"Hàn Lập giữ @c0384","blurb":"Phù bảo vẽ tiểu kiếm màu vàng, nằm trong túi trữ vật của Cổ trưởng lão.","detail":"Khi kiểm kê chiến lợi phẩm, Hàn Lập phát hiện một phù bảo họa thanh tiểu kiếm màu vàng trong số hai phù lục lấy được từ túi trữ vật Cổ trưởng lão.","hinhDang":"phù lục vẽ thanh tiểu kiếm màu vàng","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Cổ trưởng lão","tuChuong":"@c0384","denChuong":"@c0384","cachCoDuoc":"cất trong túi trữ vật","trangThai":"đã mất"},{"ten":"Hàn Lập","tuChuong":"@c0384","denChuong":"","cachCoDuoc":"thu từ túi trữ vật Cổ trưởng lão","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0384","loai":"xuất hiện","importance":"normal","giaiDoan":"Kiểm kê chiến lợi phẩm","text":"Hàn Lập phát hiện phù bảo họa tiểu kiếm màu vàng trong túi trữ vật Cổ trưởng lão.","anchor":"một phù bảo họa một thanh tiểu kiếm màu vàng"}]},"capNhatToi":"@c0384","nguon":["@c0384"]},{"id":"phu-luc-giao-long-mau-lam","name":"Phù lục giao long màu lam","cn":"","aliases":[],"category":"khac","categoryLabel":"Phù lục","phamCap":"không rõ","soHuu":["Cổ trưởng lão","Hàn Lập"],"trangThai":"Hàn Lập giữ @c0384","blurb":"Phù lục vẽ giao long màu lam, tên gọi và công năng chưa được Hàn Lập xác định.","detail":"Đây là tấm phù lục còn lại trong túi trữ vật Cổ trưởng lão. Hàn Lập chỉ nhận ra hình vẽ giao long màu lam nhưng chưa biết tên gọi cụ thể.","hinhDang":"phù lục họa giao long màu lam","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Cổ trưởng lão","tuChuong":"@c0384","denChuong":"@c0384","cachCoDuoc":"cất trong túi trữ vật","trangThai":"đã mất"},{"ten":"Hàn Lập","tuChuong":"@c0384","denChuong":"","cachCoDuoc":"thu từ túi trữ vật Cổ trưởng lão","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0384","loai":"xuất hiện","importance":"normal","giaiDoan":"Kiểm kê chiến lợi phẩm","text":"Hàn Lập phát hiện một phù lục vẽ giao long màu lam nhưng chưa biết tên gọi cụ thể.","anchor":"tấm còn lại họa một con giao long màu lam chẳng biết tên"}]},"capNhatToi":"@c0384","nguon":["@c0384"]},{"id":"noi-dan-yeu-thu-cap-nam","name":"Nội đan yêu thú cấp năm","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Yêu đan","phamCap":"yêu thú cấp năm","soHuu":["Cổ trưởng lão","Hàn Lập"],"trangThai":"Hàn Lập giữ @c0384","blurb":"Nội đan yêu thú cấp năm là viên cầu lam quang Hàn Lập tìm thấy trong túi trữ vật Cổ trưởng lão.","detail":"Hàn Lập lấy viên cầu lấp lóe lam quang ra xem xét và xác định đây là nội đan của yêu thú cấp năm nào đó, thuộc vật cực kỳ trân quý.","hinhDang":"viên cầu lấp lóe lam quang","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Cổ trưởng lão","tuChuong":"@c0384","denChuong":"@c0384","cachCoDuoc":"cất trong túi trữ vật","trangThai":"đã mất"},{"ten":"Hàn Lập","tuChuong":"@c0384","denChuong":"","cachCoDuoc":"thu từ túi trữ vật Cổ trưởng lão","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0384","loai":"xuất hiện","importance":"normal","giaiDoan":"Kiểm kê chiến lợi phẩm","text":"Hàn Lập nhận ra viên cầu lam quang trong túi trữ vật là nội đan của yêu thú cấp năm.","anchor":"đây là nôi đan của yêu thú cấp năm nào đó"}]},"capNhatToi":"@c0384","nguon":["@c0384"]},{"id":"muoi-loai-linh-duoc-ho-tro-ket-dan-cua-han-lap","name":"Mười loại linh dược hỗ trợ kết đan của Hàn Lập","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"hỗ trợ kết đan","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Mười loại linh dược do Hàn Lập chuẩn bị để tăng cơ hội kết đan.","detail":"Hàn Lập dùng linh thảo hiếm trong thời gian tu luyện ở Tiểu Hoàn Sơn để điều chế mười loại linh dược hỗ trợ kết đan, cất trong túi trữ vật để dùng khi bế quan.","congNang":["Hỗ trợ kết đan @c0385"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0385","denChuong":"","cachCoDuoc":"Điều chế bằng linh thảo hiếm trong thời gian tu luyện ở Tiểu Hoàn Sơn","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0385","loai":"xuất hiện","importance":"normal","giaiDoan":"Chuẩn bị kết đan","text":"Hàn Lập đã điều chế sẵn mười loại linh dược hỗ trợ kết đan.","anchor":"đã dùng chúng nó điều chế ra mười loại linh dược hỗ trợ kết đan"}]},"capNhatToi":"@c0385","nguon":["@c0385"]},{"id":"ngoc-gian-hai-do-khoi-tinh-dao-va-ba-dai-dao","name":"Ngọc giản hải đồ Khôi Tinh Đảo và ba đại đảo","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản hải đồ","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang có","blurb":"Hải đồ trong ngọc giản dùng để tra vị trí các đảo quanh Khôi Tinh Đảo và ba đại đảo.","detail":"Hàn Lập dùng ngọc giản này để phán đoán vị trí hiện tại, tra đặc điểm các đảo nhỏ lân cận và chọn hướng đi tới Hải Viên Đảo.","congNang":["Xác định đường biển và các đảo lân cận @c0385"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0385","denChuong":"","cachCoDuoc":"Đã mang theo trong túi trữ vật","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0385","loai":"dùng","importance":"normal","giaiDoan":"Chọn nơi bế quan","text":"Hàn Lập dùng ngọc giản hải đồ lấy Khôi Tinh Đảo và ba đại đảo làm trung tâm để xác định đường đi.","anchor":"bên trong ngọc giản này lấy Khôi Tinh Đảo cùng với ba đại đảo làm trung tâm"}]},"capNhatToi":"@c0385","nguon":["@c0385"]},{"id":"huyet-bach-tri-thu","name":"Huyết bạch tri thù","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh thú","phamCap":"yêu thú cấp thấp đã thăng hai giai","soHuu":["Hàn Lập"],"trangThai":"canh giữ động phủ tạm","blurb":"Hai con linh thú của Hàn Lập được thả ra canh giữ động phủ tạm trên Hải Viên Đảo.","detail":"Hai con Huyết bạch tri thù đã lớn hơn trước và liên tiếp thăng hai giai, đủ đối phó tu sĩ Luyện Khí Kỳ bình thường khi được giao bảo vệ động phủ tạm.","congNang":["Canh giữ động phủ và đối phó tu sĩ Luyện Khí Kỳ bình thường @c0385"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0385","denChuong":"","cachCoDuoc":"Mang theo trong áo da lưu giữ linh thú","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0385","loai":"dùng","importance":"normal","giaiDoan":"Canh giữ động phủ","text":"Hàn Lập thả hai con Huyết bạch tri thù đã thăng hai giai ra bảo vệ động phủ tạm.","anchor":"hai con “Huyết bạch tri thù” đã lớn hơn cái đầu rồi"}]},"capNhatToi":"@c0385","nguon":["@c0385"]},{"id":"ngoc-gian-tam-dac-duc-trung-cua-tu-si-ngu-linh-tong","name":"Ngọc giản tâm đắc dục trùng của tu sĩ Ngự Linh Tông","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"đang được Hàn Lập giữ","blurb":"Ngọc giản ghi tâm đắc nuôi trùng của tu sĩ Ngự Linh Tông, giúp Hàn Lập nhận diện Phệ Kim Trùng.","detail":"Hàn Lập lấy ngọc giản màu xanh biếc này ra tra cứu khi phát hiện ngân cầu trong dược viên. Nội dung trùng bảng ở vị trí thứ mười hai mô tả Phệ Kim Trùng, tập tính quần tụ, khả năng ăn linh khí, khó bị nước lửa xâm hại và việc bị nhện khắc chế.","phanLoaiPhu":"ngọc giản thông tin","hinhDang":"ngọc giản màu xanh biếc","congNang":["Lưu tâm đắc dục trùng và trùng bảng, giúp nhận diện Phệ Kim Trùng cùng thông tin khắc chế."],"chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0387","denChuong":"","cachCoDuoc":"đang giữ và dùng để tra cứu","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0387","loai":"dùng","importance":"normal","giaiDoan":"Tra cứu Phệ Kim Trùng","text":"Hàn Lập dùng ngọc giản tâm đắc dục trùng để đối chiếu ngân cầu và nhận ra Phệ Kim Trùng trên trùng bảng.","anchor":"một khối ngọc giản màu xanh biếc xuất hiện trong tay, đúng là ngọc giản nghi lại những tâm đắc dục trùng"}]},"capNhatToi":"@c0387","nguon":["@c0387"]},{"id":"phe-kim-trung","name":"Phệ Kim Trùng","cn":"噬金虫","aliases":[],"category":"khac","categoryLabel":"Kỳ trùng","phamCap":"bài danh thứ mười hai trên trùng bảng","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phệ Kim Trùng là hung trùng quần tụ bài danh thứ mười hai trên trùng bảng, lần đầu lộ diện dưới dạng ngân cầu treo dưới tán cây trong dược viên động phủ. Sau khi thể hiện uy lực cắn nuốt ma hỏa, chúng bị Hàn Lập dùng Huyết Ngọc Tri Thù thu phục, và tại Tiểu Hoàn Đảo còn phát hiện thêm ấu trùng ngủ say từ thượng cổ bị mùi trùng đánh thức.","detail":"Phệ Kim Trùng xuất hiện dưới dạng ngân cầu treo dưới tán cây trong dược viên của một động phủ. Hàn Lập nhận diện chúng nhờ ngọc giản tâm đắc dục trùng, trong đó ghi rõ đây là hung trùng quần tụ xếp hạng mười hai trên trùng bảng, bản tính thích ăn linh khí, nước lửa khó xâm hại, thường tụ thành cầu dưới tán cây, bị ngọc mộc khốn và bị nhện khắc chế. Khi Khúc Hồn dùng tử diễm ma hỏa thử nghiệm, đàn trùng tách từ ngân cầu thành vô số giáp trùng bạc nhỏ, không những không bị thiêu chết mà còn cắn nuốt ngọn lửa. Sau đó Hàn Lập dùng Huyết Ngọc Tri Thù phun tơ bao thành kén để thu giữ toàn bộ đàn trùng. Về sau tại Tiểu Hoàn Đảo, ấu trùng Phệ Kim Trùng ngủ say từ thượng cổ bị mùi trùng đánh thức, Hàn Lập tiến hành thử nhiều cách nuôi dưỡng chúng.","phanLoaiPhu":"hung trùng quần tụ","hinhDang":"ngân cầu do vô số giáp trùng bạc nhỏ tụ thành","uyLuc":"Có thể cắn nuốt ma hỏa và khó bị nước lửa xâm hại; đàn trùng số lượng cực lớn tách ra công kích khắp nơi, áp đảo đối phương bằng chiến thuật quần tụ.","dacDiem":"Thích ăn linh khí, thường tụ thành ngân cầu dưới tán cây; bị nhện khắc chế và có thể bị ngọc mộc khốn; có ấu trùng ngủ say từ thượng cổ dưới Tiểu Hoàn Đảo, bị mùi trùng đánh thức.","chuHienThoi":"Hàn Lập","congNang":["Ăn linh khí — bản tính ghi trong ngọc giản tâm đắc dục trùng (@c0387)","Kháng nước lửa — ngọc giản ghi nước lửa khó xâm hại (@c0387)","Cắn nuốt tử diễm ma hỏa của Khúc Hồn, không bị thiêu chết mà còn thôn phệ ngọn lửa (@c0387)","Quần tụ thành ngân cầu, khi chiến đấu tách ra thành vô số giáp trùng bạc nhỏ (@c0387)","Thắng bằng số lượng cực lớn, đàn trùng công kích khắp nơi (@c0392)"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0387","denChuong":"","cachCoDuoc":"Bắt lại từ động phủ Tiểu Hoàn Đảo sau khi chúng nuốt hết kỳ trùng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0387","loai":"đổi chủ","importance":"major","giaiDoan":"Bị bắt sống","text":"Phệ Kim Trùng được Hàn Lập nhận ra qua ngọc giản, lộ uy lực cắn nuốt ma hỏa rồi bị Huyết Ngọc Tri Thù phun tơ bao thành kén và thu giữ.","anchor":"Phệ Kim Trùng, quần tụ hung trùng, bài danh thứ mười hai, là một kỳ trùng thích ăn uống"},{"chuong":"@c0392","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ lai lịch và Hàn Lập thử bồi dưỡng","text":"Hé lộ ấu trùng ngủ say từ thượng cổ dưới Tiểu Hoàn Đảo, bị mùi trùng đánh thức. Hàn Lập thử nhiều cách nuôi nhưng tạm gác kế hoạch vì chi phí quá lớn.","anchor":"Chỉ khi số lượng của chúng nó đạt tới mười mấy vạn hay mấy chục vạn lúc ấy mới chính thức xứng đáng với vị trí của nó tại Kỳ trùng bảng"}]},"capNhatToi":"@c0387","nguon":["@c0387","@c0392"]},{"id":"ngan-trung-xac","name":"Ngân trùng xác","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Trùng xác","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"được Hàn Lập phát hiện","blurb":"Vỏ trùng màu bạc lớn cỡ bàn tay, là manh mối dẫn Hàn Lập tới Phệ Kim Trùng.","detail":"Trong mật thất nuôi trùng đã trống rỗng, Hàn Lập phát hiện một khối xác kỳ trùng đã lột vỏ, ngân quang lóe sáng và rất cứng rắn. Vì không giống loại kỳ trùng hắn từng nuôi, nó trở thành dấu vết quan trọng để hắn mở rộng thần thức tìm kiếm ngân cầu trong dược viên.","phanLoaiPhu":"vỏ lột xác kỳ trùng","hinhDang":"lớn cỡ bàn tay, màu bạc, bóng loáng","dacDiem":"Cứng rắn và không thuộc các kỳ trùng cũ Hàn Lập từng nuôi.","chuHienThoi":"Hàn Lập","congNang":["Làm manh mối giúp Hàn Lập truy tìm và nhận ra Phệ Kim Trùng."],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0387","denChuong":"","cachCoDuoc":"nhặt được trong mật thất nuôi trùng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0387","loai":"xuất hiện","importance":"normal","giaiDoan":"Manh mối trong mật thất","text":"Hàn Lập phát hiện Ngân trùng xác trong mật thất trống, từ đó nghi ngờ có kỳ trùng lạ xâm nhập động phủ.","anchor":"Một khối xác của kỳ trùng đã lột vỏ lớn cở bàn tay, ngân quang lóe sáng"}]},"capNhatToi":"@c0387","nguon":["@c0387"]},{"id":"tui-linh-thu-chuyen-dung","name":"Túi linh thú chuyên dụng","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm chứa linh thú","phamCap":"không rõ","soHuu":[],"trangThai":"được nhắc tới","blurb":"Vật phẩm chuyên dùng để chứa, triệu hồi và huấn luyện linh thú khi muốn dùng thú đánh địch.","detail":"Chương giải thích túi trữ vật có thể tạm chứa một số kỳ trùng đặc biệt, nhưng nếu muốn dùng thú để đánh địch thì phải dùng túi đựng linh thú chuyên dụng. Loại túi này thích hợp cho việc triệu hồi, huấn luyện và thu nhỏ linh thú có thể tích lớn.","phanLoaiPhu":"túi chứa linh thú","congNang":["Chứa linh thú để tiện triệu hồi khi chiến đấu.","Hỗ trợ huấn luyện linh thú.","Có thể thu nhỏ linh thú thể tích lớn để mang theo."],"tabs":{"tienTrinh":[{"chuong":"@c0387","loai":"nhắc tới","importance":"normal","giaiDoan":"Giải thích vật chứa linh thú","text":"Túi linh thú chuyên dụng được nêu là vật cần dùng nếu muốn điều khiển linh thú tham chiến và huấn luyện thuận tiện.","anchor":"Đương nhiên nếu là muốn dùng thú để đánh địch thì phải sử dụng túi đựng linh thú chuyên dụng"}]},"capNhatToi":"@c0387","nguon":["@c0387"]},{"id":"ho-giap-mau-vang-cua-tu-si-bo-chay","name":"Hộ giáp màu vàng của tu sĩ bỏ chạy","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phòng hộ","phamCap":"","soHuu":["Tu sĩ bỏ chạy trong nhóm chấp pháp Khôi Tinh Đảo"],"trangThai":"hong @c0388","blurb":"Pháp khí phòng hộ màu vàng của một tu sĩ chấp pháp bỏ chạy khỏi Khúc Hồn.","detail":"Một tu sĩ bỏ chạy mang hộ giáp màu vàng phát sáng, nhưng vừa gặp huyết trụ của Khúc Hồn thì cả hộ giáp lẫn người đều bị đánh thành bụi phấn.","dinhDanh":"goc","phanLoaiPhu":"pháp khí phòng hộ","hinhDang":"hộ giáp màu vàng","uyLuc":"Không chịu nổi huyết trụ của Khúc Hồn.","dacDiem":"Phát ánh sáng vàng khi hộ thân.","chuHienThoi":"Tu sĩ bỏ chạy trong nhóm chấp pháp Khôi Tinh Đảo","congNang":["Hộ thân cho tu sĩ bỏ chạy nhưng bị huyết trụ phá hủy @c0388"],"chuSoHuu":[{"ten":"Tu sĩ bỏ chạy trong nhóm chấp pháp Khôi Tinh Đảo","tuChuong":"@c0388","denChuong":"@c0388","cachCoDuoc":"Vật phòng hộ mang theo khi bỏ chạy","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c0388","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Bị huyết trụ phá hủy","text":"Hộ giáp màu vàng của tu sĩ bỏ chạy bị huyết trụ Khúc Hồn đánh nát cùng chủ nhân.","phamCap":"","anchor":"một người mang một hộ giáp màu vàng lập lòe tình quang"}]},"capNhatToi":"@c0388","nguon":["@c0388"]},{"id":"day-xich-mau-xanh-cua-tu-si-bo-chay","name":"Dây xích màu xanh của tu sĩ bỏ chạy","cn":"","category":"phap-bao","categoryLabel":"Pháp khí phòng hộ","phamCap":"","soHuu":["Tu sĩ bỏ chạy trong nhóm chấp pháp Khôi Tinh Đảo"],"trangThai":"hong @c0388","blurb":"Dây xích màu xanh của một tu sĩ chấp pháp bỏ chạy khỏi Khúc Hồn.","detail":"Một tu sĩ bỏ chạy quấn dây xích màu xanh được mô tả không phải vật phàm, nhưng vẫn bị huyết trụ của Khúc Hồn phá hủy cùng chủ nhân.","dinhDanh":"goc","phanLoaiPhu":"pháp khí phòng hộ","hinhDang":"dây xích màu xanh","uyLuc":"Không chống nổi huyết trụ của Khúc Hồn.","dacDiem":"Quấn quanh người tu sĩ khi bỏ chạy.","chuHienThoi":"Tu sĩ bỏ chạy trong nhóm chấp pháp Khôi Tinh Đảo","congNang":["Hộ thân cho tu sĩ bỏ chạy nhưng bị huyết trụ phá hủy @c0388"],"chuSoHuu":[{"ten":"Tu sĩ bỏ chạy trong nhóm chấp pháp Khôi Tinh Đảo","tuChuong":"@c0388","denChuong":"@c0388","cachCoDuoc":"Vật phòng hộ mang theo khi bỏ chạy","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c0388","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Bị huyết trụ phá hủy","text":"Dây xích màu xanh của tu sĩ bỏ chạy bị huyết trụ Khúc Hồn đánh nát cùng chủ nhân.","phamCap":"","anchor":"một người còn lại quấn lấy một sợi dây xích màu xanh"}]},"capNhatToi":"@c0388","nguon":["@c0388"]},{"id":"tui-tru-vat-cua-nhom-chap-phap-khoi-tinh-dao","name":"Túi trữ vật của nhóm chấp pháp Khôi Tinh Đảo","cn":"","category":"phap-bao","categoryLabel":"Túi trữ vật","phamCap":"","soHuu":["Hàn Lập","Khúc Hồn"],"trangThai":"doi-chu","blurb":"Các túi trữ vật rơi lại sau khi nhóm chấp pháp Khôi Tinh Đảo bị Khúc Hồn diệt sạch.","detail":"Sau khi Khúc Hồn diệt nhóm chấp pháp, hắn và Hàn Lập thu lấy mấy túi trữ vật rơi xuống của nạn nhân rồi rời khỏi hiện trường.","dinhDanh":"goc","phanLoaiPhu":"túi trữ vật","chuHienThoi":"Hàn Lập và Khúc Hồn","congNang":["Cất giữ tài vật của nhóm chấp pháp trước khi bị Hàn Lập và Khúc Hồn thu lấy @c0388"],"chuSoHuu":[{"ten":"Nhóm chấp pháp tu sĩ Khôi Tinh Đảo","tuChuong":"@c0388","denChuong":"@c0388","cachCoDuoc":"Vật mang theo trước trận phục kích","trangThai":"mat"},{"ten":"Hàn Lập","tuChuong":"@c0388","denChuong":"","cachCoDuoc":"Thu lấy sau khi nhóm chấp pháp bị diệt","trangThai":"dang-giu"},{"ten":"Khúc Hồn","tuChuong":"@c0388","denChuong":"","cachCoDuoc":"Thu lấy sau khi nhóm chấp pháp bị diệt","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c0388","loai":"đổi chủ","importance":"normal","giaiDoan":"Rơi lại sau trận","text":"Các túi trữ vật của nhóm chấp pháp bị Hàn Lập và Khúc Hồn thu lấy sau khi chủ nhân chết.","phamCap":"","anchor":"đem mấy túi trử vật rơi xuống của bọn họ đều thu lấy trong tay"}]},"capNhatToi":"@c0388","nguon":["@c0388"]},{"id":"nguyen-than-bai-cua-de-tu-vien-dao-chu","name":"Nguyên thần bài của đệ tử Viên đảo chủ","cn":"","category":"khac","categoryLabel":"Mệnh bài","phamCap":"","soHuu":["Viên đảo chủ"],"trangThai":"bao-bien","blurb":"Nguyên thần bài liên hệ với đệ tử của Viên đảo chủ, sinh dị biến khi đệ tử chết.","detail":"Khi một đệ tử của Viên đảo chủ trong nhóm chấp pháp bị giết, nguyên thần bài được Viên đảo chủ thi triển bí thuật xuất hiện dị biến, giúp ông biết đệ tử gặp bất trắc.","dinhDanh":"goc","phanLoaiPhu":"mệnh bài","nguonGoc":"Do Viên đảo chủ thi triển bí thuật liên hệ với đệ tử.","chuHienThoi":"Viên đảo chủ","congNang":["Báo tử khi đệ tử liên hệ với nguyên thần bài chết @c0388"],"chuSoHuu":[{"ten":"Viên đảo chủ","tuChuong":"@c0388","denChuong":"","cachCoDuoc":"Vật liên hệ với đệ tử do Viên đảo chủ thi triển bí thuật","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c0388","loai":"nhắc tới","importance":"normal","giaiDoan":"Dị biến báo tử","text":"Nguyên thần bài xuất hiện dị biến khi đệ tử của Viên đảo chủ chết trong nhóm chấp pháp.","phamCap":"","anchor":"bên trong nguyên thần bài được trung niên nhân thi triển bí thuật liền xuất hiện dị biến"}]},"capNhatToi":"@c0388","nguon":["@c0388"]},{"id":"ngoc-gian-dien-tich-loan-tinh-hai","name":"Ngọc giản điển tịch Loạn Tinh Hải","cn":"","aliases":[],"category":"khac","categoryLabel":"Điển tịch / ngọc giản","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Các ngọc giản Hàn Lập mua ở phường thị vùng biên. Nhờ chúng, hắn hiểu thêm về địa lý, lịch sử, thế lực và quy tắc của Loạn Tinh Hải.","detail":"Hàn Lập đọc các ngọc giản trên Thần Phong Chu sau khi rời phường thị vùng biên. Nội dung giúp hắn biết về Nội Tinh Hải, Ngoại Tinh Hải, Tinh Cung, Thiên Tinh Thành, tinh đảo và các thế lực lớn nhỏ trong Loạn Tinh Hải.","phanLoaiPhu":"ngọc giản điển tịch","congNang":["Cung cấp kiến thức về địa lý, lịch sử, thế lực và quy tắc của Loạn Tinh Hải @c0389"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0389","denChuong":"","cachCoDuoc":"mua tại phường thị vùng biên","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0389","loai":"xuất hiện","importance":"normal","giaiDoan":"Đọc trên Thần Phong Chu","text":"Hàn Lập lấy các ngọc giản ra đọc sau khi rời phường thị, nhờ đó hiểu thêm cục diện Loạn Tinh Hải.","anchor":"Ngồi trên Thần Phong Chu, Hàn Lập lấy ra những ngọc giản cẩn thận đọc qua"}]},"capNhatToi":"@c0389","nguon":["@c0389"]},{"id":"hai-vuc-do-loan-tinh-hai","name":"Hải vực đồ Loạn Tinh Hải","cn":"","aliases":[],"category":"khac","categoryLabel":"Bản đồ hải vực","phamCap":"không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bản đồ hải vực Loạn Tinh Hải mà Hàn Lập dùng để định hướng. Sau khi đọc điển tịch, hắn xem kỹ bản đồ rồi đổi hướng đi Thiên Tinh Thành.","detail":"Hải vực đồ được Hàn Lập lấy ra sau khi đã có thêm hiểu biết về cục diện Loạn Tinh Hải. Nó giúp hắn xác định phương hướng tới Thiên Tinh Thành trong hành trình rời Tây Nam Hải Vực.","phanLoaiPhu":"bản đồ","congNang":["Giúp Hàn Lập định hướng trong hải vực Loạn Tinh Hải và đổi hướng tới Thiên Tinh Thành @c0389"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0389","denChuong":"","cachCoDuoc":"mua hoặc bổ sung tại phường thị vùng biên","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0389","loai":"dùng","importance":"normal","giaiDoan":"Định hướng tới Thiên Tinh Thành","text":"Hàn Lập lấy hải vực đồ Loạn Tinh Hải ra xem kỹ rồi đổi hướng bay tới Thiên Tinh Thành.","anchor":"liền từ trên người lấy ra hải vực đồ của Loạn Tinh Hải cẩn thận xem trong chốc lát"}]},"capNhatToi":"@c0389","nguon":["@c0389"]},{"id":"yeu-dan","name":"Yêu Đan","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Tài liệu yêu thú","phamCap":"tùy cấp yêu thú","soHuu":[],"trangThai":"khong-ro","blurb":"Nội đan của yêu thú, được tu sĩ săn bắt tại Ngoại Tinh Hải để bán lấy linh thạch hoặc làm tài nguyên tu luyện. Chương nhấn mạnh giá trị lớn của Yêu Đan cấp năm và cấp sáu.","detail":"Yêu Đan được nhắc trong bối cảnh Thiên Tinh Thành có truyền tống trận tới các Yêu Thú Đảo ở Ngoại Tinh Hải. Một viên Yêu Đan cấp năm có thể bán gần ngàn linh thạch, còn Yêu Đan cấp sáu đủ giúp tu sĩ Trúc Cơ bớt lo tài nguyên trong thời gian dài.","phanLoaiPhu":"nội đan yêu thú","congNang":["Bán đổi lấy linh thạch với giá trị cao, như Yêu Đan cấp năm gần ngàn linh thạch @c0389","Làm nguồn tài nguyên tu luyện đáng kể cho tu sĩ Trúc Cơ khi đạt cấp sáu @c0389"],"tabs":{"tienTrinh":[{"chuong":"@c0389","loai":"nhắc tới","importance":"normal","giaiDoan":"Giá trị tại Ngoại Tinh Hải","text":"Yêu Đan được giới thiệu là lợi ích lớn khiến tu sĩ tới Ngoại Tinh Hải săn yêu thú.","anchor":"cơ hồ một viên Yêu Đan cấp năm có thể bán gần ngàn linh thạch"}]},"capNhatToi":"@c0389","nguon":["@c0389"]},{"id":"hong-sac-than-phan-hoan","name":"Hồng sắc thân phận hoàn","cn":"","aliases":["Hồng sắc giới chỉ"],"category":"linh-khi","categoryLabel":"Linh khí","phamCap":"","soHuu":["Hàn Lập","Khúc Hồn"],"trangThai":"dang-co","blurb":"Giới chỉ màu đỏ chứng minh thân phận cư trú lâu dài hoặc vĩnh viễn ở Thiên Tinh Thành, cần trích huyết nhận chủ.","detail":"Tu sĩ bình thường muốn ở lâu trong Thiên Tinh Thành phải nộp tám trăm linh thạch và trích huyết nhận chủ để giới chỉ phát linh quang. Tu sĩ Kết Đan kỳ trở lên được miễn phí. Khúc Hồn được cấp miễn phí, Hàn Lập tự trả linh thạch để lấy.","congNang":["Chứng minh thân phận cư trú lâu dài/vĩnh viễn tại Thiên Tinh Thành"],"chuSoHuu":[{"ten":"Khúc Hồn","tuChuong":"@c0390","denChuong":"","cachCoDuoc":"Được tu sĩ canh cửa cấp miễn phí vì thân phận Kết Đan kỳ","trangThai":"dang-co"},{"ten":"Hàn Lập","tuChuong":"@c0390","denChuong":"","cachCoDuoc":"Tự trả tám trăm linh thạch mua tại cửa thành","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0390","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ cơ chế thân phận hoàn Thiên Tinh Thành","text":"Tu sĩ canh cửa giải thích quy định lam sắc và hồng sắc thân phận hoàn. Khúc Hồn được miễn phí, Hàn Lập tự trả linh thạch mua hồng sắc giới chỉ và trích huyết nhận chủ.","anchor":"mà đỏ là có thể ở lại vĩnh viễn trong thành"}]},"nguon":["@c0390"]},{"id":"lam-sac-than-phan-hoan","name":"Lam sắc thân phận hoàn","cn":"","aliases":["Lam sắc giới chỉ"],"category":"linh-khi","categoryLabel":"Linh khí","phamCap":"","soHuu":[],"trangThai":"","blurb":"Giới chỉ màu lam dành cho tu sĩ tạm trú tại Thiên Tinh Thành, linh quang tồn tại bảy ngày.","detail":"Tu sĩ chỉ cần nộp ba khối linh thạch để nhận, linh quang tồn tại bảy ngày rồi phải rời thành hoặc đổi nhẫn khác.","congNang":["Chứng minh thân phận tạm trú bảy ngày tại Thiên Tinh Thành"],"tabs":{"tienTrinh":[{"chuong":"@c0390","loai":"xuất hiện","importance":"bridge","giaiDoan":"Được nhắc tới khi giải thích quy định","text":"Tu sĩ canh cửa giải thích lam sắc giới chỉ là loại tạm trú bảy ngày với phí ba linh thạch.","anchor":"màu lam là tu sĩ tạm thời ở lại bổn thành"}]},"nguon":["@c0390"]},{"id":"cam-che-lenh-bai-dong-phu","name":"Cấm chế lệnh bài động phủ","cn":"","category":"khac","categoryLabel":"Lệnh bài","phamCap":"Không rõ","soHuu":["Hàn Lập","Khúc Hồn"],"trangThai":"dang-co","blurb":"Lệnh bài màu vàng do bạch y tu sĩ Tinh Cung giao sau khi thu phí thuê động phủ, cho phép tự do ra vào động phủ tầng ba mươi chín, hiệu lực trăm năm.","detail":"Khối bài tử màu vàng được giao cho Khúc Hồn (đại diện Hàn Lập) khi hoàn tất thủ tục thuê. Cầm lệnh bài thì có thể tự do ra vào động phủ. Sau trăm năm nếu không gia hạn sẽ bị Tinh Cung thu hồi.","nguon":["@c0391"],"tabs":{"tienTrinh":[{"chuong":"@c0391","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhận lệnh bài","text":"Bạch y tu sĩ thu linh thạch xong, tươi cười giao khối bài tử màu vàng cho Khúc Hồn, giải thích cầm lệnh bài thì tự do ra vào động phủ.","anchor":"Tu sĩ vừa thu linh thạch, mặt tươi cười móc khối bài tử màu vàng đưa cho Khúc Hồn"}]}},{"id":"my-ngoc-thuong-pham-lat-mat-that","name":"Mỹ ngọc thượng phẩm lát mật thất","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thượng phẩm","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Mỹ ngọc thượng phẩm Hàn Lập mua ở phường thị Thiên Tinh thành, dùng lát kín mật thất vài chục trượng để chuẩn bị nuôi dưỡng Phệ Kim Trùng.","detail":"Hàn Lập đem mỹ ngọc vây quanh một gian mật thất rộng khoảng vài chục trượng, tạo môi trường cho Phệ Kim Trùng.","nguon":["@c0391"]},{"id":"tu-linh-hoan-dan-duoc","name":"Tự Linh Hoàn","cn":"滋灵丸","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Đan dược giúp yêu thú và kỳ trùng tiến cấp, Hàn Lập tự luyện từ dược thảo thúc bằng lục dịch tiểu bình.","detail":"Đan dược có tác dụng cho yêu thú tiến cấp, được xác nhận cũng có tác dụng với kỳ trùng. Hiệu quả với Huyết ngọc tri thù rất rõ rệt, giúp hai con thăng cấp lên nhóm yêu thú đỉnh cấp hàng đầu trong hai năm. Với Phệ Kim Trùng, do số lượng nhiều nên hiệu quả bị chia nhỏ, không đủ để nuôi thành đại quân. Hàn Lập luyện từ dược thảo được thúc bằng lục dịch của tiểu bình.","congNang":["Giúp yêu thú và kỳ trùng tiến cấp (@c0392)"],"tabs":{"tienTrinh":[{"chuong":"@c0392","loai":"dùng","importance":"normal","giaiDoan":"Hàn Lập dùng nuôi trùng và yêu thú","text":"Hàn Lập thử dùng Tự Linh Hoàn nuôi Phệ Kim Trùng nhưng hiệu quả chia nhỏ vì đàn trùng quá đông, sau đó chuyển hết cho Huyết ngọc tri thù.","anchor":"đan dược này có thể cho yêu thú tiến cấp, quả nhiên cũng có tác dụng với kỳ trùng"}]},"capNhatToi":"@c0392","nguon":["@c0392"]},{"id":"kim-boi-dao-lang","name":"Kim Bối Đao Lang","cn":"金背刀螂","category":"khac","categoryLabel":"Trứng kỳ trùng","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Trứng kỳ trùng, hơn mười quả được Hàn Lập cho Phệ Kim Trùng ăn, khiến linh khí biến hóa và trùng tử hung mãnh hơn.","detail":"Hơn mười quả trứng Kim Bối Đao Lang được Hàn Lập đem cho Phệ Kim Trùng ăn. Sau khi nuốt, linh khí trên thân Phệ Kim Trùng xuất hiện biến hóa, trùng tử trở nên hung mãnh hơn, khiến Hàn Lập nghi chúng cần ăn trùng khác để trưởng thành.","tabs":{"tienTrinh":[{"chuong":"@c0392","loai":"dùng","importance":"normal","giaiDoan":"Dùng làm thức ăn cho Phệ Kim Trùng","text":"Hàn Lập cho Phệ Kim Trùng ăn hơn mười quả trứng, linh khí trùng tử xuất hiện biến hóa và hung mãnh hơn.","anchor":"Sau khi Phệ Kim Trùng ăn xong, linh khí trên người trùng tử này rốt cuộc xuất hiện biến hóa"}]},"capNhatToi":"@c0392","nguon":["@c0392"]},{"id":"phu-luc-so-cap","name":"Phù lục sơ cấp","cn":"符箓","category":"khac","categoryLabel":"Phù lục","phamCap":"Sơ cấp","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hàn Lập chế tạo nhiều phù lục sơ cấp trong hai năm bế quan, xác suất thành công sơ cấp bậc cao gần một nửa.","detail":"Hàn Lập không thể chế trung cấp phù lục vì chưa Kết Đan và chưa nắm giữ trung cấp pháp thuật, nhưng nhờ chế nhiều sơ cấp phù lục nên kỹ năng tăng mạnh, xác suất chế tác sơ cấp bậc cao gần một nửa.","tabs":{"tienTrinh":[{"chuong":"@c0392","loai":"xuất hiện","importance":"bridge","giaiDoan":"","text":"Hàn Lập chế tạo nhiều phù lục sơ cấp bậc cao với xác suất thành công gần một nửa.","anchor":"cho dù là sơ cấp phù lục bậc cao, cũng có xác suất thành công gần một nửa"}]},"capNhatToi":"@c0392","nguon":["@c0392"]},{"id":"tu-lieu-yeu-thu-loan-tinh-hai-ngoai-tinh-hai","name":"Tư liệu yêu thú Loạn Tinh Hải và Ngoại Tinh Hải","category":"khac","categoryLabel":"Tư liệu","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Tập hợp tư liệu về yêu thú Loạn Tinh Hải sao chép tại Bạch Môn Các và tài liệu yêu thú Ngoại Tinh Hải tìm ở tiểu điếm cũ, Hàn Lập dùng nghiên cứu tập tính, nhược điểm để chuẩn bị săn yêu.","detail":"Hàn Lập chi hơn một trăm linh thạch sao chép tư liệu yêu thú Loạn Tinh Hải tại Bạch Môn Các, sau đó tìm được tài liệu yêu thú Ngoại Tinh Hải ở một tiểu điếm cũ trong phường thị. Dành trọn một tháng nghiên cứu nơi xuất hiện, tập tính, nhược điểm và phương án đối phó từng loại yêu thú.","congNang":["Cung cấp thông tin chi tiết về yêu thú để lập phương án đối phó"],"nguon":["@c0393"]},{"id":"hai-tui-tru-vat-dung-luong-cuc-lon","name":"Hai túi trữ vật dung lượng cực lớn","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Hai túi trữ vật dung lượng lớn gấp chục lần túi cũ, Hàn Lập mua hơn một ngàn linh thạch để chứa Khôi Lỗi thú và chiến lợi phẩm săn yêu.","detail":"Do hơn hai trăm Khôi Lỗi thú đã chiếm hết các túi trữ vật hiện có và dự tính chuyến săn yêu thú sẽ thu nhiều yêu đan cùng tài liệu quý, Hàn Lập bỏ hơn một ngàn linh thạch mua hai túi này tại phường thị Thiên Tinh Thành.","congNang":["Trữ vật dung lượng cực lớn, gấp khoảng chục lần túi trữ vật thường"],"nguon":["@c0393"]},{"id":"truyen-tong-phu","name":"Truyền tống phù","category":"khac","categoryLabel":"Phù lục","soHuu":[],"trangThai":"tiêu hao","blurb":"Phù bảo hộ truyền tống cự ly xa do phù sư Tinh Cung độc quyền luyện chế, hiệu quả tương tự Đại na di lệnh nhưng chỉ dùng một lần và có giới hạn khoảng cách.","detail":"Bạch y tu sĩ Tinh Không Điện phát cho mỗi người một tờ dán lên người trước khi truyền tống xa. Phù có hiệu quả bảo vệ giống Đại na di lệnh nhưng kém xa do chỉ dùng một lần và có hạn khoảng cách, bên ngoài Tinh Cung không có loại phù này.","congNang":["Bảo vệ tu sĩ khi truyền tống cự ly xa, dùng một lần"],"nguon":["@c0393"]},{"id":"hai-vuc-do","name":"Hải Vực Đồ (bản tinh tế)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Bản đồ hải vực dạng ngọc giản, phiên bản mới nhất ghi chép vùng phụ cận Ngoại tinh hải, giá 100 linh thạch bậc trung.","detail":"Hàn Lập mua tại cửa hiệu tạp hóa Phong Nhạc thương minh trên Ngưng Thúy Đảo. Dùng để xác định phương hướng khi bay xuyên Ngoại tinh hải bằng Thần Phong Chu.","congNang":["Bản đồ hải vực mới nhất dùng xác định phương hướng trên biển @c0394","Ghi chép tình hình hải vực, khu vực nguy hiểm và yêu thú quanh Kỳ Uyên đảo"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0394","denChuong":"","cachCoDuoc":"Mua tại tiệm tạp hóa","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0394","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập mua trên Ngưng Thúy Đảo","text":"Hàn Lập mua Hải Vực Đồ tinh tế dạng ngọc giản tại cửa hiệu tạp hóa Phong Nhạc thương minh, giá 100 linh thạch bậc trung, dùng xác định phương hướng khi rời đảo.","anchor":"Tinh tế hải đồ, một trăm linh thạch"},{"chuong":"@c0515","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập mua nghiên cứu","text":"Hàn Lập mua hải vực đồ tại tiệm tạp hóa gần Thốn Kim Các, nghiên cứu tình hình biển quanh Kỳ Uyên đảo.","anchor":"mua một hải vực đồ về vùng biển cùng tình hình thực tế các yêu thú hay xuất hiện tại nơi này"}]},"nguon":["@c0394","@c0515"]},{"id":"ne-thuong-thao","name":"Nghê Thường Thảo","cn":"霓裳草","aliases":["Dụ Yêu Thảo"],"category":"khac","categoryLabel":"Linh thảo","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Nghê Thường Thảo là linh thảo mọc trên rạn san hô ở Loạn Tinh Hải, cứ hơn trăm năm giăng một lá phát tán mùi cổ quái dẫn dụ yêu thú biển. Hàn Lập dùng lục dịch tiểu bình phá giới hạn thời gian, rút chu kỳ giăng lá xuống chỉ một đến bốn ngày, biến nó thành công cụ dẫn dụ yêu thú và kích thích Phệ Kim Trùng tiến hóa.","detail":"Thân dài một tấc, mười ba lá cuốn thành hình trụ, toàn thân tỏa quang hoa trắng mờ thay đổi theo sắc thái hoàn cảnh. Mọc tự nhiên trên rạn san hô tại Loạn Tinh Hải, nếu trồng trên đất thường sẽ héo chết. Dược hiệu tầm thường, chỉ có thể dùng làm dược dẫn cho đan dược cấp thấp. Cứ hơn trăm năm giăng một lá trong khoảng sáu bảy ngày, khi giăng lá sẽ tán phát mùi cổ quái dẫn dụ yêu thú biển trong phạm vi nhất định; tuổi cây càng lâu thì phạm vi ảnh hưởng và sức hấp dẫn đối với yêu thú cao cấp càng lớn. Nếu bị di chuyển trước khi đủ trăm năm, cây sẽ mất kỳ hiệu phát mùi. Hàn Lập đặt gốc Nghê Thường Thảo trăm năm tuổi lên rạn san hô trung tâm Hồng Hô đảo, tích lục dịch tiểu bình vào, chỉ một đến bốn ngày cây đã giăng lá và phát tán mùi, phá hoàn toàn giới hạn chu kỳ trăm năm (@c0395). Sau đó Hà","nguon":["@c0395","@c0397","@c0414"],"phanLoaiPhu":"linh thảo","hinhDang":"Thân dài một tấc, mười ba lá cuốn hình trụ, toàn thân tỏa quang hoa trắng mờ","nguonGoc":"Mọc trên rạn san hô ở Loạn Tinh Hải","dacDiem":"Thân dài một tấc, mười ba lá cuốn thành hình trụ, toàn thân tỏa quang hoa trắng mờ. Mọc trên rạn san hô, trồng đất thường sẽ héo chết. Hơn trăm năm giăng một lá trong sáu bảy ngày; di chuyển trước trăm năm sẽ mất kỳ hiệu phát mùi. Hàn Lập dùng lục dịch tiểu bình rút chu kỳ giăng lá xuống chỉ một đến","congNang":["Khi giăng lá, phát tán mùi cổ quái dẫn dụ yêu thú biển trong phạm vi nhất định (@c0395)","Tuổi càng lâu, phạm vi ảnh hưởng và sức dẫn dụ đối với yêu thú cao cấp càng lớn","Dược hiệu tầm thường, chỉ có thể làm dược dẫn cho đan dược cấp thấp","Khi được thôi thúc bằng lục dịch, phát ra khí tức cổ quái hấp dẫn yêu thú và Phệ Kim Trùng (@c0397)","Dùng làm thức ăn kích thích Phệ Kim Trùng đẻ trứng và tiến hóa (@c0397)"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0395","denChuong":"","cachCoDuoc":"Thu thập tại Loạn Tinh Hải","trangThai":"dang-co"}],"capNhatToi":"@c0395","tabs":{"tienTrinh":[{"chuong":"@c0395","loai":"xuất hiện","importance":"major","giaiDoan":"Triển khai tại Hồng Hô đảo","text":"Hàn Lập đặt gốc Nghê Thường Thảo trăm năm tuổi lên rạn san hô trung tâm Hồng Hô đảo, tích một giọt lục dịch, đến ngày thứ ba cây giăng lá phát tán mùi dẫn dụ yêu thú. Trước đó hắn đã thí nghiệm thành công tại động phủ với lục dịch tiểu bình, phá giới hạn trăm năm xuống còn 1-4 ngày.","anchor":"Đây là sát thủ lớn nhất của Hàn Lập \"Nghê Thường Thảo.\""},{"chuong":"@c0397","loai":"dùng","importance":"normal","giaiDoan":"Cho Phệ Kim Trùng ăn","text":"Hàn Lập dùng lục dịch thôi thúc Nghê Thường Thảo rồi ném vào trùng thất, ngân cầu Phệ Kim Trùng nứt ra, mấy trăm con xông tới gặm sạch. Phân phó Khúc Hồn định kỳ cho ăn tiếp.","anchor":"Nghê Thường Thảo nguyên bổn cũng không phải đối với mọi loại yêu thú đều có lực hấp dẫn"}]}},{"id":"ngu-cap-yeu-thu-dan","name":"Ngũ cấp yêu thú đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Ngũ cấp","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Viên đan lấy từ thi thể yêu thú ngũ cấp, hình cầu màu xanh biếc. Hàn Lập thu được mấy trăm khỏa sau năm năm sát yêu tại Ngoại Tinh Hải.","detail":"Viên đan nhỏ hình cầu màu xanh biếc được lấy từ thi thể yêu thú ngũ cấp. Sau năm năm săn yêu thú trong Ngoại Tinh Hải, Hàn Lập thu được mấy trăm khỏa, là thu hoạch chính của chiến dịch sát yêu.","congNang":["Nguyên liệu/vật trao đổi quý giá từ yêu thú ngũ cấp"],"nguon":["@c0396"],"tabs":{"tienTrinh":[{"chuong":"@c0396","loai":"xuất hiện","importance":"normal","giaiDoan":"Thu hoạch sát yêu","text":"Hàn Lập thu viên đan đầu tiên từ thi thể Thiên Mục Yêu, sau năm năm thu tổng cộng mấy trăm khỏa.","anchor":"Trừ mấy trăm khỏa ngũ cấp yêu thú đan ra, Hàn Lập còn thu được rất nhiều tài liệu có giá trị"}]}},{"id":"thien-muc-yeu","name":"Thiên Mục Yêu","cn":"","category":"khac","categoryLabel":"Yêu thú","phamCap":"Ngũ cấp","soHuu":[],"trangThai":"bi-tieu-diet","blurb":"Yêu thú ngũ cấp hình nhím biển khổng lồ, thân tròn đầy gai nhọn đỏ, có mấy chục con ngươi màu xanh bắn xích mang. Bị Hàn Lập và Khúc Hồn tiêu diệt tại Hồng Hô đảo.","detail":"Yêu thú ngũ cấp hình nhím biển khổng lồ, thân tròn đầy gai nhọn đỏ, có mấy chục con ngươi màu xanh có thể bắn xích mang. Phòng thủ bằng cách cuộn thành khối cầu gai, chuyển xích mang thành lục mang ngưng tụ màn hào quang. Có thể hợp mấy chục đạo xích mang thành cột sáng đỏ để chống đỡ. Bị Hàn Lập phối hợp Khúc Hồn (Hỗn Nguyên Bát) và hơn trăm Khôi Lỗi thú song trọng công kích phá vỡ phòng thủ, bị Hồng tuyến độn quang châm kết liễu.","nguon":["@c0396"]},{"id":"ke-quan-giao","name":"Kê Quan Giao","cn":"","category":"khac","categoryLabel":"Yêu thú","phamCap":"Lục cấp","soHuu":[],"trangThai":"con-song","blurb":"Yêu thú lục cấp hiếm thấy, bị Nghê Thường Thảo (400 năm tuổi) thu hút đến Hồng Hô đảo. Lưỡng lự rồi bỏ đi khi Hàn Lập phong ấn khí tức linh thảo.","detail":"Yêu thú lục cấp hiếm thấy xuất hiện khi Nghê Thường Thảo đạt bốn trăm năm tuổi, bị mùi thơm thu hút đến Hồng Hô đảo. Hàn Lập hoảng sợ vội dùng trận pháp cấm chế khí tức, con yêu thú lưỡng lự rồi rời đi. Sự kiện này khiến Hàn Lập rút bài học chỉ nên thôi thúc Nghê Thường Thảo đến ba trăm năm tuổi.","nguon":["@c0396"]},{"id":"huyet-ngoc-tri-thu","name":"Huyết Ngọc Tri Thù","cn":"血玉蜘蛛","category":"khac","categoryLabel":"Yêu thú","phamCap":"Cấp bốn đỉnh phong","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hai con yêu thú của Hàn Lập, nhờ ăn Tự Linh Hoàn nhiều năm đã thăng lên cấp bốn đỉnh phong, toàn thân trong suốt như ngọc.","detail":"Hai con Huyết ngọc tri thù nhờ ăn Tự Linh Hoàn (luyện từ lục dịch) suốt mấy chục năm đã thăng lên yêu thú cấp bốn đỉnh phong. Toàn thân trong suốt như ngọc, giống hệt con Bạch ngọc tri thù Hàn Lập từng thấy trong động quật dưới đất trước kia. Tâm ý tương thông với Hàn Lập, vui mừng đảo quanh thân hắn. Được thu vào túi linh thú.","congNang":["Yêu thú chiến đấu, tâm ý tương thông với chủ nhân","Liên quan kế hoạch đối phó/thu thập Cực Âm lão tổ (chưa rõ cơ chế cụ thể)"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0398","denChuong":"","cachCoDuoc":"Nuôi dưỡng bằng Tự Linh Hoàn nhiều năm","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0398","loai":"nang-cap","importance":"normal","giaiDoan":"Thăng cấp bốn đỉnh phong","text":"Hai con Huyết ngọc tri thù nhờ ăn Tự Linh Hoàn nhiều năm đã thăng lên cấp bốn đỉnh phong, toàn thân trong suốt như ngọc, được Hàn Lập thu vào túi linh thú.","anchor":"hai con Huyết ngọc tri thù sớm đã thăng lên vài cấp, hôm nay đã là yêu thú cấp bốn đỉnh phong"},{"chuong":"@c0471","loai":"nhắc tới","importance":"normal","giaiDoan":"Huyền Cốt yêu cầu Hàn Lập chuẩn bị sử dụng","text":"Huyền Cốt truyền âm cho Hàn Lập, nói cần dùng Huyết Ngọc Tri Thù sau khi đoạt bảo trong Nội điện mới có cơ hội thu thập Cực Âm.","anchor":"Bất quá việc này phải nhờ ngươi sử dụng Huyết ngọc tri thù sau khi lấy được bảo vật mới có cơ hội"}]},"capNhatToi":"@c0398","nguon":["@c0398","@c0471"]},{"id":"khoi-loi-tam-cap","name":"Khôi Lỗi tam cấp","cn":"傀儡三级","category":"khac","categoryLabel":"Cơ giới / Khôi Lỗi","soHuu":["Hàn Lập"],"trangThai":"Đang chế tạo","blurb":"Khôi Lỗi cấp 3, một kích toàn lực tương đương Trúc Cơ trung kỳ tu sĩ. Hàn Lập chọn gỗ làm chất liệu chủ yếu, dùng bình nhỏ lục dịch thôi sanh giảm chi phí, nhưng nguyên liệu phụ trợ vô cùng tốn kém.","detail":"Tam cấp Khôi Lỗi theo Khôi Lỗi chân kinh, một kích toàn lực tương đương Trúc Cơ trung kỳ tu sĩ. Chất liệu chính bằng gỗ (có thể dùng bình nhỏ lục dịch thôi sanh giảm chi phí). Nguyên liệu phụ trợ thăng giai và số lượng lớn khiến tiêu hao linh thạch kinh người, Hàn Lập gần như tay trắng.","congNang":["Một kích toàn lực tương đương Trúc Cơ trung kỳ tu sĩ"],"dacDiem":"Viên hình, chất liệu gỗ, cần thiết mộc đặc biệt + Thiên tinh mộc","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0399","denChuong":"","cachCoDuoc":"Tự chế tạo","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0399","loai":"xuat-hien","importance":"normal","giaiDoan":"Đang chế tạo","text":"Hàn Lập chế tạo Khôi Lỗi tam cấp chất liệu gỗ, tốn linh thạch kinh người khiến gần tay trắng, phải bán tài liệu yêu thú cấp năm giải quẫn.","anchor":"Tam cấp khôi lỗi dựa theo lời Khôi Lỗi chân kinh thì một kích toàn lực của nó tương đương so với Trúc cơ trung kỳ tu sĩ"}]},"capNhatToi":"@c0399","nguon":["@c0399"]},{"id":"tai-lieu-yeu-thu","name":"Tài liệu yêu thú","category":"khac","categoryLabel":"Vật phẩm","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lượng lớn tài liệu liên quan đến yêu thú mà Hàn Lập sở hữu, số lượng kinh người. Diệu Âm Môn muốn thu mua toàn bộ.","detail":"Hàn Lập trước đây bán nhỏ lẻ mỗi lần tìm thương gia nơi khác, một lần chỉ bán ra một ít để tránh lộ. Diệu Âm Môn phát động lực lượng tại Thiên Tinh thành truy ra thói quen này. Phạm Tĩnh Mai thương lượng mua toàn bộ, hai bên thỏa thuận giao dịch ngay hôm đó. Sau lưng, Phạm phu nhân bàn mưu cướp trắng không trả linh thạch.","nguon":["@c0400"],"tabs":{"tienTrinh":[{"chuong":"@c0400","loai":"xuất hiện","importance":"normal","giaiDoan":"Diệu Âm Môn đề nghị mua toàn bộ","text":"Hàn Lập thừa nhận còn số lượng kinh người tài liệu yêu thú, đồng ý bán toàn bộ cho Diệu Âm Môn. Phạm phu nhân sau lưng bàn mưu cướp trắng.","anchor":"tiền bối sẽ không phải cẩn thận như thế, chỉ tìm thương gia nơi khác mà bán, hơn nữa một lần chỉ bán ra một ít"}]}},{"id":"thien-loi-truc","name":"Thiên Lôi Trúc","cn":"天雷竹","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Tam đại thần mộc","soHuu":["Diệu Âm Môn","Uông bang chủ (đã bị cướp)"],"trangThai":"bi-cuop","blurb":"Thiên Lôi Trúc là một trong tam đại thần mộc, loại linh trúc quý hiếm bậc nhất từng bị cho là đã tuyệt diệt. Vốn là trấn phái chi bảo của một tiểu tông phái sa sút, sau được bán cho Diệu Âm Môn và bị cướp giữa đường.","detail":"Thiên Lôi Trúc được xưng là một trong tam đại thần mộc, từng bị cho là đã tuyệt diệt hoàn toàn. Nó vốn là trấn phái chi bảo của một tiểu tông phái đã sa sút, sau đó được bán cho Diệu Âm Môn. Phạm phu nhân của Diệu Âm Môn đích thân kiểm tra và xác nhận Thiên Lôi Trúc là thật. Uông bang chủ mang Thiên Lôi Trúc bên người, dự định đưa đến Thiên Tinh thành đấu giá, nhưng bị cướp giữa đường cùng lượng lớn hàng hóa. Diệu Âm Môn đã truy ra hung thủ và đang chuẩn bị mời đồng đạo đánh bắt. Hàn Lập vô cùng hưng phấn khi biết đến sự tồn tại của Thiên Lôi Trúc vì có thể dùng nó để luyện chế pháp bảo.","congNang":["Dùng để luyện chế pháp bảo @c0401","Luyện chế pháp bảo lôi hệ","Có thể nuôi dưỡng, tiếp tục sinh trưởng"],"chuSoHuu":[{"ten":"Diệu Âm Môn","tuChuong":"@c0401","denChuong":"","cachCoDuoc":"Thu thập","trangThai":"bi-cuop"},{"ten":"Tiểu tông phái (cũ)","tuChuong":"@c0402","denChuong":"","cachCoDuoc":"Trấn phái chi bảo","trangThai":"da-ban"},{"ten":"Uông bang chủ","tuChuong":"@c0402","denChuong":"@c0402","cachCoDuoc":"Mua từ tiểu tông phái","trangThai":"bi-cuop"}],"tabs":{"tienTrinh":[{"chuong":"@c0401","loai":"xuất hiện","importance":"major","giaiDoan":"Tiết lộ sự tồn tại","phamCap":"Tam đại thần mộc","text":"Phạm phu nhân tiết lộ Thiên Lôi Trúc — một trong tam đại thần mộc vốn tưởng đã tuyệt diệt — thực sự tồn tại và từng được Diệu Âm Môn sở hữu, nhưng bị cướp giữa đường đến Thiên Tinh thành đấu giá.","anchor":"Được xưng là một trong tam đại thần mộc – Thiên lôi trúc"},{"chuong":"@c0402","loai":"xuất hiện","importance":"major","giaiDoan":"Bị cướp cùng hàng hóa Diệu Âm môn","text":"Được tiết lộ là trấn phái chi bảo tiểu tông phái sa sút, bán cho Diệu Âm môn. Uông bang chủ mang bên người bị nhóm tu sĩ bịt mặt cướp mất. Phạm phu nhân đề nghị làm thù lao thuê Hàn Lập đoạt lại.","anchor":"Thanh Thiên lôi trúc này được tiểu môn phái đó tỉ mỉ giữ gìn hơn một nghìn năm, cho dù nhổ cả rễ ra thì tiếp tục nuôi dưỡng cũng không thành vấn đề"}]},"nguon":["@c0401","@c0402"],"dacDiem":"Một trong tam đại thần mộc, loại linh trúc quý hiếm vốn bị cho là đã tuyệt diệt; từng là trấn phái chi bảo của một tiểu tông phái sa sút @c0402."},{"id":"ngan-luan-phap-khi","name":"Ngân luân pháp khí","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Pháp khí","soHuu":["Phạm Tĩnh Mai"],"trangThai":"dang-co","blurb":"Pháp khí hình bánh xe màu bạc của Phạm phu nhân, dùng dẫn đầu công kích nhóm tà tu trên tiểu đảo.","detail":"Phạm phu nhân hô lớn rồi dẫn đầu phóng ra Ngân luân pháp khí tấn công nhóm tà tu Ẩn Sát Môn.","congNang":["Công kích"],"nguon":["@c0404"]},{"id":"hu-thien-tan-do","name":"Hư Thiên tàn đồ","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"","soHuu":["Môn chủ Ẩn Sát Môn"],"trangThai":"dang-co","blurb":"Hư Thiên tàn đồ là bản đồ tàn khuyết bị chia thành nhiều phần, đóng vai trò chìa khóa dẫn tới Hư Thiên Điện — bí cảnh xuất hiện mỗi ba trăm năm. Một phần tàn đồ do người trung niên Ẩn Sát Môn (cựu đệ tử Cực Âm lão tổ) mang theo khi bỏ trốn, và Cực Âm lão tổ dùng Ô Sửu làm bình phong để dẫn dụ nhằm đoạt lại.","detail":"Hư Thiên tàn đồ là một bản đồ không còn nguyên vẹn, bị chia thành nhiều phần lưu lạc. Tàn đồ có liên hệ trực tiếp với Hư Thiên Điện, một bí cảnh theo chu kỳ ba trăm năm mới xuất hiện một lần và thời hạn xuất hiện sắp đến. Trong số các phần tàn đồ đã biết, một phần nằm trong tay người trung niên thuộc Ẩn Sát Môn — vốn là cựu đệ tử của Cực Âm lão tổ, đã mang theo tàn đồ khi rời khỏi sư môn. Cực Âm lão tổ vì muốn thu hồi phần tàn đồ này nên đã sắp đặt Ô Sửu đóng vai bình phong, dẫn dụ người trung niên lộ diện và giao đồ (@c0405).","dacDiem":"Tàn đồ bị chia thành nhiều phần, lưu lạc ở các nơi khác nhau; cần gom đủ mới phát huy tác dụng.","congNang":["Liên quan trực tiếp đến Hư Thiên Điện — bí cảnh xuất hiện mỗi ba trăm năm; tàn đồ đóng vai trò bản đồ hoặc chìa khóa dẫn tới bí cảnh đó (@c0405)"],"chuSoHuu":[{"ten":"Môn chủ Ẩn Sát Môn","tuChuong":"@c0405","denChuong":"","cachCoDuoc":"Mang theo khi bỏ trốn khỏi Cực Âm lão tổ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0405","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện trong cuộc đối đầu ba phe","text":"Ô Sửu dẫn dụ người trung niên Ẩn Sát Môn giao Hư Thiên tàn đồ, nói thời gian ba trăm năm Hư Thiên Điện xuất hiện sắp đến. Người trung niên từ chối vì biết giao xong tất bị giết.","anchor":"Năm đó một vài phần của Hư Thiên tàn đồ bị sư thúc mang theo, chẳng biết hôm nay có ở trên người hay không"}]},"nguon":["@c0405"]},{"id":"cam-than-bai","name":"Cấm Thần bài","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Cực Âm tổ sư"],"trangThai":"dang-dung","blurb":"Mộc bài đen kịt do Cực Âm tổ sư sử dụng phối hợp Cấm Thần thuật, dùng để thu nhận và cấm chế nguyên thần của tu sĩ, từ đó khống chế hoàn toàn sinh tử đối phương.","detail":"Cấm Thần bài xuất hiện khi Cực Âm tổ sư lấy tấm mộc bài đen kịt từ trong áo ra, uy hiếp toàn bộ tu sĩ có mặt, yêu cầu mỗi người giao ba phần nguyên thần lên bài để quy thuận (@c0406). Pháp bảo này hoạt động như một công cụ cấm chế tuyệt đối: một khi nguyên thần đã bị thu vào bài, nạn nhân hoàn toàn nằm trong tay người nắm giữ bài. Đối phương có thể tùy ý hủy thần thức bên trong, khiến nạn nhân trở nên ngu ngốc điên tàng hoặc chết tại chỗ, qua đó biến Cấm Thần bài thành phương tiện khống chế sinh tử cực kỳ tàn khốc.","congNang":["Thu nhận và chứa nguyên thần của tu sĩ khác vào trong bài, phối hợp Cấm Thần thuật để cấm chế (@c0406)","Hủy thần thức đã bị thu trong bài, khiến nạn nhân ngu ngốc điên tàng hoặc chết tại chỗ (@c0406)"],"hinhDang":"Mộc bài đen kịt","chuSoHuu":[{"ten":"Cực Âm tổ sư","tuChuong":"@c0406","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0406","loai":"xuat-hien","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Cực Âm tổ sư lấy Cấm Thần bài ra uy hiếp toàn bộ tu sĩ, yêu cầu mỗi người giao ba phần nguyên thần để quy thuận Cực Âm đảo.","anchor":"lấy ra một cái mộc bài đen kịt, lạnh lùng nhìn mọi người"}]},"capNhatToi":"@c0406","nguon":["@c0406"],"dacDiem":"Mộc bài đen kịt, được mang trong người, dùng để ép buộc tu sĩ quy thuận bằng cách thu giữ nguyên thần làm con tin."},{"id":"phi-dao-tu-si-mui-ung","name":"Phi đao pháp bảo (tu sĩ mũi ưng)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tu sĩ mũi ưng"],"trangThai":"mat","blurb":"Phi đao pháp bảo của tu sĩ mũi ưng, vật duy nhất còn sót lại sau khi chủ nhân bị Thiên đô thi hỏa thiêu thành tro.","detail":"Sau khi tu sĩ mũi ưng bị hắc diễm Thiên đô thi hỏa thiêu sát, chỉ còn lại kiện phi đao pháp bảo này rơi tại hiện trường.","nguon":["@c0406"]},{"id":"han-le-chau","name":"Hàn Lê châu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo cực âm chí hàn","soHuu":["Trung niên nhân (đầu lĩnh Ẩn Sát môn)","Cực Âm tổ sư"],"trangThai":"bi-cuop","blurb":"Hàn Lê châu là viên châu trắng trong suốt toả hàn khí, được luyện từ huyền tinh đáy biển sâu, thuộc loại pháp bảo cực âm chí hàn. Có thể biến hình thành bạch xà to bằng miệng bát phun hàn vụ tiêu diệt tà khí. Bị Cực Âm lão tổ cướp đoạt từ tay trung niên nhân tại mốc @c0407.","detail":"Hàn Lê châu được luyện từ huyền tinh đáy biển sâu, là loại pháp bảo cực âm chí hàn. Khi kích hoạt, chủ nhân lấy viên châu từ giữa trán, phun huyết vụ lên để kích hoạt; viên châu liền biến thành bạch xà trắng to bằng miệng bát, có khả năng phun hàn vụ nuốt hết yêu thú hắc khí. Tại @c0407, trung niên nhân sử dụng Hàn Lê châu biến bạch xà tấn công Cực Âm lão tổ, song Cực Âm lão tổ dùng bàn tay hắc khí khổng lồ chộp bạch xà, ép hồi phục bản thể rồi thu vào người, cướp đoạt pháp bảo. Hàn Lê châu có đặc tính khắc chế Thiên đô thi hoả nhờ bản chất cực âm chí hàn.","hinhDang":"Viên châu trắng trong suốt","vatLieu":"Huyền tinh đáy biển sâu","congNang":["Biến hình thành bạch xà trắng to bằng miệng bát khi được huyết vụ kích hoạt @c0407","Phun hàn vụ tiêu diệt tà khí và nuốt hết yêu thú hắc khí @c0407","Khắc chế Thiên đô thi hoả nhờ bản chất cực âm chí hàn"],"chuSoHuu":[{"ten":"Trung niên nhân (đầu lĩnh Ẩn Sát môn)","tuChuong":"@c0407","denChuong":"@c0407","cachCoDuoc":"Xuất từ giữa trán","trangThai":"mat"},{"ten":"Cực Âm tổ sư","tuChuong":"@c0407","denChuong":"","cachCoDuoc":"Cướp đoạt bằng bàn tay hắc khí","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0407","loai":"đổi chủ","importance":"major","giaiDoan":"Bị Cực Âm lão tổ cướp","text":"Trung niên nhân kích hoạt Hàn Lê châu biến bạch xà tấn công Cực Âm lão tổ. Cực Âm lão tổ dùng bàn tay hắc khí khổng lồ chộp bạch xà, ép hồi phục bản thể rồi thu vào người.","anchor":"bàn tay lộn một cái, hạt châu biến mất vô ảnh vô tung"}]},"nguon":["@c0407"],"uyLuc":"Bạch xà phun hàn vụ nuốt sạch toàn bộ yêu thú hắc khí của Cực Âm lão tổ @c0407","dacDiem":"Viên châu trắng trong suốt toả hàn khí, luyện từ huyền tinh đáy biển sâu, thuộc loại pháp bảo cực âm chí hàn; được cất giữ giữa trán chủ nhân, cần phun huyết vụ để kích hoạt biến hình."},{"id":"phap-khi-bia-da-ba-mau","name":"Pháp khí bia đá ba màu","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí hợp nhất","soHuu":["Uông Ngưng","Phạm Tĩnh Mai","Trác Như Đình"],"trangThai":"dang-co","blurb":"Ba nữ tu sĩ hợp ba pháp khí riêng thành một kiện hình bia đá, phi hành với tốc độ ngang tu sĩ Kết Đan kỳ.","detail":"Tử Linh tiên tử, Phạm phu nhân và Trác Như Đình thi triển bí thuật đặc thù khu hợp pháp khí ba người thành một kiện pháp khí giống bia đá, biến đạo ánh sáng ba màu phi hành bỏ chạy với tốc độ ngang Kết Đan kỳ.","congNang":["Phi hành tốc độ cao ngang Kết Đan kỳ khi ba người hợp lực"],"tabs":{"tienTrinh":[{"chuong":"@c0407","loai":"xuất hiện","importance":"normal","giaiDoan":"Ba nữ tu hợp pháp khí bỏ chạy","text":"Ba nữ tu sĩ hợp ba pháp khí thành một kiện hình bia đá ba màu phi hành bỏ chạy, tốc độ ngang Kết Đan kỳ.","anchor":"ba nữ tu sĩ không biết thi triển loại phát thuật bí thuật gì mà pháp khí ba người khu hợp thành một kiện pháp khí giống như bia đá"}]},"nguon":["@c0407"]},{"id":"thanh-sac-cu-hau","name":"Thanh sắc cự hầu","cn":"","category":"khac","categoryLabel":"Khôi lỗi / Linh thú","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hơn trăm con khỉ lớn màu xanh cao hai trượng, miệng rộng răng to, có thể bắn mười đạo thanh quang từ mười ngón tay tấn công đối thủ.","detail":"Hàn Lập triệu hơn trăm thanh sắc cự hầu để tấn công yêu thi. Các cự hầu thân cao hai trượng, miệng rộng răng to, khi xuất hiện liền nhấc hai tay bắn mười đạo thanh quang từ mười ngón tay. Tuy nhiên bị yêu thi xông lên chém thành nhiều khúc.","congNang":["Bắn mười đạo thanh quang từ mười ngón tay"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0408","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0408","loai":"dùng","importance":"normal","giaiDoan":"Chiến đấu với yêu thi","text":"Hàn Lập triệu hơn trăm thanh sắc cự hầu tấn công yêu thi, bắn thanh quang từ ngón tay nhưng bị yêu thi chém thành nhiều khúc.","anchor":"Các cự viên này thân cao hai trượng, miệng rộng răng to, khi vừa xuất hiện liền nhấc hai tay"}]},"nguon":["@c0408"]},{"id":"moc-long-bi","name":"Mộc Long Bi","cn":"木龙壁","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Trấn phái chi bảo","soHuu":["Diệu Âm Môn"],"trangThai":"dang-co","blurb":"Trấn phái chi bảo của Diệu Âm Môn, có khả năng hộ thể chống công kích mạnh.","detail":"Ba nữ tu Diệu Âm Môn nhờ Mộc Long Bi hộ thể mà tránh được công kích của Thập Bát Thiên Đô Thi, thoát chết. Là bảo vật trấn phái, Tử Linh tiên tử mang theo người khi hành động.","congNang":["Hộ thể, chống được công kích mạnh cấp Thập Bát Thiên Đô Thi"],"chuSoHuu":[{"ten":"Uông Ngưng","tuChuong":"@c0409","denChuong":"","cachCoDuoc":"Trấn phái chi bảo Diệu Âm Môn mang theo","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0409","loai":"dùng","importance":"normal","giaiDoan":"Dùng hộ thể thoát Thiên Đô Thi","text":"Ba nữ tu Diệu Âm Môn dùng Mộc Long Bi hộ thể, tránh được công kích của Thập Bát Thiên Đô Thi, nhờ đó thoát chết.","anchor":"Tử Linh tiên tử kia có Mộc Long Bi, trấn phái chi bảo của Diệu Âm Môn trên người"}]},"nguon":["@c0409"]},{"id":"thien-loi-truc-doan-hai","name":"Thiên Lôi Trúc (đoạn thứ hai)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Đỉnh giai tam đại thần mộc","soHuu":["Hàn Lập"],"trangThai":"đổi chủ","blurb":"Thiên Lôi Trúc (đoạn thứ hai) là một trong hai đoạn Thiên Lôi Trúc mà Diệu Âm Môn có được, do Tử Linh tiên tử trao cho Hàn Lập làm điều kiện đổi lấy việc hắn nhận chức trưởng lão danh nghĩa của môn phái. Đây là tài liệu luyện chế pháp bảo Mộc thuộc tính đỉnh giai, thuộc hàng tam đại thần mộc, vô giá đối với tu sĩ Mộc thuộc tính.","detail":"Diệu Âm Môn ban đầu lấy được hai đoạn Thiên Lôi Trúc từ truyền nhân của một môn phái nhỏ. Nghê Thường chỉ mang một đoạn đi bán, đoạn còn lại lưu ở chỗ Tử Linh tiên tử. Thiên Lôi Trúc là tài liệu đỉnh giai thuộc hàng tam đại thần mộc, có giá trị cực lớn với tu sĩ Mộc thuộc tính nhưng gần như vô dụng với người không tu luyện thuộc tính này. Đoạn thứ hai này được bảo quản trong hộp cao ngọc và được Tử Linh dùng làm điều kiện giao dịch cốt lõi để mời Hàn Lập nhận chức trưởng lão danh nghĩa cho Diệu Âm Môn (@c0410).","congNang":["Tài liệu luyện chế pháp bảo Mộc thuộc tính đỉnh giai, thuộc hàng tam đại thần mộc (@c0410)"],"chuSoHuu":[{"ten":"Diệu Âm Môn","tuChuong":"@c0410","denChuong":"@c0410","cachCoDuoc":"Lấy được từ truyền nhân môn phái nhỏ","trangThai":"đã trao"},{"ten":"Hàn Lập","tuChuong":"@c0410","denChuong":"","cachCoDuoc":"Giao dịch với Tử Linh tiên tử, đổi lấy làm trưởng lão danh nghĩa","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0410","loai":"đổi chủ","importance":"major","giaiDoan":"Tử Linh trao cho Hàn Lập","text":"Tử Linh tiết lộ Diệu Âm Môn có hai đoạn Thiên Lôi Trúc, dùng đoạn này làm điều kiện mời Hàn Lập làm trưởng lão danh nghĩa. Mở hộp cao ngọc trao cho Hàn Lập.","anchor":"Tài liệu đỉnh giai tam đại thần mộc này làm gì có giá mà nói"}]},"nguon":["@c0410"]},{"id":"hop-cao-ngoc","name":"Hộp cao ngọc","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Tử Linh tiên tử"],"trangThai":"","blurb":"Hộp làm bằng cao ngọc, bán trong suốt, không thuộc ngũ hành, dùng bảo tồn Thiên Lôi Trúc lâu dài không để linh khí tiết ra.","detail":"Hộp chế tạo từ cao ngọc — vật liệu không phải gỗ hay ngọc thạch, toàn thân bán trong suốt, có thanh quang nhàn nhạt, không liệt vào nhóm ngũ hành. Công năng chính là bảo tồn Thiên Lôi Trúc lâu dài, ngăn linh khí tiết lộ ra ngoài. Tử Linh dùng lục quang phá tầng thanh quang phong ấn trên nắp để mở hộp.","congNang":["Bảo tồn Thiên Lôi Trúc, ngăn linh khí tiết lộ ra ngoài"],"tabs":{"tienTrinh":[{"chuong":"@c0410","loai":"xuất hiện","importance":"normal","giaiDoan":"Tử Linh mở hộp trao Thiên Lôi Trúc","text":"Tử Linh lấy ra hộp cao ngọc bán trong suốt, dùng lục quang phá phong ấn thanh quang trên nắp để mở, lộ Thiên Lôi Trúc bên trong.","anchor":"Chiếc hộp này sử dụng một loại gọi là cao ngọc chế tạo thành"}]},"nguon":["@c0410"]},{"id":"thien-loi-truc-kim","name":"Thiên Lôi Trúc","cn":"天雷竹","aliases":["Bạch Lôi Trúc","Kim Lôi Trúc"],"category":"nguyen-lieu","categoryLabel":"Linh vật / Nguyên liệu","phamCap":"Kim Lôi Trúc vạn năm (cấp cao nhất)","soHuu":["Hàn Lập"],"trangThai":"đang bồi dưỡng","blurb":"Thiên Lôi Trúc là một trong tam đại thần trúc của tu tiên giới. Ban đầu là Bạch Lôi Trúc mấy ngàn năm được Tử Linh tiên tử trao cho Hàn Lập, sau đó được bồi dưỡng bằng lục dịch từ bình thần bí, phát triển thành Kim Lôi Trúc vạn năm có thể phóng lôi điện vàng uy lực khủng khiếp, khắc chế tà pháp ma công.","detail":"Thiên Lôi Trúc phân cấp theo niên hạn: dưới hai ngàn năm là Bạch Lôi Trúc phóng lôi điện trắng, trên năm ngàn năm phóng lôi điện lam, ngoài vạn năm là Kim Lôi Trúc phóng lôi điện kim nhạt với uy lực khủng khiếp. Kim Lôi Trúc từng xuất hiện một lần ở Loạn Tinh Hải, gây ra tranh đoạt huyết vũ tinh phong kéo dài hơn mười năm rồi biến mất bí ẩn. Hàn Lập nhận Bạch Lôi Trúc từ Tử Linh tiên tử, khi đó dài hai tấc, nhỏ cỡ ngón tay. Tử Linh tiên tử chứng minh đặc tính của trúc bằng cách dùng chủy thủ chém vào khiến lôi điện phóng ra tự vệ (@c0411). Sau đó Hàn Lập dùng lục dịch từ bình thần bí tưới cho trúc mọc lên một thước, thân xanh biếc có hào quang, phóng lôi điện vàng phá hủy pháp khí tiểu kiếm, xác nhận đã đạt cấp Kim Lôi Trúc. Thiên Lôi Trúc là nguyên liệu chính để luyện bộ pháp bảo Thanh Tr","congNang":["Phóng lôi điện tự vệ khi bị tác động bên ngoài @c0411","Khắc chế tà pháp ma công, lôi điện của trúc được xưng là Ích Tà Chi Lôi @c0411","Nguyên liệu chính luyện chế bộ pháp bảo Thanh Trúc Phong Vân Kiếm @c0411"],"dacDiem":"Một trong tam đại thần trúc của tu tiên giới. Niên hạn càng cao, lôi điện càng mạnh: trắng→lam→kim.","chuSoHuu":[{"ten":"Tử Linh tiên tử (Diệu Âm Môn)","tuChuong":"@c0410","denChuong":"@c0411","cachCoDuoc":"sở hữu trước đó","trangThai":"đã tặng"},{"ten":"Hàn Lập","tuChuong":"@c0411","denChuong":"","cachCoDuoc":"được Tử Linh tiên tử tặng trong giao dịch","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0411","loai":"đổi chủ","importance":"major","giaiDoan":"Trao cho Hàn Lập và tiến hóa thành Kim Lôi Trúc","text":"Tử Linh tiên tử trao Bạch Lôi Trúc mấy ngàn năm cho Hàn Lập, chứng minh bằng cách dùng chủy thủ chém khiến lôi điện bật ra. Hàn Lập dùng lục dịch từ bình thần bí bồi dưỡng, trúc mọc từ hai tấc lên một thước, biến thành Kim Lôi Trúc vạn năm phóng lôi điện vàng phá hủy pháp khí.","anchor":"Thiên Lôi Trúc mặc dù được xưng là một trong tam đại thần trúc của Tu tiên giới nhưng trên thực tế có thể dùng vật ấy thật sự đã ít lại càng ít"}]},"capNhatToi":"@c0411","nguon":["@c0411"],"uyLuc":"Ở cấp Kim Lôi Trúc vạn năm, lôi điện vàng phóng ra có thể phá hủy pháp khí tiểu kiếm."},{"id":"lenh-bai-truong-lao-dieu-am-mon","name":"Lệnh bài trưởng lão Diệu Âm Môn","category":"khac","categoryLabel":"Tín vật","soHuu":["Hàn Lập"],"trangThai":"đang sở hữu","blurb":"Lệnh bài do Tử Linh tiên tử cấp cho Hàn Lập, xác nhận thân phận trưởng lão khách khanh Diệu Âm Môn.","detail":"Tử Linh tiên tử trao lệnh bài cho Hàn Lập kèm theo Thiên Lôi Trúc. Mang lệnh bài này, khi Diệu Âm Môn gặp đại địch, Hàn Lập khó từ chối viện trợ.","nguon":["@c0411"]},{"id":"au-truc-thien-loi-truc","name":"Ấu trúc Thiên Lôi Trúc","cn":"","category":"nguyen-lieu","categoryLabel":"Linh thực / Nguyên liệu","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"đang nuôi trồng","blurb":"Mầm trúc mới mọc bên cạnh cây Thiên Lôi Trúc vạn năm nhờ lục dịch kích thích, là giải pháp nhân giống nguyên liệu luyện chế Thanh Trúc Phong Vân Kiếm.","detail":"Mầm trúc sinh ra bên cạnh cây mẹ Thiên Lôi Trúc vạn năm khi được tưới lục dịch. Vài tháng dài khoảng năm phân, hình dáng giống hệt cây mẹ ban đầu. Giải quyết hoàn toàn vấn đề thiếu nguyên liệu chính, Hàn Lập có thể nhân giống liên tục để đạt đủ 6-7 cây bắt đầu luyện chế.","congNang":["Nguyên liệu chính luyện chế Thanh Trúc Phong Vân Kiếm","Sinh sản vô tính từ cây mẹ qua lục dịch"],"nguon":["@c0412"],"tabs":{"tienTrinh":[{"chuong":"@c0412","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện ấu trúc mọc bên cạnh cây mẹ","text":"Ấu trúc xuất hiện bên cạnh cây Thiên Lôi Trúc vạn năm nhờ lục dịch, vài tháng đạt 5 phân, giải quyết vấn đề thiếu nguyên liệu.","anchor":"ở bên cạnh xuất hiện thêm một mầm trúc nhỏ"}]}},{"id":"la-vang-ong-thien-loi-truc","name":"Lá vàng óng Thiên Lôi Trúc","cn":"","category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lá cây Thiên Lôi Trúc vạn năm rụng xuống đất hóa thành lá vàng óng đẹp đẽ, chưa rõ tác dụng.","detail":"Khi cây Thiên Lôi Trúc vạn năm rụng hết cành lá, lá chạm đất lập tức hóa thành lá vàng óng cực kỳ đẹp đẽ. Hàn Lập không biết tác dụng nhưng thu hết vào túi trữ vật, không dễ dàng bỏ đi.","nguon":["@c0412"],"tabs":{"tienTrinh":[{"chuong":"@c0412","loai":"xuất hiện","importance":"bridge","giaiDoan":"Lá rụng hóa vàng","text":"Lá Thiên Lôi Trúc vạn năm rụng chạm đất hóa vàng óng, Hàn Lập thu giữ dù chưa rõ tác dụng.","anchor":"Ngay khi chạm vào mặt đất lập tức hóa thành những lá cây màu vàng óng cực kỳ đẹp đẽ"}]}},{"id":"tran-chau-ban-do","name":"Trân châu bản đồ","category":"khac","categoryLabel":"Cổ vật","phamCap":"Không rõ","soHuu":["Kim Thanh","Bằng hữu Kim Thanh"],"trangThai":"đang sử dụng","blurb":"Hai viên trân châu trắng cỡ ngón cái, rót linh lực vào phát bạch quang hiện bản đồ cổ dẫn đến cổ tu sĩ di chỉ. Hai viên hợp thành mới có bản đồ hoàn chỉnh.","detail":"Được Kim Thanh cùng bằng hữu phát hiện trong tiểu điếm, đính trên vòng cổ lẫn với trân châu thường — phương pháp bảo tồn cổ xưa. Mỗi người giữ một viên. Tốn năm sáu năm mới tìm ra địa điểm trên bản đồ, nghi là cổ tu sĩ di chỉ nhưng bị đại trận bao phủ.","congNang":["Lưu trữ bản đồ cổ xưa, kích hoạt bằng linh lực, hai viên hợp thành bản đồ hoàn chỉnh"],"chuSoHuu":[{"ten":"Kim Thanh","tuChuong":"@c0415","denChuong":"","cachCoDuoc":"Phát hiện trong tiểu điếm","trangThai":"đang giữ một viên"},{"ten":"Bằng hữu Kim Thanh","tuChuong":"@c0415","denChuong":"","cachCoDuoc":"Cùng phát hiện","trangThai":"đang giữ viên còn lại"}],"tabs":{"tienTrinh":[{"chuong":"@c0415","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện","text":"Kim Thanh đưa cho Hàn Lập xem viên trân châu, rót linh lực vào hiện bản đồ cổ. Giải thích hai viên do mình cùng bằng hữu phát hiện trong tiểu điếm, tốn năm sáu năm tìm ra cổ tu sĩ di chỉ nhưng bị đại trận chặn.","anchor":"Trân châu tổng cộng có hai viên, hợp thành sẽ tạo nên một bộ bản đồ hoàn chỉnh"}]},"nguon":["@c0415"]},{"id":"ban-do-co-di-chi","name":"Bản đồ cổ","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Kim Thanh","Hồ Nguyệt"],"trangThai":"dang-co","blurb":"Bản đồ cổ mà Kim Thanh và Hồ Nguyệt phát hiện, chỉ dẫn vị trí hòn đảo hoang có di chỉ cổ tu sĩ trên Loạn Tinh Hải.","detail":"Kim Thanh và Hồ Nguyệt cùng phát hiện bản đồ cổ này cùng hai viên trân châu. Dựa vào bản đồ, họ tìm ra đảo hoang có tòa núi đất cao ngàn trượng bị đại trận phong ấn bao phủ, nghi là di chỉ cổ tu sĩ.","congNang":["Chỉ dẫn vị trí di chỉ cổ tu sĩ trên đảo hoang Loạn Tinh Hải"],"tabs":{"tienTrinh":[{"chuong":"@c0416","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhắc đến nguồn gốc chuyến thám hiểm","text":"Kim Thanh dùng bản đồ cổ này tìm ra đảo hoang, hỏi thăm phàm nhân quanh đó xác nhận là đảo không người ở.","anchor":"Lúc trước dựa vào bản đồ cổ kia liền tìm ra đảo này"}]},"nguon":["@c0416"]},{"id":"hai-vien-tran-chau","name":"Hai viên trân châu","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Kim Thanh","Hồ Nguyệt"],"trangThai":"dang-co","blurb":"Hai viên trân châu mà Kim Thanh và Hồ Nguyệt cùng phát hiện, gắn liền với bản đồ cổ dẫn đến di chỉ cổ tu sĩ.","detail":"Được nhắc thoáng qua khi giới thiệu Hồ Nguyệt là người cùng Kim Thanh phát hiện ra chúng. Chi tiết công năng chưa rõ.","tabs":{"tienTrinh":[{"chuong":"@c0416","loai":"nhắc tới","importance":"bridge","giaiDoan":"Nhắc qua khi giới thiệu Hồ Nguyệt","text":"Hồ Nguyệt được giới thiệu là người cùng Kim Thanh phát hiện hai viên trân châu.","anchor":"vị Hồ tu sĩ này chính là người đồng loạt với hắn phát hiện ra hai viên trân châu kia"}]},"nguon":["@c0416"]},{"id":"muoi-cay-tran-ky-nhieu-mau","name":"Mười cây trận kỳ nhiều màu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Mười cây cờ trận pháp nhỏ nhiều màu sắc khác nhau, được Hàn Lập dùng để bố trí Bắc Đẩu Lưỡng Nghi Trận nhằm phá giải huyễn trận của đại trận cổ đại.","detail":"Mười cây trận kỳ được Hàn Lập lấy ra từ túi trữ vật khi đối mặt với đại trận cổ đại. Sau khi phóng ra, mười cây cờ nhỏ bay lên luân chuyển xung quanh, rồi được bố trí trên không theo thế Bắc Đẩu phía trên hoàng vụ, hình thành Bắc Đẩu Lưỡng Nghi Trận. Mười trận kỳ đồng thời phát ra mười cột sáng hợp nhất thành một cột sáng lớn xạ xuống, phá thành công tầng huyễn trận ngoài cùng của đại trận cổ đại @c0417.","congNang":["Bố trí Bắc Đẩu Lưỡng Nghi Trận trên không theo thế Bắc Đẩu, mười cây cờ phát mười cột sáng hợp nhất thành một cột sáng lớn, dùng để phá giải trận pháp đối phương @c0417"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0417","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0417","loai":"dùng","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Hàn Lập lấy mười cây trận kỳ bố trí Bắc Đẩu Lưỡng Nghi Trận trên không, phá thành công tầng huyễn trận ngoài cùng của đại trận cổ đại.","anchor":"mười cây cờ nhỏ với màu sắc khác nhau bay ra, sau đó nhẹ nhàng luân chuyển xung quanh Hàn Lập"}]},"nguon":["@c0417"],"uyLuc":"Mười cột sáng hợp nhất thành một cột lớn xạ xuống, phá thành công tầng huyễn trận ngoài cùng của đại trận cổ đại @c0417.","dacDiem":"Gồm mười cây cờ nhỏ màu sắc khác nhau, khi kích hoạt bay lên luân chuyển rồi tự sắp xếp theo thế Bắc Đẩu trên không."},{"id":"tieu-thuoc-thuy-thuoc-tinh","name":"Tiểu thước Thủy thuộc tính","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Pháp khí","soHuu":["Hàn Lập","Kim Thanh"],"trangThai":"dang-co","blurb":"Pháp khí Thủy thuộc tính, Hàn Lập giao cho Kim Thanh để đối phó yêu linh Sí Ác hỏa hệ.","detail":"Thanh tiểu thước Thủy thuộc tính, một trong ba pháp khí Hàn Lập lấy ra giao cho các thành viên trong nhóm. Được giao cho Kim Thanh dùng tương khắc yêu linh Sí Ác hỏa hệ khi phá đạo cấm chế cuối cùng của đại trận cổ.","congNang":["Tương khắc hỏa hệ yêu linh"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0418","denChuong":"@c0418","cachCoDuoc":"Sẵn có trong túi trữ vật","trangThai":"giao-di"},{"ten":"Kim Thanh","tuChuong":"@c0418","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0418","loai":"đổi chủ","importance":"bridge","giaiDoan":"Giao cho Kim Thanh","text":"Hàn Lập lấy ra giao cho Kim Thanh để đối phó Sí Ác trong cấm chế cuối.","anchor":"Hàn Lập lấy ra một thanh tiểu thước, một tiểu chùy, cùng một cái tiểu xoa"}]},"nguon":["@c0418"]},{"id":"tieu-chuy-thuy-thuoc-tinh","name":"Tiểu chùy Thủy thuộc tính","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Pháp khí","soHuu":["Hàn Lập","Khúc Hồn"],"trangThai":"dang-co","blurb":"Pháp khí Thủy thuộc tính, Hàn Lập giao cho Khúc Hồn để đối phó yêu linh Sí Ác hỏa hệ.","detail":"Tiểu chùy Thủy thuộc tính, Hàn Lập lấy ra cùng lúc với tiểu thước và tiểu xoa, giao cho Khúc Hồn dùng tương khắc Sí Ác khi phá cấm chế cuối.","congNang":["Tương khắc hỏa hệ yêu linh"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0418","denChuong":"@c0418","cachCoDuoc":"Sẵn có trong túi trữ vật","trangThai":"giao-di"},{"ten":"Khúc Hồn","tuChuong":"@c0418","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0418","loai":"đổi chủ","importance":"bridge","giaiDoan":"Giao cho Khúc Hồn","text":"Hàn Lập giao cho Khúc Hồn dùng đối phó Sí Ác trong cấm chế cuối.","anchor":"Hàn Lập lấy ra một thanh tiểu thước, một tiểu chùy, cùng một cái tiểu xoa"}]},"nguon":["@c0418"]},{"id":"tieu-xoa-thuy-thuoc-tinh","name":"Tiểu xoa Thủy thuộc tính","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Pháp khí","soHuu":["Hàn Lập","Giản huynh"],"trangThai":"dang-co","blurb":"Pháp khí Thủy thuộc tính, Hàn Lập giao cho tu sĩ họ Giản để đối phó yêu linh Sí Ác hỏa hệ.","detail":"Tiểu xoa Thủy thuộc tính, Hàn Lập lấy ra cùng lúc với tiểu thước và tiểu chùy, giao cho tu sĩ họ Giản dùng tương khắc Sí Ác khi phá cấm chế cuối.","congNang":["Tương khắc hỏa hệ yêu linh"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0418","denChuong":"@c0418","cachCoDuoc":"Sẵn có trong túi trữ vật","trangThai":"giao-di"},{"ten":"Giản huynh","tuChuong":"@c0418","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0418","loai":"đổi chủ","importance":"bridge","giaiDoan":"Giao cho tu sĩ họ Giản","text":"Hàn Lập giao cho tu sĩ họ Giản dùng đối phó Sí Ác trong cấm chế cuối.","anchor":"cùng một cái tiểu xoa cấp cho Kim Thanh, Khúc Hồn và tu sĩ họ Giản kia"}]},"nguon":["@c0418"]},{"id":"khan-lua-mau-lam","name":"Khăn lụa màu lam","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Pháp khí","soHuu":["Thạch Điệp","Hồ Nguyệt"],"trangThai":"dang-co","blurb":"Pháp khí Thủy thuộc tính, Thạch Điệp giao cho Hồ Nguyệt để hỗ trợ phá cấm chế cuối cùng của đại trận cổ.","detail":"Khăn lụa màu lam Thủy thuộc tính do Thạch Điệp lấy ra giao cho Hồ Nguyệt, dùng tương khắc yêu linh Sí Ác hỏa hệ khi phá đạo cấm chế cuối.","congNang":["Tương khắc hỏa hệ yêu linh"],"chuSoHuu":[{"ten":"Thạch Điệp","tuChuong":"@c0418","denChuong":"@c0418","cachCoDuoc":"Sẵn có","trangThai":"giao-di"},{"ten":"Hồ Nguyệt","tuChuong":"@c0418","denChuong":"","cachCoDuoc":"Nhận từ Thạch Điệp","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0418","loai":"đổi chủ","importance":"bridge","giaiDoan":"Giao cho Hồ Nguyệt","text":"Thạch Điệp lấy ra giao cho Hồ Nguyệt dùng đối phó Sí Ác.","anchor":"Thạch Điệp cũng lấy ra một chiếc khăn lụa màu lam giao cho Hồ Nguyệt"}]},"nguon":["@c0418"]},{"id":"tran-ky-tran-ban-lam-thuy","name":"Trận kỳ và trận bàn màu lam Thủy thuộc tính","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí trận pháp","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hơn mười đạo trận kỳ và trận bàn Thủy thuộc tính, Hàn Lập dùng bố trận bao quanh màn sáng đỏ để phá cấm chế cuối cùng của đại trận cổ.","detail":"Hơn mười đạo trận kỳ và trận bàn màu lam Thủy thuộc tính bay ra từ túi trữ vật của Hàn Lập. Trận kỳ cắm sâu xuống đất vài tấc, trận bàn lơ lửng cách mặt đất vài tấc, hình thành trận pháp sâm nghiêm bao quanh màn sáng đỏ chứa Sí Ác.","congNang":["Bố trận pháp Thủy thuộc tính phá cấm chế cuối cùng"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0418","denChuong":"","cachCoDuoc":"Sẵn có trong túi trữ vật","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0418","loai":"dùng","importance":"normal","giaiDoan":"Bố trận phá cấm chế cuối","text":"Hàn Lập phóng hơn mười đạo trận kỳ và trận bàn Thủy thuộc tính bao quanh màn sáng đỏ, hình thành trận pháp sâm nghiêm chuẩn bị phá đạo cấm chế cuối cùng.","anchor":"hơn mười đạo trận kỳ, trận bàn màu lam thủy thuộc tính, toàn bộ bay ra từ túi trữ vật"}]},"nguon":["@c0418"]},{"id":"gio-hoa-truc-co-bao","name":"Giỏ hoa trúc cổ bảo","cn":"","aliases":["Pháp khí giỏ hoa","Giỏ hoa"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Hồng Hoang Cổ Bảo","soHuu":["Quái nhân đảo chủ"],"trangThai":"Đang sử dụng","blurb":"Hồng Hoang Cổ Bảo dạng giỏ hoa trúc cổ đại, do cổ tu sĩ thời hồng hoang luyện chế. Không thể thu vào cơ thể như pháp bảo thông thường, phải đeo bên mình. Phóng bạch khí vây khốn và áp chế pháp bảo đối thủ, bạch khí tự phục hồi sau khi bị phá.","detail":"Giỏ hoa trúc cổ bảo là pháp bảo cổ xưa từ thời hồng hoang, do cổ tu sĩ luyện chế, mang đặc trưng tiêu biểu của Hồng Hoang Cổ Bảo: không thể thu nhập thể nội như pháp bảo hiện đại, chủ nhân phải mang bên hông như một pháp khí. Pháp bảo này rơi vào tay quái nhân đảo chủ và được hắn sử dụng trong trận chiến với nhóm Hàn Lập. Khi kích phát, giỏ hoa trúc phóng ra bạch quang hóa thành bạch khí bao trùm, vây khốn toàn bộ pháp bảo phía đối phương, khiến linh tính của các pháp bảo bị áp chế suy giảm nghiêm trọng. Dù bạch khí bị đánh tan, nó vẫn nhanh chóng tự phục hồi nguyên trạng, khiến đối thủ rất khó hóa giải triệt để.","phanLoaiPhu":"Hồng Hoang Cổ Bảo","hinhDang":"Giỏ hoa trúc cổ quái đeo bên hông","nguonGoc":"Cổ tu sĩ thời hồng hoang luyện chế","congNang":["Phóng bạch quang biến thành bạch khí vây khốn toàn bộ pháp bảo đối thủ, làm giảm mạnh linh tính của pháp bảo bị khốn @c0419","Bạch khí bị đánh tan sẽ nhanh chóng tự phục hồi nguyên trạng @c0419"],"dacDiem":"Không thể thu vào cơ thể, phải mang bên mình — đặc trưng tiêu biểu của Hồng Hoang Cổ Bảo","chuHienThoi":"Quái nhân đảo chủ","chuSoHuu":[{"ten":"Quái nhân đảo chủ","tuChuong":"@c0419","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0419","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện trong trận chiến tại hoang đảo","text":"Quái nhân đảo chủ dùng giỏ hoa trúc tấn công nhóm Hàn Lập, bạch khí vây khốn toàn bộ pháp bảo đối thủ. Tu sĩ họ Giản nhận ra đây là Hồng Hoang Cổ Bảo.","anchor":"bạch quang của chiếc giỏ trúc giữa không trung bỗng nhoáng lên, bỗng nhiên từ giữa bắn ra đạo hào quang màu trắng, lập tức đem mấy pháp bảo vây lại ở giữa"}]},"nguon":["@c0419"]},{"id":"vien-chau-den","name":"Viên châu đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quái nhân đảo chủ"],"trangThai":"Đã tiêu hao","blurb":"Viên châu đen quái nhân phun từ miệng, va chạm pháp bảo đối thủ rồi tự vỡ tung, gây giảm mạnh linh tính pháp bảo diện rộng.","detail":"Quái nhân đảo chủ phun viên châu đen từ miệng nghênh đón pháp bảo đối thủ. Khi va chạm, viên châu tự vỡ tung nhưng khiến linh tính của tất cả pháp bảo xung quanh giảm mạnh, quang hoa trở nên ảm đạm.","congNang":["Tự vỡ khi va chạm, gây giảm linh tính pháp bảo đối thủ diện rộng"],"nguon":["@c0419"]},{"id":"hai-bo-hac-kho-lau","name":"Hai bộ hắc khô lâu","cn":"","aliases":["Quỷ đầu","Hai đầu lâu đen trên ngực","Hắc khô lâu"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quái nhân đảo chủ"],"trangThai":"Đang sử dụng","blurb":"Hai đầu lâu nhỏ bằng nắm tay gắn cố định trên ngực quái nhân, toàn thân đen, tóc dài, chuyển động như vật sống. Cắn đứt ngón tay chủ nhân để kích hoạt rồi tự chủ bay ra nghênh chiến.","detail":"Hai khối xương đầu lâu nhỏ bằng nắm tay, toàn thân màu đen, tóc dài, gắn một trái một phải trên ngực gầy đét của quái nhân. Chuyển động như vật sống. Khi quái nhân niệm chú cổ quái, hai đầu lâu phát ra âm thanh trầm thấp, cắn đứt hai ngón tay quái nhân rồi bay ra nghênh đón lôi hỏa và hắc kỳ đối phương.","hinhDang":"Đầu lâu nhỏ bằng nắm tay, toàn thân đen, tóc dài","congNang":["Tự chủ bay ra chiến đấu sau khi hấp thu máu thịt chủ nhân","Nghênh đón tấn công đối thủ"],"dacDiem":"Gắn cố định trên ngực, chuyển động như vật sống, cần cắn đứt ngón tay chủ nhân để kích hoạt","nguon":["@c0419"]},{"id":"song-kiem-xam","name":"Song kiếm xám","cn":"","aliases":["Hai thanh phi kiếm"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quái nhân đảo chủ"],"trangThai":"Đang sử dụng","blurb":"Hai thanh kiếm giắt sau lưng quái nhân, phóng kiếm quang xám tấn công, bị đại ấn trắng Kim Thanh đàn áp.","detail":"Quái nhân đảo chủ giắt hai thanh kiếm sau lưng, phóng ra hai đạo kiếm quang màu xám từ trên trời chém thẳng xuống Hồ Nguyệt. Bị tiểu ấn trắng của Kim Thanh biến lớn phát ra rồng ngâm đàn áp.","nguon":["@c0419"]},{"id":"tieu-an-trang","name":"Tiểu ấn trắng","cn":"","aliases":["Đại ấn trắng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Kim Thanh"],"trangThai":"Đang sử dụng","blurb":"Pháp bảo của Kim Thanh, nhỏ như ngón cái, đón gió biến lớn thành đại ấn, phát ra âm thanh rồng ngâm đàn áp pháp bảo đối thủ.","detail":"Tiểu ấn màu trắng nhỏ như ngón cái, đón gió biến lớn gấp mấy lần, phát ra âm thanh rồng ngâm. Dùng để đàn áp song kiếm xám của quái nhân đảo chủ.","congNang":["Biến đổi kích thước từ nhỏ thành lớn","Phát ra rồng ngâm đàn áp pháp bảo đối thủ"],"nguon":["@c0419"]},{"id":"hai-thanh-phi-dao-ho-nguyet","name":"Hai thanh phi đao","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hồ Nguyệt"],"trangThai":"Đang sử dụng","blurb":"Pháp bảo của Hồ Nguyệt, phóng ra đánh tan bạch khí nhưng bị giỏ hoa trúc cổ bảo vây khốn, gần mất linh.","detail":"Hồ Nguyệt phóng hai thanh phi đao phá tan bạch khí của giỏ hoa trúc, nhưng bạch khí nhanh chóng phục hồi và vây khốn hai thanh phi đao khiến chúng lung lay như sắp rớt, gần như mất linh.","nguon":["@c0419"]},{"id":"phi-xoa-hac-bach-nhi-khi","name":"Phi xoa hắc bạch nhị khí","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Giản huynh"],"trangThai":"Bị tổn thương nặng","blurb":"Pháp bảo của tu sĩ họ Giản, mang hắc bạch nhị khí tấn công. Bị viên châu đen quái nhân gây tổn thương nặng, cần cả năm tĩnh dưỡng nguyên thần mới phục hồi.","detail":"Tu sĩ họ Giản chủ động phóng phi xoa mang hắc bạch nhị khí tấn công quái nhân. Sau khi viên châu đen va chạm tự vỡ, phi xoa bị tổn thương nặng, cần cả năm dùng nguyên thần tĩnh dưỡng mới khôi phục.","nguon":["@c0419"]},{"id":"ba-cay-co-den","name":"Ba cây cờ đen","cn":"","aliases":["Ba cây Hắc Kỳ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Giản huynh"],"trangThai":"Đang sử dụng","blurb":"Ba cây cờ đen dài khoảng một trượng của tu sĩ họ Giản, đằng đằng sát khí, phát ra tiếng quỷ khóc sói tru khiến tâm thần đối thủ dao động.","detail":"Tu sĩ họ Giản phóng ba cây cờ đen dài khoảng một trượng, đằng đằng sát khí, phát ra tiếng quỷ khóc sói tru khiến chúng tu sĩ tâm thần dao động. Dùng trong trận tổng công quái nhân đảo chủ.","congNang":["Tấn công tinh thần diện rộng bằng tiếng quỷ khóc sói tru"],"nguon":["@c0419"]},{"id":"phap-luan-den","name":"Pháp luân đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quái nhân đảo chủ"],"trangThai":"bi-huy","blurb":"Pháp bảo của quái nhân đảo chủ, có thể phóng lớn quay nhanh và phun sương mù đen, nhưng bị Phệ Kim Trùng cắn nuốt hoàn toàn đến khi biến thành hư không.","detail":"Quái nhân vung Pháp luân đen đập nát các khối cầu kim ngân của Hàn Lập, nhưng mảnh vụn hóa thành hàng ngàn Kim ngân giáp trùng bám vào cắn nuốt. Sương mù đen do Pháp luân phun ra cũng bị giáp trùng nuốt sạch. Pháp luân từ lớn thu nhỏ rồi biến thành hư không.","congNang":["Quay tốc độ cao tấn công","Phun sương mù đen"],"nguon":["@c0420"],"tabs":{"tienTrinh":[{"chuong":"@c0420","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện và bị hủy","text":"Quái nhân vung Pháp luân đen đập nát khối cầu Phệ Kim Trùng, nhưng giáp trùng bám vào cắn nuốt sạch sẽ đến khi pháp bảo biến thành hư không.","anchor":"tốc độ từ lớn biến nhỏ của pháp luân, rồi từ nhỏ trở thành hư không, bị Phệ Kim Trùng cắn nuốt sạch sẽ"}]}},{"id":"bay-thanh-tieu-kiem-xanh-biec","name":"Bảy thanh tiểu kiếm xanh biếc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-su-dung","blurb":"Bảy thanh tiểu kiếm xanh biếc ẩn giấu trong cơ thể Hàn Lập, có thể hợp thành cự kiếm phi hành với tốc độ gấp rưỡi Lục Hoàng Kiếm, đồng thời phóng hồ quang điện vàng tiêu diệt đối thủ. Uy lực đủ nhất kích tiêu diệt quái nhân Kết Đan cấp.","detail":"Bảy thanh tiểu kiếm to khoảng bàn tay, màu xanh biếc, thường ngày ẩn giấu bên trong cơ thể Hàn Lập. Khi chiến đấu, bảy thanh kiếm được bắn ra từ trong người, có thể hợp lại thành một cự kiếm xanh biếc dùng để phi hành với tốc độ tăng gần gấp rưỡi so với Lục Hoàng Kiếm. Ngoài hình thái hợp nhất, bảy thanh kiếm cũng có thể tách riêng tấn công, tạo phân thân kiếm quang thật giả lẫn lộn khiến đối phương khó phân biệt. Đặc biệt, kiếm có khả năng phóng hồ quang điện màu vàng đánh tan hắc khí và thiêu đối thủ thành tro. Uy lực đạt mức nhất kích tiêu diệt quái nhân Kết Đan cấp (@c0421).","hinhDang":"Bảy thanh tiểu kiếm to khoảng bàn tay, màu xanh biếc","dacDiem":"Bảy thanh tiểu kiếm to khoảng bàn tay, màu xanh biếc, giấu trong cơ thể; có thể hợp thành cự kiếm phi hành hoặc tách riêng tấn công; phóng hồ quang điện màu vàng","congNang":["Hợp thành cự kiếm xanh biếc phi hành với tốc độ gấp rưỡi Lục Hoàng Kiếm (@c0421)","Phân thân kiếm quang thật giả lẫn lộn (@c0421)","Phóng hồ quang điện màu vàng đánh tan hắc khí và thiêu đối thủ thành tro (@c0421)"],"uyLuc":"Nhất kích tiêu diệt quái nhân Kết Đan cấp (@c0421)","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0421","denChuong":"","cachCoDuoc":"Giấu sẵn trong cơ thể","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0421","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Hàn Lập bắn bảy thanh tiểu kiếm từ trong cơ thể, hợp thành cự kiếm phi hành truy đuổi quái nhân, sau đó dùng kiếm quang phân thân và hồ quang điện tiêu diệt đối thủ.","anchor":"trong cơ thể đột nhiên bắn ra bảy thanh tiểu kiếm màu xanh biếc to khoảng bàn tay"}]},"nguon":["@c0421"]},{"id":"cuon-tranh-hong-quang","name":"Cuộn tranh hồng quang","cn":"","aliases":["Họa trục hồng quang"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (nghi pháp bảo không tầm thường)","soHuu":["Hàn Lập"],"trangThai":"dang-su-dung","blurb":"Cuộn tranh dạng quyển trục phát hồng quang lấp lánh chứa linh khí, chiến lợi phẩm từ quái nhân. Nội dung khiến Hàn Lập ngây ngẩn nửa ngày rồi thâm trầm nghi hoặc.","detail":"Chiến lợi phẩm thu được sau khi tiêu diệt quái nhân đảo chủ. Hồng quang lấp lánh, ẩn chứa linh khí. Hàn Lập mở ra xem thì ngây ngẩn nửa ngày rồi chậm rãi khép lại, vẻ mặt thâm trầm nghi hoặc. Nội dung cụ thể chưa được tiết lộ.","hinhDang":"Cuộn tranh dạng quyển trục, hồng quang lấp lánh","dacDiem":"Chứa linh khí, nội dung bí ẩn","chuSoHuu":[{"ten":"Quái nhân đảo chủ","tuChuong":"","denChuong":"@c0421","cachCoDuoc":"","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0421","denChuong":"","cachCoDuoc":"Chiến lợi phẩm sau khi giết quái nhân","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0421","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập thu được","text":"Hàn Lập thu cuộn tranh từ quái nhân, mở xem thì ngây ngẩn nửa ngày rồi khép lại với vẻ thâm trầm.","anchor":"vừa thấy không khỏi ngây ngẩn cả người"}]},"nguon":["@c0421"]},{"id":"hac-kho-lau-chien-loi-pham","name":"Hắc khô lâu (chiến lợi phẩm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"mat-linh-tinh","blurb":"Đầu lâu đen tà khí xung thiên, vũ khí cũ của quái nhân đảo chủ. Mất linh tính sau khi chủ chết nhưng tà khí không giảm, Hàn Lập thu vào hộp ngọc.","detail":"Vũ khí dạng đầu lâu đen của quái nhân, tà khí dày đặc. Sau khi chủ chết thì trôi nổi không trung, mất linh tính hoàn toàn nhưng tà khí không giảm nửa phân. Hàn Lập chưa từng thấy vật quỷ dị như vậy, không biết lai lịch, thu vào hộp ngọc cất giữ.","dacDiem":"Tà khí xung thiên, mất linh tính khi vô chủ","chuSoHuu":[{"ten":"Quái nhân đảo chủ","tuChuong":"","denChuong":"@c0421","cachCoDuoc":"","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0421","denChuong":"","cachCoDuoc":"Chiến lợi phẩm","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0421","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập thu về","text":"Quái nhân chết, hắc khô lâu mất linh tính nhưng tà khí không giảm. Hàn Lập thu vào hộp ngọc.","anchor":"tà khí trên cả người không giảm nửa phân nhưng lại hoàn toàn mất đi linh tính"}]},"nguon":["@c0421"]},{"id":"phong-linh-tru","name":"Phong Linh Trụ","cn":"封灵柱","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Giá trị 5-6 ngàn linh thạch","soHuu":[],"trangThai":"moi-lo-dien","blurb":"Phong Linh Trụ là cây cột đá kỳ lạ được bảo vệ bởi nhiều lớp cấm chế tại di chỉ cổ tu sĩ, lộ ra sau khi nhóm phá nốt cấm chế cuối cùng. Trên cột có tám minh ấn cổ văn, khảm Âm dương ngọc quý hiếm lóe hắc bạch quang, được tạo từ hỗn hợp chục loại tài liệu luyện khí trân quý với giá trị ước tính năm sáu ngàn linh thạch.","detail":"Phong Linh Trụ xuất hiện tại cổ tu sĩ di chỉ, nơi nó được bảo vệ bởi nhiều lớp cấm chế cùng Sí Ác. Sau khi nhóm phá bỏ cấm chế cuối cùng, cây cột đá mới lộ diện. Bề mặt cột khắc phù văn quái dị cùng tám phù hào cổ văn dạng minh ấn, đồng thời khảm nhiều loại Âm dương ngọc quý hiếm tỏa ánh sáng hắc bạch. Thạch Điệp là người nhận ra Phong Linh Trụ nhờ từng đọc điển tịch pháp trận trong động phủ, và giảng giải rằng cây cột này phải dùng hỗn hợp chục loại tài liệu luyện khí rất trân quý mới luyện chế thành, giá trị ước khoảng năm sáu ngàn linh thạch. Công dụng cụ thể của Phong Linh Trụ chưa được giải thích rõ trong tiến trình hiện có (@c0421).","hinhDang":"Cột đá có phù văn quái dị, tám minh ấn cổ văn, khảm Âm dương ngọc hắc bạch","vatLieu":"Hỗn hợp chục loại tài liệu luyện khí trân quý","dacDiem":"Trên cột có tám phù hào cổ văn dạng minh ấn cùng phù văn quái dị, khảm nhiều loại Âm dương ngọc quý hiếm tỏa hắc bạch quang. Được tạo từ hỗn hợp chục loại tài liệu luyện khí trân quý, giá trị ước tính năm sáu ngàn linh thạch.","chuSoHuu":[],"tabs":{"tienTrinh":[{"chuong":"@c0421","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện sau khi phá cấm chế","text":"Nhóm phá nốt cấm chế cuối cùng, Phong Linh Trụ lộ ra. Thạch Điệp nhận ra nhờ điển tịch pháp trận, giảng giải giá trị năm sáu ngàn linh thạch.","anchor":"kỳ thật phải có hỗn hợp của chục loại tài liệu luyện khí rất trân quý mới có thể tạo thành"}]},"nguon":["@c0421"]},{"id":"that-ha-lien","name":"Thất Hà Liên","cn":"七霞莲","category":"nguyen-lieu","categoryLabel":"Linh dược","phamCap":"Mới ba màu (chưa nở), cực trân quý","soHuu":[],"trangThai":"Trong ao thạch nhũ ngàn năm dưới đại sảnh ngầm","blurb":"Thất Hà Liên là đóa hoa sen ba màu (đỏ, vàng, xanh) còn đang nụ, mọc tự nhiên trong ao thạch nhũ ngàn năm tại đại sảnh ngầm dưới Phong Linh Trụ trong cổ tu sĩ di chỉ. Vật chỉ tồn tại trong truyền thuyết, được Hồ Nguyệt nhận diện khi nhóm tu sĩ phát hiện, và được đánh giá là linh dược cực kỳ trân quý dù mới ở giai đoạn ba màu.","detail":"Thất Hà Liên có kích thước bằng miệng bát, cánh hoa ba màu đỏ, vàng, xanh còn đang ở dạng nụ, tản hào quang ba màu, phía trên hiện cầu vồng bảy màu lung linh rực rỡ. Hoa mọc trong ao nhỏ chứa dung dịch trắng sữa — chính là thạch nhũ ngàn năm — tại đại sảnh ngầm dưới Phong Linh Trụ, được nhiều tầng trận pháp cấm chế bảo vệ. Khi nhóm tu sĩ phát hiện, Hồ Nguyệt nhận ra đây là Thất Hà Liên, một vật chỉ có trong truyền thuyết. Tu sĩ họ Giản đánh giá rằng dù hoa mới ở giai đoạn ba màu, nếu đem đấu giá cũng sẽ có giá trên trời, cho thấy giá trị phi thường của linh dược này.","hinhDang":"Hoa sen kích thước bằng miệng bát, ba màu đỏ vàng xanh, còn đang nụ","nguonGoc":"Mọc tự nhiên trong ao thạch nhũ ngàn năm, được bảo vệ bởi Phong Linh Trụ và trận pháp cấm chế","dacDiem":"Đóa hoa sen kích thước bằng miệng bát, cánh hoa ba màu đỏ, vàng, xanh còn đang nụ, tản hào quang ba màu; phía trên hiện cầu vồng bảy màu lung linh rực rỡ.","congNang":["Linh dược cực trân quý, giá trị trên trời khi đấu giá dù mới ở giai đoạn ba màu @c0422"],"chuSoHuu":[],"tabs":{"tienTrinh":[{"chuong":"@c0422","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện trong đại sảnh ngầm","text":"Nhóm tu sĩ phát hiện Thất Hà Liên — đóa hoa sen ba màu chưa nở mọc trong ao thạch nhũ ngàn năm. Hồ Nguyệt xác nhận là vật truyền thuyết, tu sĩ họ Giản đánh giá giá trị trên trời.","anchor":"Thất Hà Liên! Không sai, tuyệt đối là vật ấy, ta còn tưởng rằng nó chỉ có trong truyền thuyết thôi chứ"}]},"nguon":["@c0422"]},{"id":"thach-nhu-ngan-nam","name":"Thạch nhũ ngàn năm","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"Trong ao nhỏ dưới đại sảnh ngầm","blurb":"Dung dịch màu trắng sữa tỏa dị hương, là nước ao nơi Thất Hà Liên mọc. Hồ Nguyệt suy đoán đó là thạch nhũ ngàn năm.","detail":"Dung dịch màu trắng sữa chứa trong ao nhỏ tại đại sảnh ngầm dưới Phong Linh Trụ, tản ra dị hương đặc biệt. Hồ Nguyệt suy đoán chính là thạch nhũ ngàn năm, là môi trường nuôi dưỡng đóa Thất Hà Liên.","congNang":["Nuôi dưỡng linh dược Thất Hà Liên"],"tabs":{"tienTrinh":[{"chuong":"@c0422","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện trong ao","text":"Nhóm tu sĩ phát hiện dung dịch trắng sữa tỏa dị hương trong ao nhỏ, Hồ Nguyệt suy đoán là thạch nhũ ngàn năm.","anchor":"nước ao kia….chẳng lẽ chính là thạch nhũ ngàn năm sao"}]},"nguon":["@c0422"]},{"id":"mui-ten-xanh-biec","name":"Mũi tên nhỏ màu xanh biếc","cn":"","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":[],"trangThai":"khong-ro","blurb":"Mũi tên dài khoảng một thước, màu xanh biếc, cắm xuyên đầu lâu bộ hài cốt trắng tinh trong đại sảnh ngầm, ghim chặt xuống đất. Nguồn gốc bí ẩn.","detail":"Mũi tên nhỏ màu xanh biếc dài khoảng một thước, cắm xuyên đầu lâu bộ hài cốt trắng tinh như ngọc, ghim chặt đầu lâu xuống đất. Nằm ngay cạnh ao thạch nhũ ngàn năm nơi Thất Hà Liên mọc. Nguồn gốc và bản chất hoàn toàn chưa rõ.","congNang":["Giết chết chủ nhân bộ hài cốt (suy đoán)"],"tabs":{"tienTrinh":[{"chuong":"@c0422","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện cắm trên hài cốt","text":"Nhóm tu sĩ phát hiện mũi tên xanh biếc cắm xuyên đầu lâu bộ hài cốt bí ẩn trong đại sảnh ngầm.","anchor":"trên đầu lâu còn cắm một mũi tên nhỏ màu xanh biếc dài khoảng một thước"}]},"nguon":["@c0422","@c0424"]},{"id":"phap-bao-tru-ma-thach-diep","name":"Pháp bảo trừ ma của Thạch Điệp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Điệp"],"trangThai":"Chưa sử dụng","blurb":"Pháp bảo trừ ma lợi hại do gia phụ Thạch Điệp (tu sĩ Trúc Cơ kỳ) cấp cho, chưa sử dụng.","detail":"Pháp bảo trừ ma do gia phụ cấp cho Thạch Điệp, được mô tả là lợi hại. Thạch Điệp tự tin nhờ có vật này khi cả nhóm bàn bạc về việc mạo hiểm mở Phong Linh Trụ, nơi có thể phong ấn yêu ma quỷ linh.","congNang":["Trừ ma"],"chuSoHuu":[{"ten":"Thạch Điệp","tuChuong":"@c0422","denChuong":"","cachCoDuoc":"Gia phụ cấp cho","trangThai":"dang-co"}],"nguon":["@c0422"]},{"id":"yeu-chau-bay-mau","name":"Yêu châu bảy màu","cn":"","category":"khac","categoryLabel":"Yêu bảo","phamCap":"","soHuu":["Thạch Điệp"],"trangThai":"dang-co","blurb":"Viên châu bảy màu do Yêu Quan Xà phun ra, phóng bảo quang huyễn lệ có thể chặn pháp bảo. Sau khi yêu xà bị giết, được nhóm thương lượng cho Thạch Điệp thu lấy.","detail":"Viên yêu châu bảy màu của Yêu Quan Xà, phóng thích bảo quang huyễn lệ ngăn cản mọi pháp bảo tấn công. Sau khi yêu xà bị chế phục và chém chết, nhóm tu sĩ hợp lực áp chế viên châu và thương lượng cho Thạch Điệp thu lấy.","congNang":["Phóng bảo quang huyễn lệ chặn pháp bảo đối phương"],"chuSoHuu":[{"ten":"Yêu Quan Xà","tuChuong":"@c0424","denChuong":"@c0424","cachCoDuoc":"Tự sinh","trangThai":"da-mat"},{"ten":"Thạch Điệp","tuChuong":"@c0424","denChuong":"","cachCoDuoc":"Thu lấy sau khi giết yêu xà","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0424","loai":"đổi chủ","importance":"normal","giaiDoan":"Từ Yêu Quan Xà sang Thạch Điệp","text":"Yêu xà phun viên châu bảy màu phóng bảo quang chặn pháp bảo. Sau khi yêu xà bị giết, nhóm hợp lực áp chế viên châu và thương lượng cho Thạch Điệp thu lấy.","anchor":"phun ra một viên châu bảy màu, phóng thích bảo quang huyễn lệ, ngăn cản đại ấn cùng khăn lụa tại phía trước người"}]},"nguon":["@c0424"]},{"id":"vien-dan-mau-lam","name":"Viên đan màu lam","cn":"","category":"khac","categoryLabel":"Bất minh","phamCap":"","soHuu":["Hồ Nguyệt"],"trangThai":"bi-cuop","blurb":"Viên đan nhỏ như hạt đậu màu lam nằm trong bụng Hồ Nguyệt, bị cánh tay xương xẩu đâm xuyên bụng rút ra. Bản chất chưa rõ, có thể là nội đan hoặc bảo vật trong cơ thể.","detail":"Viên đan màu lam nhỏ như hạt đậu, ẩn trong cơ thể Hồ Nguyệt. Bị một cánh tay xương xẩu đâm xuyên bụng Hồ Nguyệt từ phía sau để cướp lấy. Bản chất chưa được tiết lộ — có thể là nội đan tu luyện hoặc bảo vật đặc biệt.","chuSoHuu":[{"ten":"Hồ Nguyệt","tuChuong":"@c0424","denChuong":"@c0424","cachCoDuoc":"Trong cơ thể","trangThai":"bi-cuop"}],"nguon":["@c0424"]},{"id":"khan-lua-tim","name":"Khăn lụa tím","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thạch Điệp"],"trangThai":"dang-co","blurb":"Pháp bảo của Thạch Điệp, ném ra tấn công Yêu Quan Xà nhưng bị yêu châu bảy màu chặn lại.","detail":"Khăn lụa tím là pháp bảo tấn công của Thạch Điệp, sử dụng trong trận chiến với Yêu Quan Xà trong di chỉ tu sĩ cổ.","nguon":["@c0424"]},{"id":"bach-an","name":"Bạch Ấn","cn":"","aliases":["Đại ấn trắng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Kim Thanh"],"trangThai":"dang-co","blurb":"Đại ấn trắng, pháp bảo của Kim Thanh, ném ra hợp lực với Thạch Điệp tấn công Yêu Quan Xà nhưng bị yêu châu chặn lại.","detail":"Pháp bảo dạng ấn màu trắng của Kim Thanh, dùng trong trận chiến với Yêu Quan Xà tại di chỉ tu sĩ cổ. Bị yêu châu bảy màu phóng bảo quang ngăn cản.","nguon":["@c0424"]},{"id":"buc-hoa-do-ruc","name":"Bức họa đỏ rực (Khu Linh đồ)","cn":"","aliases":["Bức họa Chi Dương điểu","Khu Linh đồ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bức họa đỏ rực phong ấn tinh hồn Chi Dương Điểu — loài chim lửa đã tuyệt chủng, khắc tinh âm vật. Phóng ra phân thân chim yến lửa chống quỷ vụ, nhưng uy lực kém xa bản thể vì chỉ chứa một phần tinh hồn.","detail":"Bức họa Hàn Lập sử dụng, bên trong phong ấn tinh hồn loài Chi Dương Điểu — loài chim sinh trong tinh hỏa, khắc tinh của âm vật, đã tuyệt chủng từ lâu. Khi kích hoạt, bức họa phóng ra vô số chim yến lửa tạo vòng lửa bảo vệ, xua tan hắc vụ và quỷ khí. Ngoài ra có thể phóng một con Chi Dương Điểu khổng lồ để tấn công trực tiếp. Tuy nhiên, phân thân từ bức họa chỉ chứa một phần tinh hồn nên uy lực kém xa bản thể Chi Dương Điểu thực sự. Quái ảnh xanh biếc từng nhận ra pháp bảo này liên quan đến Khu Linh Thuật — một thuật pháp đã thất truyền. Nguồn gốc cụ thể của bức họa chưa được làm rõ.","hinhDang":"Bức họa đỏ rực","nguonGoc":"Không rõ","uyLuc":"Phân thân Chi Dương Điểu đủ sức xua tan quỷ vụ và hắc khí, nhưng uy lực kém xa bản thể vì bức họa chỉ chứa một phần tinh hồn.","dacDiem":"Chứa tinh hồn loài Chi Dương Điểu đã tuyệt chủng, liên quan đến Khu Linh Thuật thất truyền.","congNang":["Phóng vô số chim yến lửa (phân thân Chi Dương Điểu) từ tinh hồn phong ấn bên trong, tạo vòng lửa bảo vệ xua tan hắc vụ và quỷ khí @c0425","Phóng một con Chi Dương Điểu khổng lồ để tấn công @c0425"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0425","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0425","loai":"dùng","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Hàn Lập cầm bức họa phóng ra vô số chim yến lửa chống hắc vụ bảo vệ nhóm. Sau đó phóng một con Chi Dương Điểu khổng lồ tấn công cột đá ép quái ảnh lộ diện.","anchor":"Bên trong bức họa cũng chỉ phong ấn một phần tinh hồn của loại linh điểu này mà thôi"}]},"capNhatToi":"@c0425","nguon":["@c0425"]},{"id":"hai-thanh-tieu-kiem-xanh-biec","name":"Hai thanh tiểu kiếm xanh biếc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hai thanh tiểu kiếm xanh biếc Hàn Lập xuất ra hộ thân khi quỷ khóc vang lên, chuyển động vòng quanh thân.","detail":"Hai thanh tiểu kiếm xanh biếc Hàn Lập xuất ra trước thân, chậm rãi chuyển động vòng quanh hộ thân khi tiếng quỷ khóc chói tai vang lên trong đại sảnh.","congNang":["Hộ thân, chuyển động vòng quanh thân chủ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0425","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0425","loai":"dùng","importance":"normal","giaiDoan":"Xuất hiện hộ thân","text":"Hàn Lập xuất hai thanh tiểu kiếm xanh biếc chuyển động vòng quanh hộ thân khi quỷ khóc vang lên.","anchor":"hai thanh tiểu kiếm xanh biếc đồng thời xuất hiện trước thân hắn, rồi chậm rãi chuyển động vòng quanh"}]},"capNhatToi":"@c0425","nguon":["@c0425"]},{"id":"bao-chau-trang-thach-diep","name":"Bảo châu trắng (của Thạch Điệp)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Điệp"],"trangThai":"khong-ro","blurb":"Viên bảo châu trắng phát hào quang khắc chế quỷ vụ thường, Thạch Điệp dùng xua hắc khí nhưng vô dụng trước quỷ trảo mạnh.","detail":"Viên châu trắng Thạch Điệp cầm, phát hào quang bắn ra bốn phía khiến hắc khí không dám tiến sát thân. Tuy nhiên khi Thạch Điệp bỏ chạy, bảo châu không đủ chống quỷ trảo xanh biếc của quái ảnh, nàng vẫn bị xuyên ngực và giết chết.","congNang":["Phát hào quang xua quỷ khí, hắc khí"],"chuSoHuu":[{"ten":"Thạch Điệp","tuChuong":"@c0425","denChuong":"@c0425","cachCoDuoc":"Không rõ","trangThai":"khong-ro"}],"tabs":{"tienTrinh":[{"chuong":"@c0425","loai":"dùng","importance":"normal","giaiDoan":"Dùng rồi chủ chết","text":"Thạch Điệp cầm bảo châu phát hào quang xua hắc khí nhưng không chống được quỷ trảo, bị giết chết.","anchor":"hào quang bắn ra bốn phía, khiến cho những luồng hắc khí ngẫu nhiên lọt lưới không dám tiến sát thân"}]},"capNhatToi":"@c0425","nguon":["@c0425"]},{"id":"mui-ten-kim-loi-truc","name":"Mũi tên Kim Lôi Trúc (pháp bảo của Tiêu Sá)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tiêu Sá"],"trangThai":"dang-dung","blurb":"Mũi tên xanh biếc dài hơn một thước, vốn là Kim Lôi Trúc bị Tiêu Sá dùng tà pháp tế luyện thành pháp bảo. Khi kích phát, mũi tên phóng lôi điện đen pha tà khí, uy lực vượt trội bảy thanh Thanh Trúc Phong Vân kiếm chưa được bồi luyện đầy đủ của Hàn Lập.","detail":"Kim Lôi Trúc nguyên là trúc tiễn linh vật, sau bị Tiêu Sá thu lấy và dùng tà pháp tế luyện thành pháp bảo. Trước khi xuất hiện trong trận chiến, mũi tên được cắm trên đầu lâu bạch cốt. Hàn Lập nhận ra khí tức quen thuộc của Kim Lôi Trúc, xác nhận rằng mũi tên chính là Kim Lôi Trúc đã bị biến đổi. Trong cuộc đối đầu giữa Tiêu Sá và Hàn Lập, Tiêu Sá phóng mũi tên ra nghênh chiến bảy thanh cự kiếm Thanh Trúc Phong Vân kiếm. Lôi điện hai bên bùng nổ dữ dội, song mũi tên Kim Lôi Trúc chiếm thế thượng phong, kiếm quang vàng của Thanh Trúc Phong Vân kiếm bị áp chế do chưa được bồi luyện đủ.","hinhDang":"Mũi tên xanh biếc dài hơn một thước","vatLieu":"Kim Lôi Trúc","nguonGoc":"Kim Lôi Trúc bị Tiêu Sá tà pháp tế luyện thành pháp bảo","uyLuc":"Phát lôi điện đen pha tà khí, thắng thế trước bảy thanh cự kiếm Thanh Trúc Phong Vân kiếm chưa được bồi luyện đầy đủ, áp chế kiếm quang vàng trong cuộc đối đầu trực diện.","dacDiem":"Lôi điện mang tà khí do tà pháp luyện hóa, mũi tên xanh biếc dài hơn một thước, trước đó được cắm trên đầu lâu bạch cốt.","congNang":["Phóng lôi điện đen pha tà khí, dùng để tấn công và đối kháng pháp bảo đối phương @c0428","Có thể dùng ám toán tầm ngắn nhờ tốc độ và uy lực của lôi điện @c0428"],"chuSoHuu":[{"ten":"Tiêu Sá","tuChuong":"@c0428","denChuong":"","cachCoDuoc":"Tự tế luyện từ Kim Lôi Trúc bằng tà pháp","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0428","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện trong giao tranh với Hàn Lập","phamCap":"Không rõ","text":"Tiêu Sá phóng mũi tên Kim Lôi Trúc tà luyện đối đầu cự kiếm Thanh Trúc Phong Vân kiếm của Hàn Lập, chiếm thế thượng phong. Hàn Lập nhận ra pháp bảo do Kim Lôi Trúc chế thành.","anchor":"mũi tên ám toán đối phương lúc trước chẳng những là do Kim Lôi trúc chế thành mà còn bi lão quỷ đem đi luyện hóa thành pháp bảo"}]},"capNhatToi":"@c0428","nguon":["@c0428"]},{"id":"tho-nguyen-qua","name":"Thọ Nguyên quả","cn":"寿元果","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"chưa thu hoạch","blurb":"Linh dược quý hiếm nằm trong Hư Thiên điện, là nguyên liệu luyện chế Trường Sinh đan có thể kéo dài tuổi thọ. Là mục tiêu của Man hồ tử và lý do cao nhân Nguyên Anh kỳ tập trung đến Hư Thiên điện.","detail":"Linh dược trong Hư Thiên điện, dùng luyện chế Trường Sinh đan để kéo dài tuổi thọ thêm khoảng 50-60 năm. Cơ hội thu hoạch linh dược này 300 năm mới có một lần, khiến các cao nhân Nguyên Anh kỳ đều tụ tập đến.","congNang":["Nguyên liệu chính luyện chế Trường Sinh đan, kéo dài tuổi thọ","Liên quan trường sinh (chưa rõ chi tiết, có thời kỳ trưởng thành)","Ăn vào có thể tăng tuổi thọ đáng kể"],"tabs":{"tienTrinh":[{"chuong":"@c0432","loai":"nhắc tới","importance":"normal","giaiDoan":"Được lão nho sinh Nam Hạc đảo nhắc tên","text":"Được tiết lộ là linh dược nằm trong Hư Thiên điện, mục tiêu của Man hồ tử để luyện Trường Sinh đan kéo dài thọ mạng.","anchor":"lần này muốn đi Hư thiên điện tìm chút ít Thọ nguyên quả ở trong này"},{"chuong":"@c0434","loai":"nhac-toi","importance":"normal","giaiDoan":"Man Hồ Tử tiết lộ đã trưởng thành","text":"Man Hồ Tử suy đoán Thọ Nguyên quả đã đến thời kỳ trưởng thành, có thể là mục tiêu của Vạn Thiên Minh.","anchor":"Chẳng lẽ hắn cũng biết Thọ Nguyên quả đã đến thời kỳ trưởng thành"},{"chuong":"@c0448","loai":"nhắc tới","importance":"normal","giaiDoan":"Man Hồ Tử nhắc đến, muốn hái","text":"Man Hồ Tử rủ Thanh Dịch cư sĩ cùng đi hái Thọ Nguyên Quả nhưng bị từ chối.","anchor":"nếu có loại quả này thì tuổi thọ sẽ tăng lên không ít đó"}]},"nguon":["@c0432","@c0434","@c0448"]},{"id":"truong-sinh-dan","name":"Trường Sinh đan","cn":"长生丹","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":[],"trangThai":"chua-luyen","blurb":"Đan dược luyện từ Thọ Nguyên quả, có thể kéo dài tuổi thọ thêm khoảng 50-60 năm. Là mục tiêu luyện chế của Man hồ tử.","detail":"Đan dược quý hiếm luyện chế từ Thọ Nguyên quả, công dụng kéo dài thọ mạng thêm khoảng 50-60 năm. Man hồ tử (Nguyên Anh kỳ) thọ nguyên sắp cạn, muốn tìm Thọ Nguyên quả trong Hư Thiên điện để luyện chế vài viên đan này.","congNang":["Kéo dài thọ mạng thêm khoảng 50-60 năm","Liên quan trường sinh (chưa rõ chi tiết)"],"tabs":{"tienTrinh":[{"chuong":"@c0432","loai":"nhắc tới","importance":"normal","giaiDoan":"Được lão nho sinh nhắc tên trong đối thoại","text":"Được tiết lộ là đan dược luyện từ Thọ Nguyên quả, Man hồ tử muốn luyện để kéo dài thêm 50-60 năm thọ mạng.","anchor":"đến luyện chế vài viên Trường sinh đan. Hy vọng có thể sống lâu thêm năm sáu chục năm nữa"},{"chuong":"@c0434","loai":"nhac-toi","importance":"normal","giaiDoan":"Man Hồ Tử tiết lộ mục đích","text":"Man Hồ Tử tiết lộ trông cậy vào thứ trong Hư Thiên điện để luyện chế Trường Sinh đan.","anchor":"Ta còn trông cậy vào thứ trong Hư Thiện điện để luyện chế Trường Sinh đan đây"}]},"nguon":["@c0432","@c0434"]},{"id":"cuu-khuc-linh-sam","name":"Cửu Khúc Linh Sâm","cn":"九曲灵参","category":"khac","categoryLabel":"Tiên thảo","phamCap":"Tiên thảo truyền thuyết","soHuu":[],"trangThai":"tiềm phục tại Tiểu Thạch Sơn","blurb":"Cửu Khúc Linh Sâm là tiên thảo truyền thuyết do thiên địa linh khí biến thành, tồn tại bên trong Hư Thiên điện ở cửa thứ hai. Bản thể tuy là linh thảo nhưng mười phần linh tính, có thể biến ảo thành các loại động vật và côn trùng, am hiểu độn thổ độn mộc, và là nguyên liệu then chốt để điều chế linh dược tăng tỷ lệ ngưng kết Nguyên Anh.","detail":"Cửu Khúc Linh Sâm là tiên thảo trong truyền thuyết, tiềm phục tại Tiểu Thạch Sơn bên trong Hư Thiên điện ở cửa thứ hai. Do thiên địa linh khí biến thành, bản thể tuy chỉ là linh thảo nhưng mười phần linh tính, có thể tự hoạt động, biến ảo thành các loại động vật và côn trùng, đồng thời am hiểu độn thổ độn mộc khiến việc bắt giữ cực kỳ khó khăn. Huyền Cốt thượng nhân từng phát hiện nó nhiều năm trước khi tu vi còn thấp nhưng không thể bắt được; đến khi tu thành Nguyên Anh thì bản thân không cần đến nữa. Sau đó Huyền Cốt thượng nhân hứa giúp Hàn Lập bắt Cửu Khúc Linh Sâm để đổi lấy sự hiệp trợ diệt Cực Âm tổ sư, và dẫn Hàn Lập đến Tiểu Thạch Sơn — nơi linh sâm tiềm phục. Là bảo vật cấp tiên gia, giá trị cực cao trong giới tu tiên.","phanLoaiPhu":"Tiên thảo / linh dược nguyên liệu","dacDiem":"Bản thể là linh thảo nhưng mười phần linh tính, do thiên địa linh khí biến thành; có thể biến ảo thành các loại động vật và côn trùng, tự hoạt động, am hiểu độn thổ độn mộc, khiến việc bắt giữ vô cùng khó khăn.","congNang":["Điều chế thành linh dược có thể tăng tỷ lệ ngưng kết Nguyên Anh @c0433","Tiên gia bảo vật cấp linh dược, giá trị cực cao"],"chuSoHuu":[],"tabs":{"tienTrinh":[{"chuong":"@c0433","loai":"xuất hiện","importance":"major","giaiDoan":"Được Huyền Cốt tiết lộ sự tồn tại","text":"Huyền Cốt thượng nhân tiết lộ Cửu Khúc Linh Sâm tồn tại trong Hư Thiên điện ở cửa thứ hai, hứa giúp Hàn Lập bắt để đổi lấy hiệp trợ diệt Cực Âm.","anchor":"Bản thể tuy nhiên chỉ là một loại linh thảo nhưng mười phần linh tính"},{"chuong":"@c0448","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện vị trí tiềm phục","text":"Huyền Cốt thượng nhân dẫn Hàn Lập đến Tiểu Thạch Sơn, nơi Cửu Khúc Linh Sâm tiềm phục. Cho biết lần đầu phát hiện khi đuổi theo Linh Cầm Thử Hổ, nhận định đây là tiên gia bảo vật do thiên địa tạo hóa tự sinh.","anchor":"Cửu Khúc Linh Sâm cơ hồ là một loại tiên gia bảo vật"}]},"nguon":["@c0433","@c0448"]},{"id":"hu-thien-dinh","name":"Hư Thiên đỉnh","cn":"虛天鼎","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cực khó thu)","soHuu":[],"trangThai":"trong Hư Thiên điện nội điện","blurb":"Bảo vật nằm trong Hư Thiên điện, Cực Âm lo Vạn Thiên Minh muốn lấy nhưng nho sinh lão giả bác bỏ vì cho rằng nếu dễ lấy thì cao nhân trước đã lấy rồi.","detail":"Bảo vật trong Hư Thiên điện, cực kỳ khó thu. Cực Âm tổ sư lo lắng Vạn Thiên Minh muốn lấy, nhưng nho sinh lão giả bác bỏ, cho rằng nếu dễ lấy được thì sớm đã nằm trong tay cao nhân lúc trước rồi.","congNang":["Chứa Bổ Thiên đan và nhiều cổ bảo đỉnh cấp do cổ tu sĩ truyền lại"],"tabs":{"tienTrinh":[{"chuong":"@c0434","loai":"nhac-toi","importance":"normal","giaiDoan":"Được bàn luận giữa phe ma đạo","text":"Cực Âm lo Vạn Thiên Minh muốn lấy Hư Thiên đỉnh. Nho sinh lão giả bác bỏ vì cho rằng nếu dễ lấy thì cao nhân trước đã lấy rồi.","anchor":"Vật ấy nếu dễ dàng lấy được thì sớm đã nằm trong tay cao nhân lúc trước rồi"},{"chuong":"@c0435","loai":"nhắc tới","importance":"major","giaiDoan":"Mục tiêu tranh đoạt chính-ma lưỡng đạo","text":"Ma đạo bàn mưu liên thủ chiếm Hư Thiên đỉnh. Cực Âm tổ sư đề nghị giữ Hư Thiên đỉnh cùng một viên Bổ Thiên đan, chia cổ bảo còn lại. Chính đạo Vạn Thiên Minh cũng nhắm mục tiêu này.","anchor":"trong Hư Thiên đỉnh ngoại trừ thứ quan trọng nhất là Bổ Thiên đan, còn có vài kiện cổ bảo đỉnh cấp do cổ tu sĩ truyền lại"}]},"nguon":["@c0434","@c0435"]},{"id":"bo-thien-dan","name":"Bổ Thiên đan","cn":"補天丹","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cực phẩm (độc nhất Tu tiên giới)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bổ Thiên đan là đan dược cực kỳ hiếm có, duy nhất trong Tu tiên giới có khả năng bù đắp ngũ hành linh căn của con người, chỉ tồn tại bên trong Hư Thiên đỉnh. Đây là mục tiêu tranh đoạt hàng đầu của các tu sĩ Nguyên Anh kỳ.","detail":"Bổ Thiên đan lần đầu được Cực Âm tổ sư giới thiệu cho Man Hồ Tử và Thanh Dịch cư sĩ, xác nhận là thứ duy nhất trong Tu tiên giới có thể bù đắp ngũ hành linh căn của con người (@c0435). Thanh Dịch cư sĩ xác nhận đan dược này nằm bên trong Hư Thiên đỉnh, khắp tu tiên giới ngoài nơi đó không còn chỗ nào có, vì thế đồng ý bảo vệ Hàn Lập trong kế hoạch đoạt lấy (@c0478). Hai trưởng lão Tinh Cung sau đó tiết lộ thêm công dụng thật sự: bồi bổ linh căn bất thuần và giúp tu sĩ Kết Đan kỳ ngưng luyện củng cố Nguyên Anh (@c0484). Dược tính của Bổ Thiên đan cực mạnh, có thể vượt quá khả năng luyện hóa của thân thể tu sĩ; phần dư lượng không luyện hóa hết sẽ ngưng tụ trong hài cốt, hóa thành châu ngũ sắc — điều này được Hàn Lập xác nhận khi đối chiếu hạt châu ngũ sắc luyện từ hài cốt Cực Huyễn với họa ","congNang":["Bù đắp ngũ hành linh căn của con người, là thứ duy nhất trong Tu tiên giới có công dụng này (@c0435)","Phục dụng có thể đột phá giới hạn tuổi tác (@c0435)","Bồi bổ linh căn bất thuần (@c0484)","Giúp tu sĩ Kết Đan kỳ ngưng luyện củng cố Nguyên Anh (@c0484)","Dược tính cực mạnh, có thể vượt khả năng luyện hóa của thân thể tu sĩ; dư lượng ngưng tụ trong hài cốt hóa thành châu ngũ sắc (@c0516)"],"tabs":{"tienTrinh":[{"chuong":"@c0435","loai":"xuất hiện","importance":"major","giaiDoan":"Được Cực Âm tổ sư tiết lộ giá trị","text":"Cực Âm tổ sư giới thiệu Bổ Thiên đan cho Man Hồ Tử và Thanh Dịch cư sĩ: thứ duy nhất trong Tu tiên giới có thể bù đắp ngũ hành linh căn, chỉ có trong Hư Thiên đỉnh.","anchor":"thứ có thể bù đắp ngũ hành linh căn của con người. Ta nghĩ khắp Tu tiên giới ngoại trừ chỗ này thì không còn chỗ nào có nữa"},{"chuong":"@c0478","loai":"nhắc tới","importance":"normal","giaiDoan":"Được xác nhận nằm trong Hư Thiên đỉnh","text":"Thanh Dịch cư sĩ xác nhận Bổ Thiên Đan ở trong Hư Thiên đỉnh, vì thế đồng ý bảo vệ Hàn Lập trong kế hoạch đoạt bảo.","anchor":"Vì Bổ Thiên Đan trong Hư Thiên đỉnh kia"},{"chuong":"@c0484","loai":"xuat-hien","importance":"major","giaiDoan":"Hé lộ công dụng thật và xuất hiện từ Hư Thiên Đỉnh","text":"Hai trưởng lão Tinh Cung tiết lộ công dụng thật: bồi bổ linh căn bất thuần, giúp củng cố Nguyên Anh cho tu sĩ Kết Đan kỳ, không tăng thọ hay đột phá bình cảnh Nguyên Anh kỳ. Hư Thiên Đỉnh phóng ra hào quang ngũ sắc chứa Bổ Thiên Đan bay lên trời, hai bên chính ma đồng thanh hô tên.","anchor":"Bổ Thiên Đan có danh tiếng không nhỏ kia, điều này cũng là chuyện dể hiểu"},{"chuong":"@c0516","loai":"xuất hiện","importance":"major","giaiDoan":"Xác định danh tính","text":"Hàn Lập đối chiếu hạt châu ngũ sắc luyện từ hài cốt Cực Huyễn với họa đồ trong ngọc giản, xác định đây chính là Bổ Thiên Đan chân chính. Cho Kim Ti Tằm sắp chết ăn hai hạt thí nghiệm dược tính.","anchor":"mấy viên châu này mới là Bổ Thiên Đan chân chính"}]},"nguon":["@c0435","@c0478","@c0484","@c0516"],"dacDiem":"Chỉ tồn tại bên trong Hư Thiên đỉnh, khắp Tu tiên giới không còn nơi nào khác có; dược tính mãnh liệt đến mức phần dư lượng không luyện hóa hết có thể ngưng kết trong hài cốt thành châu ngũ sắc."},{"id":"kim-ti-tam","name":"Kim Ti tàm","cn":"金絲蠶","category":"khac","categoryLabel":"Linh trùng","soHuu":["Vạn Pháp môn","Vạn Thiên Minh","Hàn Lập"],"trangThai":"sap-chet","blurb":"Kim Ti Tàm là kỳ trùng quý hiếm từng được đệ tử Vạn Pháp môn tìm kiếm, có khả năng hỗ trợ chiếm Hư Thiên đỉnh. Sau khi bị phế do mất dược tính Thiên Thanh Hoa, loài tằm này được hé lộ có thể tiến hóa lần hai thành Huyễn Diễm Nga, xếp thứ 17 trên bảng kỳ trùng.","detail":"Kim Ti Tàm là một loại kỳ trùng hiếm có, từng nằm trong tay Vạn Thiên Minh. Hai bạch y trưởng lão Tinh Cung nhận định rằng nhờ sở hữu Kim Ti Tàm, Vạn Thiên Minh có khả năng lấy được Bổ Thiên Đan từ Hư Thiên đỉnh. Trước đó, đệ tử Vạn Pháp môn đã nhiều năm tìm kiếm loại trùng này nhưng rồi đột nhiên mất tin tức. Kim Ti Tàm gồm sáu con, có thể phun kim ti để kéo vật nặng khi đạo hạnh đủ cao. Tuy nhiên, khi dược tính Thiên Thanh Hoa cạn kiệt, sáu con tằm đồng loạt mất kim quang, kim ti đứt đoạn và bị phế hoàn toàn. Về sau, bí mật về tầng tiến hóa thứ hai của Kim Ti Tàm được hé lộ: chúng có thể tiến hóa thành Huyễn Diễm Nga — một loại phi trùng có năng lực biến ảo, xếp hạng 17 trên bảng kỳ trùng. Thông tin này lộ ra khi Kim Ti Tàm đang hấp hối sau khi bị Vạn Thiên Minh gây hại.","congNang":["Hỗ trợ chiếm Hư Thiên đỉnh, tạo khả năng lấy Bổ Thiên Đan @c0466","Phun kim ti để kéo vật nặng khi đạo hạnh đủ cao","Có thể tiến hóa lần hai thành Huyễn Diễm Nga — phi trùng có năng lực biến ảo, xếp thứ 17 bảng kỳ trùng @c0516"],"nguon":["@c0435","@c0466","@c0477","@c0516"],"tabs":{"tienTrinh":[{"chuong":"@c0466","loai":"xuat-hien","importance":"normal","giaiDoan":"Được nhắc tới bởi hai bạch y trưởng lão","text":"Hai bạch y trưởng lão Tinh Cung nhận định Vạn Thiên Minh có Kim Ti Tằm nên có khả năng lấy Bổ Thiên Đan từ Hư Thiên Đỉnh.","anchor":"Lần này Vạn Thiên Minh còn có Kim Ti Tằm, ta nghĩ bọn họ cũng có khả năng đó chứ"},{"chuong":"@c0477","loai":"đổi chủ","importance":"major","giaiDoan":"Bị phế, đổi chủ sang Hàn Lập","text":"Dược tính Thiên Thanh Hoa hết, sáu con tằm đồng loạt mất kim quang, kim ti đứt đoạn, bị phế hoàn toàn. Vạn Thiên Minh bỏ lại xoá thần thức. Hàn Lập xin thu ba con còn sống vào túi linh vật.","anchor":"Bọn chúng đã được phục dùng Thiên Thanh Hoa để mượn vật ấy để cao đạo hạnh lên rất nhiều"},{"chuong":"@c0516","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ bí mật tiến hóa + thí nghiệm Bổ Thiên Đan","text":"Lộ bí mật tiến hóa lần hai thành Huyễn Diễm Nga xếp thứ 17 bảng kỳ trùng. Đang hấp hối sau khi bị Vạn Thiên Minh vứt bỏ. Hàn Lập cho con to nhất ăn hai hạt châu ngũ sắc thí nghiệm.","anchor":"chỉ cần cho chúng nó đủ thời gian, những yêu thú này phần lớn đều có thể tiến hóa thành một loại trùng có cánh tên là “Huyễn Diễm Nga”"}]},"chuSoHuu":[{"ten":"Vạn Thiên Minh","tuChuong":"@c0466","denChuong":"@c0477","cachCoDuoc":"Nuôi dưỡng, phục dùng Thiên Thanh Hoa","trangThai":"Bỏ lại, xoá thần thức"},{"ten":"Hàn Lập","tuChuong":"@c0477","denChuong":"","cachCoDuoc":"Xin thu lại từ tế đài","trangThai":"Đang giữ (bị phế)"}],"dacDiem":"Gồm sáu con, toàn thân phát kim quang và phun kim ti; phụ thuộc dược tính Thiên Thanh Hoa để duy trì năng lực — khi dược tính hết thì kim quang tắt, kim ti đứt đoạn và bị phế hoàn toàn @c0477."},{"id":"hoa-mang-di-chung","name":"Hỏa mãng dị chủng","cn":"火蟒異種","category":"khac","categoryLabel":"Linh thú","soHuu":["Cực Âm tổ sư"],"trangThai":"dang-co","blurb":"Hai con hỏa mãng dị chủng được Cực Âm tổ sư thu phục tại Ly Hỏa đảo, mang đến Hư Thiên điện với ý đồ dùng để chiếm Hư Thiên đỉnh. Đạo hạnh vẫn quá thấp.","detail":"Cực Âm tổ sư thu được hai con hỏa mãng dị chủng tại Ly Hỏa đảo, mang đến Hư Thiên điện nhằm dùng để chiếm Hư Thiên đỉnh. Tuy nhiên đạo hạnh của chúng vẫn quá thấp, hy vọng thành công rất xa vời, bị Man Hồ Tử vạch trần.","congNang":["Dùng để hỗ trợ chiếm Hư Thiên đỉnh (đạo hạnh quá thấp, xa vời)"],"nguon":["@c0435"]},{"id":"de-hon-thu","name":"Đề Hồn thú","cn":"提魂兽","category":"khac","categoryLabel":"Linh thú tế luyện","phamCap":"Không rõ","soHuu":["Hắc bào nữ tu","Hàn Lập"],"trangThai":"dang-co","blurb":"Đề Hồn thú là linh thú dạng khỉ nhỏ, không sinh ra tự nhiên mà được tế luyện bằng bí thuật môn phái kết hợp huyết tế tà pháp, thuộc dạng tiến hóa giữa linh thú và yêu hồn. Trời sinh có năng lực hấp hồn luyện hóa quỷ, ban đầu do tu sĩ áo đen ma đạo triệu hồi trong Hư Thiên Điện, sau được Hàn Lập dùng làm vật giao dịch đổi lấy sự hộ tống của Nguyên Dao qua Dung Nham lộ.","detail":"Đề Hồn thú cao không quá một thước, toàn thân lông phát quang xanh lục, cái mũi to chiếm hai phần ba khuôn mặt. Đây không phải linh thú bình thường mà là sản phẩm của bí thuật môn phái cùng huyết tế tà pháp, thuộc dạng tiến hóa giữa linh thú và yêu hồn. Khi Đề Hồn thú xuất hiện, Cát Lạp kinh hãi cảnh báo rằng nó có thể khiến tu tiên giới đại loạn, cho thấy sự hiếm có và nguy hiểm tiềm tàng của loài thú này. Lần đầu lộ diện khi tu sĩ áo đen ma đạo triệu hồi nó rồi một mình xông vào vùng quỷ vụ bên trong Hư Thiên Điện @c0437. Về sau, Hàn Lập lấy Đề Hồn thú làm điều kiện giao dịch, đổi cho Nguyên Dao để đổi lấy việc được hộ tống qua Dung Nham lộ; Nguyên Dao đồng ý hết sức sốt sắng, cho thấy giá trị to lớn của con thú trong mắt tu sĩ @c0462.","congNang":["Dùng mũi hút quỷ hồn vào bụng, không đầy ba khắc đã luyện hóa xong @c0437","Có khả năng hấp hồn hóa quỷ @c0437"],"hinhDang":"Giống khỉ nhỏ, cao không quá một thước, lông phát quang xanh lục, mũi to chiếm hai phần ba khuôn mặt","nguonGoc":"Được tế luyện bằng bí thuật môn phái kết hợp huyết tế tà pháp, là dạng tiến hóa giữa linh thú và yêu hồn","chuSoHuu":[{"ten":"Hắc bào nữ tu","tuChuong":"@c0437","denChuong":"","cachCoDuoc":"Tế luyện","trangThai":"dang-dung"},{"ten":"Nguyên Dao","tuChuong":"@c0454","denChuong":"@c0462","cachCoDuoc":"Không rõ","trangThai":"da-giao"},{"ten":"Hàn Lập","tuChuong":"@c0462","denChuong":"","cachCoDuoc":"Đổi lấy bằng việc hộ tống Nguyên Dao qua Dung Nham lộ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0437","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Tu sĩ áo đen ma đạo triệu hồi Đề Hồn thú khi xông vào vùng quỷ vụ trong Hư Thiên Điện. Cát Lạp kinh hãi nhận ra, Tử Linh giải thích bản chất tế luyện và năng lực hấp hồn của con thú.","anchor":"nó chỉ cần dùng cái mũi nhẹ nhàng hút một phát vào trong bụng, không đầy ba khắc sẽ bị luyện hóa"},{"chuong":"@c0462","loai":"đổi chủ","importance":"major","giaiDoan":"Đổi chủ sang Hàn Lập","text":"Hàn Lập đặt điều kiện đổi Đề Hồn Thú lấy việc hộ tống Nguyên Dao qua Dung Nham lộ. Nguyên Dao đồng ý sốt sắng, giao túi linh thú.","anchor":"tại hạ rất tò mò đối với con thú có khả năng hấp hồn hóa quỷ đó"}]},"nguon":["@c0437","@c0462","@c0516"],"dacDiem":"Cao không quá một thước, toàn thân lông phát quang xanh lục, cái mũi to chiếm hai phần ba khuôn mặt. Là dạng tiến hóa giữa linh thú và yêu hồn, phải dùng bí thuật môn phái cùng huyết tế tà pháp mới tế luyện được. Cát Lạp cảnh báo sự tồn tại của nó có thể khiến tu tiên giới đại loạn, cho thấy mức độ "},{"id":"o-hong-sac-nho","name":"Ô hồng sắc nhỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"","soHuu":["Cát Lạp"],"trangThai":"dang-dung","blurb":"Pháp khí hình chiếc ô nhỏ màu hồng của Cát Lạp, xoay trên đầu phát hồng quang bao bọc toàn thân phòng hộ trong quỷ vụ.","detail":"Chiếc ô nhỏ màu hồng, xoay ở độ cao khoảng trượng trên đầu Cát Lạp, phát hồng quang bao bọc phòng hộ. Quỷ vụ tiếp xúc hồng quang phát ra tiếng xèo xèo và khói xanh quỷ dị, không thể xâm nhập.","congNang":["Phát hồng quang bao bọc phòng hộ, quỷ khí không xâm nhập được"],"chuSoHuu":[{"ten":"Cát Lạp","tuChuong":"@c0438","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0438","loai":"dùng","importance":"normal","giaiDoan":"Phòng hộ trong quỷ vụ","text":"Cát Lạp thả ô hồng sắc nhỏ xoay trên đầu phát hồng quang bao bọc phòng hộ khi tiến vào quỷ vụ.","anchor":"Cát Lạp khoát tay thả ra một cái ô hồng sắc nhỏ, chuyển động từ từ ở độ cao khoảng trượng trên đầu"}]},"nguon":["@c0438"]},{"id":"ich-hoa-bao-y","name":"Ích Hỏa Bảo Y","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"","soHuu":["Ngọc chân nhân"],"trangThai":"chu-da-chet","blurb":"Bảo y luyện từ băng tằm ti trăm năm, lửa không thể tiếp cận thân thể, thuộc về Ngọc chân nhân. Cát Lạp nhận dạng di hài nhờ bảo vật này.","detail":"Áo bảo hộ luyện từ băng tằm ti trăm năm, miễn nhiễm hỏa công (lửa chạm vào tắt lập tức). Có chút danh tiếng trong giới tu sĩ. Hiện vẫn trên di hài Ngọc chân nhân trong quỷ vụ, áo vẫn lóe thanh quang dù chủ nhân đã chết từ lâu.","congNang":["Miễn nhiễm hỏa công, lửa không thể tiếp cận thân thể"],"vatLieu":"Băng tằm ti trăm năm","chuSoHuu":[{"ten":"Ngọc chân nhân","tuChuong":"@c0438","denChuong":"","cachCoDuoc":"","trangThai":"chu-da-chet"}],"tabs":{"tienTrinh":[{"chuong":"@c0438","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện trên di hài trong quỷ vụ","text":"Cát Lạp bắn hỏa cầu vào áo xanh trên di hài, lửa tắt lập tức, xác nhận là Ích Hỏa Bảo Y của Ngọc chân nhân.","anchor":"Trên người có cái Ích Hỏa BảoY này đã dùng băng tằm ti trăm năm luyện thành, lửa không thể tiếp cận thân thể"}]},"nguon":["@c0438"]},{"id":"phi-chuy-mau-hong","name":"Phi chuỳ màu hồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hắc bào nữ tu"],"trangThai":"dang-co","blurb":"Pháp bảo của người áo đen (tu ma), hình dáng quái dị, phun ra hoả cầu màu lam tấn công.","detail":"Phi chuỳ màu đỏ quái dị, phun ra vô số viên hoả cầu màu lam giao đấu với quỷ ảnh. Bị lục châu của quỷ ảnh phun Huyền Âm hàn khí bao vây hoàn toàn, hoả diễm dần tắt. Sau khi Hàn Lập ra tay giải vây, người áo đen thu hồi lại được.","congNang":["Phun hoả cầu màu lam tấn công"],"chuSoHuu":[{"ten":"Hắc bào nữ tu","tuChuong":"@c0440","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0440","loai":"dùng","importance":"normal","giaiDoan":"Đấu quỷ ảnh trong Quỷ vụ","text":"Người áo đen huy động phi chuỳ phun hoả cầu lam đấu quỷ ảnh nhưng bị lục châu áp chế, hoả diễm dần tắt. Sau khi Hàn Lập can thiệp mới thu hồi được.","anchor":"huy động một thanh thùy màu đỏ quái dị, phun ra vô số viên hoả cầu màu lam"}]},"nguon":["@c0440"]},{"id":"luc-chau","name":"Lục châu","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Viên châu lớn bằng ngón tay cái của quỷ ảnh, phun ra Huyền Âm hàn khí đen kịt áp chế đối thủ.","detail":"Viên lục châu lớn bằng ngón tay cái, thuộc về quỷ ảnh trong Quỷ vụ. Phun ra Huyền Âm hàn khí đen kịt, vây khốn và áp chế phi chuỳ màu hồng của người áo đen, chiếm thế thượng phong hoàn toàn.","congNang":["Phun Huyền Âm hàn khí đen kịt áp chế đối thủ"],"tabs":{"tienTrinh":[{"chuong":"@c0440","loai":"dùng","importance":"normal","giaiDoan":"Quỷ ảnh dùng áp chế người áo đen","text":"Quỷ ảnh liên tục xuất lục châu phun Huyền Âm hàn khí đen kịt bao vây phi chuỳ của người áo đen, chiếm thế thượng phong hoàn toàn.","anchor":"liên tục xuất ra một viên lục châu lớn bằng ngón tay cái phun ra Huyền Âm hàn khí đen kịt"}]},"nguon":["@c0440"]},{"id":"guong-dong-co-hac-y-nhan","name":"Gương đồng cổ của hắc y nhân","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hắc bào nữ tu"],"trangThai":"hong","blurb":"Cổ bảo gương đồng cũ kĩ mang theo trong người hắc y nhân, phát bạch quang hình cự điểu xua đuổi quỷ vật cứu mạng chủ nhân, nhưng dùng xong liền nứt vỡ thành phế phẩm.","detail":"Chiếc gương đồng cổ nằm trong áo hắc y nhân, khi quỷ ảnh xám sắp xuyên thủng hắn thì tự động phát ra bạch quang, trong quầng sáng xuất hiện hình ảnh giống cự điểu, khiến quỷ ảnh kinh sợ thối lui. Tuy nhiên, mặt gương sau đó nứt thành bảy tám phần, linh khí ẩn chứa bên trong biến mất, trở thành vật bỏ đi.","congNang":["Phát bạch quang hình cự điểu xua đuổi quỷ vật"],"dacDiem":"Dùng xong liền hỏng, chỉ phát huy được 1 lần","chuSoHuu":[{"ten":"Hắc bào nữ tu","tuChuong":"@c0441","denChuong":"","cachCoDuoc":"","trangThai":"hong"}],"capNhatToi":"@c0441","tabs":{"tienTrinh":[{"chuong":"@c0441","loai":"dung","importance":"normal","giaiDoan":"Phát bạch quang cứu mạng rồi vỡ nát","text":"Bạch quang hình cự điểu lóe lên xua đuổi quỷ ảnh xám cứu mạng hắc y nhân. Gương nứt thành bảy tám phần, linh khí biến mất, trở thành phế phẩm.","anchor":"Mặt gương đột nhiên nứt ra thành bảy, tám phần, khiến cho linh khí ẩn chứa trong nó liền biến mất vô ảnh vô tung"}]},"nguon":["@c0441"]},{"id":"quy-chau-mau-xanh","name":"Quỷ châu màu xanh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quỷ ảnh đen"],"trangThai":"dang-dung","blurb":"Quỷ châu màu xanh vốn là hộ thân pháp bảo bình thường của một tu sĩ đã chết, được quỷ ảnh đen nhặt lại và trải hơn trăm năm Huyền Âm quỷ khí bồi luyện. Bên trong phong ấn khí linh yêu hổ đen, khi kích hoạt có thể hóa hình thực thể khổng lồ phun lân hỏa xanh biếc, uy lực cực mãnh.","detail":"Viên quỷ châu màu xanh nguyên chỉ là một hộ thân pháp bảo tầm thường của tu sĩ đã mất, về sau bị quỷ ảnh đen nhặt được. Trải hơn trăm năm được Huyền Âm quỷ khí ngày đêm bồi luyện, viên châu biến đổi bản chất, có thể phun ra Huyền Âm hàn khí và ma khí mang đặc tính xâm thực linh tính, dùng để vây khốn và áp chế pháp bảo của đối thủ. Ngoài ra, bên trong viên châu còn phong ấn khí linh yêu hổ đen — khi quỷ ảnh đen dùng quỷ trảo kích hoạt, khí linh này hóa thành một yêu hổ thực thể khổng lồ, mắt lớn tựa chuông, có khả năng phun lân hỏa xanh biếc, uy mãnh phi thường.","congNang":["Phun Huyền Âm hàn khí và ma khí có đặc tính thương tổn linh tính pháp bảo, vây khốn pháp bảo đối thủ","Kích hoạt khí linh yêu hổ đen phong ấn bên trong, hóa thành yêu hổ thực thể khổng lồ phun lân hỏa xanh biếc (@c0441)"],"dacDiem":"Trải hơn trăm năm quỷ khí bồi luyện, bên trong phong ấn khí linh yêu hổ đen.","chuSoHuu":[{"ten":"Quỷ ảnh đen","tuChuong":"@c0441","denChuong":"","cachCoDuoc":"Nhặt từ tu sĩ đã chết","trangThai":"dang-dung"}],"capNhatToi":"@c0441","tabs":{"tienTrinh":[{"chuong":"@c0441","loai":"khai-phong","importance":"major","giaiDoan":"Kích hoạt khí linh yêu hổ lần đầu","text":"Quỷ ảnh đen dùng quỷ trảo kích hoạt quỷ châu, khí linh yêu hổ đen bên trong hóa thành thực thể khổng lồ phun lân hỏa xanh biếc đối đầu Thanh Trúc Phong Vân kiếm của Hàn Lập.","anchor":"viên quỷ châu màu xanh tuy chỉ là hộ thân pháp bảo cực kỳ bình thường của một tu sĩ đã chết nhưng sau khi yêu quỷ nhặt được, trải qua hơn trăm năm được Huyền Âm quỷ khí bồi luyện"}]},"nguon":["@c0441"],"uyLuc":"Khí linh yêu hổ đen khi được kích hoạt hóa thành thực thể khổng lồ, mắt như chuông, phun lân hỏa xanh biếc, uy lực cực kỳ mãnh liệt."},{"id":"bia-da-tu-linh","name":"Bia đá hình chữ nhật","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tử Linh tiên tử"],"trangThai":"đang sử dụng","blurb":"Pháp bảo phòng ngự của Tử Linh tiên tử, tạo hào quang che giấu và bảo vệ bản thân khi chiến đấu với ác quỷ trong Quỷ oan chi địa.","detail":"Tấm bia đá hình chữ nhật, khi kích hoạt phát ra hào quang bao bọc chủ nhân bên trong, có tác dụng phòng ngự. Tử Linh tiên tử dùng để tự bảo vệ khi đối đầu ác quỷ, chỉ phòng thủ mà không tấn công.","congNang":["Tạo hào quang phòng ngự bao bọc chủ nhân"],"tabs":{"tienTrinh":[{"chuong":"@c0443","loai":"dùng","importance":"normal","giaiDoan":"Quỷ oan chi địa","text":"Tử Linh tiên tử dùng bia đá tạo hào quang che giấu bản thân, chỉ phòng ngự khi chiến đấu với ác quỷ.","anchor":"bằng một tấm bia đá hình chữ nhật, đem mình giấu ở trong hào quang"}]},"nguon":["@c0443"]},{"id":"diet-ma-tien","name":"Diệt Ma tiễn","cn":"滅魔箭","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Huyền Cốt thượng nhân"],"trangThai":"dang-co","blurb":"Mũi tên luyện chế từ đoạn Kim Lôi trúc duy nhất của Huyền Cốt thượng nhân, có uy hiếp lớn với quỷ tu và yêu vật. Đồng minh quỷ đạo trong đầu Huyền Cốt từng nếm đau khổ bởi nó.","detail":"Được Huyền Cốt nhắc tới khi đối thoại với đồng minh: luyện từ đoạn Kim Lôi trúc duy nhất mà hắn có. Đồng minh giọng hùng hậu từng nếm đau khổ bởi Diệt Ma tiễn, chứng tỏ uy lực khắc chế quỷ vật rất mạnh.","congNang":["Uy hiếp quỷ tu và yêu vật","Khắc chế thực thể quỷ đạo"],"nguon":["@c0446"]},{"id":"co-truyen-tong-tran","name":"Cổ truyền tống trận","cn":"","category":"khac","categoryLabel":"Trận pháp","phamCap":"Cổ trận","soHuu":[],"trangThai":"hoạt động","blurb":"Trận pháp truyền tống cổ xưa xuất hiện trên phiến đá nhẵn trung tâm trong Hư Thiên Điện, là phương pháp duy nhất dẫn tới các cửa ải tiếp theo.","detail":"Sau một ngày chờ đợi, trận pháp xuất hiện bạch quang trên phiến đá nhẵn trung tâm, hình dáng kích thước giống lần trước. Lần này dẫn tới Băng Hỏa đạo (cửa ải thứ hai). Hai trưởng lão Tinh Cung và các tu sĩ lần lượt bước vào truyền tống.","tabs":{"tienTrinh":[{"chuong":"@c0447","loai":"dùng","importance":"normal","giaiDoan":"Truyền tống lần hai tới Băng Hỏa đạo","text":"Cổ truyền tống trận xuất hiện lần hai, dẫn tới Băng Hỏa đạo. Hai trưởng lão Tinh Cung dẫm lên trận biến mất trước, các tu sĩ lần lượt bước vào.","anchor":"Cái truyền tống trận này là phương pháp duy nhất để đi tới Băng Hoả đạo"}]},"capNhatToi":"@c0447","nguon":["@c0447"]},{"id":"kim-ti-cau","name":"Kim Ti cầu","aliases":["Kim Ti võng"],"cn":"金絲球","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Kim Ti cầu là quả cầu thuần kim to bằng trứng gà, khi kích hoạt sẽ phun kim ti kết thành Kim Ti võng — lưới thuần kim duy nhất có khả năng bắt giữ Cửu Khúc Linh Sâm. Ban đầu thuộc về Huyền Cốt thượng nhân, được giao cho Hàn Lập sử dụng.","detail":"Kim Ti cầu là quả cầu màu vàng óng ánh, kích thước bằng trứng gà, được luyện chế đặc thù từ chất liệu thuần kim. Khi được kích hoạt bằng hắc quang, quả cầu phun ra vô số kim ti đan xen kết thành Kim Ti võng có kích thước khoảng bàn tay. Huyền Cốt thượng nhân giải thích rằng Cửu Khúc Linh Sâm có thể độn tẩu thoát khỏi mọi pháp bảo hay đồ vật thông thường, chỉ đồ vật thuần kim mới có thể bắt giữ được nó, và Kim Ti cầu chính là vật chuyên dụng cho mục đích này. Huyền Cốt đã giao Kim Ti cầu cho Hàn Lập để thực hiện việc thu phục Cửu Khúc Linh Sâm.","congNang":["Phun kim ti kết thành Kim Ti võng — lưới thuần kim chuyên dùng bắt giữ Cửu Khúc Linh Sâm @c0449"],"phanLoaiPhu":"Pháp khí bắt linh vật","hinhDang":"Quả cầu to bằng trứng gà, màu vàng óng ánh","vatLieu":"Thuần kim","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Huyền Cốt thượng nhân","tuChuong":"@c0449","denChuong":"@c0449","cachCoDuoc":"Luyện chế","trangThai":"da-giao"},{"ten":"Hàn Lập","tuChuong":"@c0449","denChuong":"","cachCoDuoc":"Được Huyền Cốt giao","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0449","loai":"xuất hiện","importance":"major","giaiDoan":"Huyền Cốt giao cho Hàn Lập","text":"Huyền Cốt lấy ra Kim Ti cầu, kích hoạt phun kim ti kết thành Kim Ti võng. Giải thích chỉ đồ vật thuần kim mới bắt được Cửu Khúc Linh Sâm, giao cho Hàn Lập.","anchor":"Cửu Khúc Linh Sâm chỉ có đồ vật thuần kim thì mới có khả năng bắt giữ"}]},"nguon":["@c0449"],"dacDiem":"Quả cầu thuần kim to bằng trứng gà, màu vàng óng ánh, kích hoạt bằng hắc quang; là vật thuần kim duy nhất có thể bắt giữ Cửu Khúc Linh Sâm mà Linh Sâm không thể độn tẩu thoát."},{"id":"bon-tran-ky-tu-tuong-huyen-vu","name":"Bốn trận kỳ Tứ Tượng Huyền Vũ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo (trận kỳ)","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Bốn cây cờ nhỏ màu vàng đất phủ phù văn, khí cụ bày Tứ Tượng Huyền Vũ trận. Đã bị Huyền Cốt bí mật cài bẫy.","detail":"Bốn cây cờ nhỏ màu vàng đất phủ đầy phù văn, hào quang lờ mờ chớp động. Do Huyền Cốt thượng nhân luyện chế, là khí cụ bày Tứ Tượng Huyền Vũ trận. Huyền Cốt đã bí mật động tay chân lên trận kỳ trước khi giao cho Hàn Lập bố trí, cài bẫy nhằm phản bội Hàn Lập sau khi bắt được Cửu Khúc Linh Sâm.","hinhDang":"Bốn cây cờ nhỏ màu vàng đất phủ đầy phù văn","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Huyền Cốt thượng nhân","tuChuong":"@c0449","denChuong":"@c0449","cachCoDuoc":"Tự luyện chế","trangThai":"da-giao"},{"ten":"Hàn Lập","tuChuong":"@c0449","denChuong":"","cachCoDuoc":"Được Huyền Cốt giao","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0449","loai":"xuất hiện","importance":"normal","giaiDoan":"Huyền Cốt giao trận kỳ đã cài bẫy cho Hàn Lập","text":"Huyền Cốt lấy ra bốn trận kỳ màu vàng đất, giao cho Hàn Lập bố trí. Đã bí mật cài bẫy trên trận kỳ.","anchor":"Chẳng lẽ ngươi đã động tay động chân lên trận kỳ đó rồi sao?"}]},"nguon":["@c0449"]},{"id":"tran-ky-tho-thuoc-tinh-huyen-cot","name":"Trận kỳ thổ thuộc tính (của Huyền Cốt)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Huyền Cốt thượng nhân"],"trangThai":"dang-dung","blurb":"Bộ trận kỳ thổ thuộc tính Huyền Cốt đưa cho Hàn Lập bày trận bắt Cửu Khúc Linh Sâm, thực chất ẩn chứa gian kế.","detail":"Bộ trận kỳ nhỏ màu vàng mang linh khí thổ thuộc tính do Huyền Cốt cung cấp cho Hàn Lập dùng bày trận. Huyền Cốt giữ riêng một cây cờ mẫu tinh xảo giống y đúc (ngắn hơn một chút) để kiểm tra và kiểm soát/kích hoạt từ xa. Khi lão dùng cờ mẫu kiểm tra, đạo quang vàng bay xuống chứng tỏ trận kỳ đang hoạt động, xác nhận xong lão mặt lộ vẻ độc ác — cho thấy bộ cờ quả chứa bẫy.","congNang":["Bày trận khống chế mục tiêu","Cờ mẫu kiểm soát/kích hoạt từ xa"],"chuSoHuu":[{"ten":"Huyền Cốt thượng nhân","tuChuong":"@c0450","denChuong":"","cachCoDuoc":"Tự có","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0450","loai":"dùng","importance":"normal","giaiDoan":"Đưa cho Hàn Lập bày trận","text":"Huyền Cốt đưa trận kỳ cho Hàn Lập bày trận bắt Cửu Khúc Linh Sâm, sau đó dùng cờ mẫu kiểm tra xác nhận Hàn Lập dùng đúng loại, mặt lộ vẻ độc ác cho thấy cờ ẩn chứa gian kế. Tuy nhiên Hàn Lập đã bí mật thay bằng bộ cờ riêng.","anchor":"Cây cờ này cực kỳ tinh xảo, tuy có ngắn hơn nhưng giống y đúc những cây cờ mà hắn đưa cho Hàn Lập"}]},"nguon":["@c0450"]},{"id":"tran-ky-tho-thuoc-tinh-han-lap","name":"Trận kỳ thổ thuộc tính (của Hàn Lập)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Hơn mười cây cờ nhỏ màu vàng tản ra linh khí thổ thuộc tính nồng đậm mà Hàn Lập tự chuẩn bị, bí mật dùng thay thế bộ cờ gian kế của Huyền Cốt.","detail":"Bộ trận kỳ riêng Hàn Lập lấy từ túi trữ vật, gồm hơn mười cây cờ nhỏ màu vàng giống với loại Huyền Cốt đưa, tản ra linh khí thổ thuộc tính cực kỳ nồng đậm. Hàn Lập bí mật thay thế để đề phòng gian kế, khiến Huyền Cốt khi kiểm tra bằng cờ mẫu vẫn nhầm tưởng đúng loại.","congNang":["Bày trận thổ thuộc tính","Linh khí thổ thuộc tính đủ giống loại của Huyền Cốt để đánh lừa kiểm tra"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0450","denChuong":"","cachCoDuoc":"Tự chuẩn bị sẵn","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0450","loai":"dùng","importance":"normal","giaiDoan":"Thay thế bộ cờ gian kế","text":"Hàn Lập lấy ra hơn mười cây cờ nhỏ thổ thuộc tính riêng thay thế bộ trận kỳ gian kế của Huyền Cốt, đánh lừa thành công việc kiểm tra bằng cờ mẫu.","anchor":"từ trong túi trữ vật hắn lấy ra hơn mười cây cờ nhỏ màu vàng tương tự, tản ra linh khí thổ thuộc tính cực kỳ nồng đậm"}]},"nguon":["@c0450"]},{"id":"am-hon-ti","name":"Âm Hồn ti","cn":"阴魂丝","category":"khac","categoryLabel":"Tà vật","phamCap":"Không rõ","soHuu":["Huyền Cốt thượng nhân"],"trangThai":"da-bi-huy","blurb":"Âm Hồn ti là tà vật dạng tia nhỏ màu đen tỏa âm khí, được Huyền Cốt cài giấu trên Kim Ti võng nhằm khống chế pháp lực mục tiêu khi kích hoạt. Khi phát tác, nhiều tia đen quấn quanh thân nạn nhân khiến chân nguyên đông cứng hoàn toàn, rất khó phát hiện dù kiểm tra kỹ pháp khí mang theo.","detail":"Âm Hồn ti là loại tà vật được Huyền Cốt bí mật cài đặt lên Kim Ti võng trước khi giao cho Hàn Lập, nhằm mục đích khống chế hắn vào thời điểm then chốt. Hình dạng là nhiều tia nhỏ màu đen, khi kích hoạt sẽ quấn quanh thân thể nạn nhân và tỏa ra âm khí, khiến chân nguyên trong cơ thể bị đông cứng, không thể vận dụng pháp lực. Đặc tính nguy hiểm nhất của Âm Hồn ti nằm ở khả năng ẩn giấu cực kỳ tinh vi — Hàn Lập đã nhiều lần kiểm tra Kim Ti võng mà không hề phát hiện bất thường. Khi phát tác trên thân Hàn Lập, Phệ Kim Trùng đã cắn xé được gần phân nửa số Âm Hồn ti; phần còn lại bị điện hồ Ích Tà Thần Lôi hủy diệt hoàn toàn.","congNang":["Khống chế và đông cứng pháp lực chân nguyên của mục tiêu khi được kích hoạt, khiến nạn nhân không thể vận dụng pháp lực @c0452","Có thể cài giấu lên pháp khí khác mà cực kỳ khó bị phát hiện, ngay cả khi chủ nhân pháp khí kiểm tra nhiều lần @c0452"],"chuSoHuu":[{"ten":"Huyền Cốt thượng nhân","tuChuong":"@c0452","denChuong":"","cachCoDuoc":"Tự cài đặt","trangThai":"da-bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c0452","loai":"xuất hiện","importance":"major","giaiDoan":"Phát tác khống chế Hàn Lập rồi bị hủy","text":"Phát tác trên thân Hàn Lập, hắc khí quấn quanh khiến pháp lực đông cứng. Bị Phệ Kim Trùng cắn xé gần phân nửa, sau đó bị Ích Tà Thần Lôi hủy diệt hoàn toàn.","anchor":"Có rất nhiều tia nhỏ màu đen quấn quanh mình của hắn, nhàn nhạt toả ra âm khí"}]},"nguon":["@c0452"],"uyLuc":"Khi phát tác, hắc khí quấn quanh toàn thân khiến chân nguyên mục tiêu đông cứng hoàn toàn, mất khả năng sử dụng pháp lực.","dacDiem":"Hình dạng nhiều tia nhỏ màu đen tỏa âm khí, khả năng ẩn giấu cực kỳ tinh vi khi cài lên pháp khí khác, rất khó bị phát hiện dù kiểm tra kỹ lưỡng."},{"id":"vien-chau-xanh-biec","name":"Viên châu xanh biếc","cn":"","category":"khac","categoryLabel":"Nguyên thần vật","phamCap":"Không rõ","soHuu":["Nam tử lệ hồn"],"trangThai":"da-bi-huy","blurb":"Nguyên thần của gã bóng xanh ngưng tụ thành viên châu lóe hào quang quỷ dị, mang toàn bộ thần hồn quỷ ảnh.","detail":"Sau khi quỷ đầu bị Ích Tà Thần Lôi đánh tan, lục khí tán thành đoàn bỏ chạy, Hàn Lập đuổi theo chụp bắt viên châu nguyên thần xanh biếc rồi bóp nát dưới điện hồ trên năm ngón tay.","tabs":{"tienTrinh":[{"chuong":"@c0452","loai":"xuất hiện","importance":"normal","giaiDoan":"Ngưng tụ rồi bị bóp nát","text":"Nguyên thần gã bóng xanh ngưng tụ thành viên châu xanh biếc, bị Hàn Lập chụp bắt và bóp nát dưới điện hồ Ích Tà Thần Lôi.","anchor":"trên tay Hàn Lập đã xuất hiện một viên châu màu xanh biếc, lóe lên hào quanh quỉ dị"}]},"nguon":["@c0452"]},{"id":"huyet-ngoc-tri-chu","name":"Huyết Ngọc Tri Chu","cn":"血玉蜘蛛","aliases":["Huyết ngọc tri thù"],"category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ (cả hai Nguyên Anh kỳ đều cực kỳ thèm muốn)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Huyết Ngọc Tri Chu là linh thú nhện huyết ngọc to bằng cối xay, chứa đại bí mật liên quan đến nội điện Hư Thiên Điện khiến cả hai cường giả Nguyên Anh kỳ — Cực Âm lão tổ và Huyền Cốt — đều phản ứng dữ dội khi nhìn thấy. Bí mật thật sự của nó chưa được tiết lộ tính tới mốc hiện có trong tiến trình.","detail":"Huyết Ngọc Tri Chu hiện thân dưới dạng con nhện to bằng cối xay. Cực Âm lão tổ lần theo đoạn tơ nhện trắng thu được từ trận chiến với Ẩn Sát môn để tìm đến Hàn Lập. Khi nhìn thấy Huyết Ngọc Tri Chu, Cực Âm lão tổ mắt như phát hỏa, lộ rõ tia tham lam, trong khi Huyền Cốt thì hối hận kinh sợ. Phản ứng mãnh liệt của hai vị Nguyên Anh kỳ cường giả cho thấy bí mật mà Huyết Ngọc Tri Chu nắm giữ có tầm quan trọng phi thường, liên quan đến nội điện Hư Thiên Điện, song chi tiết cụ thể chưa được tiết lộ trong phạm vi tiến trình đã xác nhận.","congNang":["Phun tơ nhện trắng bền chắc @c0454","Chứa đại bí mật liên quan đến nội điện Hư Thiên Điện, chưa được tiết lộ @c0454"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0454","denChuong":"","cachCoDuoc":"Thu phục trước đó","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0454","loai":"xuất hiện","importance":"major","giaiDoan":"Bị Cực Âm lão tổ phát hiện, trung tâm tranh đoạt","text":"Cực Âm lão tổ dùng đoạn tơ nhện thu được từ trận Ẩn Sát môn lần ra Hàn Lập. Huyết Ngọc Tri Chu hiện thân dưới dạng nhện to bằng cối xay. Cả Cực Âm lẫn Huyền Cốt đều phản ứng cực mạnh, cho thấy nó chứa đại bí mật liên quan hai Nguyên Anh kỳ.","anchor":"Quả nhiên là Huyết Ngọc Tri Chu! Ha ha…"}]},"capNhatToi":"@c0454","nguon":["@c0454"],"dacDiem":"Hình dạng nhện to bằng cối xay; sự xuất hiện của nó khiến cả hai cường giả Nguyên Anh kỳ phản ứng dữ dội — Cực Âm lão tổ lộ tham, Huyền Cốt kinh sợ hối hận."},{"id":"huyen-am-hoan","name":"Huyền Âm hoàn","cn":"玄阴环","aliases":["Âm Dương hoàn (phần Âm)","Âm hoàn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Huyền Âm hoàn là chiếc nhẫn màu xám khắc phù văn cổ thần bí phát u quang xanh lam, thực chất là phần Âm của cặp Âm Dương hoàn do Huyền Cốt chế tạo và ban cho Cực Âm tổ sư năm xưa. Cực Âm tổ sư đổi tên thành Huyền Âm hoàn rồi trao cho Hàn Lập làm tín vật đệ tử thân truyền kiêm bảo vật phòng thân.","detail":"Nguyên là một nửa của cặp Âm Dương hoàn do Huyền Cốt chế tạo, phần Âm hoàn được Huyền Cốt ban cho Cực Âm tổ sư. Về sau Cực Âm tổ sư đổi tên thành Huyền Âm hoàn và rút từ tay mình trao cho Hàn Lập, vừa làm tín vật chứng minh thân phận đệ tử thân truyền, vừa là bảo vật phòng thân. Tuy nhiên, phần Dương hoàn vẫn nằm trên người Cực Âm tổ sư và có khả năng khắc chế Âm hoàn, khiến Hàn Lập không thể dùng Huyền Âm hoàn để chống lại Cực Âm. Huyền Cốt từng cảnh báo Hàn Lập rằng dùng Âm hoàn chống Cực Âm là tự tìm đường chết.","phanLoaiPhu":"nhẫn","hinhDang":"Nhẫn màu xám, mặt có phù văn cổ thần bí phát u quang xanh lam","nguonGoc":"Phần Âm của cặp Âm Dương hoàn, do Huyền Cốt chế tạo và ban cho Cực Âm năm xưa","dacDiem":"Bị Dương hoàn trên người Cực Âm tổ sư khắc chế, không thể dùng để chống lại Cực Âm. Ngoại hình là chiếc nhẫn màu xám khắc phù văn cổ thần bí, phát u quang xanh lam.","chuHienThoi":"Hàn Lập","congNang":["Khắc địch hộ chủ — có công hiệu tự động bảo vệ chủ nhân và khắc chế đối phương @c0456"],"chuSoHuu":[{"ten":"Huyền Cốt","tuChuong":"","denChuong":"","cachCoDuoc":"Tự chế tạo","trangThai":"da-trao"},{"ten":"Cực Âm lão tổ","tuChuong":"","denChuong":"@c0456","cachCoDuoc":"Huyền Cốt ban cho","trangThai":"da-trao"},{"ten":"Hàn Lập","tuChuong":"@c0456","denChuong":"","cachCoDuoc":"Cực Âm tổ sư trao làm tín vật ký danh đệ tử","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0456","loai":"đổi chủ","importance":"major","giaiDoan":"Cực Âm trao cho Hàn Lập","text":"Cực Âm tổ sư rút từ tay trao cho Hàn Lập làm tín vật đệ tử thân truyền và bảo vật phòng thân. Huyền Cốt tiết lộ lai lịch thật: là phần Âm của cặp Âm Dương hoàn do Huyền Cốt ban cho Cực Âm năm xưa, bị Dương hoàn trên người Cực Âm khắc chế.","anchor":"Âm hoàn này tuy có công hiệu khắc địch hộ chủ nhưng lại bị Dương hoàn trên người của hắn ta khắc chế"}]},"capNhatToi":"@c0456","dinhDanh":"goc","nguon":["@c0456"]},{"id":"noi-dan-bang-tuyet-thiem","name":"Nội đan Băng Tuyết thiềm","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Man Hồ Tử"],"trangThai":"dang-co","blurb":"Nội đan lấy từ con Băng Tuyết thiềm bị Man Hồ Tử giết gần chỗ Thọ Nguyên quả, có tác dụng lớn đối với Thác Thiên ma công.","detail":"Man Hồ Tử giết một con Băng Tuyết thiềm ở gần vị trí Thọ Nguyên quả, thu lấy nội đan. Nội đan này có tác dụng rất lớn đối với việc tinh tiến Thác Thiên ma công của lão.","congNang":["Hỗ trợ tinh tiến Thác Thiên ma công"],"chuSoHuu":[{"ten":"Man Hồ Tử","tuChuong":"@c0457","denChuong":"","cachCoDuoc":"Giết Băng Tuyết thiềm lấy nội đan","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0457","loai":"xuất hiện","importance":"normal","giaiDoan":"Man Hồ Tử thu được","text":"Man Hồ Tử tiết lộ đã giết một con Băng Tuyết thiềm gần chỗ Thọ Nguyên quả, lấy nội đan có tác dụng lớn cho ma công.","anchor":"nội đan của nó có tác dụng rất lớn đối với ma công của ta"}]},"capNhatToi":"@c0457","nguon":["@c0457"]},{"id":"han-bang-chau","name":"Hàn Băng châu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp bảo do Man Hồ Tử cấp cho Hàn Lập, có khả năng bảo hộ toàn thân khỏi nhiệt dung nham, cứu mạng Hàn Lập trên Dung Nham lộ.","detail":"Hàn Băng châu do Man Hồ Tử cấp cho Hàn Lập trước khi vào Hư Thiên Điện. Khi Hàn Lập rơi vào ao đầm dung nham, Hàn Băng châu bảo vệ toàn thân, cứu mạng hắn khỏi dung nham ngầm.","congNang":["Bảo hộ toàn thân khỏi nhiệt dung nham"],"chuSoHuu":[{"ten":"Man Hồ Tử","tuChuong":"","denChuong":"@c0458","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0458","denChuong":"","cachCoDuoc":"Man Hồ Tử cấp cho","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0458","loai":"dung","importance":"normal","giaiDoan":"Cứu mạng trên Dung Nham lộ","text":"Hàn Lập sử dụng Hàn Băng châu bảo vệ toàn thân khi rơi vào ao đầm dung nham, cứu mạng.","anchor":"sớm sử dụng Hàn Băng châu của Man Hồ Tử cấp cho"}]},"nguon":["@c0458"]},{"id":"non-xanh-biec-ky-la","name":"Nón xanh biếc kỳ lạ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam tử mặt vàng"],"trangThai":"Đang dùng","blurb":"Chiếc nón hình dáng kỳ lạ màu xanh biếc của nam tử mặt vàng, có thể phóng tầng hộ tráo xanh bảo vệ toàn thân trong môi trường khốc liệt.","detail":"Nam tử mặt vàng đội nón này khi thăm dò hắc sa mạc, nón phóng xuất tầng hộ tráo màu xanh bao bọc toàn thân. Hàn Lập từng cân nhắc giết nam tử để đoạt lấy chiếc nón này.","congNang":["Phóng tầng hộ tráo xanh bảo vệ toàn thân trong môi trường khốc liệt"],"chuSoHuu":[{"ten":"Nam tử mặt vàng","tuChuong":"@c0459","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0459","loai":"xuất hiện","importance":"normal","giaiDoan":"Thăm dò hắc sa mạc","text":"Nam tử mặt vàng đội nón xanh biếc, phóng hộ tráo xanh bảo vệ toàn thân khi tiến vào hắc sa mạc.","anchor":"hắn đội cái nón hình dáng kỳ lạ màu xanh biếc"}]},"nguon":["@c0459"]},{"id":"bat-ngoc-trang","name":"Bát ngọc trắng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam tử mặt vàng"],"trangThai":"Đang dùng","blurb":"Bát ngọc màu trắng phát hàn khí của nam tử mặt vàng, bắn bạch quang ngưng kết băng lạnh, tạo băng thuẫn và cụ phong bảo hộ.","detail":"Nam tử mặt vàng dùng bát ngọc phóng bạch quang nổ tung thành tinh quang bao phủ vài chục trượng, ngưng kết băng trên mặt đất. Trong chiến đấu với kiến bay, bát ngọc tạo thêm tầng hộ tráo và vô số băng thuẫn nhỏ xoay tròn thành cụ phong đẩy lùi kiến bay, nhưng kiến bay không bị thương.","congNang":["Phát hàn khí","Phóng bạch quang ngưng kết băng lạnh","Tạo băng thuẫn xoay tròn hình thành cụ phong bảo hộ"],"chuSoHuu":[{"ten":"Nam tử mặt vàng","tuChuong":"@c0459","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0459","loai":"dùng","importance":"normal","giaiDoan":"Chiến đấu với kiến bay","text":"Nam tử mặt vàng dùng bát ngọc phóng bạch quang dò tìm trên đỉnh núi, sau đó tạo băng thuẫn cụ phong chống kiến bay nhưng không hiệu quả.","anchor":"tay cầm một cái bát ngọc màu trắng, tại địa phương khốc liệt như thế này mà trên thân vẫn lờ mờ phát ra hàn khí"}]},"nguon":["@c0459"]},{"id":"phi-dao-mau-xam","name":"Phi đao màu xám","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam tử mặt vàng"],"trangThai":"Đã bị phá hủy","blurb":"Phi đao pháp bảo màu xám của nam tử mặt vàng, hóa hào quang dài một trượng nhưng bị kiến bay bám đầy và phá hủy hoàn toàn, khiến chủ nhân nguyên khí đại thương.","detail":"Nam tử mặt vàng xuất phi đao chém kiến bay, phi đao hóa hào quang dài một trượng. Nhưng kiến bay bám đầy phi đao, sau mấy lần lóe hào quang liền bị phá hủy. Pháp bảo liên quan tâm thần bị hủy khiến nam tử phun máu nguyên khí đại thương.","congNang":["Hóa hào quang dài một trượng tấn công"],"chuSoHuu":[{"ten":"Nam tử mặt vàng","tuChuong":"@c0459","denChuong":"@c0459","cachCoDuoc":"","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c0459","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Bị kiến bay phá hủy","text":"Nam tử dùng phi đao chém kiến bay nhưng bị chúng bám đầy và phá hủy hoàn toàn, khiến chủ nhân nguyên khí đại thương.","anchor":"Phi đao sau mấy lần lóe lên hào quang liền bị đám kiến bay phá hủy"}]},"nguon":["@c0459"]},{"id":"thiet-hoa-kien","name":"Thiết Hỏa Kiến","category":"khac","categoryLabel":"Kỳ trùng","phamCap":"Xếp hạng 37 kỳ trùng bảng","soHuu":[],"trangThai":"hoang-da","blurb":"Thiết Hỏa Kiến là loài kỳ trùng xếp hạng 37 trên kỳ trùng bảng, sinh sống tại hắc sa mạc Hư Thiên Điện, miễn nhiễm đao thương và đa số pháp thuật, có thể phun lửa đen và biến hình quần thể thành pháp bảo hỏa thuộc tính. Không thể nhận chủ — mọi nghi thức nhận chủ đều khiến chúng tự nổ — và gần ngàn năm qua dần tuyệt tích, quy mô quần thể ngày càng nhỏ.","detail":"Thiết Hỏa Kiến là đàn kiến cánh cực kỳ nguy hiểm, xếp hạng thứ 37 trên kỳ trùng bảng, chỉ kém Thiên Tinh Kiến (hạng 9) trong số các loại kiến cánh. Chúng sinh tồn trong môi trường nhiệt độ cao và cần lượng lớn quặng đồng sắt; rời khỏi điều kiện này thì suy yếu, mất năng lực đặc thù. Đàn ở hắc sa mạc Hư Thiên Điện chưa tiến hóa thành dạng Hắc kim, tương đương nửa thời kỳ thành thục. Phòng ngự trực tiếp pháp bảo của Thiết Hỏa Kiến cao hơn Phệ Kim Trùng một bậc, miễn nhiễm đao thương và đa số pháp thuật, chỉ yếu trước thủy thuộc tính và trung cấp băng thuộc tính. Linh khí dao động như có như không, thu liễm khí tức tự nhiên khiến thần thức không dò ra được. Hạn chế chí mạng nhất là không thể nhận chủ: bất kỳ nghi thức nhận chủ nào cũng khiến chúng tự nổ. Gần ngàn năm rất ít ai gặp, quy mô quầ","congNang":["Phun lửa đen @c0460","Quần thể biến hình ngưng tụ thành pháp bảo hỏa thuộc tính như trường mâu, vũ khí @c0460","Miễn nhiễm đao thương và đa số pháp thuật, chỉ yếu trước thủy thuộc tính và trung cấp băng thuộc tính @c0460","Thu liễm khí tức tự nhiên, linh khí dao động như có như không, thần thức không dò ra được @c0460"],"dacDiem":"Không thể nhận chủ — bất kỳ nghi thức nhận chủ nào cũng khiến chúng tự nổ; cần môi trường nhiệt độ cao và lượng lớn quặng đồng sắt để sinh tồn, rời khỏi thì suy yếu mất năng lực đặc thù; xếp hạng 37 trên kỳ trùng bảng; phòng ngự trực tiếp pháp bảo cao hơn Phệ Kim Trùng một bậc.","tabs":{"tienTrinh":[{"chuong":"@c0460","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện tại hắc sa mạc Hư Thiên Điện","text":"Đàn Thiết Hỏa Kiến ngưng tụ thành trường mâu đen xuyên thủng ngực nam tử mặt vàng rồi cắn nuốt hoàn toàn. Hàn Lập nhận diện lai lịch, hồi tưởng tư liệu kỳ trùng bảng và tính toán dùng Phệ Kim Trùng đối phó.","anchor":"Trừ Thiên Tinh Kiến được xếp thứ chín trong truyền thuyết, có lẽ chỉ có loại Thiết Hỏa Kiến này là đáng sợ nhất"}]},"nguon":["@c0460"],"uyLuc":"Đàn kiến ngưng tụ thành trường mâu đen xuyên thủng ngực đối thủ rồi cắn nuốt hoàn toàn, thể hiện sức công kích tàn khốc của quần thể @c0460."},{"id":"vien-dan-bich-luc","name":"Viên đạn bích lục","cn":"","category":"phap-bao","categoryLabel":"Dị bảo","phamCap":"Không rõ","soHuu":["Nguyên Dao"],"trangThai":"dang-co","blurb":"Dị bảo dạng viên đạn màu bích lục, kích trúng mục tiêu tạo lục sắc hỏa diễm có thể khắc chế cả linh trùng hỏa thuộc tính. Số lượng rất hạn chế.","detail":"Nguyên Dao bắn ra kích vào kiếm hình do Thiết Hỏa Kiến tụ thành, biến thành ngọn lửa màu lục to chừng nắm tay thiêu đốt gần trăm con kiến. Hàn Lập kinh hãi vì dị bảo này khắc chế được cả linh trùng hỏa thuộc tính, nhận định trong tu tiên giới kỳ trân dị bảo vô cùng vô tận. Dường như số lượng hiếm, Nguyên Dao chỉ bắn một phát rồi không bắn thêm.","congNang":["Tạo lục sắc hỏa diễm khắc chế hỏa thuộc tính linh trùng"],"chuSoHuu":[{"ten":"Nguyên Dao","tuChuong":"@c0461","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0461","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Nguyên Dao bắn viên đạn bích lục vào kiếm hình Thiết Hỏa Kiến, tạo lục sắc hỏa diễm thiêu đốt gần trăm con kiến, khắc chế hỏa thuộc tính linh trùng. Số lượng dường như rất hạn chế.","anchor":"Viên đạn này kích vào hắc kiếm, \"choang\" một tiếng biến thành một ngọn lửa màu lục to chừng nắm tay"}]},"nguon":["@c0461"]},{"id":"thanh-hoa-loi","name":"Thanh Hỏa Lôi","cn":"青火雷","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dị bảo tiêu hao","soHuu":["Nguyên Dao"],"trangThai":"dang-co","blurb":"Loại bảo bối tiêu hao bí chế bởi Thanh Dương Môn ma đạo, uy lực tương đương nguyên dương hỏa của tu sĩ Nguyên Anh kỳ.","detail":"Lục sắc đạn trong suốt màu lục, nguyên liệu quý hiếm, thời gian luyện chế lâu. Nguyên Dao còn ba viên, đề nghị tặng toàn bộ cho Hàn Lập làm thù lao hộ tống qua Dung Nham lộ nhưng Hàn Lập cho rằng chưa đủ.","congNang":["Uy lực tương đương nguyên dương hỏa của Nguyên Anh kỳ tu sĩ","Khắc chế/chống lại Thiết Hỏa Kiến"],"nguonGoc":"Thanh Dương Môn ma đạo bí chế","dacDiem":"Lục sắc đạn trong suốt màu lục, nguyên liệu quý hiếm","tabs":{"tienTrinh":[{"chuong":"@c0462","loai":"xuất hiện","importance":"normal","giaiDoan":"Được đề nghị làm thù lao","text":"Nguyên Dao đề nghị tặng ba viên Thanh Hỏa Lôi còn lại cho Hàn Lập làm thù lao hộ tống qua Dung Nham lộ, nhưng Hàn Lập cho rằng chưa đủ.","anchor":"uy lực tương đương với nguyên dương hỏa của Nguyên Anh kỳ tu sĩ"},{"chuong":"@c0463","loai":"nhắc tới","importance":"normal","giaiDoan":"Nguyên Dao kể đã dùng chống Thiết Hỏa Kiến","text":"Nguyên Dao tiết lộ nhờ có Thanh Hỏa Lôi trên người mới cầm cự được trước đàn Thiết Hỏa Kiến trong hắc sa mạc.","anchor":"Nếu không phải trên người ta vừa lúc có một chút Thanh Hỏa Lôi, sợ rằng căn bản kiên trì không được"}]},"nguon":["@c0462","@c0463"],"chuSoHuu":[{"ten":"Nguyên Dao","tuChuong":"@c0463","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}]},{"id":"minh-hon-chau","name":"Minh Hồn Châu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nguyên Dao"],"trangThai":"Nguyên Dao giao cho Hàn Lập nhưng hắn chưa tiếp nhận","blurb":"Minh Hồn Châu là viên châu màu xám dùng để khống chế Đề Hồn Thú. Chỉ cần luyện hóa như pháp bảo bình thường, người sở hữu có thể khiến Đề Hồn Thú vĩnh viễn tuân phục. Nguyên Dao chủ động giao viên châu này cho Hàn Lập, nhưng Hàn Lập sinh nghi trước thái độ hoan hỉ đáng ngờ của nàng nên chưa vội tiếp nhận.","detail":"Minh Hồn Châu xuất hiện khi Nguyên Dao chủ động phun viên châu ra và giao cho Hàn Lập, giải thích rằng đây là vật dùng để khống chế Đề Hồn Thú (@c0462). Theo lời Nguyên Dao, chỉ cần luyện hóa viên châu như một pháp bảo bình thường thì Đề Hồn Thú sẽ vĩnh viễn tuân theo chủ nhân. Tuy nhiên, bản thân Nguyên Dao chưa chính thức luyện hóa thành công Minh Hồn Châu, do đó nàng không thể khống chế được Đề Hồn Thú. Việc nàng chủ động giao châu với thái độ hoan hỉ đáng ngờ khiến Hàn Lập sinh nghi và chưa vội tiếp nhận.","congNang":["Khống chế Đề Hồn Thú vĩnh viễn sau khi được luyện hóa như pháp bảo bình thường (@c0462)"],"dacDiem":"Viên châu màu xám","tabs":{"tienTrinh":[{"chuong":"@c0462","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện và được giao cho Hàn Lập","text":"Nguyên Dao chủ động phun ra Minh Hồn Châu và giao cho Hàn Lập, giải thích đây là vật khống chế Đề Hồn Thú. Hàn Lập nghi ngờ thái độ sốt sắng, chưa vội tiếp nhận.","anchor":"Đây là Minh Hồn Châu, là vật khống chế Đề Hồn Thú. Chỉ cần luyện hóa vật này giống như luyện hóa pháp bảo bình thường thì Đề Hồn Thú sẽ vĩnh viễn tuân theo"}]},"nguon":["@c0462"]},{"id":"luyen-tinh","name":"Luyện Tinh","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cực hiếm","soHuu":["Hàn Lập"],"trangThai":"nguyên vẹn","blurb":"Luyện Tinh là vật liệu luyện khí cực hiếm, có hình cầu màu đen, do Thiết Hỏa Kiến ăn khoáng thạch rồi loại bỏ tạp chất, tinh chất tích tụ trong bụng kết tinh mà thành. Hàn Lập thu được Luyện Tinh sau khi dùng Phệ Kim Trùng thôn phệ trụ thủy tinh và hình nhân kiến đen, dự định dùng để tế luyện Thanh Trúc Phong Vân Kiếm.","detail":"Luyện Tinh là tinh chất khoáng thạch do Thiết Hỏa Kiến mỗi ngày ăn khoáng thạch, loại bỏ hết tạp chất, phần tinh túy còn lại tích tụ trong bụng kết thành hình cầu màu đen to bằng quả trứng gà, bề mặt hắc quang lập lòe. Đây là nguyên liệu tốt nhất để tăng cường uy lực và cường hóa bản thể pháp bảo, cực kỳ hiếm có, Hàn Lập chỉ biết đến sự tồn tại của nó nhờ đọc được một quyển sách cổ xưa. Trong lần thu phục xác đàn kiến bay bị Huyền Hoàng Kính tiêu diệt, Hàn Lập dùng Phệ Kim Trùng thôn phệ trụ thủy tinh cùng hình nhân kiến đen, từ đó Luyện Tinh lộ ra (@c0464). Hàn Lập dự định sử dụng Luyện Tinh để tế luyện Thanh Trúc Phong Vân Kiếm.","congNang":["Tăng cường uy lực pháp bảo","Cường hóa bản thể pháp bảo, khiến pháp bảo cực độ khó bị hủy"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0464","denChuong":"","cachCoDuoc":"Thu nhặt từ xác đàn Thiết Hỏa Kiến sau khi Phệ Kim Trùng thôn phệ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0464","loai":"xuat-hien","importance":"major","giaiDoan":"Được phát hiện và thu hoạch","text":"Hàn Lập dùng Phệ Kim Trùng thôn phệ trụ thủy tinh và hình nhân kiến đen, lộ ra Luyện Tinh — vật liệu hiếm nhất tăng cường pháp bảo. Dự định dùng tế luyện Thanh Trúc Phong Vân Kiếm.","anchor":"Đây chính là vật liệu tốt nhất dùng để tăng cường uy lực của pháp bảo"}]},"nguon":["@c0464"],"dacDiem":"Hình cầu màu đen to bằng quả trứng gà, bề mặt hắc quang lập lòe; do Thiết Hỏa Kiến ăn khoáng thạch loại bỏ tạp chất, tinh chất tích tụ kết tinh mà thành; cực kỳ hiếm có."},{"id":"huyen-hoang-kinh","name":"Huyền Hoàng Kính","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo hàng đầu","soHuu":["Vạn Thiên Minh"],"trangThai":"nguyên vẹn","blurb":"Huyền Hoàng Kính là pháp bảo đại danh đỉnh đỉnh của Vạn Pháp môn, do Vạn Thiên Minh sử dụng. Khi chiếu lên sinh linh sẽ khiến hồn phi phách tán, đồng thời ánh sáng tạo ra trụ thủy tinh âm hàn tồn tại rất lâu và cực kỳ khó phá hủy.","detail":"Huyền Hoàng Kính là pháp bảo nổi danh nhất của Vạn Pháp môn, được Vạn Thiên Minh mang theo và sử dụng. Ánh sáng do kính chiếu ra có thể khiến sinh linh hồn phi phách tán, đồng thời để lại trụ thủy tinh phát bạch quang âm hàn cực lạnh, cao hai ba mươi trượng, tồn tại rất lâu và cực kỳ khó phá hủy. Tại sa mạc, Vạn Thiên Minh đã dùng Huyền Hoàng Kính chiếu ra tiêu diệt đàn kiến đen biết bay, để lại các trụ thủy tinh mà sau đó Nguyên Dao xác nhận nguồn gốc (@c0464).","congNang":["Chiếu sáng lên sinh linh khiến hồn phi phách tán (@c0464)","Tạo trụ thủy tinh phát bạch quang âm hàn cực lạnh, cao hai ba mươi trượng, tồn tại rất lâu và cực kỳ khó phá hủy (@c0464)"],"hePhai":"Vạn Pháp môn","chuSoHuu":[{"ten":"Vạn Thiên Minh","tuChuong":"@c0464","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0464","loai":"dung","importance":"major","giaiDoan":"Lần đầu được nhắc đến, đã dùng tiêu diệt đàn kiến bay","text":"Nguyên Dao xác nhận trụ thủy tinh trong sa mạc do Vạn Thiên Minh dùng Huyền Hoàng Kính chiếu ra, tiêu diệt đàn kiến đen biết bay.","anchor":"Chẳng lẽ ngươi không biết Vạn pháp môn đại danh đỉnh đỉnh là Huyền Hoàng Kính"}]},"nguon":["@c0464"],"uyLuc":"Chiếu lên đàn kiến đen biết bay trong sa mạc khiến chúng bị tiêu diệt hoàn toàn, hồn phi phách tán, đồng thời để lại các trụ thủy tinh bền bỉ cực khó phá hủy (@c0464).","dacDiem":"Ánh sáng kính chiếu ra tạo thành trụ thủy tinh phát bạch quang âm hàn cực lạnh, cao hai ba mươi trượng, trường tồn cực kỳ khó phá hủy."},{"id":"ba-la-chau","name":"Bà La Châu","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (bảo vật quý của Cực Âm tổ sư)","soHuu":["Hàn Lập (tạm giữ)","Cực Âm lão tổ (chủ gốc)"],"trangThai":"Đang dùng (Hàn Lập tạm giữ)","blurb":"Bà La Châu là vòng đeo tay gồm bốn hạt châu lớn nhỏ, tỏa thanh quang nhàn nhạt và mùi gỗ đàn hương, có công dụng an thần định tâm. Vốn là vật sở hữu của Cực Âm lão tổ, được ngậm ngùi trao cho Hàn Lập nhằm đối phó Cực Diệu Huyễn Cảnh (@c0466).","detail":"Bà La Châu là vòng tay xâu từ bốn viên châu có chất liệu đặc biệt — như gỗ không phải gỗ, như vàng không phải vàng — tỏa thanh quang nhàn nhạt cùng hương đàn hương dịu. Cực Âm lão tổ vốn coi đây là vật quý, song vì cần giúp Hàn Lập đối phó với Cực Diệu Huyễn Cảnh nên đành tiếc rẻ trao lại, dự tính sau này sẽ lấy về (@c0466). Pháp bảo này đặc biệt hữu dụng trong hoàn cảnh tâm thần bị huyễn cảnh quấy nhiễu, nhờ tác dụng an thần và định tâm vượt trội.","congNang":["An thần, định tâm, giảm tâm ma quấy nhiễu khi tu luyện","Hỗ trợ đối phó Cực Diệu Huyễn Cảnh (@c0466)"],"hinhDang":"Vòng đeo tay bốn hạt châu lớn nhỏ","vatLieu":"Chất liệu đặc biệt, như gỗ không phải gỗ, như vàng không phải vàng","dacDiem":"Tỏa thanh quang nhàn nhạt và mùi gỗ đàn hương; bốn viên châu chất liệu đặc biệt — như gỗ không phải gỗ, như vàng không phải vàng — xâu thành vòng đeo tay.","chuHienThoi":"Hàn Lập (tạm giữ)","chuSoHuu":[{"ten":"Cực Âm lão tổ","tuChuong":"@c0466","denChuong":"@c0466","cachCoDuoc":"Vật của Cực Âm tổ sư truyền lại","trangThai":"da-trao"},{"ten":"Hàn Lập","tuChuong":"@c0466","denChuong":"","cachCoDuoc":"Được Cực Âm lão tổ tạm giao","trangThai":"dang-giu-tam"}],"tabs":{"tienTrinh":[{"chuong":"@c0466","loai":"doi-chu","importance":"major","giaiDoan":"Cực Âm lão tổ trao cho Hàn Lập","text":"Cực Âm lão tổ ngậm ngùi tiếc rẻ trao Bà La Châu cho Hàn Lập để đối phó Cực Diệu Huyễn Cảnh, dự tính sau này lấy lại.","anchor":"Đây là Bà La Châu, có công dụng an thần, định tâm rất kỳ diệu"}]},"capNhatToi":"@c0466","nguon":["@c0466"]},{"id":"thanh-minh-cham-phu-bao","name":"Thanh Minh Châm phù bảo","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Phù bảo Nguyên anh kỳ","soHuu":["Hàn Lập"],"trangThai":"Đang giữ","blurb":"Thanh Minh Châm phù bảo là phù bảo màu xanh do tu sĩ Nguyên Anh kỳ luyện chế, có uy lực vượt xa pháp bảo bình thường, chỉ dùng được một lần. Nho Sam lão giả tặng cho Hàn Lập mang theo phòng thân trước khi vào thông đạo.","detail":"Thanh Minh Châm phù bảo là một phù bảo màu xanh được Nho Sam lão giả lấy ra và mỉm cười tặng cho Hàn Lập. Theo lời Nho Sam lão giả, phù bảo này có uy lực mạnh hơn nhiều so với pháp bảo bình thường, thuộc loại vật phẩm dùng một lần do tu sĩ Nguyên Anh kỳ luyện chế. Việc tặng phù bảo này thể hiện sự quan tâm của Nho Sam lão giả đối với sự an nguy của Hàn Lập.","congNang":["Uy lực cực mạnh, vượt xa pháp bảo bình thường, dùng một lần @c0466"],"chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Huyền Cốt","tuChuong":"@c0466","denChuong":"@c0466","cachCoDuoc":"Tự chế hoặc thu thập","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0466","denChuong":"","cachCoDuoc":"Được Nho sam lão giả (Huyền Cốt) tặng","trangThai":"dang-giu"}],"tabs":{"tienTrinh":[{"chuong":"@c0466","loai":"doi-chu","importance":"major","giaiDoan":"Nho sam lão giả tặng Hàn Lập","text":"Nho sam lão giả lấy ra phù bảo màu xanh tặng Hàn Lập, nói uy lực mạnh hơn nhiều so với pháp bảo bình thường.","anchor":"Nho sam lão giả cũng lấy ra một cái phù bảo màu xanh mỉm cười đưa cho Hàn Lập"}]},"capNhatToi":"@c0466","nguon":["@c0466"],"uyLuc":"Theo lời Nho Sam lão giả, uy lực mạnh hơn nhiều so với pháp bảo bình thường @c0466","dacDiem":"Phù bảo màu xanh, do tu sĩ Nguyên Anh kỳ luyện chế, chỉ sử dụng được một lần"},{"id":"hoang-lan-giap","name":"Hoàng Lân Giáp","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (bảo giáp cao cấp)","soHuu":["Hàn Lập (tạm mượn)","Man Hồ tử (chủ gốc)"],"trangThai":"Đang được Hàn Lập sử dụng","blurb":"Nội giáp màu đen có lân phiến trắng, nặng trịch. Man Hồ tử cho Hàn Lập mượn tạm làm vật bảo mệnh vì Thác Thiên Công đã luyện thành nên bảo giáp không còn cần thiết.","detail":"Nội giáp màu đen có lân phiến trắng, nặng trịch, từng là vật bảo mệnh của Man Hồ tử suốt hơn trăm năm. Sau khi Thác Thiên Công luyện thành, Man Hồ tử không còn cần bảo giáp vật lý nữa nên cho Hàn Lập mượn tạm. Cực Âm lão tổ nhìn thấy liền động dung tham lam.","congNang":["Bảo giáp hộ thể","Phòng ngự thân thể mạnh mẽ"],"hinhDang":"Nội giáp màu đen có lân phiến trắng","dacDiem":"Nặng trịch, là vật bảo mệnh trăm năm của Man Hồ tử","chuHienThoi":"Hàn Lập (tạm mượn)","chuSoHuu":[{"ten":"Man Hồ Tử","tuChuong":"@c0466","denChuong":"","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0466","denChuong":"","cachCoDuoc":"Thu từ Man Hồ Tử","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0466","loai":"doi-chu","importance":"normal","giaiDoan":"Man Hồ tử cho Hàn Lập mượn tạm","text":"Man Hồ tử cho Hàn Lập mượn Hoàng Lân Giáp làm vật bảo mệnh tạm thời vì Thác Thiên Công đã luyện thành. Cực Âm lão tổ nhìn thấy liền động dung tham lam.","anchor":"Hiện giờ Thác Thiên Công của ta đã luyện thành, vậy vật này tạm thời là vật bảo mệnh cho tiểu tử nhà ngươi đi"},{"chuong":"@c0497","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập tiếp tục mặc sau khi rời Hư Thiên điện","text":"Hàn Lập kiểm tra các bảo vật từ lão ma, cất hết vào túi trữ vật nhưng riêng Hoàng Lân giáp vẫn mặc trên người vì phòng ngự mạnh.","anchor":"Hoàng Lân giáp của Man Hồ Tử kia vẫn được Hàn Lập mặc lên người"}]},"capNhatToi":"@c0466","nguon":["@c0466","@c0497"],"cn":"黄鳞甲"},{"id":"guong-hinh-tron-mau-vang","name":"Gương hình tròn màu vàng","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo (chưa rõ phẩm cấp)","soHuu":["Hàn Lập"],"trangThai":"đang sở hữu","blurb":"Cổ bảo loại gương lấy từ tầng hai Bảo Quang Các trong bí cảnh. Hàn Lập tin rằng gương là loại pháp bảo có thần thông kỳ lạ, uy lực lớn.","detail":"Một chiếc gương hình tròn màu vàng nằm trong màn hào quang bảo hộ tầng hai Bảo Quang Các. Hàn Lập chọn nó vì tin rằng pháp bảo loại gương thường có thần thông kỳ lạ. Công năng cụ thể chưa được thử nghiệm.","congNang":["Chưa rõ, Hàn Lập dự đoán có thần thông kỳ lạ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0467","denChuong":"","cachCoDuoc":"Lấy từ màn hào quang tầng hai Bảo Quang Các","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0467","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập chọn từ tầng hai Bảo Quang Các","text":"Hàn Lập chọn gương hình tròn màu vàng từ hơn mười kiện cổ bảo trong màn hào quang tầng hai, tin rằng pháp bảo loại gương có thần thông kỳ lạ.","anchor":"nó chắc chắn là một kiện pháp bảo, gần như chỗ nào cũng có thần thông kỳ lạ"}]},"nguon":["@c0467"]},{"id":"ngu-xuyen-dong-hoan","name":"Ngũ xuyến đồng hoàn","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo (chưa rõ phẩm cấp)","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Ngũ xuyến đồng hoàn là cổ bảo bao hàm thuộc tính ngũ hành, được Hàn Lập chọn từ tầng hai Bảo Quang Các. Sau thử nghiệm, pháp bảo này lộ ra ba công năng chính: phòng ngự bằng màn ngũ sắc hào quang, vây khốn đánh lén khiến đối phương cứng đờ, nhưng không thể dùng để công kích trực tiếp.","detail":"Ngũ xuyến đồng hoàn nằm trong màn hào quang bảo hộ tại tầng hai Bảo Quang Các. Hàn Lập chọn lấy pháp bảo này sau khi nhận ra bên trong bao hàm thuộc tính của cả ngũ hành (@c0467). Về sau, Hàn Lập tiến hành thử nghiệm và phát hiện pháp bảo sở hữu ba công năng: khi kích phát phòng ngự, đồng hoàn cuồng trướng thành cự hoàn liên kết tạo thành màn ngũ sắc hào quang bảo hộ chủ nhân; khi dùng vây khốn đánh lén, đồng hoàn tự xuất hiện trên cổ hoặc tay chân đối phương khiến đối phương cứng đờ không cử động được; tuy nhiên, pháp bảo này không có khả năng công kích trực tiếp (@c0469).","congNang":["Bao hàm thuộc tính ngũ hành (@c0467)","Phòng ngự: cuồng trướng thành cự hoàn liên kết, tạo màn ngũ sắc hào quang bảo hộ chủ nhân (@c0469)","Vây khốn đánh lén: tự xuất hiện trên cổ hoặc tay chân đối phương, khiến đối phương cứng đờ không cử động được (@c0469)","Không thể dùng để công kích trực tiếp (@c0469)"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0467","denChuong":"","cachCoDuoc":"Lấy từ màn hào quang tầng hai Bảo Quang Các","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0467","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập chọn từ tầng hai Bảo Quang Các","text":"Hàn Lập chọn ngũ xuyến đồng hoàn vì nhận ra bên trong bao hàm thuộc tính của cả ngũ hành.","anchor":"bên trong nó chính là bao hàm thuộc tính của cả ngũ hành"},{"chuong":"@c0469","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập thử nghiệm khám phá công năng","text":"Hàn Lập thử nghiệm phát hiện ba công năng: phòng ngự tạo màn ngũ sắc, vây khốn đánh lén khiến đối phương cứng đờ không cử động, không thể công kích trực tiếp. Đánh giá ngay cả tu sĩ Nguyên Anh kỳ cũng khó tránh.","anchor":"năm chiếc đồng hoàn quỷ dị trên tay bỗng biến mất, nhưng lập tức trên cổ và tay chân của Hàn lập đột nhiên xuất hiện hào quang chớp lên lập loè"}]},"nguon":["@c0467","@c0469"],"cn":"五串铜环","dacDiem":"Pháp bảo dạng đồng hoàn, bao hàm thuộc tính của cả ngũ hành; thiên về phòng ngự và khống chế, không có năng lực công kích trực tiếp."},{"id":"ao-choang-do-sam","name":"Áo choàng màu đỏ sậm","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo (chưa rõ phẩm cấp)","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Áo choàng màu đỏ sậm là cổ bảo được Hàn Lập chọn từ tầng hai Bảo Quang Các, sau khi truyền linh lực sẽ huyễn hóa thành lông dài màu máu bao phủ huyết quang, sở hữu năng lực thuấn di tốc độ cực cao vượt cả tu sĩ Nguyên Anh kỳ.","detail":"Áo choàng màu đỏ sậm rộng thùng thình là một trong ba cổ bảo Hàn Lập chọn lấy tại tầng hai Bảo Quang Các (@c0467). Khi khoác lên người và truyền linh lực vào, lông trên áo choàng huyễn hóa thành lông dài màu máu, bao phủ toàn thân trong huyết quang. Pháp bảo này sở hữu năng lực thuấn di với tốc độ cực cao, vượt qua cả trình độ tu sĩ Nguyên Anh kỳ (@c0469).","congNang":["Khi truyền linh lực, lông trên áo choàng huyễn hóa thành lông dài màu máu bao phủ huyết quang @c0469","Thuấn di tốc độ cực cao, vượt cả tu sĩ Nguyên Anh kỳ @c0469"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0467","denChuong":"","cachCoDuoc":"Lấy từ màn hào quang tầng hai Bảo Quang Các","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0467","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập chọn từ tầng hai Bảo Quang Các","text":"Hàn Lập chọn áo choàng màu đỏ sậm rộng thùng thình làm cổ bảo thứ ba.","anchor":"cuối cùng là cái áo choàng màu đỏ sậm"},{"chuong":"@c0469","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập thử nghiệm khám phá công năng","text":"Hàn Lập khoác áo choàng truyền linh lực, lông huyễn hóa thành lông dài màu máu bao phủ huyết quang. Thuấn di với tốc độ kinh người nhưng bắn thẳng vào vách tường, thử nhiều loại độn thuật đều không thể điều khiển. Xác định là cổ bảo thứ cấp dùng trốn thoát khi đại nạn.","anchor":"Dường như ngay khi khoác chiếc áo choàng này vào, hắn lập tức sở hữu một tốc độ kinh người, căn bản là không thể giảm tốc được chút nào"}]},"nguon":["@c0467","@c0469"],"aliases":["Áo choàng cổ bảo (lông chim đỏ sậm)"],"uyLuc":"Tốc độ thuấn di vượt cả tu sĩ Nguyên Anh kỳ (@c0469).","dacDiem":"Hình dạng áo choàng rộng thùng thình, khi kích hoạt lông huyễn hóa thành lông dài màu máu, toàn thân bao phủ huyết quang."},{"id":"ao-choang-co-bao-long-chim-do-sam","name":"Áo choàng cổ bảo (lông chim đỏ sậm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Hàn Lập"],"trangThai":"Đang sử dụng","blurb":"Cổ bảo hai lớp: trong ti tuyến dệt, ngoài phủ lông chim kỳ lạ tỏa hào quang đỏ sậm. Đoán công dụng ẩn khí tức hoặc phòng ngự.","detail":"Áo choàng cổ bảo nằm trong thạch điện Hư Thiên Đỉnh. Bên trong là lớp sợi ti tuyến dệt thành, bên ngoài phủ một lớp lông chim kỳ lạ tỏa hào quang đỏ sậm. Hàn Lập đoán công dụng là ẩn khí tức hoặc phòng ngự. Sau khi đoạt, sờ vào hơi nóng lên.","hinhDang":"Hai lớp: trong ti tuyến dệt, ngoài lông chim tỏa hào quang đỏ sậm","congNang":["Ẩn khí tức hoặc phòng ngự (phỏng đoán)"],"dacDiem":"Sờ vào hơi nóng","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0468","denChuong":"","cachCoDuoc":"Đoạt từ thạch điện Hư Thiên Đỉnh","trangThai":"dang-co"}],"capNhatToi":"@c0468","tabs":{"tienTrinh":[{"chuong":"@c0468","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Hàn Lập đoạt từ thạch điện","text":"Hàn Lập dùng Phệ Kim Trùng tạo hắc giáp khống chế cấm chế, đoạt áo choàng cùng Ngũ sắc đồng hoàn trước khi bị truyền tống.","anchor":"Bên trong là lớp sợi ti tuyến dệt thành, còn bên ngoài phủ một lớp lông chim kỳ lạ"}]},"nguon":["@c0468"]},{"id":"ngu-sac-dong-hoan","name":"Ngũ sắc đồng hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Hàn Lập"],"trangThai":"Đang sử dụng","blurb":"Vòng đồng ngũ xuyến cổ quái, quang hoa ngũ sắc chớp lóe liên tục, sờ vào lạnh như băng.","detail":"Cổ bảo nằm trong thạch điện Hư Thiên Đỉnh. Là vòng đồng ngũ xuyến cổ quái, phát ra quang hoa ngũ sắc chớp lóe liên tục. Sau khi đoạt, sờ vào lạnh lẽo như băng. Công dụng cụ thể chưa rõ.","hinhDang":"Vòng đồng ngũ xuyến cổ quái","congNang":["Chưa rõ công dụng cụ thể"],"dacDiem":"Quang hoa ngũ sắc chớp lóe, lạnh như băng khi sờ","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0468","denChuong":"","cachCoDuoc":"Đoạt từ thạch điện Hư Thiên Đỉnh","trangThai":"dang-co"}],"capNhatToi":"@c0468","tabs":{"tienTrinh":[{"chuong":"@c0468","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Hàn Lập đoạt từ thạch điện","text":"Hàn Lập gian nan di chuyển năm sáu trượng trong lúc khôi giáp đen chống đỡ lam quang, nắm được Ngũ sắc đồng hoàn trước khi hắc giáp bị phá tan.","anchor":"màn quang hoa ngũ sắc chớp loé liên tục"}]},"nguon":["@c0468"]},{"id":"khoi-loi-lang-thu-kim-sac","name":"Khôi lỗi lang thủ kim sắc","category":"khac","categoryLabel":"Cơ quan (Khôi lỗi)","phamCap":"Trên Kết Đan sơ kỳ","soHuu":[],"trangThai":"bi-huy","blurb":"Cơ quan thủ vệ tầng một Hư Thiên Điện, gồm bốn khôi lỗi cấp A và một khôi lỗi lang thủ kim sắc thực lực trên Kết Đan sơ kỳ. Làm bằng kim loại bạc hy hữu.","detail":"Nhóm cơ quan bảo vệ mê cung tầng một Hư Thiên Điện. Bốn khôi lỗi cấp A tương đương Trúc Cơ hậu kỳ, khôi lỗi lang thủ kim sắc (đầu sói) thực lực trên Kết Đan sơ kỳ. Cấu tạo từ kim loại bạc hy hữu, có lưỡi đao đen và viên bảo thạch xanh biếc tản hàn khí. Huyền Cốt nhận định tài liệu khôi lỗi này không thể luyện chế thành pháp bảo. Bị Man Hồ Tử dùng Thiên Ma Công quyền cước tiêu diệt hoàn toàn.","congNang":["Tuần tra và bảo vệ mê cung tầng một Hư Thiên Điện, tấn công xâm nhập giả bằng đao và cận chiến"],"tabs":{"tienTrinh":[{"chuong":"@c0473","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị tiêu diệt","text":"Xuất hiện trong mê cung tầng một Hư Thiên Điện, bị Man Hồ Tử vận dụng Thiên Ma Công dùng quyền cước tiêu diệt hoàn toàn. Hàn Lập thu viên bảo thạch xanh biếc từ tàn tích.","anchor":"khôi lỗi kim sắc lang thủ kia, thực lực còn trên cả Kết đan sơ kỳ"}]},"nguon":["@c0473"]},{"id":"bao-thach-xanh-biec","name":"Bảo thạch xanh biếc","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Viên bảo thạch tìm thấy trong tàn tích khôi lỗi tầng một Hư Thiên Điện, tản ra hàn khí quỷ dị.","detail":"Viên bảo thạch màu xanh biếc nằm trong tàn tích khôi lỗi lang thủ kim sắc, lập lòe tản ra một cổ hàn khí quỷ dị. Huyền Cốt nói tài liệu khôi lỗi không luyện chế được pháp bảo, nhưng Hàn Lập vẫn thu vào túi trữ vật vì muốn nghiên cứu cấu tạo và thuật chế tạo khôi lỗi cổ xưa.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0473","denChuong":"","cachCoDuoc":"Thu lượm từ tàn tích khôi lỗi","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0473","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Hàn Lập thu lượm","text":"Hàn Lập phát hiện viên bảo thạch xanh biếc trong tàn tích khôi lỗi, bất chấp lời Huyền Cốt nói không luyện chế được pháp bảo, vẫn thu vào túi trữ vật để nghiên cứu.","anchor":"Ánh mắt hắn rơi vào một viên bảo thạch màu xanh biếc, vật đó lập lòe tản ra một cổ hàn khí"}]},"nguon":["@c0473"]},{"id":"bao-thach-xanh-luc","name":"Bảo thạch xanh lục","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ (thượng cổ)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Viên bảo thạch lấp lánh ánh xanh lục từ ngực Xà vệ Khôi lỗi tầng hai, là hạch tâm cung cấp năng lượng cho Khôi lỗi. Cứng rắn vô cùng, không thể phá hủy hay luyện chế.","detail":"Man Hồ Tử đấm xuyên ngực Xà vệ Khôi lỗi móc ra viên bảo thạch này. Dù vận toàn lực Thiên Ma Công bóp chặt năm ngón kim sắc, bảo thạch vẫn nguyên vẹn không thay đổi. Thanh Dịch cư sĩ cho biết đã có người mang về nghiên cứu: không cách nào phá hủy, không thể luyện chế hòa tan vào pháp bảo hay pháp khí, các tông môn chuyên luyện Khôi lỗi cũng không biết công dụng, trừ phi thượng cổ tu sĩ sống lại. Man Hồ Tử ném cho Hàn Lập, Hàn Lập thu vào túi trữ vật.","congNang":["Hạch tâm cung cấp năng lượng cho Khôi lỗi"],"dacDiem":"Bất hoại — không thể phá hủy, không thể luyện chế vào pháp bảo/pháp khí, công dụng không ai biết","chuSoHuu":[{"ten":"Man Hồ Tử","tuChuong":"@c0474","denChuong":"@c0474","cachCoDuoc":"Móc từ ngực Xà vệ Khôi lỗi","trangThai":"da-chuyen"},{"ten":"Hàn Lập","tuChuong":"@c0474","denChuong":"","cachCoDuoc":"Man Hồ Tử ném cho","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0474","loai":"xuat-hien","importance":"normal","giaiDoan":"Lộ diện từ ngực Xà vệ Khôi lỗi","text":"Man Hồ Tử đấm xuyên ngực Xà vệ Khôi lỗi tầng hai móc ra viên bảo thạch xanh lục. Thử vận Thiên Ma Công bóp nát nhưng thất bại hoàn toàn. Thanh Dịch cư sĩ giải thích đây là vật thượng cổ bất hoại không ai biết cách dùng. Man Hồ Tử ném cho Hàn Lập.","anchor":"viên bảo thạch nọ vẫn lấp lánh ánh sáng xanh lục không chút thay đổi"}]},"nguon":["@c0474"]},{"id":"hai-ngon-giao-ngan","name":"Hai ngọn giáo ngắn (bị biến dạng)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"Bị biến dạng","blurb":"Hai ngọn giáo ngắn bị biến dạng mà Hàn Lập thu được, bị Cực Âm lão tổ liếc nhìn thèm muốn, Hàn Lập nhận định là đồ tốt.","detail":"Hai ngọn giáo nhỏ bị biến dạng mà Hàn Lập thu vào. Dù đã bị biến dạng nhưng vẫn được đánh giá là bảo vật tốt. Cực Âm lão tổ lộ ánh mắt tham lam khi nhìn hai ngọn giáo rồi nhanh chóng che giấu, tạo thêm lý do tiềm ẩn để ra tay đoạt bảo của Hàn Lập.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0475","denChuong":"","cachCoDuoc":"Thu được","trangThai":"dang-co"}],"congNang":[],"tabs":{"tienTrinh":[{"chuong":"@c0475","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập thu được, bị Cực Âm thèm muốn","text":"Hàn Lập thu hai ngọn giáo ngắn bị biến dạng. Cực Âm lão tổ lộ ánh mắt tham lam khi nhìn rồi che giấu.","anchor":"Biết rằng hai ngọn giáo ngắn này chỉ sợ cũng là đồ tốt"}]},"nguon":["@c0475"]},{"id":"quyen-truc-vang-cu-ky","name":"Quyển trục vàng cũ kỹ","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quyển trục màu vàng cũ kỹ được Hàn Lập tìm thấy trong lỗ hổng bí mật trên vách đá gần tế đàn Hư Thiên Đỉnh, nội dung chưa rõ.","detail":"Hình dáng dài tròn hơi mềm, ẩn giấu trong vách đá tại khu vực đài cao Hư Thiên Điện. Hàn Lập dùng kiếm quang mở vách đá lấy ra, giấu vào ngực nhưng chưa có cơ hội xem nội dung do bị Cực Âm đốc thúc và Ô Sửu canh chừng.","congNang":[],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0476","denChuong":"","cachCoDuoc":"Tìm thấy trong lỗ hổng bí mật trên vách đá","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0476","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập bí mật phát hiện và lấy đi","text":"Hàn Lập lợi dụng lúc Cực Âm không giám sát, dùng kiếm quang mở vách đá lấy được quyển trục vàng cũ kỹ giấu vào ngực, chưa kịp xem nội dung.","anchor":"thì ra vật nọ là một quyển trục màu vàng cũ kỹ"}]},"nguon":["@c0476"]},{"id":"han-giao","name":"Hàn Giao","aliases":["Bạch giao","tiểu bạch giao"],"category":"khac","categoryLabel":"Linh thú","phamCap":"Cấp Nguyên Anh","soHuu":["Phong Bà Tử"],"trangThai":"dang-co","blurb":"Tiểu giao màu trắng lớn chừng mấy trượng, linh thú cấp Nguyên Anh của Phong Bà Tử, được cháu Vạn Thiên Minh mượn mang vào Hư Thiên Điện.","detail":"Linh thú hình giao long trắng, thể hình mấy trượng, sở hữu sức mạnh cấp Nguyên Anh kỳ. Chặn đứng đạo kim quang tấn công của Man Hồ Tử. Được Vạn Thiên Minh triệu hoán bằng cách hô tên.","congNang":["Hộ vệ, chiến đấu cấp Nguyên Anh"],"chuSoHuu":[{"ten":"Phong Bà Tử","tuChuong":"@c0476","denChuong":"","cachCoDuoc":"Chủ nhân gốc","trangThai":"dang-co"},{"ten":"Vạn Thiên Minh","tuChuong":"@c0476","denChuong":"","cachCoDuoc":"Mượn từ Phong Bà Tử (quan hệ cháu)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0476","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Vạn Thiên Minh triệu hoán chặn đòn Man Hồ Tử","text":"Vạn Thiên Minh triệu hoán Hàn Giao (tiểu bạch giao mượn từ Phong Bà Tử) chặn đứng đạo kim quang tấn công của Man Hồ Tử. Phe tà đạo kinh hãi nhận ra đây là linh thú cấp Nguyên Anh.","anchor":"một con tiểu giao màu trắng lớn chừng mấy trượng"}]},"nguon":["@c0476"]},{"id":"ly-quy","name":"Ly Quy","aliases":["Cự quy"],"category":"khac","categoryLabel":"Linh thú","phamCap":"Cấp Nguyên Anh","soHuu":["Thiên Duyên Tử"],"trangThai":"dang-co","blurb":"Cự quy trong suốt kỳ dị, linh thú cấp Nguyên Anh của Thiên Duyên Tử, được sư đệ Thiên Ngộ Tử mượn mang vào Hư Thiên Điện.","detail":"Linh thú hình rùa lớn trong suốt, sở hữu sức mạnh cấp Nguyên Anh kỳ. Chặn đứng đạo kim quang tấn công của Man Hồ Tử. Được Thiên Ngộ Tử triệu hoán bằng cách hô tên.","congNang":["Hộ vệ, chiến đấu cấp Nguyên Anh"],"chuSoHuu":[{"ten":"Thiên Duyên Tử","tuChuong":"@c0476","denChuong":"","cachCoDuoc":"Chủ nhân gốc","trangThai":"dang-co"},{"ten":"Thiên Ngộ Tử","tuChuong":"@c0476","denChuong":"","cachCoDuoc":"Mượn từ Thiên Duyên Tử (quan hệ sư môn)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0476","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Thiên Ngộ Tử triệu hoán chặn đòn Man Hồ Tử","text":"Thiên Ngộ Tử triệu hoán Ly Quy (cự quy trong suốt mượn từ Thiên Duyên Tử) chặn đứng đạo kim quang tấn công của Man Hồ Tử. Phe tà đạo kinh hãi nhận ra đây là linh thú cấp Nguyên Anh.","anchor":"một con rùa lớn trong suốt kỳ dị"}]},"nguon":["@c0476"]},{"id":"thien-thanh-hoa","name":"Thiên Thanh Hoa","cn":"天青花","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Quý hiếm","soHuu":["Vạn Thiên Minh"],"trangThai":"Đã dùng hết","blurb":"Loại hoa quý hiếm có thể tạm nâng cao đạo hạnh kỳ trùng, được Vạn Thiên Minh dùng cho Kim Ti Tằm nhằm kéo Hư Thiên Đỉnh.","detail":"Vạn Thiên Minh cho Kim Ti Tằm phục dùng Thiên Thanh Hoa để tạm nâng cao đạo hạnh nhằm kéo Hư Thiên Đỉnh. Cực Âm tổ sư cũng từng nghĩ đến phương pháp này nhưng nhiều năm không tìm được Thiên Thanh Hoa, ngạc nhiên khi biết Vạn Thiên Minh tìm ra.","congNang":["Tạm nâng cao đạo hạnh kỳ trùng/linh thú"],"nguon":["@c0477"]},{"id":"thanh-cuc-dieu","name":"Thanh Cức Điểu","cn":"青刺鸟","category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ","soHuu":["Thanh Dịch cư sĩ"],"trangThai":"Đang dùng","blurb":"Linh thú của Thanh Dịch cư sĩ, được phái ẩn nấp lối vào canh chừng phe chính đạo quay lại.","detail":"Thanh Cức Điểu được Thanh Dịch cư sĩ cho ẩn nấp tại lối vào khu vực tế đài để trinh sát, cảnh báo nếu phe chính đạo quay trở lại.","congNang":["Trinh sát, cảnh báo"],"nguon":["@c0477"]},{"id":"thien-do-thi","name":"Thiên Đô Thi","cn":"天都尸","category":"khac","categoryLabel":"Yêu thi","phamCap":"Không rõ","soHuu":["Cực Âm lão tổ"],"trangThai":"Đang dùng","blurb":"Hai con Yêu thi cao lớn của Cực Âm tổ sư, xuất hiện từ khói đen kèm mùi tanh hôi, có khả năng ẩn hình tiềm phục.","detail":"Cực Âm tổ sư ném vật xuống đất, hai luồng khói đen bốc lên kèm mùi tanh hôi, hai con Yêu thi cao lớn hiện ra rồi biến mất vô ảnh vô tung. Được phái tiềm phục ở lối vào phòng chính đạo đánh lén. Hàn Lập nhớ lại sự quỷ dị của Yêu thi lần trước, rùng mình kiêng kỵ.","congNang":["Tiềm phục mai phục","Ẩn hình vô ảnh vô tung"],"nguon":["@c0477"]},{"id":"kien-lam-bang-diem","name":"Kiền Lam Băng Diễm","cn":"","category":"khac","categoryLabel":"Dị hoả","phamCap":"Cực phẩm (Nguyên anh kỳ không dám chạm)","soHuu":[],"trangThai":"Đang bảo vệ Hư Thiên đỉnh dưới đáy động","blurb":"Kiền Lam Băng Diễm là chí âm chí hàn chi hoả, ngọn lửa lam bí ẩn không thuộc về thế giới tu tiên này, được thượng cổ tu sĩ tìm được từ nguồn gốc không rõ. Nằm dưới đáy động sâu bảo vệ Hư Thiên đỉnh, uy lực đủ luyện hoá cả tu sĩ Nguyên anh kỳ, chỉ có ba loại vật miễn dịch.","detail":"Kiền Lam Băng Diễm tọa lạc dưới đáy động sâu khoảng hai ba chục trượng, thiêu đốt bao bọc Hư Thiên đỉnh. Theo lời Cực Âm lão tổ, đây là ngọn lửa chí âm chí hàn, không phải sản vật của thế giới tu tiên hiện tại mà do thượng cổ tu sĩ tìm được, nguồn gốc cụ thể không ai rõ. Tu sĩ Kết đan kỳ không dám chạm vào, ngay cả tu sĩ Nguyên anh kỳ tiếp xúc cũng dễ bị luyện hoá. Lửa có sắc lam đặc trưng, tản ra kỳ hàn thấu xương và khiến người nhìn trực tiếp dễ rơi vào trạng thái mê muội. Trong vạn vật, chỉ có ba thứ miễn dịch với Kiền Lam Băng Diễm: Kim ti của Kim Ti Tằm, Thù ti của Huyết Ngọc Tri Thù, và hai con Hoả Mãng Cực Âm đặc biệt.","phanLoaiPhu":"Dị hoả","nguonGoc":"Không phải vật của thế giới tu tiên này, thượng cổ tu sĩ tìm được nguồn gốc không rõ","uyLuc":"Chí âm chí hàn, uy lực đủ luyện hoá tu sĩ Nguyên anh kỳ; tu sĩ Kết đan kỳ hoàn toàn không dám tiếp xúc.","dacDiem":"Lửa sắc lam, tản kỳ hàn thấu xương thay vì nhiệt; nhìn vào gây mê muội. Chỉ ba loại vật miễn dịch: Kim ti của Kim Ti Tằm, Thù ti của Huyết Ngọc Tri Thù, và Hoả Mãng Cực Âm.","congNang":["Thiêu đốt và luyện hoá mọi vật, kể cả tu sĩ Nguyên anh kỳ @c0478","Tản kỳ hàn thấu xương bảo vệ khu vực xung quanh @c0478","Gây mê muội cho người nhìn trực tiếp vào ngọn lửa lam @c0478"],"tabs":{"tienTrinh":[{"chuong":"@c0478","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện dưới đáy động, bảo vệ Hư Thiên đỉnh","text":"Kiền Lam Băng Diễm xuất hiện dưới đáy động sâu 20-30 trượng, thiêu đốt bao bọc Hư Thiên đỉnh. Cực Âm lão tổ giải thích đây là chí âm chí hàn chi hoả, Nguyên anh kỳ cũng bị luyện hoá, không phải vật của thế giới tu tiên này.","anchor":"chính là chí âm chí hàn chi hoả. Đừng nói là tu sĩ Kết đan kỳ, ngay cả mấy lão già Nguyên anh kỳ bọn ta cũng không dám chạm vào"}]},"nguon":["@c0478"]},{"id":"hai-con-hoa-mang","name":"Hai con Hoả Mãng","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ","soHuu":["Cực Âm lão tổ"],"trangThai":"Đang kéo Hư Thiên đỉnh","blurb":"Hai con cự mãng đỏ như lửa thuộc Cực Âm lão tổ, dài bốn năm trượng, toàn thân lân phiến đỏ, bốn mắt loé hồng quang, miễn dịch Kiền Lam Băng Diễm.","detail":"Cực Âm lấy từ túi linh thú đen ra hai con cự mãng đỏ như lửa dài bốn năm trượng, toàn thân lân phiến đỏ, dưới đầu có hoa văn quái dị hình tròn, bốn mắt loé hồng quang. Là một trong ba loại vật miễn dịch Kiền Lam Băng Diễm. Được cho nuốt hai viên dược hoàn đen trước khi vào động, sau khi Cực Âm dùng pháp quyết cổ quái thúc giục bí thuật, lân phiến chuyển hồng đen, tinh thần phấn chấn. Dùng đuôi cắm sâu vài trượng xuống đất bên cửa động làm điểm neo, nửa thân trên chui vào động cắn Hư Thiên đỉnh kéo lên.","congNang":["Miễn dịch Kiền Lam Băng Diễm","Kéo vật nặng trong môi trường cực hàn"],"chuSoHuu":[{"ten":"Cực Âm lão tổ","tuChuong":"@c0478","denChuong":"","cachCoDuoc":"Nuôi dưỡng","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0478","loai":"xuất hiện","importance":"normal","giaiDoan":"Được triệu hồi để kéo Hư Thiên đỉnh","text":"Cực Âm lấy ra hai con Hoả Mãng dài bốn năm trượng, cho nuốt dược hoàn đen, dùng pháp quyết biến lân phiến hồng đen, rồi sai chui vào động cắn Hư Thiên đỉnh kéo lên.","anchor":"hai con cự mãng đỏ như lửa dài chừng bốn, năm trượng"}]},"nguon":["@c0478"]},{"id":"hoa-thach-thu","name":"Hoá thạch thú","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ","soHuu":["Vạn Thiên Minh"],"trangThai":"dang-co","blurb":"Hoá thạch thú là linh thú gián điệp hình khỉ màu lam của Vạn Thiên Minh, có khả năng ẩn nấp bên trong đá để giám sát đối phương mà không bị phát hiện bằng pháp lực thông thường. Nó được cài sẵn tại tế đàn để do thám phe ma đạo, và khi chủ nhân huýt sáo sẽ thoát ra bám vào cánh tay người gọi.","detail":"Hoá thạch thú mang hình dáng một con khỉ màu lam, không sở hữu bổn sự chiến đấu đặc biệt mà sở trường nằm ở khả năng ẩn mình bên trong tảng đá, khiến bất kỳ ai dùng pháp lực thông thường cũng không thể phát hiện sự tồn tại của nó. Vạn Thiên Minh đã cài sẵn Hoá thạch thú trong đá tại khu vực tế đàn nhằm giám sát mọi động tĩnh của phe ma đạo. Khi cần, Vạn Thiên Minh huýt sáo gọi nó ra — con thú thoát khỏi tảng đá và bám vào cánh tay chủ nhân (@c0479). Thanh Dịch cư sĩ khi nhìn thấy Hoá thạch thú đã nhận ra ngay bản chất của nó.","congNang":["Ẩn nấp hoàn toàn bên trong tảng đá, không thể bị phát hiện bằng pháp lực thông thường (@c0479)","Giám sát, do thám đối phương từ bên trong đá (@c0479)","Nghe hiệu lệnh huýt sáo của chủ nhân để thoát ra ngoài và bám vào cánh tay chủ (@c0479)"],"chuSoHuu":[{"ten":"Vạn Thiên Minh","tuChuong":"@c0479","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0479","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Vạn Thiên Minh huýt sáo gọi Hoá thạch thú từ trong tảng đá — con khỉ lam gián điệp đã ẩn giám sát phe ma đạo từ trước mà không ai phát hiện. Thanh Dịch cư sĩ thất thanh nhận ra.","anchor":"Hoá thạch thú này, những bổn sự khác không có, nhưng nó chỉ cần ẩn nấp trong đá"}]},"nguon":["@c0479"],"dacDiem":"Hình dáng con khỉ màu lam, không có bổn sự chiến đấu, chuyên dùng cho việc gián điệp và do thám nhờ khả năng hoá thạch ẩn mình trong đá."},{"id":"bao-dom-ba-mat","name":"Báo đốm ba mắt","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ","soHuu":["Man Hồ Tử"],"trangThai":"dang-co","blurb":"Linh thú của Man Hồ Tử, hình dáng báo đốm to gấp mấy lần bình thường, trán có con mắt thứ ba sắc vàng chớp động.","detail":"Con báo đốm khổng lồ to gấp mấy lần báo bình thường, trán có con mắt thứ ba sắc vàng chớp động. Man Hồ Tử triệu hồi từ túi linh thú khi chính đạo quay lại tế đàn để chuẩn bị chiến đấu.","tabs":{"tienTrinh":[{"chuong":"@c0479","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Man Hồ Tử triệu hồi từ túi linh thú khi chính đạo quay lại, chuẩn bị chiến đấu.","anchor":"một con linh thú có hình dáng như con báo đốm xuất hiện trước mặt"}]},"nguon":["@c0479"]},{"id":"bao-tay-den-man-ho-tu","name":"Bao tay đen (quyền sáo)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Man Hồ Tử"],"trangThai":"dang-co","blurb":"Pháp bảo của Man Hồ Tử, màu đen ảm đạm với mặt trước đầy móc nhọn, mỗi quyền đánh ra có bàn tay vàng thật lớn bay ra.","detail":"Pháp bảo hình bao tay màu đen ảm đạm, mặt trước đầy móc nhọn. Khi đánh ra, mỗi quyền đều phóng bàn tay màu vàng thật lớn từ trong quyền sáo bay ra, có thể đánh bay cự kiếm cấp Nguyên Anh kỳ mấy trượng.","congNang":["Phóng bàn tay vàng thật lớn công kích khi đánh quyền"],"chuSoHuu":[{"ten":"Man Hồ Tử","tuChuong":"@c0481","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0481","loai":"dùng","importance":"normal","giaiDoan":"Trận chiến Hư Thiên Điện","text":"Man Hồ Tử dùng bao tay đen giao chiến với Vạn Thiên Minh, mỗi quyền đánh ra phóng bàn tay vàng thật lớn đánh bay cự kiếm.","anchor":"mỗi một quyền đánh ra đều có một cái bàn tay màu vàng thật lớn từ trong quyền sáo bay ra"}]},"nguon":["@c0481"]},{"id":"thuoc-ngan-bach-quang","name":"Thước ngắn bạch quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thanh Dịch cư sĩ"],"trangThai":"dang-co","blurb":"Pháp bảo phòng ngự của Thanh Dịch cư sĩ, bạch quang lập lòe, phối hợp Ly Quy phòng ngự kín kẽ.","detail":"Pháp bảo hình thước ngắn phát bạch quang lập lòe, Thanh Dịch cư sĩ dùng phối hợp cùng Ly Quy để phòng ngự mưa gió không lọt vào trước công kích của Thiên Ngộ Tử.","congNang":["Phòng ngự bằng bạch quang lập lòe"],"chuSoHuu":[{"ten":"Thanh Dịch cư sĩ","tuChuong":"@c0481","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0481","loai":"dùng","importance":"normal","giaiDoan":"Trận chiến Hư Thiên Điện","text":"Thanh Dịch cư sĩ dùng thước ngắn bạch quang phối hợp Ly Quy phòng ngự trước bầy Thanh Cức Điểu của Thiên Ngộ Tử.","anchor":"một cái thước ngắn bạch quang lập lòe phòng ngự mưa gió không lọt vào"}]},"nguon":["@c0481"]},{"id":"bich-luc-ti-vong","name":"Bích lục ti võng","cn":"","aliases":["Ti võng bích lục"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Huyền Cốt"],"trangThai":"dang-co","blurb":"Bích lục ti võng là pháp bảo của Huyền Cốt, có thể phóng lục quang hóa thành ti võng bích lục khổng lồ, bao phủ và trói bắt nhiều mục tiêu cùng lúc trên diện rộng.","detail":"Tại @c0481, Huyền Cốt thi triển pháp bảo này bằng cách phóng lục quang, lục quang hóa thành ti võng bích lục có kích thước rất lớn, đủ sức bao phủ cả hắc sắc cự mãng của Ô Sửu lẫn hỏa lang hai đầu vào bên trong, qua đó đoạt quyền kiểm soát mục tiêu. Pháp bảo thể hiện khả năng khống chế diện rộng, có thể trói bắt đồng thời nhiều đối tượng kích cỡ lớn.","congNang":["Phóng lục quang hóa thành ti võng bích lục khổng lồ, bao phủ và trói bắt nhiều mục tiêu diện rộng cùng lúc @c0481","Đoạt quyền kiểm soát mục tiêu bị trói bắt @c0481"],"chuSoHuu":[{"ten":"Huyền Cốt","tuChuong":"@c0481","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0481","loai":"dùng","importance":"major","giaiDoan":"Đoạt hỏa lang hai đầu","text":"Huyền Cốt phóng lục quang hóa ti võng bích lục thật lớn bao phủ cả hắc mãng của Ô Sửu lẫn hỏa lang, đoạt quyền kiểm soát bảo vật.","anchor":"hóa thành một cái ti võng bích lục thật lớn, đem hắc sắc cự mãng và hỏa lang bao phủ vào bên trong"}]},"nguon":["@c0481"],"uyLuc":"Đủ sức bao phủ đồng thời cả hắc sắc cự mãng của Ô Sửu lẫn hỏa lang hai đầu, trói bắt và đoạt quyền kiểm soát @c0481","dacDiem":"Ti võng mang sắc bích lục, được hóa thành từ lục quang, có kích thước rất lớn đủ phủ nhiều linh thú cỡ lớn"},{"id":"ngoc-nhu-y","name":"Ngọc Như Ý","cn":"","aliases":["Hỏa lang hai đầu","Hỏa diễm cự lang","Ngân Lang","Hỏa lang cổ bảo","Ngọc Như Ý hoàng hồng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc Như Ý là cổ bảo vốn do hỏa lang trong Hư Thiên Đỉnh biến thành, mang hai màu hoàng hồng với hình sói điêu khắc sống động trên bề mặt. Bảo vật bất ngờ rơi vào tay Hàn Lập khi Ô Sửu và Huyền Cốt giằng co tranh đoạt mà không bên nào đoạt được.","detail":"Ngọc Như Ý nguyên là hỏa lang cổ bảo xuất hiện trong Hư Thiên Đỉnh. Trong cuộc tranh đoạt, Ô Sửu dùng hắc sắc cự mãng, Huyền Cốt dùng bích lục ti võng giằng co trói buộc, nhưng hỏa lang vẫn bình yên trong hào quang. Cuối cùng cổ bảo không thuộc về ai trong hai người mà tự biến thành Ngọc Như Ý hai màu hoàng hồng, trên bề mặt điêu khắc hình một con sói rất sống động, rồi bất ngờ rơi vào tay Hàn Lập — một tu sĩ Trúc Cơ kỳ ngay từ đầu không hề có ý định ra tay. Sự kiện này khiến Cực Âm sư tổ giật mình nghi hoặc, còn Ô Sửu thì oán hận.","hinhDang":"Ngọc Như Ý hai màu hoàng hồng, điêu khắc hình sói sống động","nguonGoc":"Cổ bảo trong Hư Thiên Đỉnh, do hỏa lang biến thành","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0482","denChuong":"","cachCoDuoc":"Hỏa lang cổ bảo tự rơi vào tay khi Ô Sửu và Huyền Cốt giằng co bất phân","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0482","loai":"đổi chủ","importance":"major","giaiDoan":"Hỏa lang biến thành Ngọc Như Ý, rơi vào tay Hàn Lập","phamCap":"Cổ bảo","text":"Hỏa lang cổ bảo bị Ô Sửu và Huyền Cốt tranh đoạt giằng co nhưng cuối cùng biến thành Ngọc Như Ý hai màu hoàng hồng, bất ngờ rơi vào tay Hàn Lập. Cực Âm sư tổ giật mình nghi hoặc.","anchor":"Hàn Lập đang cầm trong tay một kiện Ngọc như ý có hai màu hoàng hồng"}]},"capNhatToi":"@c0482","nguon":["@c0482"],"dacDiem":"Hai màu hoàng hồng, bề mặt điêu khắc hình sói sống động; vốn do hỏa lang cổ bảo biến hóa thành, bình yên trước sự giằng co trói buộc của hắc sắc cự mãng và bích lục ti võng (@c0482)."},{"id":"co-boi-hinh-tu-phuong","name":"Cổ Bội hình tứ phương","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thượng cấp","soHuu":["Vạn Thiên Minh"],"trangThai":"dang-co","blurb":"Cổ bảo hình tứ phương xuất thế từ Hư Thiên Đỉnh, mặt trên lưu quang phù văn chớp động, linh khí sung túc. Bị Vạn Thiên Minh dùng mưu kế giả Thiên La chân lôi dọa lui đối thủ mà đoạt được tại @c0482.","detail":"Cổ Bội hình tứ phương là một cổ bảo ẩn tàng bên trong Hư Thiên Đỉnh, khi xuất thế ban đầu hiện thành một đạo hoàng quang, sau đó hiện nguyên hình là bội ngọc hình tứ phương với bề mặt lưu quang phù văn liên tục chớp động, linh khí vô cùng sung túc, được xếp vào hàng bảo vật thượng cấp. Trong cuộc tranh đoạt tại Hư Thiên Đỉnh, Vạn Thiên Minh huyễn hóa tử sắc hỏa long nuốt lấy hoàng quang chứa cổ bội, đồng thời phun ra hai viên giả Thiên La chân lôi châu khiến Cực Âm sư tổ và lão giả nho sam hoảng sợ né tránh, nhờ đó thành công chiếm đoạt pháp bảo này (@c0482).","hinhDang":"Hình tứ phương, lưu quang phù văn chớp động","nguonGoc":"Cổ bảo trong Hư Thiên Đỉnh","chuHienThoi":"Vạn Thiên Minh","chuSoHuu":[{"ten":"Vạn Thiên Minh","tuChuong":"@c0482","denChuong":"","cachCoDuoc":"Đoạt bằng mưu kế giả Thiên La chân lôi châu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0482","loai":"đổi chủ","importance":"major","giaiDoan":"Vạn Thiên Minh đoạt Cổ Bội","phamCap":"Thượng cấp","text":"Hoàng quang từ Hư Thiên Đỉnh hiện nguyên hình Cổ Bội hình tứ phương, linh khí sung túc. Vạn Thiên Minh dùng giả Thiên La chân lôi lừa Cực Âm và lão giả nho sam né tránh, đoạt thành công.","anchor":"Là một Cổ Bội hình tứ phương, mặt trên lưu quang phù văn chớp động, linh khí sung túc"}]},"capNhatToi":"@c0482","nguon":["@c0482"],"dacDiem":"Hình dáng tứ phương, mặt trên lưu quang phù văn chớp động, linh khí sung túc, thuộc hàng bảo vật thượng cấp."},{"id":"dong-tien-co-bach-quang","name":"Đồng tiền cổ bạch quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Man Hồ Tử"],"trangThai":"dang-co","blurb":"Đồng tiền cổ xưa phát bạch quang kỳ lạ, cổ bảo từ Hư Thiên Đỉnh bay ra, bị Man Hồ Tử đoạt được.","detail":"Bạch quang từ Hư Thiên Đỉnh bắn ra hiện hình là một đồng tiền hình dạng cổ xưa, bạch quang lập lòe, thoạt nhìn rất kỳ lạ. Man Hồ Tử nhờ phòng ngự siêu cường của Thiên Ma công đón công kích của lão giả gầy ốm và Thiên Ngộ Tử, đoạt được đồng tiền cổ.","hinhDang":"Hình dạng đồng tiền cổ xưa, bạch quang lập lòe","nguonGoc":"Cổ bảo trong Hư Thiên Đỉnh","chuHienThoi":"Man Hồ Tử","chuSoHuu":[{"ten":"Man Hồ Tử","tuChuong":"@c0482","denChuong":"","cachCoDuoc":"Đoạt bằng phòng ngự Thiên Ma công","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0482","loai":"đổi chủ","importance":"normal","giaiDoan":"Man Hồ Tử đoạt đồng tiền cổ","text":"Bạch quang từ Hư Thiên Đỉnh hiện hình đồng tiền cổ xưa bạch quang lập lòe. Man Hồ Tử nhờ Thiên Ma công đón đỡ công kích, đoạt thành công.","anchor":"Là một đồng tiền hình dạng cổ xưa, bạch quang lập lòe, thoạt nhìn rất kì lạ"}]},"capNhatToi":"@c0482","nguon":["@c0482"]},{"id":"tieu-dao-xanh-biec-huyen-cot","name":"Tiểu đao xanh biếc của Huyền Cốt","cn":"","aliases":["Kim Lôi Trúc tiểu đao"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Huyền Cốt"],"trangThai":"dang-co","blurb":"Thanh tiểu đao hơn một tấc, ngắn không chuôi, đao mang bất định, thực chất do một cây Kim Lôi Trúc nhỏ tạo thành bị thuật che mắt che giấu diện mạo. Là bảo vật mà năm xưa Cực Âm từng ám toán Huyền Cốt để cướp.","detail":"Huyền Cốt phun thanh tiểu đao từ miệng tấn công ngân lang nhưng không gây thương tích. Hàn Lập nhờ bổn mạng pháp bảo cũng là Kim Lôi Trúc nên cảm ứng nhận ra bản chất thật. Cực Âm năm xưa đã ám toán Huyền Cốt vì bảo vật này, nay Huyền Cốt dám dùng trước mặt Cực Âm cho thấy mức cấp bách muốn đoạt ngân lang.","hinhDang":"Tiểu đao hơn một tấc, ngắn không có chuôi, đao mang bất định","nguonGoc":"Do một cây Kim Lôi Trúc nhỏ tạo thành, bị che giấu bằng thuật che mắt","congNang":["Tấn công cận chiến"],"dacDiem":"Bản chất là Kim Lôi Trúc, bị pháp thuật biến đổi diện mạo hoàn toàn","chuHienThoi":"Huyền Cốt","chuSoHuu":[{"ten":"Huyền Cốt","tuChuong":"@c0483","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"nguon":["@c0483"],"tabs":{"tienTrinh":[{"chuong":"@c0483","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu lộ diện","text":"Huyền Cốt phun ra thanh tiểu đao xanh biếc tấn công ngân lang. Hàn Lập cảm ứng phát hiện đó là Kim Lôi Trúc bị thuật che mắt che giấu, nhớ Cực Âm từng ám toán Huyền Cốt vì bảo vật này.","anchor":"thanh tiểu đao này rõ ràng là do một cây Kim Lôi Trúc nhỏ mà tạo thành"}]}},{"id":"nam-cai-vong-dong","name":"Năm cái vòng đồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Năm cái vòng đồng là pháp bảo Hàn Lập sử dụng để trói buộc ngân lang, chuyên khắc chế loại yêu thú này. Khi được phóng ra và phun thanh khí kích hoạt, chúng lóe ánh sáng ngũ sắc rồi ẩn vào thân ngân lang, sau đó hiện lên siết chặt tứ chi và đầu, khiến nó hoàn toàn không thể nhúc nhích.","detail":"Năm cái vòng đồng được Hàn Lập lấy ra từ túi trữ vật và phun thanh khí lên để kích hoạt. Khi ngân lang thu nhỏ thoát khỏi hắc mãng và bị đánh bắn đúng hướng Hàn Lập, Hàn Lập lập tức phóng năm vòng đồng ra. Vòng đồng lóe ánh sáng ngũ sắc rồi ẩn đi, nhập vào thân ngân lang, sau đó hiện lên trên bốn chi và đầu siết chặt hoàn toàn, khiến ngân lang không thể nhúc nhích. Pháp bảo này là khắc tinh chuyên dùng để đối phó ngân lang.","congNang":["Trói buộc ngân lang bằng cách siết chặt tứ chi và đầu, khiến nó hoàn toàn không thể nhúc nhích @c0483","Khắc chế ngân lang, là khắc tinh của loại yêu thú này @c0483","Khi được phun thanh khí kích hoạt, lóe ánh sáng ngũ sắc rồi ẩn vào thân mục tiêu trước khi hiện lên siết chặt @c0483"],"chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0483","denChuong":"","cachCoDuoc":"Có sẵn trong túi trữ vật","trangThai":"dang-co"}],"nguon":["@c0483"],"tabs":{"tienTrinh":[{"chuong":"@c0483","loai":"dùng","importance":"major","giaiDoan":"Thu phục ngân lang","text":"Hàn Lập phóng năm vòng đồng siết chặt tứ chi và đầu ngân lang, là khắc tinh khiến nó không thể nhúc nhích, phối hợp hoa lam cổ bảo thu phục thành công.","anchor":"trên tứ chi và đầu đều hiện lên mấy cái vòng đồng vừa mới ẩn đi kia"}]},"uyLuc":"Giam chặt hoàn toàn ngân lang, siết chặt tứ chi và đầu khiến nó không thể nhúc nhích dù là khẽ.","dacDiem":"Bộ năm vòng, khi kích hoạt bằng thanh khí sẽ lóe ánh sáng ngũ sắc rồi ẩn đi trước khi hiện lên trên thân mục tiêu để trói buộc."},{"id":"duong-hoan","name":"Dương hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Cực Âm lão tổ"],"trangThai":"đang sử dụng","blurb":"Nửa Dương của bộ Âm Dương hoàn, hiện trên người Cực Âm tổ sư. Có khả năng khắc chế Âm hoàn.","detail":"Nửa còn lại của bộ Âm Dương hoàn do Huyền Cốt tạo ra năm xưa, hiện trên người Cực Âm tổ sư. Dương hoàn khắc chế Âm hoàn, ai cầm Âm hoàn mà chống lại người giữ Dương hoàn sẽ phản tác dụng.","dinhDanh":"goc","boCha":"huyen-am-hoan","congNang":["Khắc chế Âm hoàn (Huyền Âm hoàn)"],"tabs":{"tienTrinh":[{"chuong":"@c0456","loai":"xuất hiện","importance":"normal","giaiDoan":"Được Huyền Cốt tiết lộ tồn tại","text":"Huyền Cốt truyền âm cho Hàn Lập tiết lộ Dương hoàn đang trên người Cực Âm, khắc chế Âm hoàn mà Cực Âm vừa trao.","anchor":"Âm hoàn này tuy có công hiệu khắc địch hộ chủ nhưng lại bị Dương hoàn trên người của hắn ta khắc chế"}]},"nguon":["@c0456"]},{"id":"bao-thach-xanh-biec-khoi-loi","name":"Bảo thạch xanh biếc (khôi lỗi)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Viên bảo thạch xanh biếc tản hàn khí quỷ dị, tìm thấy trong tàn tích khôi lỗi lang thủ tầng một Hư Thiên Điện. Hàn Lập thu vào túi trữ vật để nghiên cứu thuật chế tạo khôi lỗi cổ xưa.","detail":"Viên bảo thạch màu xanh biếc lập lòe tản ra hàn khí quỷ dị, nằm trong xác khôi lỗi lang thủ kim sắc bị Man Hồ Tử phá hủy. Huyền Cốt nói tài liệu khôi lỗi không luyện chế được pháp bảo, nhưng Hàn Lập vẫn thu lại vì muốn tìm hiểu cấu tạo và thuật chế tạo khôi lỗi cổ xưa.","congNang":["Tản hàn khí quỷ dị, nguồn gốc và công dụng cụ thể chưa rõ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0473","denChuong":"","cachCoDuoc":"Thu nhặt từ tàn tích khôi lỗi trong mê cung Hư Thiên Điện","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0473","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập phát hiện và thu nhặt","text":"Hàn Lập quan sát tàn tích khôi lỗi lang thủ bị Man Hồ Tử phá hủy, chú ý viên bảo thạch xanh biếc tản hàn khí quỷ dị. Bất chấp Huyền Cốt nói không luyện chế được pháp bảo, thu vào túi trữ vật để nghiên cứu.","anchor":"Ánh mắt hắn rơi vào một viên bảo thạch màu xanh biếc, vật đó lập lòe tản ra một cổ hàn khí"}]},"nguon":["@c0473"]},{"id":"hoa-than-phu","name":"Hóa Thân Phù","cn":"","aliases":["Tinh Cung Hóa Thân Phù"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hai trưởng lão áo trắng Tinh Cung"],"trangThai":"da-dung","blurb":"Hóa Thân Phù là phù lục đặc biệt của Tinh Cung, cho phép người dùng tạo phân thân có sức chiến đấu thực tế mà chân thân không cần hiện diện. Phân thân sau khi hoàn thành nhiệm vụ sẽ tan biến thành điểm sáng trắng, để lại phù vàng tự thiêu.","detail":"Hóa Thân Phù là bảo phù thuộc về Tinh Cung, được sử dụng để tạo ra phân thân chiến đấu từ xa. Phân thân do phù tạo ra sở hữu năng lực chiến đấu thực sự — có thể đỡ được đòn tấn công của tu sĩ Nguyên Anh kỳ, đồng thời cũng có khả năng phóng phi kiếm tấn công. Hai trưởng lão Tinh Cung đã sử dụng Hóa Thân Phù tạo phân thân lẻn vào nội điện Hư Thiên điện nhằm phá hoại cuộc đoạt bả (@c0484). Trong suốt quá trình, chân thân người dùng vẫn an toàn ở nơi khác. Khi phân thân hoàn thành nhiệm vụ hoặc hết hiệu lực, nó tan thành những điểm sáng trắng, mỗi phân thân để lại một đạo phù màu vàng tự bốc cháy rồi biến mất, không để lại dấu vết.","congNang":["Tạo phân thân chiến đấu từ xa, chân thân không cần có mặt tại hiện trường (@c0484)","Phân thân có sức chiến đấu thực tế cấp Nguyên Anh kỳ, đỡ được đòn công kích và phóng được phi kiếm","Phân thân có thể xâm nhập khu vực được bảo vệ để thực hiện nhiệm vụ phá hoại (@c0484)"],"chuSoHuu":[{"ten":"Hai trưởng lão áo trắng Tinh Cung","tuChuong":"@c0484","denChuong":"","cachCoDuoc":"","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0484","loai":"dung","importance":"major","giaiDoan":"Sử dụng phá hoại đoạt bảo","text":"Hai trưởng lão Tinh Cung dùng Hóa Thân Phù tạo phân thân lẻn vào nội điện Hư Thiên điện, phá hoại cuộc đoạt bảo của cả chính lẫn ma, chém đứt Huyết Ngọc Tri Thù và đánh văng Hàn Lập. Phân thân tan biến sau khi hoàn thành.","anchor":"Tinh Cung Hóa thân phù! Cũng không phải là chân thân đến đây"}]},"nguon":["@c0484"],"uyLuc":"Phân thân do Hóa Thân Phù tạo ra đạt sức chiến đấu thực tế cấp Nguyên Anh kỳ, đủ sức đỡ quyền kình Nguyên Anh kỳ và phóng phi kiếm tấn công.","dacDiem":"Phân thân sau khi hoàn thành nhiệm vụ tan thành điểm sáng trắng, mỗi vị để lại một đạo phù màu vàng tự bốc cháy rồi tiêu hủy hoàn toàn, thuộc loại phù dùng một lần."},{"id":"quan-nhat-kiem","name":"Quán Nhật Kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hai trưởng lão áo trắng Tinh Cung"],"trangThai":"dang-co","blurb":"Phi kiếm của trưởng lão Tinh Cung, tốc độ cực nhanh, uy lực đủ chém đứt sinh vật Nguyên Anh kỳ.","detail":"Phi kiếm phóng ra dưới dạng hai đạo bạch hồng tốc độ cực nhanh. Một đạo chém đứt đôi Huyết Ngọc Tri Thù, một đạo đánh Hàn Lập văng ra nhưng không chém đứt nhờ Ngọc Như Ý hộ thân.","congNang":["Phi kiếm tấn công tầm xa, tốc độ cực nhanh, uy lực chém đứt sinh vật cấp Nguyên Anh kỳ"],"chuSoHuu":[{"ten":"Hai trưởng lão áo trắng Tinh Cung","tuChuong":"@c0484","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0484","loai":"dung","importance":"normal","giaiDoan":"Đánh lén Huyết Ngọc Tri Thù và Hàn Lập","text":"Trưởng lão Tinh Cung phóng hai đạo bạch hồng, một đạo chém đứt đôi Huyết Ngọc Tri Thù, một đạo đánh Hàn Lập văng nhưng bị Ngọc Như Ý đỡ.","anchor":"Bị pháp bảo “Quán Nhật Kiếm” của hắn đánh trúng ở khoảng cách như vậy"}]},"nguon":["@c0484"]},{"id":"thien-la-chan-loi","name":"Thiên La chân lôi","cn":"天罗真雷","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vạn Thiên Minh"],"trangThai":"dang-co","blurb":"Thiên La chân lôi là bảo vật có uy lực cực lớn mà Vạn Thiên Minh dùng để uy hiếp nhằm đoạt Bổ Thiên Đan. Nhiều lão quái Nguyên Anh Kỳ như Cực Âm lão tổ và Thanh Dịch cư sĩ đều khiếp sợ trước vật này.","detail":"Thiên La chân lôi xuất hiện trong cuộc tranh đoạt Bổ Thiên Đan, khi Vạn Thiên Minh dùng nó làm lời uy hiếp để buộc các tu sĩ khác không được cản trở. Cực Âm lão tổ và Thanh Dịch cư sĩ — đều là nhân vật Nguyên Anh Kỳ — tỏ ra kiêng dè trước bảo vật này. Man Hồ Tử ban đầu thách thức, không tin Vạn Thiên Minh dám sử dụng. Viên châu tím trong suốt trên tay Nguyên Anh của Vạn Thiên Minh có thể là hình thái của Thiên La chân lôi.","congNang":["Uy lực khiến nhiều lão quái Nguyên Anh Kỳ khiếp sợ, được dùng làm phương tiện uy hiếp trong tranh đoạt @c0485"],"chuSoHuu":[{"ten":"Vạn Thiên Minh","tuChuong":"@c0485","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0485","loai":"xuất hiện","importance":"major","giaiDoan":"Vạn Thiên Minh uy hiếp dùng","text":"Vạn Thiên Minh uy hiếp sử dụng Thiên La chân lôi để đoạt Bổ Thiên Đan. Cực Âm và Thanh Dịch đều sợ. Man Hồ Tử thách thức nhưng kinh sợ khi thấy Nguyên Anh xuất khiếu cầm viên châu tím.","anchor":"Thiên La chân lôi! Cực Âm và Thanh Dịch sợ vật ấy nhưng bổn đại gia muốn xem thử"}]},"nguon":["@c0485"],"uyLuc":"Khiến các tu sĩ Nguyên Anh Kỳ lão luyện như Cực Âm lão tổ và Thanh Dịch cư sĩ đều phải kiêng sợ, không dám cản trở.","dacDiem":"Có thể tồn tại dưới hình thái một viên châu tím trong suốt nằm trên tay Nguyên Anh của chủ nhân."},{"id":"hap-loi-thach","name":"Hấp Lôi thạch","cn":"","aliases":["Hấp Lôi châu"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Man Hồ Tử"],"trangThai":"đang sử dụng","blurb":"Hấp Lôi thạch là tinh thạch tử quang lấy từ cơ thể Lôi Kình yêu thú, có khả năng hấp thu hơn phân nửa uy lực lôi điện. Man Hồ Tử gắn viên thạch này vào tiểu thuẫn nguyên anh để chống đỡ Thiên La chân lôi của Vạn Thiên Minh, nhờ đó chỉ chịu tổn thương nhẹ bề ngoài.","detail":"Hấp Lôi thạch là viên tinh thạch trong suốt phát ra tử quang, được Man Hồ Tử đoạt từ xác Lôi Kình yêu thú mà hắn từng giết trước đây. Man Hồ Tử gắn viên thạch vào trung tâm tiểu thuẫn hình tròn của nguyên anh, khiến thuẫn phóng ra quang thuẫn xanh nhạt bảo vệ. Trong trận chiến với Vạn Thiên Minh, khi đối phương kích hoạt Thiên La chân lôi, Hấp Lôi thạch hấp thu hơn phân nửa uy lực lôi điện, khiến Man Hồ Tử chỉ bị tổn thương nhẹ bề ngoài thay vì chịu toàn bộ sức công phá của lôi pháp.","congNang":["Hấp thu hơn phân nửa uy lực lôi điện mà bản thân không bị tổn hao @c0486"],"nguonGoc":"Lấy từ cơ thể Lôi Kình yêu thú bị Man Hồ Tử giết","chuSoHuu":[{"ten":"Man Hồ Tử","tuChuong":"@c0486","denChuong":"","cachCoDuoc":"Giết Lôi Kình yêu thú đoạt được","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0486","loai":"dùng","importance":"major","giaiDoan":"Phá giải Thiên La chân lôi","text":"Man Hồ Tử dùng Hấp Lôi thạch gắn trong tiểu thuẫn hấp thu hơn phân nửa uy lực Thiên La chân lôi của Vạn Thiên Minh, thoát ra khỏi lôi vân mà chỉ bị tổn thương nhẹ.","anchor":"có thể đoạt được khối Hấp Lôi thạch không bị tổn hao gì ở trong cơ thể nó"}]},"nguon":["@c0486"],"uyLuc":"Hấp thu hơn phân nửa uy lực Thiên La chân lôi, khiến người sử dụng chỉ chịu tổn thương nhẹ bề ngoài.","dacDiem":"Viên tinh thạch trong suốt phát tử quang, nguồn gốc từ cơ thể Lôi Kình yêu thú."},{"id":"loi-hoan","name":"Lôi hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vạn Thiên Minh"],"trangThai":"đã dùng","blurb":"Quả cầu lôi điện tiêu hao, Vạn Thiên Minh ném ra nổ tung thành quang đoàn tử sắc lớn như bánh xe để kích hoạt Thiên La chân lôi.","detail":"Vạn Thiên Minh có hai quả lôi hoàn trong lòng bàn tay nguyên anh. Ném ra nổ tung thành quang đoàn tử sắc lớn như bánh xe, kích hoạt Thiên La chân lôi tạo lôi vân tử sắc hơn mười trượng bao phủ Man Hồ Tử.","congNang":["Kích hoạt Thiên La chân lôi thành lôi vân tử sắc @c0486"],"chuSoHuu":[{"ten":"Vạn Thiên Minh","tuChuong":"@c0486","denChuong":"","cachCoDuoc":"","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0486","loai":"dùng","importance":"normal","giaiDoan":"Kích hoạt Thiên La chân lôi","text":"Vạn Thiên Minh ném lôi hoàn nổ tung thành quang đoàn tử sắc, kích hoạt lôi vân hơn mười trượng bao phủ Man Hồ Tử.","anchor":"cầm một trong hai quả lôi hoàn trong lòng bàn tay ném ra"}]},"nguon":["@c0486"]},{"id":"thanh-sac-quai-xa","name":"Thanh sắc quái xà","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Huyền Cốt"],"trangThai":"đang dùng","blurb":"Pháp bảo hình rắn xanh của Huyền Cốt, bay ra từ tay áo quấn quanh yêu thi, phối hợp hoa sen lục phong ấn đối phương.","detail":"Bay ra từ tay áo Huyền Cốt, quấn quanh Thiên Đô yêu thi rồi kết hợp hoa sen lục phong ấn yêu thi khiến Ô Sửu mất liên lạc với yêu thi.","congNang":["Trói buộc mục tiêu, phối hợp hoa sen lục phong ấn"],"chuSoHuu":[{"ten":"Huyền Cốt","tuChuong":"@c0487","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0487","loai":"xuất hiện","importance":"normal","giaiDoan":"Trận giết Ô Sửu","text":"Bay ra từ tay áo Huyền Cốt, quấn quanh Thiên Đô yêu thi phối hợp hoa sen lục phong ấn.","anchor":"một đầu thanh sắc quái xà từ trong tay áo bay ra"}]},"nguon":["@c0487"]},{"id":"tieu-kiem-bon-mang-o-suu","name":"Tiểu kiếm màu đen (bổn mạng pháp bảo Ô Sửu)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Ô Sửu"],"trangThai":"chủ nhân đã chết","blurb":"Bổn mạng pháp bảo của Ô Sửu, tiểu kiếm màu đen phun ra từ miệng tấn công. Bị Huyền Cốt tay không bắt giữ, tổn hại khiến Ô Sửu phun máu đen.","detail":"Ô Sửu phun tiểu kiếm từ miệng tấn công Huyền Cốt, nhưng bị quỷ trảo tay không bắt giữ, hắc khí tan đi mất linh tính. Tổn hại bổn mạng pháp bảo gây tổn thương trực tiếp lên chủ nhân.","congNang":["Bổn mạng pháp bảo liên kết chủ nhân, tổn hại pháp bảo thì chủ nhân cũng bị thương"],"chuSoHuu":[{"ten":"Ô Sửu","tuChuong":"@c0487","denChuong":"@c0487","cachCoDuoc":"Bổn mạng pháp bảo","trangThai":"chủ nhân đã chết"}],"tabs":{"tienTrinh":[{"chuong":"@c0487","loai":"dùng","importance":"normal","giaiDoan":"Trận Ô Sửu vs Huyền Cốt","text":"Ô Sửu phun tiểu kiếm tấn công nhưng bị Huyền Cốt quỷ trảo tay không bắt giữ, hắc khí tan đi, Ô Sửu tổn thương phun máu đen.","anchor":"thanh tiểu kiếm kia liền bị hắn nắm trong tay, không hề phảng kháng được"}]},"nguon":["@c0487"]},{"id":"ngoc-gian-luyen-che-cuu-khuc-linh-sam","name":"Ngọc giản luyện chế Cửu Khúc Linh Sâm","category":"khac","categoryLabel":"Vật phẩm khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bạch sắc ngọc giản cổ kính do Huyền Cốt giao cho Hàn Lập làm tín vật liên thủ, bên trong ghi phương pháp luyện chế Cửu Khúc Linh Sâm cùng hai ba loại dược tài phụ trợ lạ.","detail":"Ngọc giản cổ kính màu trắng chứa nội dung luyện chế linh dược Cửu Khúc Linh Sâm và hai ba loại dược tài phụ trợ mà Hàn Lập chưa từng nghe. Hàn Lập dùng quang đoàn bao phủ kiểm tra trước, rồi dùng thần thức quét nhanh nội dung, sơ bộ thấy không giống ngụy tạo, liền thu vào túi trữ vật.","congNang":["Ghi phương pháp luyện chế Cửu Khúc Linh Sâm cùng dược tài phụ trợ"],"chuSoHuu":[{"ten":"Huyền Cốt","tuChuong":"@c0488","denChuong":"@c0488","cachCoDuoc":"Tự sở hữu từ trước","trangThai":"da-giao"},{"ten":"Hàn Lập","tuChuong":"@c0488","denChuong":"","cachCoDuoc":"Nhận từ Huyền Cốt làm tín vật liên thủ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0488","loai":"xuất hiện","importance":"normal","giaiDoan":"Huyền Cốt giao tín vật","text":"Huyền Cốt giao ngọc giản cổ kính chứa phương luyện chế Cửu Khúc Linh Sâm cho Hàn Lập làm tín vật thể hiện thành ý liên thủ. Hàn Lập kiểm tra sơ bộ thấy không giống ngụy tạo, thu vào túi trữ vật.","anchor":"bên trong quả thật có nói về linh dược ‘Cửu khúc linh sâm’ này"}]},"nguon":["@c0488"]},{"id":"lam-sac-bang-diem","name":"Lam sắc băng diễm","cn":"","aliases":[],"category":"khac","categoryLabel":"Dị hỏa","phamCap":"Không rõ","soHuu":["Huyền Cốt"],"trangThai":"Đã bị hợp nhất vào Tu La thánh hỏa","blurb":"Ngọn lửa lam sắc trong quang cầu Huyền Cốt vừa đoạt được, có thể biến hóa thành băng long ngũ trảo và băng thuẫn tam giác, uy lực ngang Ích Tà Thần Lôi.","detail":"Ngọn lửa lam sắc nằm trong quang cầu mà Huyền Cốt vừa đoạt được (tức Kiền Lam Băng Diễm). Có thể biến hóa linh hoạt thành băng long ngũ trảo (rồng băng năm móng) và băng thuẫn tam giác. Uy lực cực lớn, ngang sức Ích Tà Thần Lôi, không bên nào áp chế. Tuy nhiên chưa bị luyện hóa hoàn chỉnh. Là một trong ba thành phần được Huyền Cốt hợp nhất để tạo Tu La thánh hỏa.","congNang":["Biến hóa thành băng long ngũ trảo tấn công","Tạo băng thuẫn tam giác phòng thủ","Đóng băng pháp bảo đối phương","Thành phần hợp thành Tu La thánh hỏa"],"chuSoHuu":[{"ten":"Huyền Cốt","tuChuong":"@c0490","denChuong":"","cachCoDuoc":"Đoạt được","trangThai":"dang-dung"}],"capNhatToi":"@c0490","tabs":{"tienTrinh":[{"chuong":"@c0490","loai":"dùng","importance":"normal","giaiDoan":"Huyền Cốt dùng lam sắc băng diễm chiến đấu rồi hợp nhất vào Tu La thánh hỏa","text":"Huyền Cốt dùng lam sắc băng diễm đóng băng và vẩy rơi Ngũ xuyến đồng hoàn, triệu băng long ngũ trảo và băng thuẫn tam giác chống cự kiếm Hàn Lập. Sau đó hợp nhất cùng Huyền Hồn âm hỏa và hắc sắc điện hồ thành Tu La thánh hỏa.","anchor":"lam sắc băng diễm cũng chẳng làm gì được Ích Tà Thần Lôi"}]},"nguon":["@c0490"]},{"id":"kim-loi-truc-tieu-tien","name":"Mũi tên Kim Lôi Trúc","cn":"金雷竹小箭","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Huyền Cốt"],"trangThai":"Không rõ (chủ đã chết)","blurb":"Tiểu tiễn Kim Lôi trúc của Huyền Cốt, phun ra từ miệng, có thể phá hủy nhiều đạo kiếm quang.","detail":"Huyền Cốt phun ra một đạo lục mang (tiểu tiễn Kim Lôi trúc) từ miệng để chống kiếm quang Hàn Lập, phá hủy được bốn năm đạo Thanh Nguyên kiếm quang trước khi bị đánh bay.","tabs":{"tienTrinh":[{"chuong":"@c0491","loai":"dùng","importance":"normal","giaiDoan":"Huyền Cốt sử dụng trong trận chiến cuối","text":"Huyền Cốt phun tiểu tiễn Kim Lôi trúc từ miệng chống kiếm quang Hàn Lập, phá được bốn năm đạo nhưng cuối cùng bị đánh bay.","anchor":"Lục mang sau khi phá hủy bốn, năm đạo kiếm quang, cuối cùng cũng bị đánh bay sang một bên"}]},"congNang":["Phun ra từ miệng dưới dạng lục mang, phá hủy kiếm quang đối thủ"],"chuSoHuu":[{"ten":"Huyền Cốt","tuChuong":"@c0491","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"chủ đã chết"}],"nguon":["@c0491"]},{"id":"bach-te-boi","name":"Bạch Tê bội","cn":"白犀佩","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Pháp bảo phát bạch quang cực nóng, có khả năng xua hàn khí. Hàn Lập dùng để chống đỡ hàn khí Kiền Lam Băng Diễm sau khi Huyền Cốt chết.","detail":"Khi đưa linh lực vào, Bạch Tê bội phát ra bạch quang cực nóng có thể xua đi hàn khí xung quanh. Trong trận Kiền Lam Băng Diễm vô chủ bùng phát, Hàn Lập dựa vào nó bảo hộ bản thân khỏi bị đóng băng.","congNang":["Phát bạch quang cực nóng xua hàn khí"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0492","denChuong":"","cachCoDuoc":"đã sở hữu từ trước","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0492","loai":"dùng","importance":"normal","giaiDoan":"Chống hàn khí Kiền Lam Băng Diễm","text":"Hàn Lập đưa linh lực vào Bạch Tê bội phát bạch quang cực nóng xua hàn khí Kiền Lam Băng Diễm vô chủ, bảo hộ bản thân khỏi bị đóng băng.","anchor":"vội vàng đưa linh lực vào Bạch Tê bội, bạch quang cực nóng xua đi hàn khí xung quanh"}]},"nguon":["@c0492"]},{"id":"khuc-xuong-trang-bat-hoai","name":"Khúc xương trắng bất hoại","cn":"","category":"khac","categoryLabel":"Dị vật","soHuu":["Hàn Lập"],"trangThai":"đang giữ","blurb":"Tàn dư xương cốt duy nhất của Huyền Cốt không bị Tu La thánh hỏa hủy, trắng như ngọc dài vài tấc. Từng chứa Hư Thiên tàn đồ bên trong.","detail":"Khúc xương trắng như ngọc dài vài tấc, là phần duy nhất trên người Huyền Cốt không bị Tu La thánh hỏa luyện hóa thành tro. Trước đó Huyền Cốt từng lấy Hư Thiên tàn đồ từ bên trong đoạn xương này. Hàn Lập suy đoán nó có khả năng chứa đựng vật phẩm, thu vào túi trữ vật.","congNang":["Có thể chứa đựng vật phẩm bên trong","Bất hoại trước Tu La thánh hỏa"],"chuSoHuu":[{"ten":"Huyền Cốt","tuChuong":"@c0492","denChuong":"@c0492","cachCoDuoc":"xương cốt bản thân","trangThai":"chết"},{"ten":"Hàn Lập","tuChuong":"@c0492","denChuong":"","cachCoDuoc":"thu nhặt sau khi Huyền Cốt bị tiêu diệt","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0492","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát hiện và thu giữ","text":"Hàn Lập phát hiện khúc xương trắng bất hoại tại nơi Huyền Cốt bị tiêu diệt, suy đoán có thể chứa vật phẩm, thu vào túi trữ vật.","anchor":"Chỉ là nó lại không bị Tu La thành hỏa luyện hóa thành tro bụi mà vẫn an nhiên tồn tại"}]},"nguon":["@c0492"]},{"id":"tieu-tien-mau-xanh","name":"Tiểu tiễn màu xanh","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Mũi tên nhỏ từng chứa tàn hồn Huyền Cốt, có khả năng tự bay. Sau khi thần thức Huyền Cốt bị Đề Hồn thú nuốt sạch, Hàn Lập nhặt lấy.","detail":"Tiểu tiễn màu xanh chứa tàn hồn Huyền Cốt, có thể tự bay trốn. Bị Hàn Lập dùng kiếm khí chặn lại và Đề Hồn thú phóng hấp hồn thần quang cuốn lấy. Sau khi thần thức bên trong bị nuốt trọn, Hàn Lập bước tới nhặt lấy.","congNang":["Chứa/mang hồn phách","Có khả năng tự bay"],"chuSoHuu":[{"ten":"Huyền Cốt","tuChuong":"@c0493","denChuong":"@c0493","cachCoDuoc":"Trú hồn bên trong","trangThai":"tu-vong"},{"ten":"Hàn Lập","tuChuong":"@c0493","denChuong":"","cachCoDuoc":"Nhặt sau khi tiêu diệt tàn hồn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0493","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập thu được sau khi diệt tàn hồn","text":"Tiểu tiễn chứa tàn hồn Huyền Cốt cố bay trốn nhưng bị chặn lại, thần thức bên trong bị Đề Hồn thú nuốt sạch, Hàn Lập nhặt lấy.","anchor":"Hàn Lập bước tới vài bước, cầm lấy tiểu tiễn màu xanh kia"}]},"nguon":["@c0493"]},{"id":"quyen-truc-co-so-do-hu-thien-dien","name":"Quyển trục cổ (sơ đồ nội điện Hư Thiên điện)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quyển trục cổ niên đại cùng thời kỳ Hư Thiên đỉnh, là sơ đồ kiến trúc nội điện năm tầng Hư Thiên điện do chủ nhân nơi này để lại. Bên trong chứa một lộ tuyến duy nhất vẽ bằng bút đỏ dẫn tới Truyền Tống trận, có thể là sinh lộ thoát hiểm cuối cùng của chủ nhân Hư Thiên điện.","detail":"Quyển trục cũ kỹ có niên đại rất cổ, cùng thời kỳ với Hư Thiên đỉnh. Khi mở ra không toát chút linh lực nào, nội dung vẽ ngoằn ngoèo thô sơ nhưng rõ ràng thể hiện sơ đồ kiến trúc nội điện năm tầng Hư Thiên điện. Trên sơ đồ có tiêu ký các vị trí trọng yếu gồm thạch đài, đỉnh nhỏ hai tai ba chân (tức Hư Thiên đỉnh), mật thất và các thông đạo liên kết giữa các tầng. Đặc biệt, toàn bộ sơ đồ chỉ có duy nhất một lộ tuyến được vẽ bằng bút đỏ; điểm cuối của lộ tuyến này là một bức tường cao nằm ở biên nội điện, phía sau bức tường có tiêu ký hình dạng giống Truyền Tống trận. Quyển trục được cho là do chủ nhân Hư Thiên điện để lại, lộ tuyến đỏ có thể chính là sinh lộ thoát hiểm mà người này chuẩn bị sẵn. Hàn Lập khai phong và phát hiện nội dung quyển trục này tại @c0493.","congNang":["Chỉ dẫn đường đi trong nội điện năm tầng Hư Thiên điện, bao gồm vị trí thạch đài, Hư Thiên đỉnh, mật thất và các thông đạo @c0493","Lộ tuyến đỏ duy nhất dẫn tới vị trí Truyền Tống trận nằm sau bức tường cao ở biên nội điện @c0493"],"hinhDang":"Quyển trục cũ kỹ, nét vẽ nguyên sơ thô sơ","nguonGoc":"Cùng thời kỳ Hư Thiên đỉnh, chủ nhân Hư Thiên điện để lại","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0493","denChuong":"","cachCoDuoc":"Lấy được trước đó trong Hư Thiên điện","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0493","loai":"khai phong","importance":"major","giaiDoan":"Hàn Lập mở ra phát hiện sơ đồ nội điện","text":"Hàn Lập mở quyển trục cổ phát hiện là sơ đồ nội điện năm tầng Hư Thiên điện với lộ tuyến đỏ duy nhất dẫn tới Truyền Tống trận, quyết định đi theo lộ tuyến này.","anchor":"trong tấm bản đồ này các hình vẽ khác đều dùng bút màu đen, duy nhất có một lộ tuyến sử dụng bút màu đỏ"}]},"nguon":["@c0493"],"dacDiem":"Quyển trục niên đại rất cổ, không toát linh lực, nội dung vẽ thô sơ ngoằn ngoèo; chỉ chứa một lộ tuyến bút đỏ duy nhất giữa toàn bộ sơ đồ, gợi ý đây là sinh lộ bí mật của chủ nhân Hư Thiên điện."},{"id":"cu-vien-khoi-loi","name":"Cự viên khôi lỗi","cn":"","category":"khac","categoryLabel":"Khôi lỗi","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Khôi lỗi hình viên lớn phát bạch quang, được Hàn Lập triệu ra dò đường trên lộ tuyến đỏ trong nội điện Hư Thiên điện.","detail":"Mấy con cự viên khôi lỗi phát bạch quang, được Hàn Lập triệu ra đi trước dò đường khi bắt đầu đi theo lộ tuyến đỏ trên bản đồ cổ.","nguon":["@c0493"]},{"id":"binh-ngoc-xanh-phu-dieu-dau-rong","name":"Bình ngọc xanh dưới phù điêu đầu rồng","cn":"","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":["Nguyên Dao"],"trangThai":"dang-co","blurb":"Bình ngọc cổ dài màu xanh đặt dưới phù điêu hình đầu rồng bạch ngọc trong thạch thất linh tuyền, đang hứng lấy thứ gì đó từ phù điêu. Nguyên Dao lộ vẻ lo lắng khi Hàn Lập chú ý đến bình, sau đó lén giấu đi khi Hàn Lập mất cảnh giác.","detail":"Bình ngọc cổ dài màu xanh nằm ở chỗ lõm dưới phù điêu hình đầu rồng bằng bạch ngọc trên tường đá thạch thất chứa hồ Linh nhãn chi tuyền. Khi Hàn Lập phát hiện, bình đang hứng lấy thứ gì đó từ phù điêu đầu rồng. Nguyên Dao biến sắc lo lắng khi thấy Hàn Lập nhìn vào bình, rồi dùng kế đánh lạc hướng, lén cất bình đi trong lúc bay lên bờ mặc đồ. Nội dung chứa bên trong và công năng cụ thể chưa được làm rõ trong tiến trình hiện có, tuy nhiên vị trí đặt bình gợi ý liên quan đến Linh nhãn chi tuyền dạng cô đọng.","congNang":["Hứng và chứa chất lỏng từ phù điêu đầu rồng bạch ngọc, có thể là Linh nhãn chi tuyền dạng cô đọng @c0494"],"chuSoHuu":[{"ten":"Nguyên Dao","tuChuong":"@c0494","denChuong":"","cachCoDuoc":"Lén giấu khi Hàn Lập mất cảnh giác","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0494","loai":"đổi chủ","importance":"major","giaiDoan":"Nguyên Dao lén giấu bình","text":"Bình ngọc xanh đặt dưới phù điêu đầu rồng bạch ngọc đang hứng thứ gì đó. Nguyên Dao biến sắc khi Hàn Lập nhìn vào, dùng kế phong tình đánh lạc hướng rồi lén giấu bình đi.","anchor":"còn cái bình màu xanh dưới chỗ phù điêu hình đầu rồng kia đã biến mất vô ảnh vô tung"}]},"nguon":["@c0494"],"dacDiem":"Bình ngọc cổ dài màu xanh, đặt ở chỗ lõm dưới phù điêu hình đầu rồng bạch ngọc trên tường đá thạch thất linh tuyền."},{"id":"van-nien-linh-nhu","name":"Vạn niên linh nhũ","cn":"万年灵乳","category":"dan-duoc","categoryLabel":"Linh dịch","phamCap":"Cực hiếm (trăm vạn linh thạch không mua được)","soHuu":["Nguyên Dao"],"trangThai":"dang-co","blurb":"Vạn niên linh nhũ là linh dịch huyền thoại được sinh ra từ linh tuyền cổ đại trong mật thất tầng hai nội điện Hư Thiên điện, trải qua vạn năm không ai lai vãng mà tích lũy thành. Nguyên Dao thu được nửa bình và đề nghị tặng cho Hàn Lập để đổi lấy Dưỡng Hồn mộc.","detail":"Vạn niên linh nhũ là loại linh dịch truyền thuyết, trăm vạn linh thạch cũng không thể mua được. Nó được sản sinh từ linh tuyền cổ đại nằm trong mật thất tầng hai nội điện Hư Thiên điện — nơi không ai lai vãng suốt hàng vạn năm, nhờ đó linh nhũ tích lũy dần mà thành. Nguyên Dao sau khi ngâm trong linh tuyền đã thu được nửa bình linh nhũ này, và tiết lộ sự tồn tại của nó khi đề nghị tặng cho Hàn Lập để đổi lấy Dưỡng Hồn mộc.","congNang":["Hồi phục pháp lực tức thì @c0495"],"nguon":["@c0495"],"tabs":{"tienTrinh":[{"chuong":"@c0495","loai":"xuất hiện","importance":"major","giaiDoan":"Nguyên Dao đề nghị dùng làm vật giao dịch với Hàn Lập","text":"Nguyên Dao tiết lộ sở hữu nửa bình Vạn niên linh nhũ do linh tuyền Hư Thiên điện tích lũy vạn năm, đề nghị tặng Hàn Lập để đổi lấy Dưỡng Hồn mộc.","anchor":"linh dịch trong truyền thuyết có thể hồi phục pháp lực trong nháy mắt mà dù có trăm vạn linh thạch cũng không mua được"}]},"dacDiem":"Linh dịch cực kỳ hiếm, trăm vạn linh thạch không thể mua được, cần linh tuyền tích lũy suốt vạn năm mới sinh ra."},{"id":"duong-hon-moc","name":"Dưỡng Hồn mộc","cn":"养魂木","category":"nguyen-lieu","categoryLabel":"Thần mộc","phamCap":"Thần mộc (1 trong 3 loại)","soHuu":["Hàn Lập"],"trangThai":"dang-nuoi-duong","blurb":"Dưỡng Hồn mộc là một trong ba loại thần mộc, được phát hiện ẩn sau cấm chế bạch quang trong mật thất tầng hai nội điện Hư Thiên điện. Nguyên Dao cần nó để ký gửi hồn phách bảo vệ thần trí không tiêu tán, còn Hàn Lập sau khi có được đã dùng lục dịch nuôi dưỡng rễ của nó nhằm tái hiện toàn bộ công năng.","detail":"Dưỡng Hồn mộc là một đoạn thần mộc nằm sau cấm chế bạch quang trong mật thất tầng hai của nội điện Hư Thiên điện, chưa từng được ai sử dụng. Nguyên Dao là người phát hiện sự tồn tại của nó trước nhưng chưa phá được cấm chế để lấy ra. Nàng cần Dưỡng Hồn mộc không phải vì công dụng tăng cường thần thức thông thường mà để ký gửi hồn phách, bảo vệ thần trí không tiêu tán — cho thấy nàng đang gặp vấn đề nghiêm trọng liên quan đến hồn phách. Sau đó Hàn Lập đã có được Dưỡng Hồn mộc và dùng toàn bộ lục dịch sản sinh ra để nuôi dưỡng phần rễ của nó, tin rằng chỉ cần vài năm sẽ có thể tái hiện toàn bộ công năng vốn có của thần mộc này.","congNang":["Bồi dưỡng hồn phách nguyên thân, từ từ tăng cường thần thức @c0495","Ký gửi hồn phách, bảo vệ thần trí không tiêu tán @c0495","Có thể được nuôi dưỡng bằng lục dịch để phục hồi và tái hiện toàn bộ công năng @c0516"],"nguon":["@c0495","@c0516"],"tabs":{"tienTrinh":[{"chuong":"@c0495","loai":"xuất hiện","importance":"major","giaiDoan":"Nguyên Dao tiết lộ sự tồn tại và công dụng","text":"Nguyên Dao tiết lộ bên trong cấm chế mật thất tầng hai có một đoạn Dưỡng Hồn mộc chưa sử dụng, nàng cần nó để ký gửi hồn phách bảo vệ thần trí.","anchor":"một trong ba loại thần mộc, có thể đeo trên người để bồi dưỡng hồn phách nguyên thân, từ từ tăng cường thần thức"},{"chuong":"@c0516","loai":"dùng","importance":"normal","giaiDoan":"Nuôi dưỡng bằng lục dịch","text":"Hàn Lập dùng toàn bộ lục dịch sản sinh để nuôi dưỡng rễ Dưỡng Hồn Mộc, tin rằng vài năm nữa sẽ tái hiện vạn năm.","anchor":"chỉ cần cho hắn vài năm nữa, từ nơi đây sẽ tái hiện Dưỡng Hồn Mộc vạn năm"}]},"dacDiem":"Là một trong ba loại thần mộc, vô cùng quý hiếm; được cất giữ sau cấm chế bạch quang trong mật thất tầng hai nội điện Hư Thiên điện; có thể dùng lục dịch nuôi dưỡng phần rễ để tái sinh công năng."},{"id":"tang-hon-hop","name":"Tàng hồn hộp","cn":"藏魂匣","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Nguyên Dao"],"trangThai":"Chưa luyện chế","blurb":"Pháp bảo Nguyên Dao định nhờ người luyện từ Dưỡng Hồn mộc, giúp Nghiên tỷ tỷ thoát khỏi khổ sở thuật luyện hồn.","detail":"Nguyên Dao hứa sẽ tìm người dùng Dưỡng Hồn mộc luyện chế thành Tàng hồn hộp, mục đích giải thoát Nghiên tỷ tỷ hoàn toàn khỏi thuật luyện hồn. Chưa được luyện thành.","congNang":["Giải thoát khỏi thuật luyện hồn"],"nguon":["@c0496"]},{"id":"ngan-lang-khi-linh","name":"Ngân lang khí linh","cn":"银狼器灵","category":"khac","categoryLabel":"Khí linh","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"Chưa thuần phục","blurb":"Khí linh chân chính của Ngọc Như Ý, hình dạng cự lang màu bạc. Hai tiểu lang đỏ-vàng đều là hóa thân của nó. Bướng bỉnh, chưa thuần phục Hàn Lập.","detail":"Khí linh bên trong Ngọc Như Ý, hiện hình là cự lang bạc. Tiểu lang đỏ dùng pháp thuật hỏa, tiểu lang vàng dùng pháp thuật thổ (bao gồm Thổ độn chi thuật). Ngân lang có thần sắc mang tính người, uể oải giả ngô giả ngơ, không chịu phục tùng mệnh lệnh. Huyền Cốt lão ma từng kinh ngạc khi thấy ngân lang xuất hiện, cho thấy nó có danh tiếng lớn. Chưa bị luyện hóa hoàn toàn.","congNang":["Triệu hoán qua Ngọc Như Ý (niệm chú thượng cổ + thần thức vào đầu cự lang)","Hóa thân tiểu lang đỏ — hỏa thuộc tính","Hóa thân tiểu lang vàng — thổ thuộc tính (Thổ độn chi thuật)","Bản thể ngân lang — năng lực chưa rõ, chưa thuần phục"],"tabs":{"tienTrinh":[{"chuong":"@c0497","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập lần đầu triệu hoán","text":"Hàn Lập khám phá cách triệu hoán lang hình khí linh từ Ngọc Như Ý. Ngân lang hiện hình nhưng bướng bỉnh không phục tùng, giả ngô giả ngơ. Huyền Cốt từng kinh ngạc khi thấy nó.","anchor":"hiển nhiên nó mới là khí linh chân chính của miếng Ngọc Như ý"}]},"nguon":["@c0497"]},{"id":"vien-chau-ngu-sac","name":"Viên châu ngũ sắc","cn":"五色珠","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"Đang cất giữ","blurb":"Viên châu thu được từ hài cốt ngũ sắc của Cực Huyễn gần Truyền Tống trận Thiên Nam. Màu sắc giống Bổ Thiên đan nhưng nhỏ hơn và hào quang yếu hơn.","detail":"Viên châu phát ra hào quang năm màu, thu từ bộ hài cốt ngũ sắc (được xác nhận là Cực Huyễn — nghịch đồ của Huyền Cốt) gần Truyền Tống trận ở Thiên Nam. Hàn Lập liên tưởng nó giống Bổ Thiên đan về màu sắc, chỉ khác kích thước (nhỏ hơn) và hào quang (yếu hơn). Trịnh trọng cất vào túi trữ vật, bản chất vẫn là ẩn số.","congNang":["Chưa rõ"],"tabs":{"tienTrinh":[{"chuong":"@c0497","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập kiểm tra và liên hệ với Bổ Thiên đan","text":"Hàn Lập vô tình chạm viên châu ngũ sắc, liên tưởng nó giống Bổ Thiên đan, khẳng định hài cốt chủ nhân là Cực Huyễn, trịnh trọng cất đi.","anchor":"Màu sắc giống nhau nhưng Bổ Thiên đan lớn hơn, đồng thời cả viên châu phát ra hào quang sáng hơn mà thôi"}]},"nguon":["@c0497"]},{"id":"thien-tinh-lenh","name":"Thiên Tinh lệnh","category":"khac","categoryLabel":"Lệnh bài","soHuu":["Tinh Cung"],"trangThai":"dang-co","blurb":"Thiên Tinh lệnh là lệnh bài do Tinh Cung phát đến các thế lực lớn nhỏ trong Loạn Tinh Hải, cưỡng chế triệu tập tất cả thủ lĩnh tông phái và đảo chủ đến diện kiến Thiên Tinh Song Thánh, kẻ bất tuân sẽ bị tiêu diệt.","detail":"Tinh Cung phát Thiên Tinh lệnh nhân sự kiện Nguyên Từ thần quang đại thành. Lệnh bài mang tính cưỡng chế tuyệt đối, yêu cầu toàn bộ thủ lĩnh tông phái và đảo chủ trong Loạn Tinh Hải phải đích thân đến diện kiến Thiên Tinh Song Thánh. Bất cứ thế lực nào kháng lệnh đều bị coi là bất kính Tinh Cung và đối diện nguy cơ bị tiêu diệt. Thiên Tinh lệnh thể hiện quyền uy tối thượng của Tinh Cung đối với toàn bộ các thế lực tại Loạn Tinh Hải.","congNang":["Triệu tập cưỡng chế tất cả thủ lĩnh tông phái và đảo chủ trong Loạn Tinh Hải đến diện kiến Thiên Tinh Song Thánh @c0498"],"tabs":{"tienTrinh":[{"chuong":"@c0498","loai":"xuất hiện","importance":"major","giaiDoan":"Tinh Cung phát lệnh","text":"Tinh Cung phát Thiên Tinh lệnh đến các thế lực lớn nhỏ Loạn Tinh Hải, bắt tất cả thủ lĩnh tông phái cùng đảo chủ lập tức đến gặp Thiên Tinh Song Thánh, đe dọa tiêu diệt kẻ bất tuân.","anchor":"Tinh Cung đích thực đưa “Thiên Tinh lệnh” đến các thế lực lớn nhỏ"}]},"nguon":["@c0498"]},{"id":"nghich-tinh-lenh","name":"Nghịch Tinh lệnh","category":"khac","categoryLabel":"Lệnh bài","soHuu":["Nghịch Tinh minh"],"trangThai":"dang-co","blurb":"Nghịch Tinh lệnh là quỷ bài do Nghịch Tinh minh phát đến các thế lực, đe dọa rằng kẻ nào đến diện kiến Thiên Tinh Song Thánh sẽ trở thành kẻ thù. Mặt quỷ trên lệnh bài gần giống lệnh bài mà trưởng lão Lục Liên điện từng đưa cho Ô Sửu, cho thấy ma đã sớm câu kết và cài nội gian vào các thế lực.","detail":"Nghịch Tinh minh phát Nghịch Tinh lệnh dưới hình thức quỷ bài đến các thế lực, với nội dung đe dọa rằng bất cứ ai phục tùng Thiên Tinh lệnh hoặc đến diện kiến Thiên Tinh Song Thánh sẽ bị coi là kẻ thù. Khi Hàn Lập xem ngọc giản phục chế, nhận ra mặt quỷ trên lệnh bài gần giống cái mà trưởng lão Lục Liên điện từng đưa cho Ô Sửu, từ đó chứng tỏ rằng ma đã sớm câu kết và cài nội gian vào các thế lực từ trước.","congNang":["Đe dọa các thế lực không được phục tùng Thiên Tinh lệnh, tuyên bố kẻ phục tùng sẽ trở thành kẻ thù của Nghịch Tinh minh @c0498"],"tabs":{"tienTrinh":[{"chuong":"@c0498","loai":"xuất hiện","importance":"major","giaiDoan":"Nghịch Tinh minh phát lệnh","text":"Nghịch Tinh minh phát quỷ bài đến các thế lực, đe dọa kẻ nào phục tùng Thiên Tinh lệnh sẽ trở thành kẻ thù. Hàn Lập nhận ra mặt quỷ trên lệnh bài gần giống lệnh bài Lục Liên điện đưa Ô Sửu.","anchor":"mặt quỷ ở trên lệnh bài gần giống cái mà trưởng lão của Lục Liên điện đưa cho Ô sửu xem"}]},"nguon":["@c0498"],"dacDiem":"Hình thức quỷ bài, mặt quỷ trên lệnh bài gần giống lệnh bài mà trưởng lão Lục Liên điện từng đưa cho Ô Sửu, cho thấy mối liên hệ câu kết giữa ma và nội gian trong các thế lực."},{"id":"huyet-sac-phi-phong","name":"Huyết sắc phi phong","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp bảo phi hành của Hàn Lập, hóa thành đoàn huyết quang khi kích hoạt, có thể đạt tốc độ ngang Nguyên Anh kỳ khi bổ sung đủ pháp lực.","detail":"Hàn Lập dùng Huyết sắc phi phong liên tục phi hành nửa tháng với tốc độ ngang Nguyên Anh kỳ, nhờ bổ sung pháp lực bằng Vạn niên linh nhũ. Đoàn huyết quang khiến tu sĩ Kết Đan kỳ trên đường tưởng nhầm là cao nhân Nguyên Anh kỳ, tránh xa không dám cản trở.","congNang":["Phi hành tốc độ cao, có thể đạt cấp Nguyên Anh kỳ khi đủ pháp lực"],"nguon":["@c0498"]},{"id":"thien-diep-lo","name":"Thiên Diệp lộ","cn":"千叶露","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"Chưa thu được","blurb":"Thiên Diệp lộ là tên gọi thượng cổ của dịch thể chiết xuất từ Bạn Yêu Thảo, một trong những nguyên liệu then chốt để luyện chế Cửu Khúc Linh Sâm. Do tên gọi đã thất truyền, ngay cả chưởng quỹ làm việc hơn trăm năm ở Nam Minh đảo cũng chưa từng nghe qua, phải tra cứu điển tịch mới xác định được thân phận thật của nó.","detail":"Thiên Diệp lộ là nguyên liệu cuối cùng còn thiếu trong phương thuốc Cửu Khúc Linh Sâm mà Hàn Lập cần thu thập. Khi hỏi chưởng quỹ Nam Minh đảo, vị này dù kinh nghiệm hơn trăm năm cũng không nhận ra, và gợi ý rằng đây có thể là tên gọi từ thời thượng cổ, đã bị đổi thành tên khác ở thời hiện đại, cần tra cứu điển tịch cổ để tìm ra thân phận thật (@c0499). Về sau, Hàn Lập tra ngọc giản và xác nhận Thiên Diệp lộ chính là dạng lỏng của Bạn Yêu Thảo; tuy nhiên, chỉ có Bạn Yêu Thảo sinh trưởng gần yêu thú cấp tám mới đủ hiệu lực để sử dụng (@c0514).","congNang":["Nguyên liệu then chốt để luyện chế Cửu Khúc Linh Sâm (@c0514)","Thực chất là dạng lỏng (dịch thể) của Bạn Yêu Thảo, chỉ loại sinh trưởng gần yêu thú cấp tám mới đạt hiệu quả (@c0514)"],"nguonGoc":"Tên gọi thượng cổ, khả năng đã đổi tên ở hiện đại","tabs":{"tienTrinh":[{"chuong":"@c0499","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập tìm kiếm nhưng không ai biết","text":"Chưởng quỹ Nam Minh đảo chưa từng nghe qua Thiên Diệp lộ, gợi ý đây có thể là tên thượng cổ đã đổi.","anchor":"vãn bối từ khi mở cửa hàng cho đến nay đều chưa từng nghe qua nguyên liệu “Thiên Diệp lộ”"},{"chuong":"@c0514","loai":"xuất hiện","importance":"major","giaiDoan":"Xác nhận bản chất","text":"Hàn Lập tra ngọc giản, xác nhận Thiên Diệp Lộ chính là Bạn Yêu Thảo dạng lỏng. Chỉ Bạn Yêu Thảo sinh trưởng gần yêu thú cấp tám mới có tác dụng cần thiết, gây khó khăn lớn vì Hắc Thạch thành chỉ có yêu thú tối đa cấp bảy.","anchor":"Cái gọi là Thiên Diệp Lộ chính là Bạn Yêu Thảo dạng lỏng"}]},"capNhatToi":"@c0499","nguon":["@c0499","@c0514"],"aliases":["Bạn Yêu Thảo dạng lỏng"],"dacDiem":"Tên gọi thượng cổ đã thất truyền, thời hiện đại được biết đến dưới tên Bạn Yêu Thảo; yêu cầu nguồn gốc khắt khe — chỉ cây mọc gần yêu thú cấp tám mới đủ dược lực."},{"id":"ma-nao-giac","name":"Mã Não giác","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"chua-tim-thay","blurb":"Độc giác trân quý do Mã não thú sinh ra, tu sĩ bình thường không thể gặp được, chỉ có thể tìm ở đấu giá.","detail":"Nguyên liệu cuối cùng còn thiếu để luyện Cửu Khúc Linh Sâm. Mã Não giác là độc giác do Mã não thú sinh ra, cực kỳ trân quý và hiếm, tu sĩ bình thường căn bản không thể gặp được.","congNang":["Nguyên liệu luyện chế Cửu Khúc Linh Sâm"],"dacDiem":"Độc giác, cực hiếm","tabs":{"tienTrinh":[{"chuong":"@c0499","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập được biết về độ hiếm","text":"Chưởng quỹ cho biết Mã Não giác là độc giác trân quý do Mã não thú sinh ra, tu sĩ bình thường không thể gặp được, chỉ có thể tìm ở đấu giá.","anchor":"“Mã Não giác” tuy là độc giác trân quý do Mã não thú sinh ra, tu sĩ bình thường căn bản không thể gặp được"}]},"capNhatToi":"@c0499","nguon":["@c0499"]},{"id":"yeu-bai-dieu-am-mon","name":"Yêu bài trưởng lão Diệu Âm Môn","cn":"","category":"khac","categoryLabel":"Tín vật","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Yêu bài chứng minh thân phận Khách khanh trưởng lão Diệu Âm Môn, do Tử Linh Tiên Tử tặng cho Hàn Lập. Phát huy tác dụng khi Hàn Lập cần qua ải bàn tra của Nghịch Minh Tinh tại Nam Minh đảo.","detail":"Tín vật chính thức của Diệu Âm Môn, đại diện thân phận Khách khanh trưởng lão. Tử Linh Tiên Tử tặng cho Hàn Lập trước đây. Hàn Lập dùng yêu bài này xưng họ Hàn, qua mặt hộ pháp Thương Vân Long (Kết Đan sơ kỳ) trong cuộc bàn tra tại Nam Minh đảo — Thương Vân Long nhận ra ngay là thật.","congNang":["Chứng minh thân phận Khách khanh trưởng lão Diệu Âm Môn"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0500","denChuong":"","cachCoDuoc":"Tử Linh Tiên Tử tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0500","loai":"dùng","importance":"normal","giaiDoan":"Qua ải bàn tra","text":"Hàn Lập dùng yêu bài chứng minh thân phận Khách khanh trưởng lão Diệu Âm Môn, qua mặt hộ pháp Thương Vân Long tại bến cảng Nam Minh đảo.","anchor":"Cũng may ngày đó Tử Linh tiên tử tặng cho hắn cái yêu bài trưởng lão"}]},"nguon":["@c0500"]},{"id":"ngoc-gian-mau-luc-chan-dung","name":"Ngọc giản màu lục (chân dung trưởng lão Diệu Âm môn)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Thương Vân Long"],"trangThai":"dang-co","blurb":"Ngọc giản chứa chân dung hai vị trưởng lão Diệu Âm môn đã được phục chế, Thương hộ pháp dùng để đối chiếu nhận dạng tu sĩ qua cảng khẩu.","detail":"Thương hộ pháp dùng ngọc giản này đối chiếu nhận dạng Hàn Lập khi hắn đi qua cảng khẩu Nghịch Minh Tinh, xác nhận thân phận trưởng lão Diệu Âm môn khớp với chân dung bên trong.","nguon":["@c0501"]},{"id":"me-huyen-nghien","name":"Mê Huyễn Nghiên","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nho sinh Nghịch Tinh Minh","Hàn Lập"],"trangThai":"đổi chủ","blurb":"Pháp bảo hình nghiên mực đen, luyện bằng phương pháp cổ xưa tốn gần hết tài lực nửa đời nho sinh Nghịch Tinh Minh. Phun sương mù đen tạo quái điểu tấn công và mê vụ gây huyễn cảnh. Tương giao thần thức với chủ nên duy trì hoạt động dù chủ mất pháp lực. Sau khi nho sinh chết, bị Hàn Lập thu.","detail":"Luyện chế bằng phương pháp cổ xưa, hao phí rất lớn tài lực mới thành. Phun sương mù đen có mùi mực, ngưng thành hơn chục con quái điểu đen dài hơn nửa thước tấn công đối thủ. Người hãm vào mê vụ sẽ lâm huyễn cảnh không thoát ra được. Đặc biệt tương giao thần thức với chủ nhân, dù chủ bị phong tỏa pháp lực vẫn duy trì hoạt động. Giúp nho sinh hiếm gặp đối thủ đồng cấp, liều được với tu sĩ Kết Đan trung kỳ. Bị Giỏ hoa trúc cổ bảo phóng bạch quang nuốt trọn quái điểu. Sau khi chủ chết trở thành vô chủ, bị Hàn Lập thu làm chiến lợi phẩm.","congNang":["Phun sương mù đen ngưng thành quái điểu tấn công (@c0502)","Tạo mê vụ gây huyễn cảnh khiến đối phương không thoát (@c0502)","Tương giao thần thức — duy trì hoạt động dù chủ mất pháp lực (@c0502)"],"chuSoHuu":[{"ten":"Nho sinh Nghịch Tinh Minh","tuChuong":"@c0502","denChuong":"@c0502","cachCoDuoc":"Tự luyện chế","trangThai":"tu-vong"},{"ten":"Hàn Lập","tuChuong":"@c0502","denChuong":"","cachCoDuoc":"Thu chiến lợi phẩm","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0502","loai":"dùng","importance":"normal","giaiDoan":"Thực chiến và đổi chủ","text":"Nho sinh phun Mê Huyễn Nghiên tạo quái điểu đen tấn công Hàn Lập. Bị Giỏ hoa trúc cổ bảo phóng bạch quang nuốt trọn quái điểu. Chủ chết, Hàn Lập thu làm chiến lợi phẩm.","anchor":"Khối Mê Huyễn Nghiên kia của hắn chính là dùng phương pháp luyện chế từ cổ xưa, tổn hao rất lớn mới có thể luyện thành"}]},"capNhatToi":"@c0502","nguon":["@c0502"]},{"id":"dai-an-bach-ngoc","name":"Đại ấn bạch ngọc","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại hán Nghịch Tinh Minh","Hàn Lập"],"trangThai":"đổi chủ","blurb":"Pháp bảo của đại hán Nghịch Tinh Minh, bay ra phóng to với bạch quang cuốn quanh. Bạch quang áp đảo cự kiếm xanh của Thanh Trúc Phong Vân Kiếm. Bị đại hán vứt bỏ khi bỏ chạy, Hàn Lập thu làm chiến lợi phẩm.","detail":"Pháp bảo hình đại ấn bằng bạch ngọc, khi tung ra lập tức phóng to với bạch quang cuốn quanh nghênh chiến. Bạch quang áp đảo cự kiếm xanh hợp nhất từ sáu đạo Thanh Trúc Phong Vân Kiếm, khiến cự kiếm gãy tan. Bị Giỏ hoa trúc cổ bảo bao trùm, không thoát được. Đại hán vứt bỏ khi quyết định bỏ chạy, trở thành vô chủ và bị Hàn Lập thu.","congNang":["Phóng to và bạch quang cuốn quanh nghênh chiến, áp đảo kiếm quang (@c0502)"],"chuSoHuu":[{"ten":"Đại hán Nghịch Tinh Minh","tuChuong":"@c0502","denChuong":"@c0502","cachCoDuoc":"Sở hữu sẵn","trangThai":"tu-vong"},{"ten":"Hàn Lập","tuChuong":"@c0502","denChuong":"","cachCoDuoc":"Thu chiến lợi phẩm","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0502","loai":"đổi chủ","importance":"normal","giaiDoan":"Thực chiến và đổi chủ","text":"Đại hán tung đại ấn nghênh chiến sáu đạo thanh quang, bạch quang áp đảo cự kiếm xanh khiến gãy tan. Bị Giỏ hoa trúc cổ bảo bao trùm. Đại hán vứt bỏ khi bỏ chạy, Hàn Lập thu chiến lợi phẩm.","anchor":"bạch quang cuốn quanh đại ấn nghênh đón lấy sáu đạo thanh quang"}]},"capNhatToi":"@c0502","nguon":["@c0502"]},{"id":"thien-huong-tac","name":"Thiên Hương Tác","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Lăng Ngọc Linh"],"trangThai":"dang-co","blurb":"Bảo vật hộ thân của Lăng Ngọc Linh, giúp bảo vệ khi bị pháp bảo đánh trúng, giảm thiểu thương tích.","detail":"Vật hộ thân Lăng Ngọc Linh mang theo bên người. Khi bị tu sĩ Nghịch Tinh Minh dùng pháp bảo đánh trúng, Thiên Hương Tác phát huy tác dụng hộ thân khiến thương tích không đáng ngại.","congNang":["Hộ thân, giảm thương khi bị pháp bảo đánh trúng"],"chuSoHuu":[{"ten":"Lăng Ngọc Linh","tuChuong":"@c0503","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0503","loai":"xuất hiện","importance":"normal","giaiDoan":"Lăng Ngọc Linh nhắc tới khi giải thích vì sao bị thương nhưng không nguy hiểm","text":"Lăng Ngọc Linh thừa nhận bị pháp bảo đánh trúng nhưng có Thiên Hương Tác hộ thân nên không đáng ngại.","anchor":"ta có Thiên Hương Tác hộ thân, vì vậy không có gì đáng ngại"}]},"nguon":["@c0503"]},{"id":"thien-linh-dan","name":"Thiên Linh đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"","soHuu":["Lăng Ngọc Linh"],"trangThai":"dang-co","blurb":"Đan dược bổ sung nguyên khí, tu sĩ mặt vàng (sư huynh) tặng Lăng Ngọc Linh khi bị thương.","detail":"Tu sĩ mặt vàng mang theo bên người, tặng cho Lăng Ngọc Linh một viên để bổ sung nguyên khí sau khi bị pháp bảo đánh trúng trên đường trở về từ Nam Minh đảo.","congNang":["Bổ sung nguyên khí khi bị thương"],"chuSoHuu":[{"ten":"Tu sĩ mặt vàng (sư huynh Lăng Ngọc Linh)","tuChuong":"@c0503","denChuong":"@c0503","cachCoDuoc":"","trangThai":"da-dung"},{"ten":"Lăng Ngọc Linh","tuChuong":"@c0503","denChuong":"","cachCoDuoc":"Được sư huynh tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0503","loai":"xuất hiện","importance":"normal","giaiDoan":"Tu sĩ mặt vàng tặng cho Lăng Ngọc Linh chữa thương","text":"Tu sĩ mặt vàng tặng một viên Thiên Linh đan cho Lăng Ngọc Linh bổ sung nguyên khí sau khi bị thương.","anchor":"Ta có một viên Thiên Linh đan, Lăng sư đệ, người hãy dùng trước đi cho đỡ phải tổn hao nguyên khí"}]},"nguon":["@c0503"]},{"id":"nhan-mau-vang-tinh-cung","name":"Nhẫn màu vàng (thành viên tạm thời Tinh Cung)","cn":"","category":"phap-bao","categoryLabel":"Tín vật","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Chiếc nhẫn màu vàng do Vu hộ pháp trao cho Hàn Lập, làm bằng chứng thành viên tạm thời của Tinh Cung, dùng khi đại chiến để chấp hành nhiệm vụ hoặc báo danh tham chiến.","detail":"Tín vật xác nhận thành viên tạm thời Tinh Cung. Vu hộ pháp lục lọi trên người một hồi mới lấy ra, trao cho Hàn Lập sau khi Hàn Lập quyết định báo danh tham chiến. Có chiếc nhẫn này, Hàn Lập tạm thời được tính là thành viên Tinh Cung, có thể chấp hành nhiệm vụ trong đại chiến.","congNang":["Xác nhận thành viên tạm thời Tinh Cung, dùng khi đại chiến để chấp hành nhiệm vụ hoặc báo danh tham chiến"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0504","denChuong":"","cachCoDuoc":"Vu hộ pháp trao","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0504","loai":"xuất hiện","importance":"normal","giaiDoan":"Vu hộ pháp trao cho Hàn Lập","text":"Vu hộ pháp lục lọi trên người lấy ra nhẫn vàng trao cho Hàn Lập làm bằng chứng thành viên tạm thời Tinh Cung sau khi Hàn Lập quyết định báo danh tham chiến.","anchor":"Ngươi cầm chiếc nhẫn này, có chiếc nhẫn này làm bằng chứng ngươi tạm thời cũng tính là một thành viên của Tinh Cung chúng ta"}]},"nguon":["@c0504"]},{"id":"hai-thanh-phi-dao-hong-quang","name":"Hai thanh phi đao pháp bảo (hồng quang)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo","soHuu":["Lão giả hói đầu","Tu sĩ họ Kiền"],"trangThai":"doi-chu","blurb":"Hai thanh phi đao pháp bảo phát hồng quang, vốn là vật của Hồ Nguyệt. Sau khi Hồ Nguyệt bị Huyền Cốt sát hại, Hàn Lập tiện tay lấy rồi đem tặng cho hai tu sĩ Kết Đan Tinh Cung để đổi quyền qua Truyền tống trận.","detail":"Pháp bảo dạng phi đao không có thần thông đặc thù nhưng dùng trực tiếp không cần luyện gia, phát huy được bảy thành uy lực dù chưa tâm thần tương thông. Với tu sĩ Kết Đan phổ thông vô cùng quý giá. Hàn Lập đánh giá pháp bảo dạng này hắn có nhiều nên không tiếc.","congNang":["Phi đao tấn công, phát huy bảy thành uy lực khi chưa tâm thần tương thông, không cần luyện gia"],"nguonGoc":"Vốn là vật của Hồ Nguyệt","chuSoHuu":[{"ten":"Hồ Nguyệt","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"","denChuong":"@c0508","cachCoDuoc":"Tiện tay lấy sau khi Hồ Nguyệt bị Huyền Cốt sát hại","trangThai":"da-tang"},{"ten":"Lão giả hói đầu","tuChuong":"@c0508","denChuong":"","cachCoDuoc":"Được Hàn Lập tặng","trangThai":"dang-co"},{"ten":"Tu sĩ họ Kiền","tuChuong":"@c0508","denChuong":"","cachCoDuoc":"Được Hàn Lập tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0508","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập tặng cho hai tu sĩ Tinh Cung","text":"Hàn Lập đem hai thanh phi đao (vốn của Hồ Nguyệt bị Huyền Cốt sát hại) tặng cho hai tu sĩ Kết Đan Tinh Cung (họ Cố, họ Kiền) để đổi quyền qua Truyền tống trận.","anchor":"Hai thanh phi đao này chính là vật của Hồ Nguyệt bị Huyền Cốt sát hại khi xưa"}]},"nguon":["@c0508"]},{"id":"yem-nao-thu","name":"Yếm Não thú","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ","soHuu":["Tu sĩ họ Kiền"],"trangThai":"dang-co","blurb":"Linh thú nhỏ như mèo con, tai dài như thỏ, mắt xanh lục. Có khả năng đặc biệt cảm ứng thần thức tu sĩ, phân biệt được cấp Kết Đan trung-hậu kỳ, run rẩy khi gặp thần thức cấp Nguyên Anh Kỳ.","detail":"Linh thú thuộc sở hữu tu sĩ họ Kiền. Nhạy cảm trong cảm ứng thần thức: có thể phân biệt tu sĩ Kết Đan trung kỳ, hậu kỳ có chút phản ứng; khi gặp thần thức cấp Nguyên Anh Kỳ hoặc Trưởng lão Tinh Cung thì run rẩy không phản ứng cụ thể được. Nhờ nó mà tu sĩ họ Kiền phát hiện Hàn Lập không phải Trúc Cơ thường mà có thần thức vượt xa cảnh giới.","congNang":["Cảm ứng mức thần thức tu sĩ, phân biệt cấp bậc tu vi từ Kết Đan trở lên"],"nguon":["@c0509"]},{"id":"trung-tu-van-ung","name":"Trứng Tử Vân Ưng","cn":"紫云鹰蛋","category":"khac","categoryLabel":"Trứng yêu thú","phamCap":"Cấp 4","soHuu":[],"trangThai":"da-ban","blurb":"Trứng yêu thú cấp bốn thổ thuộc tính. Tử Vân Ưng trưởng thành thân cứng như sắt, tốc độ phi hành sánh ngang thượng phẩm pháp khí phi hành, lợi trảo phá được vòng bảo hộ Trúc Cơ kỳ.","detail":"Trứng yêu thú Tử Vân Ưng thuộc thổ thuộc tính, cấp bốn. Khi trưởng thành, thân thể cứng như sắt, biết hộ thuẫn pháp thuật đơn giản, tốc độ phi hành cực nhanh sánh ngang thượng phẩm pháp khí phi hành, một đôi lợi trảo có thể dễ dàng phá tan vòng bảo hộ của tu sĩ Trúc Cơ kỳ. Được đấu giá tại Hắc Thạch thành với giá khởi điểm 2.000 linh thạch, bán cho một nữ tu sĩ với giá 3.300 linh thạch. Ở Thiên Tinh thành giá tối thiểu ngoài 5.000 linh thạch. Đại bộ phận trứng yêu thú không thể truyền tống qua truyền tống trận (sẽ thành trứng chết), nên phải mua tại chỗ rồi bồi dưỡng đến khi linh thú có thể chịu được truyền tống mới mang về.","congNang":["Phi hành cực nhanh sánh ngang thượng phẩm pháp khí phi hành","Hộ thuẫn pháp thuật đơn giản","Lợi trảo phá vòng bảo hộ Trúc Cơ kỳ"],"tabs":{"tienTrinh":[{"chuong":"@c0512","loai":"xuat-hien","importance":"normal","giaiDoan":"Đấu giá tại Hắc Thạch thành","text":"Trứng Tử Vân Ưng được đem ra đấu giá tại Hắc Thạch thành, giá khởi điểm 2.000 linh thạch, bán 3.300 linh thạch cho một nữ tu sĩ.","anchor":"Một đôi lợi trảo có thể dễ dàng phá tan vòng bảo hộ của tu sĩ Trúc Cơ kỳ"}]},"nguon":["@c0512"]},{"id":"ngan-sac-cu-lang","name":"Ngân sắc cự lang","cn":"","aliases":["Lang hình khí linh"],"category":"khac","categoryLabel":"Khí linh","phamCap":"Không rõ (danh tiếng, Huyền Cốt từng kinh ngạc)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngân sắc cự lang là khí linh chân chính của Ngọc Như Ý, được triệu hoán khi niệm chú thượng cổ khắc trên bảo vật. Nó có thể hóa thành hai tiểu lang đỏ-vàng mang thuộc tính hỏa-thổ, sở hữu thần sắc mang tính người nhưng bướng bỉnh chưa bị luyện hóa hoàn toàn.","detail":"Ngân sắc cự lang xuất hiện khi Hàn Lập niệm chú thượng cổ khắc trên Ngọc Như Ý, là khí linh chân chính ẩn chứa bên trong pháp bảo này. Ngân lang có thần sắc mang tính người nhưng biểu hiện uể oải bướng bỉnh, giả ngô giả ngơ không chịu triển thị pháp thuật, cho thấy chưa bị luyện hóa hoàn toàn. Bản thể của nó chính là hai tiểu lang đỏ và vàng mang thuộc tính hỏa và thổ. Khi Huyền Cốt nhìn thấy ngân lang xuất hiện, lập tức lộ vẻ kinh ngạc và phóng tiểu tiễn Kim Lôi trúc vào nó, phản ứng này cho thấy ngân sắc cự lang là loại khí linh danh tiếng đáng sợ.","congNang":["Có thể hóa thành hai tiểu lang đỏ-vàng mang thuộc tính hỏa-thổ @c0497"],"tabs":{"tienTrinh":[{"chuong":"@c0497","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập phát hiện khí linh chân chính của Ngọc Như Ý","text":"Hàn Lập niệm chú thượng cổ triệu hoán được ngân sắc cự lang — khí linh chân chính của Ngọc Như Ý, có thần sắc mang tính người nhưng bướng bỉnh không phục, chưa bị luyện hóa hoàn toàn.","anchor":"Hắn cũng nhìn ra hai con tiểu lang kia đều là hóa thân của ngân lang mà thôi, hiển nhiên nó mới là khí linh chân chính của miếng Ngọc Như ý"}]},"nguon":["@c0497"],"dacDiem":"Có thần sắc mang tính người nhưng uể oải bướng bỉnh, giả ngô giả ngơ không chịu triển thị pháp thuật, chưa bị luyện hóa hoàn toàn."},{"id":"tieu-lang-do","name":"Tiểu lang đỏ","cn":"","aliases":[],"category":"khac","categoryLabel":"Khí linh (hóa thân)","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hóa thân hỏa thuộc tính của ngân sắc cự lang, do linh khí hỏa cực kỳ tinh thuần huyễn hóa thành, có vài loại pháp thuật bẩm sinh uy lực không nhỏ.","detail":"Một trong hai hóa thân tiểu lang của ngân sắc cự lang (khí linh Ngọc Như Ý). Mang hỏa thuộc tính tinh thuần, có pháp thuật bẩm sinh.","boCha":"ngan-sac-cu-lang","nguon":["@c0497"]},{"id":"tieu-lang-vang","name":"Tiểu lang vàng","cn":"","aliases":[],"category":"khac","categoryLabel":"Khí linh (hóa thân)","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hóa thân thổ thuộc tính của ngân sắc cự lang, am hiểu pháp thuật thổ linh bao gồm Thổ độn chi thuật.","detail":"Một trong hai hóa thân tiểu lang của ngân sắc cự lang (khí linh Ngọc Như Ý). Mang thổ thuộc tính, am hiểu Thổ độn chi thuật mà Hàn Lập từng muốn học.","boCha":"ngan-sac-cu-lang","nguon":["@c0497"]},{"id":"sung-ma-nao-thu","name":"Sừng Mã Não thú","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Hy hữu","soHuu":["Hàn Lập"],"trangThai":"Đang sở hữu","blurb":"Sừng thú hy hữu, dài hơn thước, trong suốt, mũi nhọn hình xoắn ốc, ẩn hiện lam quang. Hàn Lập mua từ cửa hàng Ly Tầm với giá năm nghìn linh thạch.","detail":"Sừng Mã Não thú vô cùng hy hữu, cửa hàng Ly Tầm vừa mua được hai cái. Sừng dài hơn thước, trong suốt, mũi nhọn hình xoắn ốc, bên ngoài ẩn hiện lam quang. Hàn Lập mua một cái với giá gốc năm nghìn linh thạch. Công dụng cụ thể chưa được tiết lộ.","nguon":["@c0514"],"congNang":["Chưa rõ công dụng cụ thể"],"hinhDang":"Dài hơn thước, trong suốt, mũi nhọn hình xoắn ốc, ẩn hiện lam quang","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0514","denChuong":"","cachCoDuoc":"Mua từ cửa hàng Ly Tầm giá năm nghìn linh thạch","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0514","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập mua được","text":"Hàn Lập mua một sừng Mã Não thú từ cửa hàng Ly Tầm với giá gốc năm nghìn linh thạch.","anchor":"Sừng Mã Não này tuy vô cùng hy hữu, nhưng tháng trước bổn điếm vừa mua được hai cái"}]}},{"id":"ngoc-gian-dien-tich-co-ngoc","name":"Ngọc giản điển tịch (của Cổ Ngọc)","cn":"","aliases":["Ngọc giản màu vàng (Cổ Ngọc đưa)"],"category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Đang sở hữu","blurb":"Ngọc giản chứa nội dung điển tịch cổ được Cổ Ngọc phục chế, ghi chép về Thiên Diệp Lộ và một vài thứ khác.","detail":"Cổ Ngọc đã đọc được nội dung từ một quyển điển tịch cổ hai năm trước và phục chế vào ngọc giản này. Trong đó có nhắc đến Thiên Diệp Lộ cùng một số nội dung khác. Hàn Lập xin giữ lại để nghiên cứu thêm, đổi lại tặng Cổ Ngọc đan dược và phù bảo.","nguon":["@c0514"],"chuSoHuu":[{"ten":"Cổ Ngọc","tuChuong":"@c0514","denChuong":"@c0514","cachCoDuoc":"Phục chế từ điển tịch cổ","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0514","denChuong":"","cachCoDuoc":"Đổi bằng đan dược và phù bảo từ Cổ Ngọc","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0514","loai":"xuất hiện","importance":"normal","giaiDoan":"Cổ Ngọc đưa, Hàn Lập giữ lại","text":"Cổ Ngọc đưa ngọc giản chứa điển tịch cổ nhắc đến Thiên Diệp Lộ cho Hàn Lập, được đổi bằng đan dược tăng tu vi và phù bảo hình tiểu kiếm.","anchor":"Trong ngọc giản này còn ghi lại một vài thứ, sau này ta có thời gian phải xem qua một chút"}]}},{"id":"hop-ngoc-trang-chua-chau-sac-so","name":"Hộp ngọc trắng chứa châu nhỏ sặc sỡ","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang giữ","blurb":"Hộp ngọc trắng chứa vài viên châu nhỏ màu sắc sặc sỡ, Hàn Lập lấy ra sau khi đọc ngọc giản vàng của Cổ Ngọc. Danh tính và công dụng chưa rõ.","detail":"Sau khi dùng thần thức đọc kỹ ngọc giản vàng mà Cổ Ngọc (Thốn Kim Các) đưa, Hàn Lập vẻ mặt ngưng trọng, trầm tư suy nghĩ rồi lấy ra hộp ngọc trắng chứa vài viên châu nhỏ màu sắc sặc sỡ. Nội dung ngọc giản và danh tính châu chưa được tiết lộ.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0515","denChuong":"","cachCoDuoc":"Không rõ (đã có sẵn trong túi trữ vật)","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0515","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập lấy ra sau khi đọc ngọc giản","text":"Hàn Lập lấy hộp ngọc trắng từ túi trữ vật sau khi đọc xong ngọc giản vàng của Cổ Ngọc, mở nắp lộ ra vài viên châu nhỏ sặc sỡ.","anchor":"trong tay hiện ra một hộp ngọc màu trắng"}]},"nguon":["@c0515"]},{"id":"huyen-diem-nga","name":"Huyễn Diễm Nga","cn":"幻焰蛾","category":"khac","categoryLabel":"Yêu trùng","phamCap":"Thứ 17 bảng kỳ trùng","soHuu":[],"trangThai":"chua-xuat-hien","blurb":"Dạng tiến hóa lần hai của Kim Ti Tằm, phi trùng xếp thứ 17 trên bảng kỳ trùng, trời sinh có năng lực biến ảo, cực hiếm từ thượng cổ.","detail":"Theo tư liệu thượng cổ, Kim Ti Tằm nếu có đủ thời gian phần lớn đều có thể tiến hóa thành Huyễn Diễm Nga — loại phi trùng có cánh. Xếp thứ 17 trên bảng kỳ trùng, thiên phú năng lực biến ảo. Rất hiếm người thấy qua nên năng lực cụ thể không rõ ràng, nhưng xếp hạng cao nên tuyệt đối không nhỏ.","congNang":["Năng lực biến ảo thiên phú"],"dinhDanh":"goc","nguon":["@c0516"]},{"id":"tran-ky-vang-nhat","name":"Trận kỳ màu vàng nhạt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo (trận kỳ)","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Cây cờ dài hai ba thước có vẽ phù văn, dùng để kích hoạt cấm chế bảo vệ động phủ của Hàn Lập.","detail":"Hàn Lập phun thanh khí lên trận kỳ rồi đâm xuống đất, đọc chú kích hoạt — toàn bộ mặt đất vách tường tỏa kim quang, cách ly chấn động bên ngoài, bảo vệ toàn bộ động phủ khỏi sóng thần và động đất do Cự Quy độ kiếp gây ra.","nguon":["@c0518"]},{"id":"sac-ngoc-hoan","name":"Sắc ngọc hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Kim Hà đạo sĩ"],"trangThai":"","blurb":"Ngọc hoàn của Kim Hà đạo sĩ, từ tay áo xuất ra đón gió phát tiếng vù vù, dùng để đối phó huyết quang Độc Giao.","detail":"Khi Kim Hà đạo sĩ khoát tay, ngọc hoàn từ tay áo bắn ra, đón gió liền phát tiếng vù vù, đối phó huyết quang mà Độc Giao phun về phía lão.","congNang":["Công kích/phòng ngự tầm xa, đón gió phát tiếng vù vù bắn ra đối phó huyết quang @c0519"],"chuSoHuu":[{"ten":"Kim Hà đạo sĩ","tuChuong":"@c0519","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0519","loai":"dùng","importance":"normal","giaiDoan":"Đại chiến Độc Giao","text":"Kim Hà đạo sĩ khoát tay, sắc ngọc hoàn từ tay áo bắn ra đón gió, đối phó huyết quang Độc Giao phun tới.","anchor":"một thanh sắc ngọc hoàn từ tay áo xuất ra, đón gió liền phát ra tiếng vù vù"}]},"nguon":["@c0519"]},{"id":"quy-dau-truong","name":"Quỷ đầu trượng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hoắc thị huynh đệ"],"trangThai":"","blurb":"Pháp bảo của một trong Hoắc thị huynh đệ, tự động hóa thành ác quỷ dữ tợn cao hơn trượng để phòng ngự.","detail":"Khi Độc Giao ẩn thân tập kích từ sau lưng Hoắc thị huynh đệ, quỷ đầu trượng tự động hóa thành ác quỷ dữ tợn cao hơn trượng, dùng bàn tay khổng lồ màu xanh đỡ một kích, cứu chủ nhân.","congNang":["Tự động phòng ngự: hóa thành ác quỷ cao hơn trượng, dùng bàn tay khổng lồ đỡ kích @c0519"],"chuSoHuu":[{"ten":"Hoắc thị huynh đệ","tuChuong":"@c0519","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0519","loai":"dùng","importance":"normal","giaiDoan":"Đại chiến Độc Giao","text":"Quỷ đầu trượng tự động hóa thành ác quỷ cao hơn trượng, dùng bàn tay khổng lồ màu xanh đỡ kích từ Độc Giao tập kích sau lưng chủ nhân.","anchor":"quải trượng của hồng bào tu sĩ tự động hóa thành một ác quỷ dữ tợn cao hơn trượng"}]},"nguon":["@c0519"]},{"id":"hong-ho-lo","name":"Hồng hồ lô","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hoắc thị huynh đệ"],"trangThai":"","blurb":"Hồ lô đỏ chứa Phá Thiên Thần Sa, khi tế xuất phun tinh sa đỏ phủ trời lấp đất tạo kết giới hỏa hồng trăm trượng vây Độc Giao.","detail":"Một trong Hoắc thị huynh đệ mang hồng hồ lô, khi tế xuất phun ra vô số tinh sa màu đỏ phô thiên cái địa, biến phương viên trăm trượng thành thế giới hỏa hồng vây Độc Giao trong đó.","congNang":["Phóng thích Phá Thiên Thần Sa tạo kết giới lửa phương viên trăm trượng @c0519"],"chuSoHuu":[{"ten":"Hoắc thị huynh đệ","tuChuong":"@c0519","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0519","loai":"dùng","importance":"normal","giaiDoan":"Đại chiến Độc Giao","text":"Hoắc thị huynh đệ tế hồng hồ lô, phun ra vô số tinh sa đỏ phủ trời lấp đất, biến phương viên trăm trượng thành thế giới hỏa hồng vây Độc Giao.","anchor":"vô số tinh sa màu đỏ từ hồ lô phô thiên cái địa tuôn ra"}]},"nguon":["@c0519"]},{"id":"pha-thien-than-sa","name":"Phá Thiên Thần Sa","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Hoắc thị huynh đệ"],"trangThai":"","blurb":"Tinh sa màu đỏ uy lực đáng kể, chứa trong hồng hồ lô của Hoắc thị huynh đệ, dùng vây Độc Giao cấp tám.","detail":"Tinh sa đỏ chứa trong hồng hồ lô, khi phóng ra phủ trời lấp đất tạo thế giới hỏa hồng phương viên trăm trượng. Kim Hà đạo sĩ Nguyên Anh kỳ cũng phải kiêng nể, nhưng một mình vẫn chưa chắc vây nổi Độc Giao.","congNang":["Tạo kết giới lửa phương viên trăm trượng vây yêu thú @c0519"],"tabs":{"tienTrinh":[{"chuong":"@c0519","loai":"dùng","importance":"normal","giaiDoan":"Đại chiến Độc Giao","text":"Hoắc thị huynh đệ phóng Phá Thiên Thần Sa từ hồng hồ lô, tạo thế giới hỏa hồng trăm trượng vây Độc Giao, nhưng Kim Hà nhận định một mình chưa chắc vây nổi.","anchor":"hai người mang Phá Thiên Thần Sa cũng không chắc vây được yêu thú này"}]},"nguon":["@c0519"]},{"id":"ngu-sac-chau","name":"Ngũ sắc châu","cn":"五色珠","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Ngũ sắc châu là linh châu nhiều màu cực cứng nhưng vào miệng trở nên mềm mại, rơi vào đan điền sinh ra nhiệt khí, cần dùng đan hỏa luyện hóa. Sau khi Hàn Lập bế quan nửa năm luyện hóa hết sáu viên, tốc độ hấp thụ thiên địa linh khí và vận chuyển linh lực được cải thiện đôi chút.","detail":"Hàn Lập bế quan nửa năm để luyện hóa toàn bộ sáu viên Ngũ sắc châu. Viên châu có chất liệu rất cứng, song khi cho vào miệng lại trở nên mềm mại, tự rơi xuống đan điền và sinh ra nhiệt khí. Quá trình luyện hóa đòi hỏi sử dụng đan hỏa phát ra từ kim đan để tiêu hóa hoàn toàn. Kết quả thu được không quá rõ rệt: Hàn Lập chỉ mơ hồ nhận thấy tốc độ hấp thụ thiên địa linh khí và vận chuyển linh lực nhanh hơn trước một chút. Ngũ sắc châu không phải Bổ Thiên Đan, nhưng vẫn có ích nhất định cho thân thể tu luyện. @c0520","congNang":["Tăng tốc hấp thụ thiên địa linh khí (mức độ mơ hồ nhận thấy, nhanh hơn trước một chút) @c0520","Tăng tốc vận chuyển linh lực trong cơ thể @c0520"],"dacDiem":"Rất cứng nhưng vào miệng mềm mại, rơi vào đan điền sinh nhiệt khí, cần dùng đan hỏa từ kim đan để luyện hóa; không phải Bổ Thiên Đan nhưng có ích cho thân thể","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0520","denChuong":"","cachCoDuoc":"Thu thập từ trước","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0520","loai":"dùng","importance":"major","giaiDoan":"Luyện hóa hoàn tất sáu viên","text":"Hàn Lập bế quan nửa năm luyện hóa hết sáu viên Ngũ sắc châu bằng đan hỏa từ kim đan, mơ hồ nhận thấy tốc độ hấp thụ thiên địa linh khí và vận chuyển linh lực nhanh hơn trước.","anchor":"hắn mơ hồ nhận thấy bản thân đã có thể hấp thụ thiên địa linh khí cùng vận chuyển linh lực so với trước kia nhanh hơn một chút","phamCap":"Không rõ"}]},"nguon":["@c0520"]},{"id":"ngu-hanh-hoan","name":"Ngũ Hành Hoàn","cn":"五行环","aliases":["Cổ Bảo Ngũ Hành Hoàn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Cổ bảo Ngũ Hành Hoàn, phóng năm vệt sáng trói chặt mục tiêu khiến không thể nhúc nhích, dùng xong tự trở về tay chủ.","detail":"Hàn Lập tế xuất Ngũ Hành Hoàn, năm vệt sáng xuyên vào hắc khí trói chặt cự hà cấp sáu như một cái bánh, hoàn toàn không thể nhúc nhích. Sau khi dùng xong tự biến mất trở về tay Hàn Lập.","congNang":["Phóng năm vệt sáng trói chặt mục tiêu hoàn toàn không thể nhúc nhích"],"uyLuc":"Trói chặt hoàn toàn yêu thú cấp sáu","dacDiem":"Dùng xong tự trở về tay chủ","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0521","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0521","loai":"dùng","importance":"normal","giaiDoan":"Trói cự hà cấp sáu","text":"Hàn Lập tế xuất Ngũ Hành Hoàn trói chặt cự hà cấp sáu như một cái bánh, hoàn toàn không nhúc nhích.","anchor":"Giờ phút này nó bị Ngũ Hành Hoàn trói chặt, giống như một cái bánh"}]},"nguon":["@c0521"]},{"id":"noi-dan-yeu-thu-cap-sau","name":"Nội đan yêu thú cấp sáu","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cấp sáu","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Viên cầu xanh nhạt lấy từ cự hà cấp sáu, lớn hơn và bắt đầu trở nên trong suốt so với nội đan cấp năm, ẩn hiện quang mang.","detail":"Nội đan lấy từ thi thể cự hà xanh sáu mắt cấp sáu. So với nội đan cấp năm thì lớn hơn, bắt đầu trở nên trong suốt và có quang mang phóng ra ẩn hiện.","nguon":["@c0521"]},{"id":"da-luu-ly-thu","name":"Da Lưu Ly Thú","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Làn da trong suốt của Lưu Ly Thú, tài liệu tốt nhất để luyện chế hộ giáp.","detail":"Hàn Lập dùng thanh quang lột da trong suốt của Lưu Ly Thú sau khi giết nó, thu lại làm nguyên liệu luyện hộ giáp.","congNang":["Nguyên liệu thượng hạng luyện chế hộ giáp"],"dacDiem":"Da trong suốt","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0523","denChuong":"","cachCoDuoc":"Tự lột từ Lưu Ly Thú bị giết","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0523","loai":"xuat-hien","importance":"normal","giaiDoan":"Thu hoạch","text":"Hàn Lập dùng thanh quang lột da trong suốt Lưu Ly Thú làm nguyên liệu luyện hộ giáp.","anchor":"Da Lưu ly thú chính là tài liệu tốt nhất để luyện chế ra hộ giáp"}]},"nguon":["@c0523"]},{"id":"vong-co-ba-mau-giap-trung","name":"Vòng cổ ba màu (giáp trùng)","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Đàn giáp trùng hóa thành vòng cổ ba màu, dùng để khống chế đối tượng. Hàn Lập phóng pháp quyết giải trừ, giáp trùng tản ra bay về túi linh thú.","detail":"Vòng cổ do đàn giáp trùng của Hàn Lập hóa thành, quấn quanh cổ đối tượng để trói buộc khống chế. Khi Hàn Lập phóng ba đạo pháp quyết xanh, vòng cổ tản ra thành vô số giáp trùng bay về túi linh thú.","congNang":["Khống chế/trói buộc đối tượng bằng cách quấn quanh cổ, hóa từ đàn giáp trùng"],"tabs":{"tienTrinh":[{"chuong":"@c0524","loai":"dùng","importance":"normal","giaiDoan":"Giải trừ vòng cổ cho ba tu sĩ","text":"Hàn Lập phóng ba đạo pháp quyết xanh giải trừ vòng cổ ba màu trên cổ ba tu sĩ Kết Đan kỳ, giáp trùng tản ra bay về túi linh thú.","anchor":"vòng cổ ba màu trên cổ của ba người tản ra, một lần nữa hóa thành vô số giáp trùng"}]},"nguon":["@c0524"]},{"id":"muoi-cu-vien-khoi-loi","name":"Mười cự viên Khôi Lỗi","cn":"","category":"phap-bao","categoryLabel":"Cơ quan Khôi Lỗi","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Mười cơ quan hình cự viên cao lớn, tóc đen phát sáng, hai tay hướng phía trước phóng hơn trăm cột sáng cực sắc bén. Diệt sạch mười mấy Ưng Diên Thú cấp hai trong chốc lát.","detail":"Mười cơ quan Khôi Lỗi thân hình cao lớn, tóc đen phát sáng, phóng hơn trăm cột sáng nhỏ bằng ngón tay nhưng sắc bén phi thường từ hai tay, xuyên thủng toàn bộ yêu thú thành vô số lỗ rỗng trong chớp mắt. Sau khi tấn công xong, buông tay rồi biến mất vô thanh vô tức.","congNang":["Phóng cột sáng sắc bén diệt yêu thú hàng loạt"],"hinhDang":"Cự viên cao lớn, tóc đen phát sáng","uyLuc":"Giết gọn mười mấy yêu thú cấp hai trong chốc lát","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0528","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0528","loai":"dùng","importance":"normal","giaiDoan":"Diệt Ưng Diên Thú cứu nhóm Thanh Linh Môn","text":"Mười cự viên Khôi Lỗi xuất hiện từ bên trong màn ánh sáng bạc, phóng hơn trăm cột sáng xuyên thủng toàn bộ Ưng Diên Thú cấp hai trong chốc lát, rồi biến mất vô thanh vô tức.","anchor":"từ trong màn ánh sáng bạc kia lại đột nhiên vùn vụt phóng ra hơn trăm cột ánh sáng"}]},"nguon":["@c0528"]},{"id":"chi-nguyen-dan","name":"Chí Nguyên Đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Nam tử thần bí trong trận pháp","Trung niên tu sĩ Thanh Linh Môn"],"trangThai":"dang-co","blurb":"Ba viên đan dược màu lam trong bình ngọc trắng, được luyện chế từ Yêu Đan, có mùi thơm đặc biệt. Dùng làm giá trao đổi cho Công Tôn Hạnh làm lô đỉnh, công hiệu chữa bệnh trọng cho tu sĩ.","detail":"Đan dược màu lam, ba viên chứa trong bình ngọc nhỏ màu trắng. Được luyện chế từ Yêu Đan, khi mở nắp bình tỏa mùi thơm đặc biệt khiến tinh thần rung động. Trung niên sư thúc Thanh Linh Môn xác nhận là đan dược trân quý. Nam tử thần bí dùng ba viên này đổi lấy Công Tôn Hạnh làm lô đỉnh song tu, nhằm cứu chưởng môn Thanh Linh Môn đang bệnh nặng.","congNang":["Chữa bệnh trọng cho tu sĩ (chưởng môn Thanh Linh Môn)"],"chuSoHuu":[{"ten":"Nam tử thần bí trong trận pháp","tuChuong":"@c0530","denChuong":"@c0530","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-dung"},{"ten":"Trung niên tu sĩ Thanh Linh Môn","tuChuong":"@c0530","denChuong":"","cachCoDuoc":"Công Tôn Hạnh ném bình ngọc nhờ mang về cho phụ thân","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0530","loai":"xuat-hien","importance":"normal","giaiDoan":"Xuất hiện làm giá trao đổi","text":"Nam tử thần bí đưa ba viên Chí Nguyên Đan trong bình ngọc trắng cho Công Tôn Hạnh, đổi lấy nàng làm lô đỉnh. Trung niên sư thúc xác nhận là đan dược luyện từ Yêu Đan, vật trân quý.","anchor":"Đây là đan dược được luyện chế từ Yêu Đan!"}]},"nguon":["@c0530"]},{"id":"hai-do-hai-vuc-ngoc-gian","name":"Hải đồ hải vực (ngọc giản)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản chứa bản đồ hải vực do Công Tôn Hạnh đưa cho Hàn Lập, giúp hắn biết đường tới phường thị.","detail":"Công Tôn Hạnh lấy từ Túi Trữ Vật đưa cho Hàn Lập khi hắn hỏi thăm nơi mua bán trong hải vực. Ngọc giản ghi bản đồ vùng hải vực phụ cận, bao gồm vị trí phường thị tiểu hoang đảo hướng Nam.","nguon":["@c0531"],"chuSoHuu":[{"ten":"Công Tôn Hạnh","tuChuong":"","denChuong":"@c0531","cachCoDuoc":"","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0531","denChuong":"","cachCoDuoc":"Được Công Tôn Hạnh đưa","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0531","loai":"xuất hiện","importance":"normal","giaiDoan":"Công Tôn Hạnh đưa hải đồ cho Hàn Lập","text":"Công Tôn Hạnh lấy ngọc giản hải đồ từ Túi Trữ Vật đưa cho Hàn Lập để hắn tìm đường tới phường thị.","anchor":"có hải đồ tự nhiên là rất tốt"}]}},{"id":"phap-khi-vong-lua","name":"Pháp khí vòng lửa","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"","soHuu":["Hoàng Minh Lễ"],"trangThai":"dang-dung","blurb":"Pháp khí hỏa thuộc tính của Hoàng Minh Lễ, dùng phối hợp chiến đấu với yêu thú.","detail":"Pháp khí vòng lửa hỏa thuộc tính, Hoàng Minh Lễ dùng phối hợp cùng Hàn Lập đánh năm yêu thú cấp ba, bốn.","nguon":["@c0532"]},{"id":"thien-linh-tu","name":"Thiên Linh tử","cn":"天灵子","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Trân quý cấp Kết Đan","soHuu":["Lão giả mập áo lam"],"trangThai":"dang-co","blurb":"Ba miếng linh vật quý hiếm, do lão giả mập áo lam đưa ra trao đổi tại Giao hoán hội Kết Đan kỳ.","detail":"Được lão giả mập áo lam mang đến Giao hoán hội, xếp cùng yêu đan Ngọa Hổ Sa và da Hỏa Hải thú. Thuộc loại vật phẩm trân quý với tu sĩ Kết Đan kỳ.","nguon":["@c0534"]},{"id":"yeu-dan-ngoa-ho-sa","name":"Yêu đan Ngọa Hổ Sa","cn":"卧虎鲨","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Yêu đan yêu thú cấp sáu","soHuu":["Lão giả mập áo lam"],"trangThai":"dang-co","blurb":"Yêu đan của yêu thú cấp sáu Ngọa Hổ Sa, do lão giả mập đưa ra tại Giao hoán hội. Hàn Lập coi thường vì hắn có bảy tám viên yêu đan tương đương.","detail":"Yêu đan trân quý với Kết Đan kỳ, nhưng Hàn Lập cười lạnh không thèm vì bản thân đã sở hữu bảy tám viên yêu đan cấp sáu.","nguon":["@c0534"]},{"id":"trung-yeu-thu-ban-le-dan","name":"Trứng yêu thú Bàn Lê Dẫn cấp năm","cn":"盘梨引","aliases":[],"category":"khac","categoryLabel":"Khác","phamCap":"Yêu thú cấp năm","soHuu":["Quái nhân cao gầy (giao hoán hội)"],"trangThai":"dang-co","blurb":"Quả trứng màu vàng nhỏ của yêu thú Bàn Lê Dẫn cấp năm, cực hiếm, khiến toàn bộ tu sĩ Kết Đan tại Giao hoán hội khát khao.","detail":"Do quái nhân cao gầy đưa ra tại Giao hoán hội, là vật phẩm duy nhất y mang tới. Toàn bộ tu sĩ Kết Đan trong phòng đều lộ vẻ khát khao khi thấy quả trứng này.","nguon":["@c0534"]},{"id":"mieng-dong-van-tu-co","name":"Miếng đồng khắc văn tự cổ","cn":"","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":["Tu sĩ họ Tôn"],"trangThai":"đang bán","blurb":"Miếng đồng cỡ bàn tay, ảm đạm vô quang, khắc văn tự cổ quái giống văn tự trên công pháp luyện khí vô danh bằng da thú của Hàn Lập.","detail":"Do tu sĩ họ Tôn (Kết Đan trung kỳ) đưa ra tại đại hội trao đổi bí thị, cùng với linh cốt yêu thú cấp tám. Hắn tuyên bố chỉ bán cho người am hiểu giá trị, không giải thích. Hàn Lập nhận ra văn tự trên miếng đồng rất giống với văn tự trên quyển công pháp luyện khí vô danh bằng da thú, sinh hứng thú nhưng chưa đổi.","congNang":["Chưa rõ công dụng, khắc văn tự cổ quái có liên quan đến công pháp luyện khí vô danh bằng da thú"],"chuSoHuu":[{"ten":"Tu sĩ họ Tôn","tuChuong":"@c0535","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"đang bán"}],"tabs":{"tienTrinh":[{"chuong":"@c0535","loai":"xuất hiện","importance":"normal","giaiDoan":"Đưa ra tại đại hội trao đổi","text":"Tu sĩ họ Tôn đưa ra miếng đồng cỡ bàn tay khắc văn tự cổ quái tại đại hội trao đổi bí thị. Hàn Lập nhận ra văn tự giống công pháp luyện khí vô danh bằng da thú, sinh hứng thú nhưng chưa đổi.","anchor":"mặt trên khắc một dạng văn tự cổ quái, mấy cái văn tự này cùng với quyển công pháp luyện khí vô danh bằng da thú kia không khác nhau lắm"}]},"nguon":["@c0535"]},{"id":"linh-cot-yeu-thu-cap-tam","name":"Linh cốt yêu thú cấp tám","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cấp 8","soHuu":["Tu sĩ họ Tôn"],"trangThai":"đang bán","blurb":"Đoạn xương dài nửa thước, màu xám trắng, được Vân Thiên Khiếu nhận dạng là linh cốt yêu thú cấp tám, trân phẩm quý nhất tại đại hội trao đổi.","detail":"Do tu sĩ họ Tôn đưa ra tại đại hội trao đổi bí thị cùng miếng đồng khắc văn tự cổ. Vân Thiên Khiếu cười lớn nhận dạng đây là linh cốt yêu thú cấp tám, gây chấn động cả trường. Là kỳ bảo khó gặp đối với tu sĩ Kết Đan.","congNang":["Linh cốt yêu thú cấp tám, nguyên liệu quý hiếm"],"chuSoHuu":[{"ten":"Tu sĩ họ Tôn","tuChuong":"@c0535","denChuong":"","cachCoDuoc":"Không rõ nguồn gốc","trangThai":"đang bán"}],"tabs":{"tienTrinh":[{"chuong":"@c0535","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhận dạng tại đại hội","text":"Tu sĩ họ Tôn đưa ra đoạn xương xám trắng dài nửa thước. Vân Thiên Khiếu cười lớn nhận dạng đây là linh cốt yêu thú cấp tám, gây chấn động cả trường.","anchor":"có thể xuất ra linh cốt của yêu thú cấp tám, Vân mỗ có chút động tâm"}]},"nguon":["@c0535"]},{"id":"tieu-xoa-mau-xam","name":"Tiểu xoa màu xám","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vân Thiên Khiếu"],"trangThai":"Chưa sử dụng","blurb":"Pháp bảo hình xoa màu xám của Vân Thiên Khiếu, vừa kịp lấy ra nhưng chưa thi triển đã bị hạ gục.","detail":"Vân Thiên Khiếu lấy ra tiểu xoa màu xám trong lúc bị mười hai thanh phi kiếm tấn công, nhưng chưa kịp sử dụng đã ngã xuống. Công năng chưa rõ.","chuSoHuu":[{"ten":"Vân Thiên Khiếu","tuChuong":"@c0536","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0536","loai":"xuất hiện","importance":"bridge","giaiDoan":"Xuất hiện lần đầu","text":"Vân Thiên Khiếu vừa kịp lấy tiểu xoa màu xám ra nhưng chưa thi triển đã bị Hàn Lập hạ gục.","anchor":"Vân Thiên Khiếu lúc này vừa mới lấy ra pháp bảo tiểu xoa màu xám"}]},"nguon":["@c0536"]},{"id":"tam-dong-tu-si-ho-ton","name":"Tấm đồng (của tu sĩ họ Tôn)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Đang sở hữu (Hàn Lập)","blurb":"Tấm đồng mà Hàn Lập chủ động hút về tay từ hắc tu sĩ họ Tôn, đổi bằng yêu đan cấp năm. Giá trị khoảng năm nghìn linh thạch, là mục tiêu chuyến đi của Hàn Lập.","detail":"Tấm đồng ban đầu thuộc sở hữu của tu sĩ họ Tôn (hắc tu sĩ) tại hội trao đổi vách núi đá Ngoại Tinh Hải. Hàn Lập hút về tay xem xét rồi đổi bằng một viên yêu đan cấp năm. Giá trị khoảng năm nghìn linh thạch. Mục đích chuyến đi của Hàn Lập đạt được nhờ có được vật này.","chuSoHuu":[{"ten":"Tu sĩ họ Tôn","tuChuong":"@c0537","denChuong":"@c0537","cachCoDuoc":"Không rõ","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0537","denChuong":"","cachCoDuoc":"Đổi bằng yêu đan cấp năm","trangThai":"dang-co"}],"congNang":[],"tabs":{"tienTrinh":[{"chuong":"@c0537","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập đổi yêu đan cấp năm lấy tấm đồng","text":"Hàn Lập hút tấm đồng từ tay hắc tu sĩ họ Tôn, đổi bằng yêu đan cấp năm, mục đích chuyến đi đạt được.","anchor":"Tấm đồng của tu sĩ họ Tôn kia đột nhiên vù một tiếng, bắn vào lòng bàn tay Hàn Lập"}]},"nguon":["@c0537"]},{"id":"huyen-mong-thach","name":"Huyễn Mộng Thạch","cn":"幻梦石","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Phạm Tĩnh Mai","Hàn Lập"],"trangThai":"dang-co","blurb":"Huyễn Mộng Thạch là loại linh thạch cực hiếm, đóng vai trò tài liệu trọng yếu nhất để hoàn thiện Truyền Tống Trận truyền tống cự ly dài từ Ngoại Tinh Hải về Nội Tinh Hải. Nơi sản sinh loại đá này có yêu thú cấp năm–sáu canh giữ, thậm chí có yêu thú cấp bảy, khiến việc thu thập vô cùng nguy hiểm.","detail":"Huyễn Mộng Thạch là thành phần then chốt cuối cùng để hoàn thành Truyền Tống Trận của Diệu Âm Môn. Diệu Âm Môn đã dò xét nơi sản sinh loại đá này suốt nhiều năm, song do khu vực đó có đám yêu thú cấp năm–sáu sinh sống, thậm chí có yêu thú cấp bảy, nên chưa dám hành động một mình. Phạm phu nhân tiết lộ rằng Diệu Âm Môn năm xưa đã từng mua Huyễn Mộng Thạch để lắp đặt Truyền Tống Trận, và nàng đã bí mật giữ lại một phần. Truyền Tống Trận vốn đã hoàn thành tám chín phần, chỉ cần bổ sung thêm Huyễn Mộng Thạch là có thể sử dụng được.","congNang":["Tài liệu trọng yếu nhất để xây dựng Truyền Tống Trận @c0537","Nguyên liệu thiết yếu để khởi động và hoàn thiện Truyền Tống Trận truyền tống cự ly dài từ Ngoại Tinh Hải về Nội Tinh Hải @c0554","Thành phần then chốt cuối cùng để đưa Truyền Tống Trận từ trạng thái hoàn thành tám chín phần sang sử dụng được @c0555"],"tabs":{"tienTrinh":[{"chuong":"@c0537","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc là tài liệu mấu chốt còn thiếu","text":"Phạm phu nhân tiết lộ Huyễn Mộng Thạch là tài liệu trọng yếu nhất của Truyền Tống Trận, nơi sản sinh có yêu thú cấp cao canh giữ.","anchor":"Chúng ta trải qua mấy năm nay dò xét sản sinh loại đá đó nhưng lại có một đám yêu thú cấp cao sinh sống ở phụ cận"},{"chuong":"@c0554","loai":"xuất hiện","importance":"major","giaiDoan":"Phạm phu nhân tiết lộ bí mật tàng trữ","phamCap":"Trân quý","text":"Phạm phu nhân tiết lộ Diệu Âm môn năm xưa đã mua Huyễn Mộng thạch để lắp Truyền tống trận. Nàng bí mật giữ trong người, giấu không cho Vân Thiên Khiếu biết. Đưa ra làm điều kiện trao đổi cuối cùng với Hàn Lập, đủ để khởi động Truyền tống trận đưa hắn về Nội Tinh Hải.","anchor":"Diệu Âm môn chúng ta năm đó từng bỏ ra rất nhiều tiền mua các loại tài liệu trân quý, trong đó cũng có cả Huyễn Mộng thạch"},{"chuong":"@c0555","loai":"nhắc tới","importance":"normal","giaiDoan":"Được xác nhận là nguyên liệu cuối cùng còn thiếu","text":"Phạm phu nhân xác nhận Truyền tống trận đã hoàn thành tám chín phần, chỉ cần thêm Huyễn Mộng thạch là có thể sử dụng.","anchor":"Chỉ cần có thêm Huyễn Mộng thạch là lập tức có thể sử dụng"}]},"nguon":["@c0537","@c0554","@c0555"],"chuSoHuu":[{"ten":"Phạm Tĩnh Mai","tuChuong":"@c0554","denChuong":"","cachCoDuoc":"Diệu Âm môn mua sắm, nàng giữ lại khi ra ngoại hải","trangThai":"dang-giu"}],"dacDiem":"Loại linh thạch cực kỳ hiếm có, nơi sản sinh được yêu thú cấp năm–sáu canh giữ, thậm chí có yêu thú cấp bảy, khiến việc thu thập vô cùng gian nan nguy hiểm."},{"id":"tam-dong-ba-dau-sau-tay","name":"Tấm đồng ba đầu sáu tay","cn":"","aliases":["Miếng đồng khắc văn tự cổ"],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Tấm đồng một mặt khắc chữ cùng nguồn gốc sách da thú, mặt kia khắc đồ hình quái vật ba đầu sáu tay. Rót linh lực sẽ phóng bức họa công pháp yêu tu.","detail":"Một mặt khắc văn tự cùng nguồn gốc với quyển sách da thú, mặt còn lại khắc đồ hình quái vật ba đầu sáu tay. Khi rót linh lực, tấm đồng phát ra âm thanh trầm, rung động rồi bắn cột sáng lên vách đá, hiện bức họa cổ xưa — yêu thú vảy bạc có sừng biểu diễn 36 tư thế tu luyện. Hàn Lập kết luận đây là vật truyền thừa yêu tu, bỏ vào túi trữ vật.","congNang":["Phóng bức họa công pháp yêu tu khi rót linh lực"],"nguonGoc":"Vật truyền thừa yêu tu, cùng nguồn gốc với quyển sách da thú","tabs":{"tienTrinh":[{"chuong":"@c0539","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập nghiên cứu và từ bỏ","text":"Hàn Lập rót linh lực, tấm đồng phóng bức họa 36 tư thế tu luyện yêu tu. So sánh văn tự với sách da thú thấy cùng nguồn gốc. Kết luận là vật yêu tu, bỏ vào túi trữ vật.","anchor":"kiểu chữ trên tấm đồng kia hầu như là giống với kiểu chữ trên quyển sách da thú"}]},"nguon":["@c0539"]},{"id":"quyen-sach-da-thu","name":"Quyển sách da thú","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quyển sách văn tự cùng nguồn gốc với tấm đồng ba đầu sáu tay, Hàn Lập kết luận cũng là công pháp yêu tu.","detail":"Hàn Lập so sánh văn tự trên quyển sách da thú với tấm đồng, phát hiện hai loại chữ hầu như giống nhau, cùng nguồn gốc nhưng biểu hiện bên ngoài khác nhau. Kết luận đây cũng là một loại công pháp yêu tu, bỏ vào túi trữ vật cùng tấm đồng.","congNang":["Phỏng chừng là công pháp yêu tu"],"tabs":{"tienTrinh":[{"chuong":"@c0539","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập so sánh và kết luận","text":"Hàn Lập so sánh văn tự với tấm đồng, kết luận cùng nguồn gốc yêu tu, bỏ vào túi trữ vật.","anchor":"phỏng chừng nó cũng là một loại công pháp yêu tu nào đó mà thôi"}]},"nguon":["@c0539"]},{"id":"ban-yeu-thao","name":"Bạn Yêu Thảo","cn":"","category":"khac","categoryLabel":"Linh thảo","phamCap":"Cực phẩm (gần yêu thú cấp tám)","soHuu":[],"trangThai":"chua-thu-hoach","blurb":"Bạn Yêu Thảo là linh thảo quan trọng nhất mà Hàn Lập cần tìm, liên quan trực tiếp đến việc đột phá tu vi tiến thêm một tầng. Nó mọc quanh hồ nước nóng xanh trong động thiên nhiên tại sào huyệt Liệt Phong Thú, có màu đen chứng tỏ gần yêu thú cấp tám.","detail":"Bạn Yêu Thảo được Hàn Lập phát hiện khi xâm nhập sào huyệt của Liệt Phong Thú. Linh thảo này mọc quanh bờ hồ nước nóng màu xanh bên trong một động thiên nhiên. Màu sắc của Bạn Yêu Thảo phản ánh cấp bậc yêu thú gần đó: màu đen khi ở gần yêu thú cấp tám, màu xám khi cấp thấp hơn. Những cây Bạn Yêu Thảo tại đây có màu đen, cao khoảng một tấc. Đối với Hàn Lập, đây là thứ quan trọng nhất cần thu hoạch, bởi nó liên quan đến việc tu vi tiến thêm một tầng. Hắn lập tức lao tới bờ hồ, lấy hộp ngọc phất tay thu hái.","congNang":["Liên quan đến việc đột phá tu vi, giúp tiến thêm một tầng @c0539"],"dacDiem":"Màu đen khi mọc gần yêu thú cấp tám, màu xám khi gần yêu thú cấp thấp hơn; cao khoảng một tấc; mọc quanh hồ nước nóng xanh trong sào huyệt yêu thú.","tabs":{"tienTrinh":[{"chuong":"@c0539","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập phát hiện và thu hái","text":"Hàn Lập xâm nhập sào huyệt Liệt Phong Thú, phát hiện Bạn Yêu Thảo màu đen cao một tấc mọc quanh hồ nước nóng. Lao tới bờ hồ lấy hộp ngọc thu hái.","anchor":"Đây chính là Bạn Yêu Thảo - thứ mà hắn cần"}]},"nguon":["@c0539"]},{"id":"bich-diem-tuu","name":"Bích Diễm Tửu","cn":"碧焰酒","category":"dan-duoc","categoryLabel":"Linh tửu","phamCap":"Cực phẩm linh tửu","soHuu":["Phong Hi","Hàn Lập"],"trangThai":"da-dung","blurb":"Linh tửu do Phong Hi (bộ tộc Liệt Phong Thú) tự chế suốt hơn trăm năm, cần hóa hình giai yêu đan làm nguyên liệu chủ và thiên phú thần thông riêng của bộ tộc mới điều chế được. Đối với tu sĩ Kết Đan kỳ lần đầu uống, có thể kích thích chân nguyên giúp đột phá bình cảnh; Hàn Lập bị ép uống và phải mạo hiểm dùng đan hoả cùng linh dịch ngàn năm để luyện hoá.","detail":"Bích Diễm Tửu là linh tửu do Phong Hi — yêu tu thuộc bộ tộc Liệt Phong Thú — bỏ ra hơn trăm năm tự tay luyện chế. Nguyên liệu chủ yếu là một viên hóa hình giai yêu đan, kết hợp thiên phú thần thông đặc thù chỉ riêng bộ tộc Liệt Phong Thú sở hữu; các loài yêu tu khác không có khả năng điều chế. Rượu có sắc ngọc lục bích, hương thơm nồng đậm, được Phong Hi rót vào chén bạch ngọc khi giới thiệu với Hàn Lập (@c0541). Tác dụng chính là kích thích chân nguyên của tu sĩ Kết Đan kỳ, giúp đột phá bình cảnh, song chỉ có hiệu quả ở lần uống đầu tiên. Hàn Lập bị ép uống Bích Diễm Tửu, sau đó phải mạo hiểm bức toàn bộ đan hoả luyện hoá, tiêu tốn linh dịch ngàn năm để đẩy nhanh quá trình tiêu hoá dược lực (@c0542).","congNang":["Kích thích chân nguyên của tu sĩ Kết Đan kỳ, giúp đột phá bình cảnh; chỉ hiệu quả ở lần uống đầu tiên (@c0541)","Có thể bao quấn kiềm chế vật thể bất ổn trong cơ thể"],"nguonGoc":"Phong Hi (Liệt Phong Thú) tự chế, cần thiên phú thần thông bộ tộc + hóa hình giai yêu đan","chuSoHuu":[{"ten":"Phong Hi","tuChuong":"@c0541","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"da-cho"},{"ten":"Hàn Lập","tuChuong":"@c0542","denChuong":"","cachCoDuoc":"Phong Hi cho uống","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0541","loai":"xuất hiện","importance":"major","giaiDoan":"Phong Hi lấy ra, ép Hàn Lập uống","text":"Phong Hi rót Bích Diễm Tửu vào chén bạch ngọc, giới thiệu đây là linh tửu tự chế hơn trăm năm, cần hóa hình giai yêu đan và thiên phú bộ tộc Liệt Phong Thú mới luyện được. Ép Hàn Lập uống để đột phá bình cảnh lên Kết Đan hậu kỳ.","anchor":"Bích Diễm Tửu do Phong mỗ tự chế xem thế nào. Ta đã phải mất hơn trăm năm mới có thể chế riêng ra một bình linh tửu này"},{"chuong":"@c0542","loai":"dùng","importance":"major","giaiDoan":"Hàn Lập luyện hoá và đột phá Kết Đan Hậu Kỳ","text":"Hàn Lập uống Bích Diễm Tửu, mạo hiểm bức toàn bộ đan hoả luyện hoá, tiêu tốn linh dịch ngàn năm đẩy nhanh tiến độ. Lặng lẽ đột phá vào Kết Đan Hậu Kỳ khi rượu chưa luyện xong hết. Phần thừa được dùng bao lấy Kiền Lam Băng Châu đang bất ổn.","anchor":"xem ra Bích Diễm Tửu của Phong mỗ cũng không có lãng phí"}]},"nguon":["@c0541","@c0542"],"dacDiem":"Chất lỏng sắc ngọc lục bích, hương thơm nồng đậm; chỉ bộ tộc Liệt Phong Thú với thiên phú thần thông riêng mới điều chế được, nguyên liệu chủ là hóa hình giai yêu đan, thời gian luyện chế hơn trăm năm."},{"id":"hoa-hinh-giai-yeu-dan","name":"Hóa hình giai yêu đan","cn":"化形阶妖丹","category":"dan-duoc","categoryLabel":"Đan dược / Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"Đã dùng làm nguyên liệu Bích Diễm Tửu","blurb":"Viên yêu đan dùng làm nguyên liệu chủ để luyện chế Bích Diễm Tửu.","detail":"Nguyên liệu chủ không thể thiếu trong quá trình luyện chế Bích Diễm Tửu, kết hợp cùng thiên phú thần thông của bộ tộc Liệt Phong Thú.","nguon":["@c0541"]},{"id":"kien-lam-bang-chau","name":"Kiền Lam Băng Châu","cn":"乾蓝冰珠","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Kiền Lam Băng Châu là viên châu bí ẩn Hàn Lập từng nuốt vào bụng lúc liều chết, tiềm ẩn nguy cơ tự bạo nổ khi thiếu pháp lực kiềm chế. Sau khi suýt nổ trong cơ thể, viên châu được Bích Diễm Tửu bao lại ổn định tạm thời và sau đó được Hàn Lập lấy ra ngoài.","detail":"Kiền Lam Băng Châu được Hàn Lập nuốt vào bụng trong một tình huống liều chết trước đây, và hắn vẫn giữ nguyên bên trong cơ thể do kiêng kỵ Phong Hi mà không dám tùy tiện xử lý. Tuy nhiên, khi pháp lực của Hàn Lập khô kiệt, viên châu đột nhiên chuyển động biến hình, suýt bạo nổ bên trong cơ thể hắn. Nhờ Bích Diễm Tửu bao bọc mới tạm ổn định được tình thế. Sau khi Hàn Lập hồi phục pháp lực, hắn đã lấy viên châu ra khỏi cơ thể. Bản chất thực sự và công dụng cụ thể của Kiền Lam Băng Châu vẫn chưa được giải thích rõ ràng.","congNang":["Bản chất và công dụng chưa rõ","Có nguy cơ tự bạo nổ khi thiếu pháp lực kiềm chế @c0542"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0542","denChuong":"","cachCoDuoc":"Nuốt vào bụng trước đó","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0542","loai":"hư tổn/tu bổ","importance":"major","giaiDoan":"Suýt bạo nổ trong cơ thể Hàn Lập","text":"Đột nhiên chuyển động biến hình trong cơ thể Hàn Lập khi pháp lực hắn khô kiệt. Được Bích Diễm Tửu bao lại may mắn ổn định, sau đó Hàn Lập lấy ra khỏi cơ thể.","anchor":"Kiền Lam Băng Châu ở bên ngoài Ích Tà Thần Lôi đột nhiên bắt đầu chuyển động biến hình trong cơ thể"}]},"nguon":["@c0542"],"dacDiem":"Viên châu bất ổn, khi không có đủ pháp lực trấn áp sẽ tự chuyển động biến hình và có thể bạo nổ; cần ngoại lực như Bích Diễm Tửu bao bọc để tạm thời ổn định."},{"id":"phong-loi-si","name":"Phong Lôi Sí","cn":"风雷翅","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa hoàn thành (đang luyện chế)","soHuu":["Phong Hi"],"trangThai":"dang-luyen-che","blurb":"Phong Lôi Sí là pháp bảo dạng đôi cánh mà Phong Hi dự định luyện chế từ bộ xương cánh bạc của di hài Lôi Bằng điểu thượng cổ tìm được ở cô đảo dưới đáy biển, kết hợp kiến thức luyện bảo của nhân loại và phương pháp tu luyện của Liệt Phong tộc. Luyện thành sẽ sở hữu phong lôi lực và khả năng dịch chuyển tức thời.","detail":"Đôi cánh thứ hai mà Phong Hi muốn luyện, khác biệt với Phong Hỏa Sí bản mệnh. Nguyên liệu chính là bộ xương cánh bạc từ di hài Lôi Bằng điểu thượng cổ đã hóa hình, ẩn chứa lôi điện lực kinh người, được Phong Hi tìm thấy tại cô đảo dưới đáy biển. Quá trình luyện chế kết hợp cách luyện pháp bảo của nhân loại với phương pháp tu luyện Phong Hỏa Sí của Liệt Phong tộc, đồng thời bổ sung thêm nguyên liệu linh cầm khác. Việc luyện chế đòi hỏi bốn thuộc tính phối hợp: thổ do Quy yêu đảm nhiệm, thủy do Độc Giao đảm nhiệm — hai thuộc tính này bố trận tạo lôi thuộc tính; phong do chính Phong Hi phối hợp để tạo phong lôi lực; mộc do Hàn Lập đảm nhiệm nhằm cân bằng toàn bộ. Phong Hi tự đánh giá bảy tám phần nắm chắc thành công. Tại chương @c0543, Phong Hi tiết lộ toàn bộ kế hoạch luyện chế và phân công ","hinhDang":"Đôi cánh","vatLieu":"Xương cánh bạc di hài Lôi Bằng điểu + nguyên liệu linh cầm khác","nguonGoc":"Phong Hi tìm được di hài Lôi Bằng điểu ở cô đảo dưới đáy biển, kết hợp kiến thức luyện bảo nhân loại và phương pháp Liệt Phong tộc","congNang":["Dịch chuyển tức thời đến bất kỳ đâu @c0543","Phong lôi lực — sức mạnh kết hợp giữa phong và lôi thuộc tính @c0543"],"chuSoHuu":[{"ten":"Phong Hi","tuChuong":"@c0543","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"dang-luyen-che"}],"tabs":{"tienTrinh":[{"chuong":"@c0543","loai":"xuất hiện","importance":"major","giaiDoan":"Phong Hi tiết lộ kế hoạch luyện chế","phamCap":"Chưa hoàn thành","text":"Phong Hi tiết lộ kế hoạch luyện chế Phong Lôi Sí từ bộ xương cánh bạc Lôi Bằng điểu thượng cổ. Phân công bốn người phối hợp bốn thuộc tính. Đã nghiên cứu nhiều năm, tự tin bảy tám phần thành công.","anchor":"Có được linh sí thứ hai này hỗ trợ, Phong mỗ tự tin rằng thiên hạ này to lớn thật nhưng bất kỳ chổ nào mà tại hạ muốn là có thể đi tới ngay lập tức"}]},"nguon":["@c0543"]},{"id":"di-hai-loi-bang-dieu","name":"Di hài Lôi Bằng điểu (bộ xương cánh bạc)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Phong Hi"],"trangThai":"dang-co","blurb":"Bộ xương màu bạc từ di hài một con Lôi Bằng điểu thượng cổ đã hóa hình, ẩn chứa lôi điện lực kinh người. Là nguyên liệu chính để luyện Phong Lôi Sí.","detail":"Phong Hi tìm được ở cô đảo dưới đáy biển khi tu luyện vài năm trước. Lôi Bằng điểu là yêu thú thượng cổ thuộc top mười yêu thú cấp cao nhất về tốc độ phi độn, có lôi quang điện hỏa. Di hài chỉ còn bộ xương bạc, ẩn chứa lôi điện lực mạnh mẽ kinh người.","nguonGoc":"Cô đảo dưới đáy biển","dacDiem":"Xương bạc, ẩn chứa lôi điện lực kinh người, thuộc Lôi Bằng điểu thượng cổ đã hóa hình","tabs":{"tienTrinh":[{"chuong":"@c0543","loai":"xuất hiện","importance":"normal","giaiDoan":"Phong Hi kể lai lịch tìm được","text":"Phong Hi kể vài năm trước tu luyện dưới đáy biển, phát hiện cô đảo có di hài Lôi Bằng điểu thượng cổ đã hóa hình, chỉ còn bộ xương bạc ẩn chứa lôi điện lực kinh người.","anchor":"tìm được một khối di hài của một con chim thượng cổ khổng lồ đã bị tàn phá, chỉ còn lại một bộ xương màu bạc"}]},"nguon":["@c0543"]},{"id":"pham-thanh-chan-phien","name":"Phạm Thánh Chân Phiến","cn":"梵圣真片","category":"khac","categoryLabel":"Thánh vật","phamCap":"Thánh vật yêu tộc truyền thừa","soHuu":["Hàn Lập (nghi)"],"trangThai":"thất lạc nhiều mảnh, Hàn Lập nghi đang sở hữu một phần","blurb":"Phạm Thánh Chân Phiến là thánh vật truyền thừa đời đời của yêu tộc, ghi chép hoang cổ mật thuật Tam phạm thánh công. Trước đây nằm trên người Toan Nghê Thú cấp bảy thuộc vương tộc Vạn trượng hải, sau bị tu sĩ nhân loại giết Toan Nghê Thú mà đoạt lấy, hiện đã thất lạc nhiều mảnh không còn trọn vẹn.","detail":"Phạm Thánh Chân Phiến là vật truyền thừa thiêng liêng của hải tộc (yêu tộc), ghi chép công pháp Tam phạm thánh công — một hoang cổ mật thuật của thượng cổ yêu tộc. Thánh vật này vốn nằm trên người Toan Nghê Thú cấp bảy thuộc vương tộc Vạn trượng hải, về sau bị tu sĩ nhân loại giết Toan Nghê Thú rồi lấy đi. Trải qua biến cố, Phạm Thánh Chân Phiến đã mất nhiều mảnh, không còn nguyên vẹn. Giao Long Nhất tộc tham gia chiến tranh yêu–nhân một phần cũng vì mục đích thu hồi thánh vật này. Sự tồn tại của Phạm Thánh Chân Phiến được Độc Giao tiết lộ trong cuộc đàm luận giữa tam yêu (@c0544). Hàn Lập từng nghe được cuộc đàm luận ấy và nghi ngờ rằng đồng phiến ghi công pháp yêu tộc mà mình đang nắm giữ chính là một phần của Phạm Thánh Chân Phiến.","congNang":["Ghi chép công pháp Tam phạm thánh công — hoang cổ mật thuật của thượng cổ yêu tộc (@c0544)"],"chuSoHuu":[{"ten":"Toan Nghê Thú cấp bảy","tuChuong":"@c0544","denChuong":"","cachCoDuoc":"vật truyền thừa bộ tộc","trangThai":"bị lấy"},{"ten":"Hắc phu tu sĩ (nghi)","tuChuong":"@c0544","denChuong":"","cachCoDuoc":"giết Toan Nghê Thú cấp bảy lấy được","trangThai":"không rõ"},{"ten":"Hàn Lập (nghi)","tuChuong":"@c0544","denChuong":"","cachCoDuoc":"có được đồng phiến ghi công pháp yêu tộc","trangThai":"đang giữ (chưa xác nhận)"}],"tabs":{"tienTrinh":[{"chuong":"@c0544","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ lai lịch trong đàm luận tam yêu","text":"Độc Giao tiết lộ thánh vật Phạm Thánh Chân Phiến của hải tộc bị tu sĩ nhân loại lấy từ Toan Nghê Thú cấp bảy. Giao Long tộc tham chiến để thu hồi. Hàn Lập nghi ngờ đồng phiến mình đang có chính là vật này.","anchor":"thánh vật “Phạm Thánh Chân Phiến” của hải tộc chúng ta đời đời tương truyền"}]},"capNhatToi":"@c0544","nguon":["@c0544"]},{"id":"hon-don-ma-khi","name":"Hỗn độn ma khí","cn":"","category":"khac","categoryLabel":"Tà vật","phamCap":"Không rõ","soHuu":["Phong Hi"],"trangThai":"đã cài vào cơ thể Hàn Lập","blurb":"Hỗn độn ma khí là một loại ma khí do Phong Hi luyện hóa từ trên xác một ma đạo tu sĩ đã bị hắn đánh chết nhiều năm trước. Phong Hi pha thứ ma khí này vào Bích Diễm Tửu cho Hàn Lập uống nhằm mục đích khống chế, ma khí ẩn trong cơ thể rất khó khu trừ.","detail":"Phong Hi từng đánh chết một ma đạo tu sĩ nhiều năm trước và từ trên người hắn luyện hóa ra thứ hỗn độn ma khí này. Hắn bí mật pha ma khí vào Bích Diễm Tửu rồi cho Hàn Lập uống, dùng làm thủ đoạn khống chế. Ma khí sau khi vào cơ thể sẽ ẩn tàng rất sâu, cực kỳ khó khu trừ. Hàn Lập từng tự dò xét cơ thể nhưng không phát hiện được sự tồn tại của tà khí, cho thấy tính chất ẩn giấu rất cao của loại ma khí này; tại thời điểm ghi nhận, tà khí vẫn chưa phát tác.","congNang":["Khống chế người uống, Phong Hi dùng để uy hiếp và sai khiến Hàn Lập @c0544","Ẩn tàng trong cơ thể nạn nhân, rất khó bị dò xét phát hiện và khu trừ @c0544"],"tabs":{"tienTrinh":[{"chuong":"@c0544","loai":"dùng","importance":"major","giaiDoan":"Phong Hi tiết lộ đã cài vào Bích Diễm Tửu","text":"Phong Hi tiết lộ đã pha hỗn độn ma khí vào Bích Diễm Tửu cho Hàn Lập uống. Ma khí luyện từ xác ma đạo tu sĩ, ẩn trong cơ thể rất khó khu trừ. Hàn Lập tự kiểm tra không phát hiện.","anchor":"Cái hỗn độn tà khí này đúng ra phải nói là hỗn độn ma khí mới đúng"}]},"capNhatToi":"@c0544","nguon":["@c0544"],"dacDiem":"Ma khí luyện hóa từ xác ma đạo tu sĩ, có thể pha vào rượu cho người uống mà không hay biết, ẩn trong cơ thể cực kỳ sâu kín, ngay cả nạn nhân tự dò xét cũng không phát hiện được."},{"id":"van-yeu-lenh","name":"Vạn yêu lệnh","cn":"","category":"khac","categoryLabel":"Lệnh bài","phamCap":"Không rõ","soHuu":["Lão Toan Nghê"],"trangThai":"đã phát động","blurb":"Lệnh bài do Lão Toan Nghê phát động, triệu tập mấy vạn yêu thú đồng loạt san bằng các đảo nhỏ nhân loại.","detail":"Lão Toan Nghê tiêu hao máu huyết phát động Vạn yêu lệnh để báo thù cho con cháu bị giết, dẫn đến mấy vạn yêu thú đồng loạt ra tay san bằng các đảo nhỏ của nhân loại.","nguon":["@c0544"]},{"id":"loi-bang-cot-si","name":"Lôi Bằng cốt sí","cn":"雷鹏骨翅","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Cực phẩm (tàn cốt yêu thú hóa hình mạt kỳ)","soHuu":["Phong Hi"],"trangThai":"Đang luyện chế","blurb":"Lôi Bằng cốt sí là tàn cốt đôi cánh của một Lôi Bằng điểu tu vi hóa hình mạt kỳ bị vây đánh chết, vẫn lưu giữ ngân quang và uy lực khổng lồ dù đã tàn phá nặng. Được tam yêu Phong Hi, Độc Giao và Quy yêu dùng làm vật liệu cốt lõi để luyện chế pháp bảo trong trận pháp địa hỏa trì.","detail":"Cốt sí nguyên là đôi cánh bằng xương trắng lớn khoảng một trượng, thuộc về một Lôi Bằng điểu đã đạt hóa hình mạt kỳ — loài yêu thú có tốc độ ngạo thị thiên hạ. Chủ nhân của cốt sí không phải tọa hóa tự nhiên mà bị vây khốn đánh chết, do đó tàn cốt mang dấu vết tàn phá nghiêm trọng: một bên chỉ còn nửa, bên kia nát vụn. Dù vậy, cốt sí vẫn chớp ngân quang và tản ra uy lực khổng lồ, cho thấy tinh hoa Lôi thuộc tính trong xương chưa hề tiêu tán. Tại địa hỏa trì, Phong Hi phóng cốt sí ra giữa không trung từ Túi trữ vật; Độc Giao và Quy yêu dùng tơ ánh sáng tu bổ cốt sí trở về hình dạng đầy đủ, sau đó phủ tinh dịch từ tinh thạch xanh lên bề mặt và dùng đan hỏa từ Yêu Đan của ba yêu bao quanh luyện hóa, biến cốt sí thành nguyên liệu cốt lõi cho pháp bảo đang luyện chế.","hinhDang":"Đôi cánh xương trắng lớn khoảng một trượng, ban đầu tàn phá nặng","vatLieu":"Xương cánh Lôi Bằng điểu","nguonGoc":"Tàn cốt Lôi Bằng điểu hóa hình mạt kỳ bị vây đánh chết","dacDiem":"Đôi cánh xương trắng lớn khoảng một trượng, dù tàn phá nặng vẫn chớp ngân quang và tản uy lực khổng lồ; mang Lôi thuộc tính nguyên bản từ Lôi Bằng điểu hóa hình mạt kỳ.","congNang":["Vật liệu cốt lõi để tam yêu luyện chế pháp bảo trong trận pháp địa hỏa trì @c0545"],"chuSoHuu":[{"ten":"Phong Hi","tuChuong":"@c0545","denChuong":"","cachCoDuoc":"Không rõ nguồn gốc, lấy từ Túi trữ vật","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0545","loai":"xuất hiện","importance":"major","giaiDoan":"Phóng ra và bắt đầu luyện chế","text":"Phong Hi phóng cốt sí từ Túi trữ vật ra giữa không trung địa hỏa trì. Tam yêu tu bổ cốt sí tàn phá trở về nguyên dạng, phủ tinh dịch tinh thạch xanh, dùng đan hỏa ba Yêu Đan bao quanh luyện hóa. Bước đầu thành công.","anchor":"một đôi cánh bằng xương trắng lớn khoảng một trượng"}]},"capNhatToi":"@c0545","nguon":["@c0545"]},{"id":"tinh-thach-xanh-trong-suot","name":"Tinh thạch xanh trong suốt","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Phong Hi"],"trangThai":"Đã sử dụng","blurb":"Khối tinh thạch trong suốt màu xanh không rõ danh, được Phong Hi ném vào màn hào quang nóng chảy thành dịch lỏng phủ lên bề mặt Lôi Bằng cốt sí.","detail":"Phong Hi ném khối tinh thạch này vào màn hào quang ngũ sắc, tinh thạch mềm chảy thành dịch lỏng rồi được khống chế thấm đều lên bề mặt cốt sí trong quá trình luyện chế.","congNang":["Nóng chảy thành dịch lỏng phủ đều lên bề mặt cốt sí khi luyện chế @c0545"],"tabs":{"tienTrinh":[{"chuong":"@c0545","loai":"dùng","importance":"normal","giaiDoan":"Phủ lên cốt sí","text":"Phong Hi ném tinh thạch vào màn hào quang, nóng chảy thành dịch lỏng thấm đều lên bề mặt Lôi Bằng cốt sí.","anchor":"một khối tinh thạch trong suốt màu xanh, không biết nó là vật gì"}]},"capNhatToi":"@c0545","nguon":["@c0545"]},{"id":"phong-linh-kinh","name":"Phong Linh Kính","cn":"风灵镜","category":"khac","categoryLabel":"Thủ đoạn khống chế","phamCap":"Không rõ","soHuu":["Phong Hi"],"trangThai":"Đã cài vào cơ thể Hàn Lập","blurb":"Phong Linh Kính là thủ đoạn khống chế của Liệt Phong Thú, được bắn vào cơ thể đối phương dưới dạng bạch quang. Chỉ cần người gieo thúc dục pháp lực, nạn nhân sẽ chịu đau đớn cùng cực, nhưng qua một khoảng thời gian Phong Linh Kính sẽ tự tan mất.","detail":"Liệt Phong Thú sử dụng Phong Linh Kính sau khi giải trừ màn hào quang vây quanh Hàn Lập, bắn bạch quang vào cơ thể hắn nhằm thay thế phương thức khống chế trước đó (tà khí đã bị Ích Tà Thần Lôi thanh trừ). Phong Linh Kính đóng vai trò công cụ uy hiếp tạm thời, buộc nạn nhân phải phục tùng trong khoảng thời gian nó còn tồn tại trong cơ thể. Do bản chất sẽ chậm rãi tan mất theo thời gian, hiệu quả khống chế chỉ mang tính giai đoạn.","congNang":["Khống chế đối tượng bằng cách gây đau đớn cùng cực khi người gieo thúc dục pháp lực @c0546","Tự chậm rãi tan mất sau một khoảng thời gian, chỉ có hiệu quả khống chế tạm thời @c0546"],"chuSoHuu":[{"ten":"Phong Hi","tuChuong":"@c0546","denChuong":"","cachCoDuoc":"Tự có","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0546","loai":"dùng","importance":"major","giaiDoan":"Cài vào cơ thể Hàn Lập","text":"Liệt Phong Thú giải trừ màn hào quang vây Hàn Lập rồi bất ngờ bắn bạch quang Phong Linh Kính vào cơ thể hắn, thay thế tà khí đã bị thanh trừ, khiến hơn nửa kế thoát thân của Hàn Lập vô hiệu.","anchor":"Phong Linh Kính này không có gì đáng ngại. Qua một đoạn thời gian sẽ chậm rãi tan mất"}]},"nguon":["@c0546"],"uyLuc":"Khiến nạn nhân sống không bằng chết mỗi khi người gieo thúc dục pháp lực.","dacDiem":"Biểu hiện dưới dạng bạch quang khi được bắn vào cơ thể đối phương; mang tính tạm thời, sẽ tự tan theo thời gian."},{"id":"linh-dich-van-nam","name":"Linh dịch vạn năm","cn":"灵液万年","category":"dan-duoc","categoryLabel":"Linh dịch","phamCap":"Không rõ","soHuu":["Phong Hi"],"trangThai":"Đã sử dụng một phần","blurb":"Linh dịch quý hiếm chứa trong ba bình nhỏ, mỗi bình một giọt. Dùng để bổ sung pháp lực nhanh chóng khi cạn kiệt.","detail":"Phong Hi mang theo ba bình nhỏ linh dịch vạn năm, phát cho Độc Giao và Quy Yêu mỗi yêu một bình, bản thân giữ một bình. Sử dụng trong quá trình dung hợp Phong Lôi Sí để đảm bảo tam yêu không gián đoạn pháp lực. Quy Yêu pháp lực yếu nhất nên uống trước tiên.","congNang":["Bổ sung và khôi phục linh lực nhanh chóng"],"nguon":["@c0546"]},{"id":"yeu-dan-doc-giao","name":"Yêu đan Độc Giao","cn":"","category":"nguyen-lieu","categoryLabel":"Yêu đan","phamCap":"Cấp tám","soHuu":["Hàn Lập"],"trangThai":"Đã thu","blurb":"Viên yêu đan huyết sắc cỡ nắm tay, lộ ra từ hài cốt Độc Giao cấp tám sau khi bị đàn Phệ Kim Trùng gặm nát. Bên trong chứa tinh hồn Giao long; khi lộ diện đã tự bay trốn nhưng bị Hàn Lập dùng kiếm khí kích trúng rồi thu hồi.","detail":"Yêu đan Độc Giao là viên nội đan huyết sắc cỡ nắm tay, hình thành trong thân thể Độc Giao cấp tám. Sau khi Độc Giao bị đàn Phệ Kim Trùng giết chết và gặm nát hài cốt, viên yêu đan lộ ra và lập tức tự bay đi trốn, cho thấy nó vẫn mang linh tính nhất định. Hàn Lập đã kịp thời phát kiếm khí kích trúng, ngăn nó thoát đi và thu hồi thành công. Bên trong viên đan chứa tinh hồn Giao long (Giao hồn) — phần cốt tủy tu vi của yêu thú cấp tám.","congNang":["Chứa tinh hồn Giao long (Giao hồn) @c0549","Có khả năng tự bay trốn khi thoát khỏi thân xác yêu thú @c0549"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0549","denChuong":"","cachCoDuoc":"Thu từ hài cốt Độc Giao sau khi diệt","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0549","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ ra và bị thu","text":"Lộ ra từ hài cốt Độc Giao sau khi bị Phệ Kim Trùng gặm nát. Tự bay trốn nhưng bị Hàn Lập kích kiếm khí rồi thu hồi.","anchor":"một viên huyết sắc Yêu đan cỡ một nắm tay lóe ra"}]},"nguon":["@c0549"],"dacDiem":"Viên đan huyết sắc, cỡ nắm tay, mang linh tính có thể tự di chuyển khi không bị trấn áp."},{"id":"giao-hon","name":"Giao hồn","cn":"","category":"nguyen-lieu","categoryLabel":"Hồn phách yêu thú","phamCap":"Cấp tám","soHuu":["Hàn Lập"],"trangThai":"Nhốt trong bình ngọc","blurb":"Giao hồn là tinh hồn của Độc Giao cấp tám, hồn phách cường đại vượt xa yêu thú cấp sáu bảy, có khả năng ẩn hình trốn chạy. Được Hàn Lập thu phục và coi là bảo vật cực kỳ trân quý.","detail":"Giao hồn là tinh hồn tồn tại bên trong Yêu đan của Độc Giao cấp tám. Khi hiện ra, nó mang hình thái lam quang nhỏ bé nhưng sở hữu hồn phách cường đại hơn hẳn yêu thú cấp sáu bảy. Tinh hồn này có năng lực ẩn hình trốn chạy, và khi bị Đề Hồn Thú phun hoàng quang bắt lộ, nó vẫn có thể dùng lam quang giằng co kháng cự. Sau cùng Hàn Lập tay không tóm lấy, nhét vào bình ngọc cất trong Túi trữ vật. Hàn Lập coi đây là yêu hồn yêu thú cấp tám, một bảo vật cực kỳ trân quý, dù mục đích sử dụng cụ thể chưa được tiết lộ tại thời điểm thu phục.","congNang":["Ẩn hình: tinh hồn có thể tự ẩn hình trốn chạy sau khi thoát ra khỏi Yêu đan @c0549","Kháng hoàng quang: dùng lam quang giằng co kháng cự hoàng quang của Đề Hồn Thú @c0549"],"dacDiem":"Hồn phách cường đại, có thể ẩn hình, kháng hoàng quang Đề Hồn Thú; mang hình thái lam quang nhỏ bé.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0549","denChuong":"","cachCoDuoc":"Tay không bắt sau khi Đề Hồn Thú bắt lộ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0549","loai":"xuất hiện","importance":"major","giaiDoan":"Bị bắt nhốt","text":"Tinh hồn Độc Giao hiện ra từ Yêu đan rồi ẩn hình trốn chạy, bị Đề Hồn Thú phun hoàng quang bắt lộ, giằng co bằng lam quang. Hàn Lập tay không tóm nhét vào bình ngọc.","anchor":"Yêu hồn của yêu thú cấp tám là bảo vật cực kỳ trân quý"}]},"nguon":["@c0549"],"uyLuc":"Hồn phách cường đại hơn yêu thú cấp sáu bảy, có thể dùng lam quang kháng cự hoàng quang của Đề Hồn Thú."},{"id":"o-hac-quy-xac","name":"Ô hắc quy xác","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Trân quý","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quy xác bằng nắm tay, sản phẩm yêu thú hóa hình lần thứ hai, thu được từ túi trữ vật Quy yêu. Kết hợp vảy đỏ có thể luyện hộ giáp sánh ngang Hoàng Lân Giáp.","detail":"Thu được từ túi trữ vật của Quy yêu. Là thứ yêu thú hóa hình lần thứ hai tạo thành nên rất trân quý. Hàn Lập dự định kết hợp với hơn trăm phiến vảy màu đỏ để luyện chế hộ giáp không kém Hoàng Lân Giáp của Man Hồ Tử.","chuSoHuu":[{"ten":"Quy yêu","tuChuong":"","denChuong":"@c0551","cachCoDuoc":"","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0551","denChuong":"","cachCoDuoc":"Thu từ túi trữ vật Quy yêu","trangThai":"dang-co"}],"congNang":["Nguyên liệu luyện hộ giáp cấp cao @c0551"],"tabs":{"tienTrinh":[{"chuong":"@c0551","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập phát hiện trong túi trữ vật","text":"Hàn Lập kiểm tra túi trữ vật Quy yêu, phát hiện ô hắc quy xác bằng nắm tay cùng hơn trăm phiến vảy đỏ — sản phẩm yêu thú hóa hình lần hai, có thể luyện hộ giáp ngang Hoàng Lân Giáp.","anchor":"hắn còn phát hiện ra một ô hắc quy xác bằng nắm tay cùng hơn trăm phiến vảy màu đỏ"}]},"capNhatToi":"@c0551","nguon":["@c0551"]},{"id":"vay-do-hoa-hinh","name":"Hơn trăm phiến vảy màu đỏ","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Trân quý","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hơn trăm phiến vảy đỏ, sản phẩm yêu thú hóa hình lần thứ hai, thu từ túi trữ vật Độc Giao. Kết hợp quy xác để luyện hộ giáp.","detail":"Thu được từ túi trữ vật Độc Giao. Cũng là sản phẩm hóa hình lần hai, rất trân quý. Kết hợp với ô hắc quy xác có thể luyện chế hộ giáp tuyệt đối không kém Hoàng Lân Giáp của Man Hồ Tử.","chuSoHuu":[{"ten":"Độc Giao","tuChuong":"","denChuong":"@c0551","cachCoDuoc":"","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0551","denChuong":"","cachCoDuoc":"Thu từ túi trữ vật Độc Giao","trangThai":"dang-co"}],"congNang":["Nguyên liệu luyện hộ giáp cấp cao @c0551"],"tabs":{"tienTrinh":[{"chuong":"@c0551","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập phát hiện trong túi trữ vật","text":"Thu từ túi trữ vật Độc Giao, cùng với quy xác có thể luyện hộ giáp sánh ngang Hoàng Lân Giáp.","anchor":"Đây là thứ mà khi yêu thú hóa hình lần thứ hai tạo thành nên trân quý vô cùng"}]},"capNhatToi":"@c0551","nguon":["@c0551"]},{"id":"chuy-ngoc-nho","name":"Chùy ngọc nhỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Diệu Hạc chân nhân"],"trangThai":"dang-co","blurb":"Tiểu chùy bằng ngọc lớn chừng bàn tay, trên đầu chùy có rất nhiều phù văn, tỏa linh khí kinh người. Vũ khí chiến đấu của Diệu Hạc chân nhân.","detail":"Phóng ra bạch quang chói mắt nóng bỏng tấn công, đánh bay tu sĩ Kết Đan Kỳ có cổ bảo hộ thân vào vách đá. Tấn công Hàn Lập hai lần nhưng không hạ được nhờ Ngũ Hành Hoàn và Ngọc Như Ý đỡ.","congNang":["Phóng bạch quang nóng bỏng tấn công"],"chuSoHuu":[{"ten":"Diệu Hạc chân nhân","tuChuong":"@c0557","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0557","loai":"xuất hiện","importance":"normal","giaiDoan":"Diệu Hạc dùng tấn công Hàn Lập","text":"Diệu Hạc chân nhân phóng chùy ngọc nhỏ tỏa bạch quang tấn công Hàn Lập hai lần, đẩy bay hắn vào thạch bích nhưng không hạ được nhờ cổ bảo hộ thân.","anchor":"đó là một cái chùy nhỏ bằng ngọc. Trên đầu chùy có rất nhiều phù văn, chỉ lớn chừng bàn tay tỏa ra linh khí kinh người"}]},"nguon":["@c0557"]},{"id":"huyet-hac","name":"Huyết hạc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Diệu Hạc chân nhân"],"trangThai":"dang-co","blurb":"Hình vẽ bạch hạc ẩn trên áo Diệu Hạc chân nhân, kích hoạt bằng tinh huyết hóa thành hạc khổng lồ toàn thân đỏ như máu, hai mắt xanh biếc, dùng cưỡi phi hành tốc độ gấp bội.","detail":"Bình thường ẩn dưới dạng hình vẽ bạch hạc trên áo bào. Khi kích hoạt, Diệu Hạc phun tinh huyết hóa huyết vụ, huyết vụ bị hạc hút sạch rồi biến thành con hạc khổng lồ toàn thân đỏ như máu, hai mắt xanh biếc. Tốc độ phi hành tăng gấp bội so với bình thường, nhưng vẫn không bằng lôi độn của Hàn Lập dùng Phong Lôi Sí.","congNang":["Tăng tốc phi hành gấp bội khi cưỡi"],"tabs":{"tienTrinh":[{"chuong":"@c0558","loai":"dùng","importance":"normal","giaiDoan":"Kích hoạt lần đầu","text":"Diệu Hạc phun tinh huyết kích hoạt bạch hạc trên áo hóa thành huyết hạc khổng lồ để cưỡi đuổi theo Hàn Lập và Phong Hi.","anchor":"một con hạc đỏ như máu bắt đầu lan tỏa ra từ trên người lão"}]},"nguon":["@c0558"]},{"id":"co-kinh-mau-lam","name":"Cổ kính màu lam","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Diệu Hạc chân nhân"],"trangThai":"dang-co","blurb":"Cổ bảo của Diệu Hạc chân nhân, có thể xuất ra rất nhiều chiếc, dùng chiến đấu.","detail":"Một trong hai cổ bảo mà Diệu Hạc rút ra chuẩn bị đối đầu với Phong Hi (yêu thú cấp chín). Xuất ra rất nhiều chiếc cổ kính màu lam, công năng cụ thể chưa thi triển.","nguon":["@c0558"]},{"id":"tieu-chuy-bich-ngoc","name":"Tiểu chùy bích ngọc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Diệu Hạc chân nhân"],"trangThai":"dang-co","blurb":"Cổ bảo cầm tay của Diệu Hạc chân nhân, cùng cổ kính màu lam dùng chuẩn bị chiến đấu với Phong Hi.","detail":"Cổ bảo thứ hai mà Diệu Hạc rút ra khi đối mặt Phong Hi, cầm trên tay. Công năng cụ thể chưa thi triển.","nguon":["@c0558"]},{"id":"thanh-duong-loi","name":"Thanh Dương Lôi","cn":"青阳雷","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật trấn môn Thanh Dương Môn","soHuu":["Nguyên Dao"],"trangThai":"dang-co","blurb":"Thanh Dương Lôi là bảo vật uy lực lớn của Thanh Dương Môn, bị Nguyên Dao cướp đoạt từ thiếu chủ của môn phái sau khi dùng mị thuật ám hại hắn.","detail":"Thanh Dương Lôi vốn là bảo vật trấn môn của Thanh Dương Môn, được biết đến với uy lực đáng kể. Sau khi Nguyên Dao dùng mị thuật ám hại thiếu chủ Thanh Dương Môn, hắn đã cướp đoạt Thanh Dương Lôi cùng toàn bộ bảo vật khác của đối phương. Sự kiện này được tiết lộ trước nhóm tu sĩ, và Đinh lão giả cảnh báo mọi người phải hết sức cẩn thận khi đối mặt với bảo vật này trong tay Nguyên Dao.","congNang":["Uy lực lớn, được xem là bảo vật trấn môn của Thanh Dương Môn @c0560"],"chuSoHuu":[{"ten":"Thiếu chủ Thanh Dương Môn","tuChuong":"@c0560","denChuong":"@c0560","cachCoDuoc":"Bảo vật tông môn","trangThai":"da-mat"},{"ten":"Nguyên Dao","tuChuong":"@c0560","denChuong":"","cachCoDuoc":"Cướp từ thiếu chủ Thanh Dương Môn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0560","loai":"đổi chủ","importance":"major","giaiDoan":"Bị Nguyên Dao cướp từ thiếu chủ","text":"Được tiết lộ là bảo vật uy lực lớn của Thanh Dương Môn, bị Nguyên Dao cướp từ thiếu chủ sau khi ám hại hắn. Đinh lão giả cảnh báo nhóm phải cẩn thận.","anchor":"Người lại mang theo bảo vật uy lực lớn, chính là Thanh Dương Lôi của bổn môn"}]},"nguon":["@c0560"]},{"id":"mui-nhon-vang","name":"Mũi nhọn màu vàng","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đinh lão giả"],"trangThai":"khong-ro","blurb":"Pháp bảo của lão giả họ Đinh, chà xát hai tay mọc ra, phóng đi hóa cầu vồng dùng phá Câu Linh Trận.","detail":"Mũi nhọn màu vàng chói mắt từ trong tay lão giả bỗng nhiên mọc lên, phóng đi hóa cầu vồng phá tan trận pháp che giấu linh khí.","congNang":["Phá trận pháp"],"chuSoHuu":[{"ten":"Đinh lão giả","tuChuong":"@c0561","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"chủ chết"}],"tabs":{"tienTrinh":[{"chuong":"@c0561","loai":"dùng","importance":"normal","giaiDoan":"Phá Câu Linh Trận","text":"Lão giả họ Đinh chà xát hai tay mọc ra mũi nhọn vàng, phóng đi hóa cầu vồng phá tan Câu Linh Trận lộ ra ngọn núi linh khí.","anchor":"một mũi nhọn màu vàng chói mắt từ trong tay bỗng nhiên mọc lên"}]},"nguon":["@c0561"]},{"id":"phi-kiem-trang-dinh-lao-gia","name":"Phi kiếm trắng (Đinh lão giả)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đinh lão giả"],"trangThai":"khong-ro","blurb":"Phi kiếm của lão giả họ Đinh, phun ra dùng phá sương mù huyễn trận, kiếm quang cuồng vũ hóa bánh xe ánh sáng đường kính mấy trượng.","detail":"Lão giả phun phi kiếm trắng tại không trung cuồng vũ, trong nháy mắt hóa thành bánh xe ánh sáng đường kính mấy trượng để phá tan sương mù huyễn trận của Nguyên Dao.","congNang":["Công kích","Phá huyễn trận"],"chuSoHuu":[{"ten":"Đinh lão giả","tuChuong":"@c0561","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"chủ chết"}],"tabs":{"tienTrinh":[{"chuong":"@c0561","loai":"dùng","importance":"normal","giaiDoan":"Phá huyễn trận sương mù","text":"Lão giả phun phi kiếm trắng cuồng vũ hóa bánh xe ánh sáng mấy trượng phá tan sương mù huyễn trận Nguyên Dao.","anchor":"tại không trung cuồng vũ, trong nháy mắt hóa thành một bánh xe ánh sáng đường kích mấy trượng"}]},"nguon":["@c0561"]},{"id":"quai-nhan-den","name":"Quái nhận đen","cn":"","aliases":["Quái nhận"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Khô lâu"],"trangThai":"dang-co","blurb":"Pháp bảo của khô lâu, hình dáng nửa đao nửa kiếm phi thường quái dị, dùng chiến đấu cùng Nguyên Dao.","detail":"Thanh quái nhận màu đen nửa đao nửa kiếm, hình dáng quái dị, khô lâu dùng trong trận chiến phía sau núi để khống chế Nguyên Dao.","congNang":["Công kích cận/viễn chiến"],"hinhDang":"Nửa đao nửa kiếm, phi thường quái dị","chuSoHuu":[{"ten":"Khô lâu","tuChuong":"@c0561","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0561","loai":"dùng","importance":"normal","giaiDoan":"Trận chiến phía sau núi","text":"Khô lâu dùng quái nhận đen nửa đao nửa kiếm phối hợp đại hán hung ác chiến đấu khống chế Nguyên Dao.","anchor":"một thanh quái nhận màu đen, nửa đao nửa kiếm, phi thường quái dị"}]},"nguon":["@c0561"]},{"id":"bua-lon","name":"Búa lớn","cn":"","aliases":["Khai sơn việt","Cự việt"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại hán khuôn mặt hung ác"],"trangThai":"dang-co","blurb":"Pháp bảo của đại hán hung ác, hàn quang dày đặc khí thế phá núi, binh khí to lớn làm pháp bảo cực kỳ hiếm thấy theo nhận xét của Hàn Lập.","detail":"Thanh búa lớn hàn quang dày đặc, có thể phóng to nhiều lần bổ vào cửa đá động phủ. Hàn Lập nhận xét binh khí to lớn như vậy làm pháp bảo cực kỳ hiếm thấy.","congNang":["Công kích trọng lực","Phá cửa đá"],"hinhDang":"Búa lớn binh khí to lớn hiếm thấy","chuSoHuu":[{"ten":"Đại hán khuôn mặt hung ác","tuChuong":"@c0561","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0561","loai":"dùng","importance":"normal","giaiDoan":"Bổ cửa đá động phủ","text":"Đại hán hung ác phóng búa lớn to nhiều lần bổ vào cửa đá động phủ Nguyên Dao, hàn quang dày đặc khí thế phá núi.","anchor":"một thanh búa lớn hàn quang dày đặc khí thế như phá núi mà ra"}]},"nguon":["@c0561"]},{"id":"quai-chuy-do","name":"Quái chùy đỏ","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Pháp bảo xuất hiện trong trận chiến phía sau núi, dùng đối đầu Nguyên Dao cùng quái nhận đen.","detail":"Quái chùy màu đỏ xuất hiện trong trận chiến phía sau núi giữa khô lâu/đại hán hung ác và Nguyên Dao, dùng phối hợp chiến đấu.","congNang":["Công kích"],"tabs":{"tienTrinh":[{"chuong":"@c0561","loai":"dùng","importance":"bridge","giaiDoan":"Trận chiến phía sau núi","text":"Quái chùy đỏ được dùng cùng quái nhận đen chiến đấu với Nguyên Dao.","anchor":"cùng một thanh quái chùy màu đỏ chiến đấu cùng một chỗ"}]},"nguon":["@c0561"]},{"id":"hai-binh-dan-duoc-yeu-dan-cap-sau","name":"Hai bình đan dược (yêu đan cấp sáu)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Nguyên Dao"],"trangThai":"đang sử dụng","blurb":"Đan dược do Hàn Lập luyện từ yêu đan cấp sáu làm nguyên liệu chủ yếu, tặng Nguyên Dao. Giúp từ Kết Đan sơ kỳ tiến vào trung kỳ, tiết kiệm hơn mười lần công sức tu luyện.","detail":"Đựng trong hai bình bạch ngọc nhỏ. Hàn Lập dùng yêu đan cấp sáu làm nguyên liệu chủ yếu luyện chế, tặng Nguyên Dao đáp lễ Vạn niên linh dịch. Hiệu quả giúp tu sĩ Kết Đan sơ kỳ thuận lợi tiến vào Kết Đan trung kỳ, tiết kiệm hơn mười lần công sức so với tu luyện bình thường.","congNang":["Gia tăng pháp lực, trợ giúp từ Kết Đan sơ kỳ lên trung kỳ, tiết kiệm hơn mười lần công sức"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0563","denChuong":"@c0563","cachCoDuoc":"Tự luyện chế","trangThai":"đã tặng"},{"ten":"Nguyên Dao","tuChuong":"@c0563","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0563","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập tặng Nguyên Dao","text":"Hàn Lập tặng hai bình đan dược luyện từ yêu đan cấp sáu cho Nguyên Dao, giúp nàng thuận lợi tiến vào Kết Đan trung kỳ.","anchor":"dùng yêu đan cấp sáu làm nguyên liệu chủ yếu luyện chế ra"}]},"nguon":["@c0563"]},{"id":"ngoc-gian-tran-phap-thanh-duong-mon","name":"Ngọc giản trận pháp điển tịch Thanh Dương Môn","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Khối ngọc giản màu đen chứa toàn bộ trận pháp điển tịch của Thanh Dương Môn, bao gồm bí thuật Câu Linh Trận và nhiều trận pháp uy lực khác.","detail":"Nguyên Dao trao cho Hàn Lập không chút do dự khi hắn hỏi xin phương pháp bố trí Câu Linh Trận. Hàn Lập dùng thần thức kiểm tra nội dung, xác nhận đầy đủ rồi hài lòng thu lại.","congNang":["Chứa toàn bộ trận pháp điển tịch Thanh Dương Môn, bao gồm Câu Linh Trận ẩn nặc linh khí động phủ"],"chuSoHuu":[{"ten":"Nguyên Dao","tuChuong":"","denChuong":"@c0563","cachCoDuoc":"Lấy từ Thanh Dương Môn","trangThai":"đã tặng"},{"ten":"Hàn Lập","tuChuong":"@c0563","denChuong":"","cachCoDuoc":"Nhận từ Nguyên Dao","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0563","loai":"đổi chủ","importance":"normal","giaiDoan":"Nguyên Dao trao cho Hàn Lập","text":"Nguyên Dao trao ngọc giản đen chứa trận pháp điển tịch Thanh Dương Môn cho Hàn Lập khi hắn xin phương pháp bố trí Câu Linh Trận.","anchor":"Ngọc giản này chứa trận pháp điển tịch của Thanh Dương Môn"}]},"nguon":["@c0563"]},{"id":"quan-tai-han-ngoc","name":"Quan tài hàn ngọc","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Nguyên Dao"],"trangThai":"dang-co","blurb":"Quan tài dài bảy thước, cao ba thước, làm bằng hàn ngọc trân quý trong suốt, dùng bảo quản thi thể cho Hoàn Hồn Thuật.","detail":"Toàn thân được bao quanh bởi màu trắng nhạt, chế bằng hàn ngọc trân quý. Nằm giữa pháp trận Hoàn Hồn Thuật tại đảo Mộ huyệt yêu thú. Bên trong chứa thi thể mà Nguyên Dao tìm cho Nghiên Lệ dùng trong Hoàn Hồn Thuật.","congNang":["Bảo quản thi thể cho Hoàn Hồn Thuật"],"chuSoHuu":[{"ten":"Nguyên Dao","tuChuong":"@c0564","denChuong":"","cachCoDuoc":"Tự chuẩn bị","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0564","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện trong pháp trận","text":"Nguyên Dao kích hoạt pháp trận, lộ ra quan tài hàn ngọc trong suốt chứa thi thể. Hàn Lập đánh giá hàn ngọc trân quý.","anchor":"toàn thân được bao quanh bởi màu trắng nhạt, đúng là dùng hàn ngọc trân quý chế thành"}]},"capNhatToi":"@c0564","dinhDanh":"goc","nguon":["@c0564"]},{"id":"khi-cu-bo-tran","name":"Khí cụ bố trận","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Mấy bộ khí cụ bố trận lấy từ Túi trữ vật, dùng để dựng bốn năm cái trận pháp phòng hộ quanh sơn cốc, đủ chặn tu sĩ Trúc Cơ kỳ nhưng không ngăn được Kết Đan kỳ.","detail":"Hàn Lập phân phát mấy bộ khí cụ bố trận cho mười mấy khôi lỗi cự viên, chỉ huy chúng bố trí bốn phía sơn cốc trong gần một canh giờ, dựng bốn năm cái trận pháp phòng hộ.","congNang":["Dựng trận pháp phòng hộ chặn tu sĩ Trúc Cơ kỳ xâm nhập"],"tabs":{"tienTrinh":[{"chuong":"@c0565","loai":"dùng","importance":"normal","giaiDoan":"Bố trận phòng hộ sơn cốc","text":"Hàn Lập lấy mấy bộ khí cụ bố trận từ Túi trữ vật, phân cho khôi lỗi cự viên dựng bốn năm cái trận pháp quanh sơn cốc.","anchor":"Mặc dù ngăn không được tu sĩ Kết Đan Kỳ, nhưng đối với tu sĩ Trúc Cơ Kỳ thì sẽ không cách nào xông qua được"}]},"nguon":["@c0565"]},{"id":"thu-xa-hoa-le","name":"Thú xa hoa lệ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-su-dung","blurb":"Chiếc xe dài sáu bảy trượng hoàn toàn bằng gỗ quý, phù chú tầng tầng phát bạch quang nhàn nhạt, do ba quái điểu xanh sáu mắt bốn cánh kéo.","detail":"Thú xa hoa lệ xuất hiện cùng hơn mười đạo độn quang hồng tiếp cận tiểu đảo nơi Hàn Lập ẩn tu. Xe dài khoảng sáu bảy trượng, hoàn toàn bằng gỗ quý, trên thân có phù chú tầng tầng lớp lớp tỏa bạch quang nhàn nhạt. Ba con quái điểu xanh sáu mắt bốn cánh kéo xe bay cực nhanh.","congNang":["Phương tiện di chuyển trên không, tốc độ cực nhanh"],"tabs":{"tienTrinh":[{"chuong":"@c0567","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Thú xa hoa lệ cùng hơn mười đạo độn quang hồng vây quanh bay đến phụ cận tiểu đảo nơi Hàn Lập ẩn tu.","anchor":"Chiếc xe này dài khoảng sáu bảy trượng, hoàn toàn được làm bằng gỗ quý"}]},"nguon":["@c0567"]},{"id":"thanh-tiem-truy-lam-quang","name":"Thanh tiêm trùy lam quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Ôn Thiên Nhân"],"trangThai":"dang-co","blurb":"Pháp bảo kỳ lạ phóng từ miệng, hàn quang lập lòe, phù văn quấn quanh, tốc độ cực nhanh dùng để tập kích.","detail":"Ôn Thiên Nhân phóng từ miệng, hàn quang lập lòe, phù văn quấn quanh, phát âm thanh quái dị. Biến mất rồi xuất hiện trước người Hàn Lập, đánh vào quang tráo Ngọc Như Ý đẩy lùi hắn mấy trượng.","congNang":["Tập kích tốc độ cao, phù văn gia trì"],"hinhDang":"Tiêm trùy lam quang, phù văn quấn quanh","tabs":{"tienTrinh":[{"chuong":"@c0569","loai":"dùng","importance":"normal","giaiDoan":"Tập kích Hàn Lập","text":"Ôn Thiên Nhân phóng từ miệng tập kích Hàn Lập, đánh vào quang tráo Ngọc Như Ý đẩy lùi mấy trượng.","anchor":"chính là một thanh tiêm trùy kỳ lạ, hàn quang lập lòe trên đó, phù văn quấn quanh"}]},"nguon":["@c0569"]},{"id":"tieu-phien-tu-quang","name":"Tiểu phiên tử quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Ôn Thiên Nhân"],"trangThai":"dang-co","blurb":"Pháp bảo dài ba bốn tấc, tử quang lập lòe, linh khí bức người, phóng tử sắc vân vụ bao phủ thân hình ẩn dấu.","detail":"Ôn Thiên Nhân rút ra khi giao chiến, phóng vô số tử sắc vân vụ bao phủ thân hình. Phi kiếm xuyên qua tử vân mấy trăm lần nhưng như xuyên hư không, hoàn toàn vô hiệu — miễn dịch kiếm khí vật lý.","congNang":["Ẩn thân trong tử vân, miễn dịch kiếm khí vật lý"],"hinhDang":"Dài ba bốn tấc, tử quang lập lòe","tabs":{"tienTrinh":[{"chuong":"@c0569","loai":"dùng","importance":"normal","giaiDoan":"Ẩn thân chống Hàn Lập","text":"Phóng tử sắc vân vụ bao phủ thân Ôn Thiên Nhân, phi kiếm xuyên qua như hư không.","anchor":"Vô số đám tử sắc vân vụ từ trong đó xuất ra, cẩn thận đem hắn bao phủ vào bên trong"}]},"nguon":["@c0569"]},{"id":"kim-ti-phi-cham","name":"Kim ti phi châm","cn":"","aliases":["Kim ti"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Phi châm (loại khó luyện chế nhất)","soHuu":["Ôn Thiên Nhân"],"trangThai":"dang-dung","blurb":"Hơn trăm cây kim châm tinh tế dài hơn một tấc phát ra kim quang chói mắt, là pháp bảo phi châm của Ôn Thiên Nhân. Có thể hóa vô số sợi kim ti bắn ra bốn phương tám hướng giết gần vạn Phệ Kim Trùng tam sắc dễ dàng, đồng thời ngưng kết thành tiểu kiếm phá vỡ cấm chế hoa lam cổ bảo.","detail":"Kim ti phi châm là loại pháp bảo phi châm được Hàn Lập nhận xét là khó luyện chế nhất. Bảo vật gồm hơn trăm cây kim châm tinh tế dài hơn một tấc, cùng loại với Thanh Minh Châm chỉ khác màu sắc. Khi thi triển, kim châm hóa thành vô số sợi kim ti phóng ra từ tử vân, bắn ra bốn phương tám hướng, là khắc tinh của linh trùng — Phệ Kim Trùng tam sắc vốn khó bị pháp bảo thông thường tổn thương nhưng bị kim ti giết như cắt giấy, gần vạn con bị tiêu diệt dễ dàng. Ngoài hình thái phân tán, kim ti còn có thể ngưng kết thành tiểu kiếm tập trung công kích, đủ sức phá vỡ cấm chế trên hoa lam cổ bảo.","hinhDang":"Hơn trăm cây kim châm tinh tế dài hơn một tấc, kim quang chói mắt","congNang":["Hóa vô số sợi kim ti bắn ra bốn phương tám hướng, đặc biệt khắc chế linh trùng, giết gần vạn Phệ Kim Trùng tam sắc dễ dàng @c0570","Ngưng kết kim ti thành tiểu kiếm tập trung công kích @c0570","Phá vỡ cấm chế trên hoa lam cổ bảo @c0570"],"uyLuc":"Giết gần vạn Phệ Kim Trùng tam sắc dễ dàng — loại linh trùng vốn khó bị pháp bảo thông thường tổn thương — đồng thời đủ sức phá vỡ cấm chế hoa lam cổ bảo.","dacDiem":"Cùng loại phi châm với Thanh Minh Châm, chỉ khác màu sắc. Gồm hơn trăm cây kim châm tinh tế dài hơn một tấc, kim quang chói mắt, thuộc loại pháp bảo phi châm khó luyện chế nhất.","chuSoHuu":[{"ten":"Ôn Thiên Nhân","tuChuong":"@c0570","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0570","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Ôn Thiên Nhân phóng kim ti từ tử vân giết gần vạn Phệ Kim Trùng tam sắc. Kim ti hiện nguyên hình là hơn trăm cây kim châm tinh tế, sau đó ngưng kết thành tiểu kiếm phá vỡ cấm chế hoa lam cổ bảo.","anchor":"Là những cây kim châm tinh tế, chỉ có dài hơn một tấc, kim quang chói mắt"}]},"capNhatToi":"@c0570","nguon":["@c0570"]},{"id":"dong-co-thuan","name":"Đồng cổ thuẫn","cn":"","aliases":["Thanh đồng cổ thuẫn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Ôn Thiên Nhân"],"trangThai":"dang-dung","blurb":"Khiên đồng phòng ngự của Ôn Thiên Nhân, bay ra từ tử vân dễ dàng chặn công kích cự kiếm Thanh Trúc Phong Vân Kiếm của Hàn Lập.","detail":"Pháp bảo phòng ngự dạng khiên đồng. Khi Hàn Lập dùng hai thanh Thanh Trúc Phong Vân Kiếm hóa cự kiếm tấn công tử vân, đồng cổ thuẫn bay ra dễ dàng ngăn cản được công kích.","congNang":["Phòng ngự, chặn kiếm"],"chuSoHuu":[{"ten":"Ôn Thiên Nhân","tuChuong":"@c0570","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0570","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Bay ra từ tử vân dễ dàng chặn công kích hai thanh cự kiếm Thanh Trúc Phong Vân Kiếm.","anchor":"một thanh đồng cổ thuẫn bay ra dễ dàng ngăn cản được công kích của hai thanh cự kiếm"}]},"capNhatToi":"@c0570","nguon":["@c0570"]},{"id":"cu-chung-bac","name":"Cự chung màu bạc","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Ôn Thiên Nhân"],"trangThai":"dang-dung","blurb":"Pháp bảo tấn công của Ôn Thiên Nhân, từ bạch quang hóa thành cự chung bạc khổng lồ giáng xuống từ trên cao.","detail":"Ôn Thiên Nhân phóng ra bạch quang hóa thành một cự chung màu bạc thật lớn giáng xuống đỉnh đầu Hàn Lập. Được dùng sau khi Lục Cực Chân Ma bị phá, là đòn phản kích cuối chương.","congNang":["Hóa thành cự chung khổng lồ giáng từ trên trời xuống tấn công đối phương @c0571"],"chuSoHuu":[{"ten":"Ôn Thiên Nhân","tuChuong":"@c0571","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0571","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Ôn Thiên Nhân phóng bạch quang hóa thành cự chung bạc khổng lồ giáng xuống đỉnh đầu Hàn Lập sau khi Lục Cực Chân Ma bị phá.","anchor":"bạch quang Ôn Thiên Nhân bắn ra đã hóa thanh một cự chung màu bạc thật lớn từ trên trời giáng xuống đỉnh đầu hắn"}]},"capNhatToi":"@c0571","dinhDanh":"goc","nguon":["@c0571"]},{"id":"bat-mon-kim-quang-kinh","name":"Bát Môn Kim Quang Kính","cn":"八门金光镜","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo cấp cao","soHuu":["Ôn Thiên Nhân"],"trangThai":"dang-co","blurb":"Tám tấm cổ kính thuần kim, pháp bảo đắc lực của Ôn Thiên Nhân. Hoạt động theo nguyên lý khuếch đại liên hoàn: kim quang bắn từ sừng vàng lần lượt xuyên qua tám tấm kính, mỗi lần đi qua một kính lại lớn mạnh thêm vài phần, uy lực khiến cả Tử Linh tiên tử lẫn Hàn Lập đều kiêng dè.","detail":"Bát Môn Kim Quang Kính là tám tấm cổ kính thuần kim lớn khoảng ba bàn tay. Một mặt bóng loáng có kim quang lưu động, mặt còn lại gồ ghề xấu xí. Khi triển khai, Ôn Thiên Nhân phóng tám ngọn kim diễm từ tay áo, kim diễm biến hóa thành tám tấm kính bày ra trận thế. Phối hợp với sừng vàng trên trán, hắn bắn kim quang liên hoàn xuyên qua lần lượt tám tấm kính; mỗi lần kim quang đi qua một tấm kính đều được khuếch đại, lớn mạnh thêm vài phần so với trước đó. Tử Linh tiên tử khi nhận ra pháp bảo này đã kinh hãi gọi tên, cho thấy danh tiếng và sự lợi hại của nó được giới tu tiên biết đến rộng rãi.","hinhDang":"Tám tấm cổ kính thuần kim, lớn khoảng ba bàn tay, một mặt bóng loáng kim quang lưu động, mặt còn lại gồ ghề xấu xí","congNang":["Khuếch đại kim quang liên hoàn qua tám tấm kính, mỗi lần kim quang xuyên qua một kính đều lớn mạnh thêm vài phần @c0572"],"chuSoHuu":[{"ten":"Ôn Thiên Nhân","tuChuong":"@c0572","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0572","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện trong trận đấu","text":"Ôn Thiên Nhân phóng tám ngọn kim diễm biến thành tám tấm cổ kính thuần kim — Bát Môn Kim Quang Kính, dùng sừng vàng bắn kim quang liên hoàn qua tám kính khuếch đại. Tử Linh tiên tử kinh hãi kêu tên pháp bảo.","anchor":"Lúc này kim diễm như được đông cứng lại, hiện ra tám cái cổ kính thuần kim"}]},"nguon":["@c0572"],"uyLuc":"Kim quang sau khi liên hoàn khuếch đại qua tám tấm kính đạt uy lực đủ khiến Tử Linh tiên tử kinh hãi, cả nàng lẫn Hàn Lập đều nhận biết sự lợi hại của pháp bảo này.","dacDiem":"Tám tấm cổ kính thuần kim lớn khoảng ba bàn tay, một mặt bóng loáng kim quang lưu động, mặt còn lại gồ ghề xấu xí; ban đầu ẩn dưới dạng tám ngọn kim diễm trong tay áo, khi phóng ra mới biến thành hình kính."},{"id":"bat-mon-kim-quang-kinh-phuc-che","name":"Bát Môn Kim Quang Kính (phục chế phẩm)","cn":"八门金光镜","aliases":["Bát Môn Kim Quang Kính"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Phục chế phẩm (bản gốc là truyền thuyết pháp bảo)","soHuu":["Ôn Thiên Nhân"],"trangThai":"dang-co","blurb":"Phục chế phẩm của pháp bảo truyền thuyết từng thuộc Thiên Kính Tán Nhân — đệ nhất pháp bảo công kích Loạn Tinh Hải. Tám mặt kính kim sắc, có thể bắn cột sáng tốc độ cực nhanh, tạo lồng kim quang giam giữ và hóa Kim Quang Thần Diễm thiêu đốt. Ôn Thiên Nhân điều khiển bảo vật này qua chiếc sừng vàng trên trán.","detail":"Bát Môn Kim Quang Kính nguyên bản là pháp bảo truyền thuyết của Thiên Kính Tán Nhân, nổi danh là đệ nhất pháp bảo công kích tại Loạn Tinh Hải. Bản gốc từng giết năm sáu tu sĩ Nguyên Anh Kỳ và tiêu diệt tuyệt đỉnh pháp bảo của người đứng đầu Tinh Cung. Phiên bản phục chế do Ôn Thiên Nhân sử dụng tuy uy lực suy giảm so với nguyên tác, nhưng vẫn đủ sức phá hủy kiếm quang huyễn hóa cùng Ngũ Hành Cự Hoàn của Hàn Lập, đồng thời giam chặt đối thủ khiến Phong Lôi Sí bị vô hiệu hóa. Ôn Thiên Nhân điều khiển pháp bảo thông qua chiếc sừng vàng trên trán.","congNang":["Bắn kim quang cột sáng với tốc độ cực nhanh, đủ sức phá hủy kiếm quang huyễn hóa và Ngũ Hành Cự Hoàn @c0573","Tạo lồng kim quang giam bốn phía, khóa chặt đối thủ khiến Phong Lôi Sí bị vô hiệu hóa @c0573","Hóa thành Kim Quang Thần Diễm thiêu đốt"],"hinhDang":"Tám mặt kính kim sắc","nguonGoc":"Phục chế từ pháp bảo truyền thuyết của Thiên Kính Tán Nhân","chuHienThoi":"Ôn Thiên Nhân","nguon":["@c0573"],"chuSoHuu":[{"ten":"Thiên Kính Tán Nhân","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ nhân nguyên bản (bản gốc)","trangThai":"da-mat"},{"ten":"Ôn Thiên Nhân","tuChuong":"@c0573","denChuong":"","cachCoDuoc":"Không rõ (sở hữu phục chế phẩm)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0573","loai":"xuat hien","importance":"major","giaiDoan":"Lần đầu xuất hiện trong trận chiến","text":"Ôn Thiên Nhân kích hoạt Bát Môn Kim Quang Kính phục chế phẩm, phá hủy kiếm quang và Ngũ Hành Cự Hoàn của Hàn Lập, tạo lồng kim quang giam chặt rồi hóa Kim Quang Thần Diễm nhốt Hàn Lập.","anchor":"từng được xưng là đệ nhất pháp bảo công kích của Loạn Tinh Hải"}]},"uyLuc":"Phiên bản phục chế vẫn đủ uy lực phá hủy kiếm quang huyễn hóa cùng Ngũ Hành Cự Hoàn và giam chặt Hàn Lập khiến Phong Lôi Sí bất lực; bản gốc từng giết năm sáu tu sĩ Nguyên Anh Kỳ và tiêu diệt tuyệt đỉnh pháp bảo của người đứng đầu Tinh Cung.","dacDiem":"Tám mặt kính kim sắc; được điều khiển qua sừng vàng trên trán Ôn Thiên Nhân; là phục chế phẩm nên uy lực giảm so với nguyên bản."},{"id":"ngu-hanh-cu-hoan","name":"Ngũ Hành Cự Hoàn","cn":"五行巨环","aliases":["Năm cái vòng đồng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"hong","blurb":"Năm cái vòng ngũ hành, tiện dụng khi đối phó tu sĩ cấp thấp. Bị kim quang Bát Môn Kim Quang Kính phá hủy thành bột phấn, mất vĩnh viễn.","detail":"Hàn Lập dùng Ngũ Hành Cự Hoàn hộ thể nhưng chỉ cản được kim quang chốc lát rồi bị phá hủy hoàn toàn. Hàn Lập tiếc nuối vì pháp bảo này rất hữu dụng khi giao chiến với tu sĩ cấp thấp hơn.","congNang":["Hộ thể","Đối phó tu sĩ cấp thấp hiệu quả"],"nguonGoc":"Không rõ","chuHienThoi":"Không còn (đã phá hủy)","nguon":["@c0573"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"","denChuong":"@c0573","cachCoDuoc":"Không rõ","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c0573","loai":"hu ton/tu bo","importance":"normal","giaiDoan":"Bị phá hủy","text":"Bị kim quang Bát Môn Kim Quang Kính phá thành bột phấn, mất vĩnh viễn.","anchor":"Ngũ hành cự hoàn ở phía sau hào quang chợt lóe lên nhưng thật ra chỉ ngăn cản trong chốc lát"}]}},{"id":"van-nien-linh-dich","name":"Vạn niên linh dịch","cn":"万年灵液","category":"dan-duoc","categoryLabel":"Đan dược / Linh dịch","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bình linh dịch vạn năm Hàn Lập thu được từ Nguyên Dao, có tác dụng bổ sung pháp lực, là lợi thế then chốt trong trận đấu tiêu hao với Ôn Thiên Nhân.","detail":"Hàn Lập lấy ra từ túi trữ vật khi bị kim diễm vây khốn, tự nhận xét rằng nếu không có linh dịch này thì đã chết nhưng cũng chính vì nó mà gặp Lục Đạo Truyền Nhân và bị vây khốn. Nhờ linh dịch này hắn tự tin tĩnh tọa thi đấu pháp lực tiêu hao lâu dài với Ôn Thiên Nhân.","congNang":["Bổ sung pháp lực cho tu sĩ, cho phép duy trì chiến đấu tiêu hao lâu dài @c0574"],"chuSoHuu":[{"ten":"Nguyên Dao","tuChuong":"@c0570","denChuong":"@c0573","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0573","denChuong":"","cachCoDuoc":"Thu được từ Nguyên Dao","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0574","loai":"dùng","importance":"normal","giaiDoan":"Hàn Lập dùng trong trận đấu tiêu hao","text":"Hàn Lập lấy ra bình Vạn niên linh dịch khi bị kim diễm vây khốn, dùng làm lợi thế trong trận tĩnh tọa thi đấu pháp lực tiêu hao với Ôn Thiên Nhân.","anchor":"Vạn niên linh dịch này vừa mới đến tay, sợ rằng bảo toàn không được bao lâu"}]},"nguon":["@c0574"]},{"id":"nghich-tinh-co-hieu","name":"Nghịch Tinh Minh cờ hiệu","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Ôn Thiên Nhân"],"trangThai":"dang-co","blurb":"Cờ hiệu đại diện thế lực Nghịch Tinh Minh, được thị nữ Ôn Thiên Nhân xuất ra để hù dọa các tu sĩ muốn tiếp cận đảo.","detail":"Nữ tu thị nữ xuất ra cờ hiệu Nghịch Tinh Minh khiến các tu sĩ muốn tiếp cận đảo hoảng sợ bỏ đi, cho thấy uy danh khủng khiếp của thế lực Lục Đạo Cực Thánh.","nguon":["@c0574"]},{"id":"binh-khi-toa-nhiet-ky-di","name":"Binh khí tỏa nhiệt kỳ dị","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Hán tử gầy gò","Nhóm cư dân Vô Danh Chi Địa"],"trangThai":"dang-co","blurb":"Đao kiếm của cư dân Vô Danh Chi Địa, tỏa ra cảm giác nóng rực như sắt nung, phát ánh sáng kỳ dị, khác hẳn pháp khí tu tiên giới thông thường.","detail":"Hơn hai mươi thanh niên nam nữ thuộc nhóm trung niên gầy gò đều cầm binh khí loại này. Hàn Lập kinh ngạc khi cảm nhận nhiệt lượng tỏa ra từ đao kiếm, nóng rực như sắt vừa nung, ánh sáng kỳ dị bao phủ. Đặc thù này có thể liên quan đến năng lượng hoặc vật liệu riêng của Vô Danh Chi Địa.","congNang":["Tỏa nhiệt nóng rực như sắt nung, phát ánh sáng kỳ dị"],"tabs":{"tienTrinh":[{"chuong":"@c0577","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Nhóm cư dân Vô Danh Chi Địa vây Hàn Lập bằng hơn hai mươi thanh đao kiếm tỏa nhiệt kỳ dị, Hàn Lập kinh ngạc khi cảm nhận.","anchor":"hắn cảm nhận trên binh khí tỏa ra một loại cảm giác nóng rực, như là đao kiếm mỗi người đều là sắt nung vậy"}]},"nguon":["@c0577"]},{"id":"noi-dan-am-thu","name":"Nội đan âm thú","cn":"","aliases":["tinh thạch xanh biếc","tinh thạch âm thú","Thú tinh","Âm Minh thú tinh","tinh hạch âm thú"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Lão già mập mạp"],"trangThai":"dang-co","blurb":"Viên tinh thạch lớn bằng ngón tay cái màu xanh biếc, được móc ra từ đầu cự thú (âm thú) sau khi giết. Giống hệt tinh hạch bên trong khôi lỗi Hư Thiên Điện.","detail":"Nội đan của âm thú trong Âm Minh chi địa, hình dạng là tinh thạch màu xanh biếc lớn bằng ngón tay cái. Hàn Lập nhận ra nó giống hệt tinh hạch bên trong khôi lỗi mà hắn đã thu được ở Hư Thiên Điện trước đây, cho thấy mối liên hệ giữa khôi lỗi và âm thú.","congNang":["Chưa rõ công dụng cụ thể, được thôn dân coi trọng thu giữ","Cung cấp Âm Minh lực để thi triển pháp thuật","Khảm lên thạch phù khởi động pháp trận"],"tabs":{"tienTrinh":[{"chuong":"@c0580","loai":"xuất hiện","importance":"normal","giaiDoan":"Thu hoạch từ cự thú","text":"Thôn dân chặt đầu cự thú, móc ra viên tinh thạch xanh biếc. Hàn Lập nhận ra nó giống hệt tinh hạch trong khôi lỗi Hư Thiên Điện. Đại trưởng lão cất giữ viên tinh thạch.","anchor":"móc ra một tinh thạch lớn bằng ngón tay cái màu xanh biếc"},{"chuong":"@c0582","loai":"hé lộ công năng","importance":"normal","giaiDoan":"Bão Hoàn Tử giải thích cho Hàn Lập","text":"Bão Hoàn Tử giải thích thú tinh là khoáng kết tinh trong đầu Âm thú, nguồn duy nhất để thi triển pháp thuật tại Âm Minh giới, cả năm thôn chỉ thu khoảng mười khối.","anchor":"thi pháp làm tiêu hao Âm Minh thú tinh nhiều hay ít cũng là tiêu chuẩn để xét là có cường đại hay không"}]},"nguon":["@c0580","@c0582"]},{"id":"thu-tinh-am-minh","name":"Thú tinh","cn":"","aliases":["Âm Minh thú tinh"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu / Khoáng kết tinh","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Khoáng vật hoặc viên kết tinh trong đầu Âm thú, nguồn năng lượng duy nhất để thi triển pháp thuật tại Âm Minh giới thay cho pháp lực đã tiêu thất.","detail":"Âm thú mạnh hơn thì xác suất có thú tinh cao hơn nhưng không chắc chắn. Cả năm thôn chỉ thu được khoảng mười khối, do trưởng lão phân bảo quản, chỉ giao khi chiến đấu rồi thu hồi ngay. Cũng dùng để khảm lên thạch phù khởi động pháp trận. Lượng Âm Minh lực tiêu hao khi thi pháp là tiêu chuẩn đánh giá sức mạnh pháp thuật.","congNang":["Cung cấp Âm Minh lực để thi triển pháp thuật trong Âm Minh giới","Khảm lên thạch phù để khởi động pháp trận"],"tabs":{"tienTrinh":[{"chuong":"@c0582","loai":"xuất hiện","importance":"normal","giaiDoan":"Bão Hoàn Tử giải thích cho Hàn Lập","text":"Bão Hoàn Tử giải thích: thú tinh là khoáng kết tinh trong đầu Âm thú, nguồn năng lượng duy nhất thi triển pháp thuật tại Âm Minh, cực hiếm và phân bổ hạn chế.","anchor":"thi pháp làm tiêu hao Âm Minh thú tinh nhiều hay ít cũng là tiêu chuẩn để xét là có cường đại hay không"}]},"nguon":["@c0582"]},{"id":"dan-van-thach-phu","name":"Đàn vân thạch phù","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Trận cụ / Phù chú cổ","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Bàn đá hình tròn đường kính một trượng, khắc phù văn chú ngữ cổ quái, kết hợp phù chú và pháp trận, mượn Âm Minh lực để khởi động. Loại thạch phù/ngọc phù cổ xưa gần thất truyền, chỉ Ngũ Long Hải còn chế tác được.","detail":"Bàn đá hình tròn trên đài cao, mặt khắc phù văn chú ngữ cổ quái, phát ra khí tím kết nối với tử vân trên trời. Kết hợp hiệu lực phù chú và pháp trận nhưng uy lực bị giảm so với bình thường. Bình thường không khảm thú tinh, chỉ khi chiến đấu mới khảm. Loại thạch phù/ngọc phù này gần thất truyền, chỉ một ít tông môn trong Ngũ Long Hải còn có người chế tác.","congNang":["Mượn Âm Minh lực khởi động pháp trận phòng thủ/tấn công"],"nguonGoc":"Kỹ thuật cổ xưa của Ngũ Long Hải","tabs":{"tienTrinh":[{"chuong":"@c0582","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập nghiên cứu, Bão Hoàn Tử giải thích","text":"Hàn Lập nghiên cứu thạch phù trên đài cao, Bão Hoàn Tử giải thích đây là đàn vân thạch phù — loại phù chú cổ xưa kết hợp phù chú và pháp trận, mượn Âm Minh lực khởi động.","anchor":"nó có thể mượn Âm Minh lực, mà khởi động một ít pháp trận đặc biệt, làm cho nó có hiệu lực như phù chú cùng pháp trận"}]},"nguon":["@c0582"]},{"id":"thanh-tieu-kiem","name":"Thanh tiểu kiếm","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Thanh tiểu kiếm màu xanh của Hàn Lập, sắc bén cực kỳ, chỉ cần một ngón tay lực là cắt đứt yết hầu. Được cất trong ống tay áo.","detail":"Hàn Lập dùng thanh tiểu kiếm này kề cổ họng Phong Thiên Cực để uy hiếp sau khi dùng La Yên Bộ xuất hiện sau lưng đối phương. Kiếm vô thanh vô tức, sắc bén đủ để một ngón tay lực cắt đứt yết hầu.","congNang":["Sắc bén cực kỳ, kề cổ uy hiếp @c0583"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0583","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0583","loai":"dùng","importance":"normal","giaiDoan":"Dùng uy hiếp Phong Thiên Cực","text":"Hàn Lập xuất hiện sau lưng Phong Thiên Cực, kề thanh tiểu kiếm xanh vào cổ họng đối phương uy hiếp, sau đó cất vào ống tay áo.","anchor":"phía sau người xuất hiện một thanh tiểu kiếm màu xanh, vô thanh vô tức kề ngay cổ họng"}]},"nguon":["@c0583"]},{"id":"thong-ngoc-phung-tuy-than","name":"Thông ngọc phượng tủy thân","cn":"通玉凤髓身","category":"khac","categoryLabel":"Thể chất đặc thù","phamCap":"Cực hiếm","soHuu":["Mai Ngưng"],"trangThai":"dang-co","blurb":"Thể chất đặc thù chỉ xuất hiện ở nữ nhân, sau khi vào Trúc Cơ kỳ sinh ra Thông linh khí — một trong thất đại linh lực tinh túy trên thế gian.","detail":"Thể chất không giúp tu luyện nhưng sau Trúc Cơ kỳ sinh ra Thông linh khí. Biểu hiện: trên cánh tay có dấu thủ cung sa đỏ tươi, ấn vào hiện đồ án phượng hoàng bạc có hào quang lưu động gọi là Thông ngọc linh phượng. Mất thân xử nữ thì linh khí cũng mất.","nguon":["@c0584"]},{"id":"tram-thuy","name":"Trầm Thủy","category":"khac","categoryLabel":"Khác","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Chất lỏng đặc biệt được tìm thấy trong một căn nhà đá tại nơi âm minh, Hàn Lập thu thập khoảng một nửa lượng có sẵn.","detail":"Chất lỏng có tại nơi âm minh, được chứa trong một căn nhà đá. Hàn Lập dùng mấy bình không dung lượng lớn lấy đi khoảng một nửa số lượng. Công dụng cụ thể chưa rõ.","congNang":["Chưa rõ công dụng cụ thể, Hàn Lập đặc biệt thu thập gợi ý có giá trị","Công dụng chưa rõ, được Hàn Lập đặc biệt thu thập tại nơi âm minh"],"tabs":{"tienTrinh":[{"chuong":"@c0585","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập thu thập","text":"Hàn Lập bí mật vào căn nhà đá, dùng mấy bình lớn lấy khoảng một nửa lượng Trầm Thủy tại đó.","anchor":"Hàn Lập dùng mấy bình không dung lượng lớn trong Túi trữ vật, lấy đi khoảng một nửa chỗ này"}]},"nguon":["@c0585","@c0582"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0585","denChuong":"","cachCoDuoc":"Tự thu thập tại căn nhà đá nơi âm minh","trangThai":"dang-co"}]},{"id":"co-bao-kim-kinh","name":"Cổ bảo kim kính","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Một trong ba cổ bảo Hàn Lập mang theo, được thu lại vào Túi trữ vật vì không cần dùng.","detail":"Cổ bảo kim kính được Hàn Lập lấy từ trong áo ra rồi thu vào Túi trữ vật vì không dùng đến tại nơi âm minh.","nguon":["@c0585"]},{"id":"co-bao-hoa-lam","name":"Cổ bảo hoa lam","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Một trong ba cổ bảo Hàn Lập mang theo, được thu lại vào Túi trữ vật.","detail":"Cổ bảo hoa lam được Hàn Lập thu vào Túi trữ vật vì không cần dùng tại nơi âm minh.","nguon":["@c0585"]},{"id":"co-bao-ngan-chung","name":"Cổ bảo ngân chung","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Một trong ba cổ bảo Hàn Lập mang theo, được thu lại vào Túi trữ vật.","detail":"Cổ bảo ngân chung được Hàn Lập thu vào Túi trữ vật vì không cần dùng tại nơi âm minh.","nguon":["@c0585"]},{"id":"de-hon-thu-linh-thu","name":"Đề Hồn Thú","category":"khac","categoryLabel":"Linh thú","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Linh thú của Hàn Lập, vốn lười biếng nhưng hưng phấn bất thường khi ở nơi âm minh, gợi ý khả năng cảm ứng hồn phách.","detail":"Được Hàn Lập nuôi trong Túi linh thú. Khi triệu hồn tại nơi âm minh, phản ứng bất thường: vốn lười biếng nhưng đột nhiên hưng phấn đánh hơi chạy quanh, gợi ý nơi này có nguồn hồn phách hoặc âm khí đặc biệt. Sau đó tự bay vào ống tay áo Hàn Lập theo hắn ra ngoài.","congNang":["Cảm ứng hồn phách, phản ứng mạnh tại nơi âm khí dồi dào"],"tabs":{"tienTrinh":[{"chuong":"@c0585","loai":"dùng","importance":"normal","giaiDoan":"Triệu hồi tại nơi âm minh","text":"Được triệu hồi từ Túi linh thú, hưng phấn bất thường đánh hơi chạy quanh, gợi ý cảm ứng hồn phách mạnh.","anchor":"con thú nguyên vốn lười biếng này đột nhiên tinh thần rung lên, dùng mũi đánh hơi vài cái, lập tức hưng phấn lên"}]},"nguon":["@c0585"]},{"id":"phap-khi-phi-cham-xanh","name":"Pháp khí phi châm xanh","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Đỉnh cấp pháp khí","soHuu":["Hàn Lập","Mai Ngưng"],"trangThai":"dang-dung","blurb":"Cây châm dài màu xanh đỉnh cấp pháp khí, Hàn Lập lấy từ tu sĩ chết, đưa cho Mai Ngưng dùng xuyên qua da thú cứng để may áo chống âm phong.","detail":"Đỉnh cấp pháp khí hình cây châm dài màu xanh, có khả năng xuyên thủng da thú cao cấp mà binh khí thường không làm được. Hàn Lập thu được từ một tu sĩ chết trên tay hắn trước đó, sau đưa cho Mai Ngưng dùng may áo da thú hỏa thuộc tính chống âm phong.","nguon":["@c0586"]},{"id":"da-thu-hoa-thuoc-tinh","name":"Da thú cao cấp hỏa thuộc tính","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Da thú cao cấp có hỏa thuộc tính, Hàn Lập có sẵn, dùng may thành áo mặc chống âm phong trong Âm Minh giới.","detail":"Da thú cao cấp mang hỏa thuộc tính, cứng đến mức cần pháp khí phi châm mới xuyên qua được, dùng gân thú khâu lại thành áo chống âm phong.","nguon":["@c0586"]},{"id":"cot-hap","name":"Cốt hạp","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hộp làm bằng xương nham nhám do Vân đạo hữu (chưởng môn đời 57 Linh Phù Môn) gửi gắm Hàn Lập, nhờ mang giao cho Linh Phù Môn nếu thoát khỏi Âm Minh giới. Nội dung bên trong chưa được tiết lộ.","detail":"Hộp hình dáng nham nhám, chất liệu bằng xương. Vân đạo hữu lén lút tìm đến Hàn Lập đêm trước ngày rời thôn, hai tay ôm lấy đưa cho hắn, nhờ nếu có cơ hội thoát khỏi đại nạn thì mang giao cho Linh Phù Môn. Đây là niềm hy vọng cuối cùng của lão.","hinhDang":"Hộp bằng xương, bề mặt nham nhám","vatLieu":"Xương","nguonGoc":"Vân đạo hữu mang theo người từ trước khi bị kẹt trong Âm Minh giới","chuHienThoi":"Hàn Lập (được gửi gắm)","chuSoHuu":[{"ten":"Vân đạo hữu","tuChuong":"@c0587","denChuong":"@c0587","cachCoDuoc":"Mang theo từ trước","trangThai":"da-giao"},{"ten":"Hàn Lập","tuChuong":"@c0587","denChuong":"","cachCoDuoc":"Được Vân đạo hữu gửi gắm","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0587","loai":"xuat-hien","importance":"normal","giaiDoan":"Xuất hiện lần đầu","text":"Vân đạo hữu lén lút tìm đến Hàn Lập đêm trước ngày rời thôn, lấy từ trong áo ra một cái hộp làm bằng xương nham nhám, hai tay ôm lấy đưa cho Hàn Lập, nhờ mang giao cho Linh Phù Môn.","anchor":"từ trong áo lấy ra một cái hộp làm bằng xương nham nhám, hai tay ôm lấy đưa cho Hàn Lập"}]},"nguon":["@c0587"]},{"id":"hop-xuong-hang-linh-phu","name":"Hộp xương chứa cốt phiến Hàng Linh Phù","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Đang được Hàn Lập giữ","blurb":"Hộp xương bên trong chứa ba cốt phiến khắc đầy ký tự kỳ lạ, ghi khẩu quyết luyện chế Hàng Linh Phù, tuyệt học trấn phái Linh Phù Môn.","detail":"Hộp xương do chưởng môn đời 57 Linh Phù Môn trao cho Hàn Lập. Bên trong chứa ba khối cốt phiến khắc đầy ký tự kỳ lạ, ghi toàn bộ khẩu quyết luyện chế Hàng Linh Phù. Hàn Lập xem xong cốt phiến đầu phát hiện nguyên liệu cần tinh hạch yêu thú Hóa Hình Kỳ, xem cốt phiến tiếp theo lại lộ vẻ kỳ bí.","chuSoHuu":[{"ten":"Vân đạo hữu","tuChuong":"@c0588","denChuong":"@c0588","cachCoDuoc":"Truyền thừa chưởng môn","trangThai":"đã trao"},{"ten":"Hàn Lập","tuChuong":"@c0588","denChuong":"","cachCoDuoc":"Được chưởng môn Linh Phù Môn trao tặng","trangThai":"đang giữ"}],"capNhatToi":"@c0588","tabs":{"tienTrinh":[{"chuong":"@c0588","loai":"đổi chủ","importance":"normal","giaiDoan":"Chưởng môn Linh Phù Môn trao cho Hàn Lập","text":"Chưởng môn đời 57 Linh Phù Môn trao hộp xương chứa ba cốt phiến Hàng Linh Phù cho Hàn Lập. Hàn Lập mở ra xem, phát hiện nguyên liệu chính cần tinh hạch yêu thú Hóa Hình Kỳ.","anchor":"Sau đó hắn mở nắp hộp ra, đem ra một khối cốt phiến khắc đầy những kí tự kì lạ ra"}]},"nguon":["@c0588"],"congNang":["Lưu trữ khẩu quyết trấn phái Hàng Linh Phù"]},{"id":"tinh-thach-am-thu","name":"Tinh thạch âm thú","cn":"","aliases":["Tinh hạch âm thú","Thú tinh","Tinh thạch xanh biếc","Âm Minh thú tinh"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Viên tinh thạch xanh biếc to bằng ngón tay, nằm trong đầu âm thú cấp cao vùng âm minh. Hàn Lập nhận định rất hiếm, quyết tâm thu thập.","detail":"Tinh thạch nằm trong đầu cự thú cấp cao ở vùng âm minh. Hàn Lập dùng đoản đao chẻ đầu lấy ra. Hàn Lập mơ hồ nhận ra thú tinh có tác dụng đặc biệt nên muốn thu thập nhiều trước khi rời vùng âm minh.","congNang":["Tác dụng cụ thể chưa tiết lộ, Hàn Lập mơ hồ nhận ra có công dụng đặc biệt"],"tabs":{"tienTrinh":[{"chuong":"@c0589","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập thu hoạch lần đầu","text":"Hàn Lập chẻ đầu cự thú cấp cao bị Đề Hồn thú hút khô, lấy ra viên tinh thạch xanh biếc to bằng ngón tay. Nhận định nơi âm minh hiếm có nên quyết thu thập thêm.","anchor":"một viên tinh thạch to bằng ngón cái xanh biếc xuất hiện"}]},"nguon":["@c0589"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0589","denChuong":"","cachCoDuoc":"Chẻ đầu cự thú cấp cao lấy ra","trangThai":"dang-co"}]},{"id":"vien-chau-trang-ti-phong","name":"Viên châu trắng tị phong","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang dùng","blurb":"Viên châu trắng tỏa bạch quang bao bọc quanh người, khiến cuồng phong chạm vào liền suy yếu trở nên vô lực. Hàn Lập dùng để chống âm minh phong trên Bạo Phong Sơn.","detail":"Hàn Lập lấy từ trong áo ra khi leo Bạo Phong Sơn trên ngàn trượng, viên châu lóe sáng bao bọc hai người trong bạch quang, cuồng phong chạm vào liền bị suy yếu trở nên mềm yếu vô lực, giúp chống chọi âm minh phong cực mạnh.","congNang":["Tị phong — tỏa bạch quang khiến cuồng phong suy yếu trở nên vô lực"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0590","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0590","loai":"dùng","importance":"normal","giaiDoan":"Lần đầu sử dụng trên Bạo Phong Sơn","text":"Hàn Lập lấy viên châu trắng từ trong áo, tỏa bạch quang bao bọc hai người, cuồng phong chạm vào liền suy yếu, giúp chống âm minh phong khi leo núi trên ngàn trượng.","anchor":"khi mà cuồng phong chạm vào bạch quang này liền bị suy yếu đi, trở nên mềm yếu vô lực"}]},"nguon":["@c0590"]},{"id":"tu-tuong-ban-long-dai","name":"Tứ Tượng Bàn Long Đái","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập thu từ Ôn Thiên Nhân","blurb":"Tứ Tượng Bàn Long Đái là đai lưng bích ngọc vốn thuộc sở hữu của Ôn Thiên Nhân, bên trong khảm bốn loại kỳ châu mang công năng tị phong, ích hỏa, tị thủy, tị trần, đồng thời có tác dụng an thần bính tĩnh hồn. Sau khi Ôn Thiên Nhân bị giết, pháp bảo này được Hàn Lập thu lấy.","detail":"Tứ Tượng Bàn Long Đái là một đai lưng chế tác từ bích ngọc, bên trong khảm bốn loại kỳ châu, mỗi loại mang một công năng riêng biệt: tị phong, ích hỏa, tị thủy và tị trần. Ngoài bốn tác dụng chính này, đai còn sở hữu thêm khả năng an thần bính tĩnh hồn. Ôn Thiên Nhân khi còn sống đã nhờ vào công năng của đai mà leo được lên cao trong sương mù. Sau khi Ôn Thiên Nhân bị giết, Tử Linh Tiên Tử đã giới thiệu công năng của đai cho Hàn Lập, và pháp bảo này được Hàn Lập thu lấy.","hinhDang":"Đai lưng bích ngọc","vatLieu":"Bích ngọc, bốn loại kỳ châu","congNang":["Tị phong — chống gió @c0591","Ích hỏa — trợ ích cho lửa @c0591","Tị thủy — chống nước @c0591","Tị trần — chống bụi trần @c0591","An thần bính tĩnh hồn — ổn định thần trí, giữ yên hồn phách @c0591"],"chuSoHuu":[{"ten":"Ôn Thiên Nhân","tuChuong":"@c0591","denChuong":"@c0591","cachCoDuoc":"Sở hữu sẵn","trangThai":"tu-vong"},{"ten":"Hàn Lập","tuChuong":"@c0591","denChuong":"","cachCoDuoc":"Thu từ thi thể Ôn Thiên Nhân","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0591","loai":"đổi chủ","importance":"major","giaiDoan":"Ôn Thiên Nhân bị giết, Hàn Lập thu lấy","phamCap":"Không rõ","text":"Đai lưng bích ngọc của Ôn Thiên Nhân, khảm bốn loại kỳ châu tị phong ích hỏa tị thủy tị trần, thêm tác dụng an thần bính tĩnh hồn. Sau khi Hàn Lập giết Ôn Thiên Nhân, thu lấy đai lưng này. Tử Linh Tiên Tử giới thiệu công năng.","anchor":"Bên trong là có khảm bốn loại kì châu tị phong, ích hỏa, tị thủy, tị trần, ngoài ra còn có tác dụng an thần bính tĩnh hồn"}]},"nguon":["@c0591"],"dacDiem":"Đai lưng chế tác từ bích ngọc, bên trong khảm bốn loại kỳ châu tương ứng bốn công năng."},{"id":"noi-giap-xanh-biec","name":"Nội giáp xanh biếc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập thu từ Ôn Thiên Nhân","blurb":"Nội giáp mặc bên trong y phục của Ôn Thiên Nhân, ẩn hiện lục quang, đỡ được tiểu kiếm khiến bật ngược trở lại. Bị Hàn Lập thu lấy sau khi giết Ôn Thiên Nhân.","detail":"Nội giáp phòng ngự mặc bên trong quần áo, ẩn hiện lục quang. Khi Hàn Lập phóng tiểu kiếm lần đầu vào ngực Ôn Thiên Nhân, nội giáp đỡ được khiến tiểu kiếm bật ngược trở lại. Sau khi Ôn Thiên Nhân bị giết, Hàn Lập thu lấy.","congNang":["Phòng ngự vật lý, đỡ được tiểu kiếm bật ngược @c0591","Phòng ngự vật lý, đỡ được tiểu kiếm khiến bật ngược @c0591"],"chuSoHuu":[{"ten":"Ôn Thiên Nhân","tuChuong":"@c0591","denChuong":"@c0591","cachCoDuoc":"Sở hữu sẵn","trangThai":"tu-vong"},{"ten":"Hàn Lập","tuChuong":"@c0591","denChuong":"","cachCoDuoc":"Thu từ thi thể Ôn Thiên Nhân","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0591","loai":"đổi chủ","importance":"normal","giaiDoan":"Ôn Thiên Nhân bị giết, Hàn Lập thu lấy","text":"Nội giáp ẩn hiện lục quang bên trong y phục Ôn Thiên Nhân, đỡ được tiểu kiếm khiến bật ngược. Hàn Lập thu lấy sau khi giết Ôn Thiên Nhân.","anchor":"va chạm vào thiết giáp, bắn ngược trở lại. Từ hao tổn trên quần áo thì hình như bên trong có ẩn hiện lục quang"}]},"nguon":["@c0591"]}]};
